  "main.rs": "use std::io::{self, Read};

/// Tokenize a command line using (a subset of) shell-like rules:
/// - Whitespace separates tokens (outside quotes)
/// - Single quotes preserve everything verbatim until the next single quote
/// - Adjacent quoted/unquoted parts concatenate into the same token
/// - Empty quotes ('') can produce an empty token if separated by whitespace
fn tokenize(input: &str) -> Result<Vec<String>, String> {
    let mut tokens: Vec<String> = Vec::new();
    let mut cur = String::new();

    let mut in_single_quotes = false;
    // Distinguish “we are between tokens” from “current token is empty but real”.
    let mut token_started = false;

    for ch in input.chars() {
        if in_single_quotes {
            if ch == '\'' {
                in_single_quotes = false;
            } else {
                cur.push(ch);
            }
            continue;
        }

        match ch {
            '\'' => {
                in_single_quotes = true;
                token_started = true; // even '' should count as a token
            }
            c if c.is_whitespace() => {
                if token_started {
                    tokens.push(std::mem::take(&mut cur));
                    token_started = false;
                }
                // else: still between tokens, keep skipping whitespace
            }
            other => {
                token_started = true;
                cur.push(other);
            }
        }
    }

    if in_single_quotes {
        return Err("unterminated single quote".to_string());
    }

    if token_started {
        tokens.push(cur);
    }

    Ok(tokens)
}

fn main() {
    // Read all stdin (so you can paste input or pipe it in). If empty, use a demo string.
    let mut buf = String::new();
