  "main.rs": "use core::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;

/// A `fetch_add` replacement implemented using a critical section.
///
/// Ordering note:
/// - In your original code you used `fetch_add(1, Ordering::Relaxed)`, meaning you only
///   required *atomicity of the increment* and did not use this operation for synchronization.
/// - When you protect the read-modify-write with `critical_section::with`, the critical
///   section itself provides the mutual exclusion, so the atomic operation is no longer used
///   to establish ordering with other memory accesses.
/// - Therefore `Ordering::Relaxed` is the correct direct replacement for the semantics of
///   `fetch_add(..., Relaxed)`.
///
/// If you needed the increment to also publish/observe other data between threads/cores,
/// you would need an explicit synchronization design (e.g. Release/Acquire on some atomic,
/// or using a mutex). But that is *not* what `Relaxed` fetch_add provided.
fn fetch_add_via_cs(a: &AtomicUsize, inc: usize) -> usize {
    critical_section::with(|_| {
        let old = a.load(Ordering::Relaxed);
        a.store(old.wrapping_add(inc), Ordering::Relaxed);
        old
    })
}

fn main() {
    // Demonstrate correctness under contention on a host, using the `critical-section` std impl.
    // (On RP2040, you'd use the RP2040 critical-section implementation instead.)

    let counter = Arc::new(AtomicUsize::new(0));

    let threads = 8;
    let iters_per_thread = 50_000;

    let mut handles = Vec::new();
    for _ in 0..threads {
        let c = Arc::clone(&counter);
        handles.push(std::thread::spawn(move || {
            for _ in 0..iters_per_thread {
                // We ignore the returned index here; the goal is to safely increment.
                let _prev = fetch_add_via_cs(&c, 1);
            }
        }));
    }

    for h in handles {
        h.join().unwrap();
    }

    let final_val = counter.load(Ordering::Relaxed);
    let expected = threads * iters_per_thread;

    println!("final counter = {final_val}, expected = {expected}");
    assert_eq!(final_val, expected);
}
"
}
