struct AVisitor;

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
        f.write_str("a map/object representing A")
    }

    fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut x: Option<usize> = None;
        let mut b: Option<Vec<B>> = None;

        while let Some(key) = map.next_key::<Field>()? {
            match key {
                Field::X => {
                    if x.is_some() {
                        return Err(de::Error::duplicate_field("x"));
                    }
                    x = Some(map.next_value()?);
                }
                Field::B => {
                    if b.is_some() {
                        return Err(de::Error::duplicate_field("b"));
                    }
                    // This is the "connect the levels" part:
                    // ask serde to deserialize the value as Vec<B>.
                    b = Some(map.next_value()?);
                }
                Field::Other => {
                    // Ignore unknown fields.
                    let _: IgnoredAny = map.next_value()?;
                }
            }
        }

        let x = x.ok_or_else(|| de::Error::missing_field("x"))?;
        let b = b.unwrap_or_default();

        Ok(A { x, b })
    }
}

// Using a Field enum avoids runtime issues with `&str` keys in formats
// that cannot provide borrowed strings, and also lets you handle unknown keys.
#[derive(Debug)]
enum Field {
    X,
    B,
    Other,
}

impl<'de> Deserialize<'de> for Field {
    fn deserialize<D>(deserializer: D) -> Result<Field, D::Error>
    where
