impl Helper for ShellHelper {}

impl Completer for ShellHelper {
    type Candidate = Pair;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        ctx: &Context<'_>,
    ) -> rustyline::Result<(usize, Vec<Pair>)> {
        // Find start of the "current word".
        let start = line[..pos]
            .rfind(|c: char| c.is_whitespace())
            .map(|i| i + 1)
            .unwrap_or(0);

        // If there's whitespace before the cursor, we're not completing the command name anymore.
        // Delegate to the built-in filename completer.
        if line[..pos].chars().any(|c| c.is_whitespace()) {
            return self.files.complete(line, pos, ctx);
        }

        // Otherwise complete command names.
        let prefix = &line[start..pos];
        eprintln!("[debug] tab completion requested: line={line:?} pos={pos} prefix={prefix:?}");

        let mut out = Vec::new();
        for cmd in &self.commands {
            if cmd.starts_with(prefix) {
                out.push(Pair {
                    display: cmd.clone(),
                    replacement: cmd.clone(),
                });
            }
        }
        Ok((start, out))
    }
}

