impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// Safe, no `unsafe`, no cloning/copying of `Vec<B>`.
    /// Also updates both i and j neighbor lists (symmetric update).
    pub fn build_lists_seq(&mut self) {
        let n = self.get_nelems();
        for e in &mut self.elems {
            e.nb.clear();
        }

        let cutoff = self.cutoff;
        for i in 0..n {
            for j in (i + 1)..n {
                // Get two distinct mutable references safely.
                let (left, right) = self.elems.split_at_mut(j);
                let bi = &mut left[i];
                let bj = &mut right[0];

                if bi.criterion(&*bj) < cutoff {
                    bi.nb.push(j);
                    bj.nb.push(i);
                }
            }
        }
