    pub fn build_lists_par(&mut self) {
        let n = self.get_nelems();
        let cutoff = self.cutoff;

        // Compute neighbor lists in parallel without mutating `self.elems`.
        let nbs: Vec<Mutex<Vec<usize>>> = {
            let elems = &self.elems;
            let nbs: Vec<Mutex<Vec<usize>>> = (0..n).map(|_| Mutex::new(Vec::new())).collect();

            (0..n).into_par_iter().for_each(|i| {
                for j in (i + 1)..n {
                    if elems[i].criterion(&elems[j]) < cutoff {
                        nbs[i].lock().unwrap().push(j);
                        nbs[j].lock().unwrap().push(i);
                    }
                }
            });

            nbs
        };

        // Write back results.
        for (i, m) in nbs.into_iter().enumerate() {
            self.elems[i].nb = m.into_inner().unwrap();
        }
    }
