async fn process_prefix(
    container: ContainerClient,
    prefix: String,
    sem: Arc<Semaphore>,
    max_in_flight_queue: usize,
) -> Result<Vec<TradeData>> {
    let mut out: Vec<TradeData> = Vec::new();
    let mut in_flight: FuturesUnordered<_> = FuturesUnordered::new();

    let mut stream = container.list_blobs().prefix(prefix.clone()).into_stream();

    while let Some(page) = stream.next().await {
        let page = page.with_context(|| format!("list_blobs failed for prefix={prefix}"))?;

        for b in page.blobs.blobs() {
            if !b.name.ends_with(".json") {
                continue;
            }

            let blob_name = b.name.clone();
            let blob = container.blob_client(blob_name.clone());
            let sem = sem.clone();

            // Bound download concurrency with a semaphore.
            // Also, avoid letting the queue grow unbounded by draining periodically.
            in_flight.push(async move {
                let _permit = sem
                    .acquire_owned()
                    .await
                    .context("semaphore acquire failed")?;

                // Download entire blob content.
                let bytes = blob
                    .get_content()
                    .await
                    .with_context(|| format!("download failed: {blob_name}"))?;

                // Parse JSON.
                let trade: TradeData = serde_json::from_slice(&bytes)
                    .with_context(|| format!("json parse failed: {blob_name}"))?;

                Ok::<TradeData, anyhow::Error>(trade)
            });

            if in_flight.len() >= max_in_flight_queue {
                if let Some(res) = in_flight.next().await {
                    out.push(res?);
                }
            }
        }
    }

    while let Some(res) = in_flight.next().await {
        out.push(res?);
    }

    Ok(out)
}

