            let e = io::Error::last_os_error();
            unsafe {
                libc::close(fd);
                libc::shm_unlink(cname.as_ptr());
            }
            return Err(e);
        }

        Ok(Self {
            name,
            fd,
            ptr: ptr as *mut u8,
            len,
        })
    }

