fn parse_lancedb_datetime(s: &str) -> Result<DateTime<Utc>, chrono::ParseError> {
    let s = s.trim().trim_matches('"');

    // If the string ever includes a timezone/offset, RFC3339 parsing is the most robust.
    // (e.g. "2025-08-02T17:35:41.409Z" or "2025-08-02T17:35:41+00:00")
