/// Minimal Unix-datagram DogStatsD sink that sends one metric per datagram.
/// This avoids relying on cadence's optional unix-sink types and makes the
/// transport behavior explicit.
struct UnixDgramSink {
    sock: UnixDatagram,
}

impl UnixDgramSink {
    fn connect(socket_path: &str) -> io::Result<Self> {
        let sock = UnixDatagram::unbound()?;
        sock.connect(socket_path)?;
        Ok(Self { sock })
    }
}

impl MetricSink for UnixDgramSink {
    fn emit(&self, metric: &str) -> io::Result<()> {
        // DogStatsD expects newline-delimited frames, but sending one metric per
        // datagram is fine. Add a trailing newline to match common framing.
        let mut s = String::with_capacity(metric.len() + 1);
        s.push_str(metric);
        s.push('\n');
        let _n = self.sock.send(s.as_bytes())?;
        Ok(())
    }
}

