    let q2 = nand("r", r, r2_box).box_it_clone();

    // Close the loop
    {
        let mut r2_observer = r2.clone();
        q1.clone().subscribe(move |v| r2_observer.next(v));
    }
    {
        let mut s2_observer = s2.clone();
        q2.clone().subscribe(move |v| s2_observer.next(v));
    }

    (q1, q2)
}

fn main() {
    // Inputs are active-low for a NAND RS latch.
    let s = Shared::behavior_subject::<bool, Infallible>(true);
    let r = Shared::behavior_subject::<bool, Infallible>(true);

    let (q1, q2) = flipflop(s.clone().box_it_clone(), r.clone().box_it_clone());

    q1.combine_latest(q2, |q1, q2| (q1, q2))
        .subscribe(|(q1, q2)| println!("Q=(q1={q1}, q2={q2})"));

    // Drive the latch
    let mut s_in = s;
    let mut r_in = r;

    // Set (S low)
    s_in.next(false);
    s_in.next(true);

    // Reset (R low)
    r_in.next(false);
    r_in.next(true);
}
