    let mean: RowDVector<f64> = matrix.row_mean_tr();

    // Option 1: broadcast by replicating the row vector to n x k.
    let centered = &matrix - &mean.clone().replicate(matrix.nrows(), 1);

    // Option 2 (often more efficient): subtract the mean from each row in-place.
    let mut centered_inplace = matrix.clone();
    for mut r in centered_inplace.row_iter_mut() {
        r -= &mean;
    }

