  "Cargo.toml": "[package]
name = "manual_poll_tokio"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1.36", features = ["full"] }
futures = "0.3"
",
  "main.rs": "use futures::task::noop_waker_ref;
use std::{
    future::Future,
    pin::Pin,
    task::{Context, Poll},
    time::Duration,
};

/// Poll `fut` exactly once, synchronously.
fn try_poll_once<F: Future>(fut: Pin<&mut F>) -> Poll<F::Output> {
    // A waker that does nothing. This is OK because we only want to see whether
    // the future is *already* ready; if it's Pending we'll hand it to Tokio.
    let waker = noop_waker_ref();
    let mut cx = Context::from_waker(waker);
    fut.poll(&mut cx)
}

/// In a non-async function (but called from within a Tokio runtime), either:
/// - use the output immediately if the future is ready *without yielding*, or
/// - spawn a Tokio task to await it and run `cont` there.
fn poll_or_spawn<F, C>(fut: F, cont: C)
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
    C: FnOnce(F::Output) + Send + 'static,
{
    let mut fut = Box::pin(fut);

    match try_poll_once(fut.as_mut()) {
        Poll::Ready(v) => {
            // Completed without yielding.
            cont(v);
        }
        Poll::Pending => {
            // Not ready: move the (already-polled) future into a Tokio task.
            tokio::spawn(async move {
                let v = fut.await;
                cont(v);
            });
        }
    }
}

#[tokio::main]
async fn main() {
    // Future that is immediately ready.
    poll_or_spawn(async { 123u32 }, |v| {
        println!("immediate: {v}");
    });

    // Future that yields (sleep) so it will be Pending on the first poll.
    poll_or_spawn(
        async {
            tokio::time::sleep(Duration::from_millis(200)).await;
            456u32
        },
        |v| {
            println!("spawned task: {v}");
        },
    );

    // Give the spawned task time to run.
    tokio::time::sleep(Duration::from_millis(400)).await;
}
"
}

