fn deserialize_server_name<'de, D>(deserializer: D) -> Result<String, D::Error>
where
    D: Deserializer<'de>,
{
    struct ServerNameVisitor;

    impl<'de> Visitor<'de> for ServerNameVisitor {
        type Value = String;

        fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
            write!(f, "a string or an object with a 'name' field")
        }

        fn visit_str<E>(self, v: &str) -> Result<Self::Value, E>
        where
            E: de::Error,
        {
            Ok(v.to_owned())
        }

        fn visit_string<E>(self, v: String) -> Result<Self::Value, E>
        where
            E: de::Error,
        {
            Ok(v)
        }

        fn visit_map<M>(self, mut map: M) -> Result<Self::Value, M::Error>
        where
            M: MapAccess<'de>,
        {
            let mut name: Option<String> = None;

            while let Some(key) = map.next_key::<String>()? {
                match key.as_str() {
                    "name" => name = Some(map.next_value()?),
                    _ => {
                        let _: de::IgnoredAny = map.next_value()?;
                    }
                }
            }

            name.ok_or_else(|| de::Error::missing_field("name"))
        }
    }

    deserializer.deserialize_any(ServerNameVisitor)
}

fn main() {
    // Valid JSON requires quoted keys
    let json = r#"{
        "name": "Name",
        "server": { "name": "Server" }
    }"#;

    let c: Character = serde_json::from_str(json).unwrap();
