#[self_referencing]
struct ResourceRef<R: Resource>
where
    R::DynamicType: Default + Clone,
{
    _type: PhantomData<R>,

    dynamic_type: R::DynamicType,

    #[borrows(dynamic_type)]
    #[covariant]
