            group_builder: |dt| {
                let g = R::group(dt);
                if g.is_empty() {
                    None
                } else {
                    Some(g)
                }
            },
            kind_builder: |dt| R::kind(dt),
            name: name.to_string(),
        }
        .build()
    }

