    let cors = CorsLayer::new()
        .allow_origin(state.allowed_origin.parse().unwrap())
        .allow_methods([Method::GET, Method::POST])
        .allow_headers([header::CONTENT_TYPE]);

    // Apply the origin check only to the websocket route.
    let app = Router::new()
