            state.clone(),
            websocket_origin_guard,
        ))
        .layer(cors)
        .with_state(state);

    let addr: SocketAddr = "127.0.0.1:3000".parse().unwrap();
    info!(%addr, "listening");

    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
    axum::serve(listener, app).await.unwrap();
}

/// Middleware that enforces the `Origin` header for websocket upgrade requests.
///
/// Notes:
/// - Browsers send the `Origin` header on WS handshakes.
/// - Non-browser clients might omit it; this example rejects missing origins.
async fn websocket_origin_guard(
    State(state): State<AppState>,
    req: Request<axum::body::Body>,
    next: Next,
) -> Response {
    // This middleware is attached only to the websocket route. If you attach it
    // more broadly, you may want to only enforce it for websocket upgrade requests.

    let origin = req
        .headers()
        .get(header::ORIGIN)
        .and_then(|v| v.to_str().ok());

    if origin != Some(state.allowed_origin.as_str()) {
        warn!(
            origin = origin.unwrap_or("<missing/invalid>"),
            allowed = %state.allowed_origin,
            "blocked websocket handshake due to origin"
        );
        return StatusCode::FORBIDDEN.into_response();
    }

    next.run(req).await
}

async fn client_ws_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

async fn handle_socket(mut socket: WebSocket, session_id: String) {
    use axum::extract::ws::Message;

    info!(%session_id, "websocket connected");

    while let Some(Ok(msg)) = socket.recv().await {
        match msg {
            Message::Text(text) => {
                // Simple echo with session id prefix
                let _ = socket
                    .send(Message::Text(format!("[{session_id}] {text}")))
                    .await;
            }
            Message::Binary(bin) => {
                let _ = socket.send(Message::Binary(bin)).await;
            }
            Message::Close(_) => break,
            _ => {}
        }
    }

    info!(%session_id, "websocket disconnected");
}
"
}
