        println!("{}{}", pad, s.as_ref());
    }

    fn indented(&mut self, f: impl FnOnce(&mut Ui)) {
        self.indent += 1;
        f(self);
        self.indent -= 1;
    }
}

// ----------------------------
// The key idea:
// Don't accept `&mut dyn Any` and try to downcast.
// Instead, accept `&mut dyn PropertyUi` and use dynamic dispatch.
//
// Then you can write ONE implementation for Vec<T> and Option<T>
// and it automatically works for any inner T that also implements PropertyUi.
// ----------------------------
trait PropertyUi {
    fn show(&mut self, ui: &mut Ui, title: &str, interactable: bool);
}

fn property(ui: &mut Ui, title: &str, v: &mut dyn PropertyUi, interactable: bool) {
    v.show(ui, title, interactable);
}

// ----------------------------
// Implementations for leaf types
// ----------------------------
impl PropertyUi for String {
    fn show(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.line(format!(
            "{title}: String = {:?}{}",
            self,
            if interactable { "" } else { " (disabled)" }
        ));
    }
}

impl PropertyUi for i32 {
    fn show(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.line(format!(
            "{title}: i32 = {}{}",
            *self,
            if interactable { "" } else { " (disabled)" }
        ));
    }
}

impl PropertyUi for f32 {
    fn show(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.line(format!(
            "{title}: f32 = {}{}",
            *self,
            if interactable { "" } else { " (disabled)" }
        ));
    }
}

impl PropertyUi for usize {
    fn show(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.line(format!(
            "{title}: usize = {}{}",
            *self,
            if interactable { "" } else { " (disabled)" }
        ));
    }
}

impl PropertyUi for bool {
    fn show(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.line(format!(
            "{title}: bool = {}{}",
            *self,
            if interactable { "" } else { " (disabled)" }
        ));
    }
}

// ----------------------------
// ONE generic implementation for Vec<T>
// ----------------------------
impl<T> PropertyUi for Vec<T>
where
    T: PropertyUi + Default + 'static,
{
    fn show(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.line(format!("{title}: Vec(len={})", self.len()));

        // Demo interaction: if empty and interactable, auto-add one default item.
        if self.is_empty() && interactable {
            self.push(T::default());
            ui.indented(|ui| ui.line("(auto-added one default item)"));
        }

        ui.indented(|ui| {
            for (i, item) in self.iter_mut().enumerate() {
                item.show(ui, &format!("[{i}]"), interactable);
            }
        });
    }
}

// ----------------------------
// ONE generic implementation for Option<T>
// ----------------------------
impl<T> PropertyUi for Option<T>
where
    T: PropertyUi + Default + 'static,
{
    fn show(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        match self {
            None => {
                ui.line(format!("{title}: Option = None"));
                // Demo interaction: if interactable, auto-create a default value.
                if interactable {
                    *self = Some(T::default());
                    ui.indented(|ui| ui.line("(auto-set to Some(default))"));
                }
            }
            Some(inner) => {
                ui.line(format!("{title}: Option = Some"));
                ui.indented(|ui| inner.show(ui, "value", interactable));
            }
        }
    }
}

// ----------------------------
// Example custom types (enums/structs)
// ----------------------------
#[derive(Default)]
enum DataType {
    #[default]
    Int,
    Text,
}

impl fmt::Display for DataType {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            DataType::Int => write!(f, "Int"),
            DataType::Text => write!(f, "Text"),
        }
    }
}

impl PropertyUi for DataType {
    fn show(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.line(format!(
            "{title}: DataType = {}{}",
            self,
            if interactable { "" } else { " (disabled)" }
        ));
    }
}

#[derive(Default)]
struct NamedTypeValue {
    name: String,
    ty: DataType,
}

impl PropertyUi for NamedTypeValue {
    fn show(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.line(format!("{title}: NamedTypeValue"));
        ui.indented(|ui| {
            self.name.show(ui, "name", interactable);
            self.ty.show(ui, "ty", interactable);
        });
    }
}

// ----------------------------
// Demo
// ----------------------------
fn main() {
    let mut ui = Ui::default();

    let mut s = String::from("hello");
    let mut nums: Vec<i32> = vec![1, 2, 3];
    let mut maybe_text: Option<String> = None;
    let mut nested: Vec<Option<i32>> = vec![Some(10), None, Some(30)];
    let mut named: NamedTypeValue = NamedTypeValue {
        name: "player_speed".to_string(),
        ty: DataType::Int,
    };
    let mut list_of_named: Vec<NamedTypeValue> = vec![named];

    ui.line("--- properties (interactable=true) ---");
    property(&mut ui, "s", &mut s, true);
    property(&mut ui, "nums", &mut nums, true);
    property(&mut ui, "maybe_text", &mut maybe_text, true);
    property(&mut ui, "nested", &mut nested, true);
    property(&mut ui, "list_of_named", &mut list_of_named, true);

    ui.line("\n--- properties (interactable=false) ---");
    property(&mut ui, "s", &mut s, false);
    property(&mut ui, "nums", &mut nums, false);
    property(&mut ui, "maybe_text", &mut maybe_text, false);
}
