// ----- abstract layer (al) -----
mod al {
    use super::enum_dispatch;

    // Trait lives in the abstract layer.
    // In a real project this would be in its own crate (e.g. `al`).
    #[enum_dispatch]
    pub trait Rest {
        fn name(&self) -> &'static str;

        fn get(&self, path: &str) -> String;
        fn post(&self, path: &str, body: &str) -> String;
        fn put(&self, path: &str, body: &str) -> String;
        fn delete(&self, path: &str) -> String;

        fn health(&self) -> bool;
        fn version(&self) -> u32;
        fn default_header(&self, key: &str) -> Option<&'static str>;
    }

    // Key idea:
    // Put BOTH the trait and the enum in the *same crate* (here: `al`),
    // but make the enum generic over the concrete implementors.
    // This avoids `al <-> il` cyclic crate dependencies.
    #[enum_dispatch(Rest)]
    pub enum Item<F: Rest, B: Rest> {
        Foo(F),
        Boo(B),
    }

    // Example of generic code in `al` that can operate on any `Rest`, including `Item<..>`.
    pub fn call_common_api<R: Rest>(r: &R) {
        println!("== calling through Rest on {} ==", r.name());
        println!("health: {}", r.health());
        println!("version: {}", r.version());
        println!("GET /ping -> {}", r.get("/ping"));
        println!("POST /echo -> {}", r.post("/echo", "hello"));
    }
}

// ----- implementation layer (il) -----
mod il {
    use crate::al::Rest;

    pub struct Foo;
    pub struct Boo;

    impl Rest for Foo {
        fn name(&self) -> &'static str {
            "Foo"
        }

        fn get(&self, path: &str) -> String {
            format!("Foo GET {}", path)
        }
        fn post(&self, path: &str, body: &str) -> String {
            format!("Foo POST {} body={}", path, body)
        }
        fn put(&self, path: &str, body: &str) -> String {
            format!("Foo PUT {} body={}", path, body)
        }
        fn delete(&self, path: &str) -> String {
            format!("Foo DELETE {}", path)
        }

        fn health(&self) -> bool {
            true
        }
        fn version(&self) -> u32 {
            1
        }
        fn default_header(&self, key: &str) -> Option<&'static str> {
            match key {
                "x-impl" => Some("foo"),
                _ => None,
            }
        }
    }

    impl Rest for Boo {
        fn name(&self) -> &'static str {
            "Boo"
        }

        fn get(&self, path: &str) -> String {
            format!("Boo GET {}", path)
        }
        fn post(&self, path: &str, body: &str) -> String {
            format!("Boo POST {} body={}", path, body)
        }
        fn put(&self, path: &str, body: &str) -> String {
            format!("Boo PUT {} body={}", path, body)
        }
        fn delete(&self, path: &str) -> String {
            format!("Boo DELETE {}", path)
        }

        fn health(&self) -> bool {
            false
        }
        fn version(&self) -> u32 {
            2
        }
        fn default_header(&self, key: &str) -> Option<&'static str> {
            match key {
                "x-impl" => Some("boo"),
                _ => None,
            }
        }
    }
}

// ----- business layer (bl) -----
mod bl {
    // In a real project this would be in its own crate (e.g. `bl`) depending on `al` and `il`.
    // It does NOT need to define the enum; it just instantiates the generic enum type.

    pub type Item = crate::al::Item<crate::il::Foo, crate::il::Boo>;

    pub fn make(which: &str) -> Item {
        match which {
            "foo" => crate::al::Item::Foo(crate::il::Foo),
            "boo" => crate::al::Item::Boo(crate::il::Boo),
            _ => crate::al::Item::Foo(crate::il::Foo),
        }
    }

    pub fn run(which: &str) {
        let item = make(which);

        // Static dispatch via enum_dispatch-generated impl.
        println!("default header x-impl: {:?}", item.default_header("x-impl"));
        println!("PUT /k -> {}", item.put("/k", "v"));

        // Also works through generic code in the abstract layer.
        crate::al::call_common_api(&item);
    }
}

fn main() {
    bl::run("foo");
    println!();
    bl::run("boo");
}
