{
  "Cargo.toml": "[package]
name = "bevy_lazy_asset_loader_demo"
version = "0.1.0"
edition = "2021"

[dependencies]
bevy = "0.14"
anyhow = "1"
futures-lite = "2"
",
  "main.rs": "use anyhow::{anyhow, Context, Result};
use bevy::app::AppExit;
use bevy::asset::io::Reader;
use bevy::asset::{Asset, AssetApp, AssetLoader, Assets, Handle, LoadContext};
use bevy::prelude::*;
use bevy::reflect::TypePath;
use bevy::utils::BoxedFuture;
use futures_lite::{AsyncReadExt, AsyncSeekExt};
use std::io::SeekFrom;

/// A very small example asset type: a UTF-8 text file stored *inside* a container.
#[derive(Asset, TypePath, Debug, Clone)]
pub struct PackedText(pub String);

/// Loader for files with extension `.pak`.
///
/// The important part for "lazy" loading is that we only read:
/// 1) the small header + directory/index, and then
/// 2) *only the requested entry's byte range*, using `seek`.
///
/// Which entry to load is selected via the asset *label*:
/// `demo.pak#hello.txt` loads the entry named `hello.txt` from inside `demo.pak`.
#[derive(Default)]
pub struct PakTextLoader;

impl AssetLoader for PakTextLoader {
    type Asset = PackedText;
    type Settings = ();
    type Error = anyhow::Error;

    fn load<'a>(
        &'a self,
        reader: &'a mut Reader,
        _settings: &'a Self::Settings,
        load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            let label = load_context
                .path()
                .label()
                .ok_or_else(|| anyhow!(
                    "Missing label. Use e.g. `demo.pak#hello.txt` to select an entry inside the container."
                ))?
                .to_string();

            // Parse header
            let mut magic = [0u8; 4];
            reader
                .read_exact(&mut magic)
                .await
                .context("reading magic")?;
            if &magic != b"PAK0" {
                return Err(anyhow!(
                    "Bad magic {:?}. Expected 'PAK0'",
                    std::str::from_utf8(&magic).unwrap_or("<non-utf8>")
                ));
            }

            let entry_count = read_u32_le(reader).await.context("reading entry_count")?;

            // Directory: find the matching entry (offset, len)
            let mut found: Option<(u64, u64)> = None;
            for _ in 0..entry_count {
                let name_len = read_u16_le(reader).await.context("reading name_len")? as usize;
                let mut name_bytes = vec![0u8; name_len];
                reader
                    .read_exact(&mut name_bytes)
                    .await
                    .context("reading name")?;
                let name = String::from_utf8(name_bytes).context("entry name not utf-8")?;

                let offset = read_u64_le(reader).await.context("reading offset")?;
                let len = read_u64_le(reader).await.context("reading len")?;

                if name == label {
                    found = Some((offset, len));
                    // We could break here, but continuing keeps the parsing simple/robust.
                    // For huge indices you can break early.
                }
            }

            let (offset, len) = found.ok_or_else(|| anyhow!("Entry '{label}' not found in container"))?;

            // Lazy part: seek directly to the payload and read only that slice.
            reader
                .seek(SeekFrom::Start(offset))
                .await
                .context("seeking to entry")?;

            let mut bytes = vec![0u8; len as usize];
            reader
                .read_exact(&mut bytes)
                .await
                .context("reading entry bytes")?;

            let text = String::from_utf8(bytes).context("entry payload not utf-8")?;
            Ok(PackedText(text))
        })
    }

    fn extensions(&self) -> &[&str] {
        &["pak"]
    }
}

#[derive(Resource)]
struct DemoHandles {
    hello: Handle<PackedText>,
    lorem: Handle<PackedText>,
    numbers: Handle<PackedText>,
    printed: bool,
}

fn main() -> Result<()> {
    // Make the example self-contained: create `assets/demo.pak` at startup.
    write_demo_pak_file("assets/demo.pak")?;

    App::new()
        // Keep DefaultPlugins for simplicity, but disable opening a window.
        .add_plugins(DefaultPlugins.set(WindowPlugin {
            primary_window: None,
            ..default()
        }))
        .init_asset::<PackedText>()
        .register_asset_loader(PakTextLoader::default())
        .add_systems(Startup, start_loading)
        .add_systems(Update, print_when_ready)
        .run();

    Ok(())
}

fn start_loading(mut commands: Commands, asset_server: Res<AssetServer>) {
    // Label syntax: `path.ext#label`
    let hello: Handle<PackedText> = asset_server.load("demo.pak#hello.txt");
    let lorem: Handle<PackedText> = asset_server.load("demo.pak#lorem.txt");
    let numbers: Handle<PackedText> = asset_server.load("demo.pak#numbers.txt");

    commands.insert_resource(DemoHandles {
        hello,
        lorem,
        numbers,
        printed: false,
    });
}

fn print_when_ready(
    mut exit: EventWriter<AppExit>,
    mut demo: ResMut<DemoHandles>,
    assets: Res<Assets<PackedText>>,
) {
    if demo.printed {
        return;
    }

    let Some(hello) = assets.get(&demo.hello) else { return };
    let Some(lorem) = assets.get(&demo.lorem) else { return };
    let Some(numbers) = assets.get(&demo.numbers) else { return };

    println!("Loaded from container lazily:");
    println!("- hello.txt:   {:?}", hello.0);
    println!("- lorem.txt:   {:?}", lorem.0);
    println!("- numbers.txt: {:?}", numbers.0);

    demo.printed = true;
    exit.send(AppExit::Success);
}

// -----------------------
// Demo container creation
// -----------------------

/// Demo container format (very small and zip-like):
///
/// Header:
/// - magic: [u8; 4] = "PAK0"
/// - entry_count: u32 LE
///
/// Directory entries (repeated entry_count times):
/// - name_len: u16 LE
/// - name: [u8; name_len] (UTF-8)
/// - offset: u64 LE (from start of file)
/// - len: u64 LE
///
/// Then raw payload bytes for each entry, concatenated.
fn build_demo_pak(entries: Vec<(&str, Vec<u8>)>) -> Vec<u8> {
    let table_size: usize = entries
        .iter()
        .map(|(name, _)| 2 + name.as_bytes().len() + 8 + 8)
        .sum();

    let header_size = 4 + 4;
    let data_base_offset = (header_size + table_size) as u64;

    let mut out = Vec::with_capacity(header_size + table_size + entries.iter().map(|e| e.1.len()).sum::<usize>());

    // Header
    out.extend_from_slice(b"PAK0");
    out.extend_from_slice(&(entries.len() as u32).to_le_bytes());

    // Table (with computed offsets)
    let mut current_data_offset = data_base_offset;
    for (name, bytes) in &entries {
        let name_bytes = name.as_bytes();
        out.extend_from_slice(&(name_bytes.len() as u16).to_le_bytes());
        out.extend_from_slice(name_bytes);
        out.extend_from_slice(&current_data_offset.to_le_bytes());
        out.extend_from_slice(&(bytes.len() as u64).to_le_bytes());
        current_data_offset += bytes.len() as u64;
    }

    // Data
    for (_, bytes) in entries {
        out.extend_from_slice(&bytes);
    }

    out
}

fn write_demo_pak_file(path: &str) -> Result<()> {
    std::fs::create_dir_all("assets").context("creating assets directory")?;

    let entries = vec![
        ("hello.txt", b"Hello from inside the container!".to_vec()),
        (
            "lorem.txt",
            b"Lorem ipsum dolor sit amet, consectetur adipiscing elit.".to_vec(),
        ),
        ("numbers.txt", (0..10).map(|n| format!("{n}\n")).collect::<String>().into_bytes()),
    ];

    let bytes = build_demo_pak(entries);
    std::fs::write(path, bytes).with_context(|| format!("writing {path}"))?;
    Ok(())
}

// -----------------------
// Async binary read helpers
// -----------------------

async fn read_u16_le(reader: &mut Reader) -> Result<u16> {
    let mut b = [0u8; 2];
    reader.read_exact(&mut b).await?;
    Ok(u16::from_le_bytes(b))
}

async fn read_u32_le(reader: &mut Reader) -> Result<u32> {
    let mut b = [0u8; 4];
    reader.read_exact(&mut b).await?;
    Ok(u32::from_le_bytes(b))
}

async fn read_u64_le(reader: &mut Reader) -> Result<u64> {
    let mut b = [0u8; 8];
    reader.read_exact(&mut b).await?;
    Ok(u64::from_le_bytes(b))
}
"
}
