  "main.rs": "use std::{sync::Arc, time::Duration};

use opentelemetry::{global, trace::TracerProvider as _};
use opentelemetry_sdk::trace as sdktrace;
use tokio::time::sleep;
use tracing::{info, info_span, Instrument, Span};
use tracing_opentelemetry::OpenTelemetrySpanExt;
use tracing_subscriber::{fmt::format::FmtSpan, prelude::*};

#[derive(Clone)]
struct RequestCtx {
    // A handle to the request span; can be cloned and used from any thread.
    request_span: Span,

    // If you need *OpenTelemetry* context propagation, capture it once.
    // This is useful when you can't (or don't want to) make the tracing Span current.
    otel_parent: opentelemetry::Context,
}

fn init_tracing() {
    // A minimal tracer provider (no exporter configured). This is enough to demonstrate
    // how to *rehydrate* parent context and build correct parent/child relationships.
    let provider = sdktrace::TracerProvider::builder().build();
    let tracer = provider.tracer("rehydrate-span-demo");
    global::set_tracer_provider(provider);

    let fmt_layer = tracing_subscriber::fmt::layer()
        .with_target(false)
        .with_thread_names(true)
        .with_thread_ids(true)
        // Emit logs when spans are created/closed so you can see the nesting.
        .with_span_events(FmtSpan::NEW | FmtSpan::CLOSE)
        // Show which spans are currently active for each event.
        .with_current_span(true)
        .with_span_list(true);

    let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);

    tracing_subscriber::registry()
        .with(fmt_layer)
        .with(otel_layer)
        .init();
}

fn new_request_ctx(request_id: u64) -> Arc<RequestCtx> {
    // Create the logical parent span for the whole request lifecycle.
    let request_span = info_span!("request", request_id);

    // Capture the OTEL context associated with this tracing span.
    // You can store this and later call `.attach()` (or `.set_parent(...)`) in callbacks.
    let otel_parent = request_span.context();

    Arc::new(RequestCtx {
        request_span,
        otel_parent,
    })
}

// Technique A (recommended for tracing):
// Rehydrate by instrumenting the future with the request span.
// This makes the request span the *current* span for the duration of the async work,
// even across `.await` points and even if called from other threads/tasks.
async fn stage1(ctx: Arc<RequestCtx>) {
    let parent = ctx.request_span.clone();

    async move {
        let stage_span = info_span!("stage1");
        async move {
            info!("stage1 work start");
            sleep(Duration::from_millis(50)).await;
            info!("stage1 work end");
        }
        .instrument(stage_span)
        .await;
    }
    .instrument(parent)
    .await;
}

// Technique B (useful when you only have OTEL context):
// Create a span and explicitly set its OTEL parent using stored Context.
// Note: this affects OTEL parentage; for *tracing* parentage you typically want
// Technique A or `info_span!(parent: &ctx.request_span, ...)`.
async fn stage2(ctx: Arc<RequestCtx>) {
    let stage_span = info_span!("stage2");

    // Set the OTEL parent explicitly (works even if there is no current tracing span).
    stage_span.set_parent(ctx.otel_parent.clone());

    async move {
        info!("stage2 work start");
        sleep(Duration::from_millis(40)).await;

        // Child spans of stage2: keep stage2 current across await by instrumenting.
        let inner = info_span!("stage2-inner");
        async {
            info!("stage2 inner work");
            sleep(Duration::from_millis(10)).await;
        }
        .instrument(inner)
        .await;

        info!("stage2 work end");
    }
    .instrument(stage_span)
    .await;
}

// Another stage, also rehydrating via parent instrumentation.
async fn upstream(ctx: Arc<RequestCtx>) {
    let parent = ctx.request_span.clone();

    async move {
        let stage_span = info_span!("upstream");
        async move {
            info!("connecting to upstream");
            sleep(Duration::from_millis(30)).await;
            info!("received upstream response");
        }
        .instrument(stage_span)
        .await;
    }
    .instrument(parent)
    .await;
}

#[tokio::main(flavor = "multi_thread", worker_threads = 2)]
async fn main() {
    init_tracing();

    let ctx = new_request_ctx(42);

    // Simulate Pingora/Tokio calling different lifecycle callbacks on different tasks/threads.

    // Stage 1: called on a normal async task.
    {
        let ctx = ctx.clone();
        tokio::spawn(async move {
            sleep(Duration::from_millis(30)).await;
            stage1(ctx).await;
        });
    }

    // Stage 2: called from a blocking thread (no current tracing span!).
    // We still get correct parenting because stage2 uses OTEL parent linkage.
    // (And you could also wrap the async work with `.instrument(ctx.request_span.clone())`.)
    {
        let ctx = ctx.clone();
        let handle = tokio::runtime::Handle::current();
        tokio::task::spawn_blocking(move || {
            std::thread::sleep(Duration::from_millis(60));
            handle.spawn(async move {
                stage2(ctx).await;
            });
        })
        .await
        .unwrap();
    }

    // Upstream: another async task.
    {
        let ctx = ctx.clone();
        tokio::spawn(async move {
            sleep(Duration::from_millis(90)).await;
            upstream(ctx).await;
        });
    }

    // Give all tasks time to complete.
    sleep(Duration::from_millis(400)).await;

    global::shutdown_tracer_provider();
}
