    pub fn shutdown(&self) {
        self.tx.close_channel();
    }
}

pub struct EventStreamFactory {
    tx: Sender<Event>,
}

impl EventStreamFactory {
    pub fn all_events(
        &self,
    ) -> impl tokio_stream::Stream<Item = Result<Event, RecvError>> + Send + 'static {
        BroadcastStream::new(self.tx.subscribe()).filter_map(|event| async move {
            match event {
                Ok(event) => Some(Ok(event)),
                // Lagged errors can be handled differently; here we surface an error.
                Err(_lagged) => Some(Err(RecvError)),
            }
        })
    }
}

