    let sender_a = sender.clone();
    let sender_b = sender.clone();

    // Consumer task: this will stop once the channel is closed.
    let mut stream = factory.all_events();
    let consumer = tokio::spawn(async move {
        println!("consumer: started");
        while let Some(item) = stream.next().await {
            match item {
                Ok(ev) => println!("consumer: event: {:?}", ev),
                Err(_) => println!("consumer: (lagged)"),
            }
        }
        println!("consumer: stream ended (channel closed)");
    });

    // Two producer tasks, each using a different clone.
    let producer_a = tokio::spawn(async move {
        let mut id = 0u64;
        loop {
            sender_a.send(Event { id });
            id += 1;
            sleep(Duration::from_millis(200)).await;
        }
    });

    let producer_b = tokio::spawn(async move {
        let mut id = 10_000u64;
        loop {
            sender_b.send(Event { id });
            id += 1;
            sleep(Duration::from_millis(350)).await;
        }
    });

    // Shut down either on Ctrl+C or after a short delay.
    tokio::select! {
        _ = tokio::signal::ctrl_c() => {
            println!("main: Ctrl+C received, shutting down");
        }
        _ = sleep(Duration::from_secs(2)) => {
            println!("main: timer elapsed, shutting down");
        }
    }

    // Key point: this closes the channel for all receivers, even though producer tasks
    // still hold Sender clones.
    sender.shutdown();

    // Give the consumer a moment to observe shutdown and exit.
    let _ = consumer.await;

    // Stop producers (they would otherwise loop forever).
    producer_a.abort();
    producer_b.abort();

