impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// Safe, no `unsafe`, and updates BOTH i and j when the criterion is met.
    /// This avoids the “mutably borrow one element while reading all the others” issue
    /// by iterating pairs (i, j) and using `split_at_mut`.
    pub fn build_lists_sequential(&mut self) {
        let n = self.get_nelems();
        let cutoff = self.cutoff;

        // reset neighbor lists
        for b in &mut self.elems {
            b.nb.clear();
        }

        for i in 0..n {
            for j in (i + 1)..n {
                // Borrow two distinct mutable elements safely.
                let (left, right) = self.elems.split_at_mut(j);
                let bi = &mut left[i];
                let bj = &mut right[0];

                if bi.criterion(bj) < cutoff {
                    bi.nb.push(j);
                    bj.nb.push(i);
                }
            }
        }
    }

