    ///
    /// Key idea: compute neighbor lists using shared immutable access to `elems`,
    /// while pushing indices into per-element `Mutex<Vec<usize>>`. Then move the
    /// results back into `self.elems[*].nb`.
    pub fn build_lists_parallel(&mut self) {
        let n = self.get_nelems();
        let cutoff = self.cutoff;

        // Temporary, thread-safe neighbor lists
        let neighbors: Vec<Mutex<Vec<usize>>> = (0..n).map(|_| Mutex::new(Vec::new())).collect();

        // Immutable view for the parallel region
        let elems = &self.elems;

        (0..n).into_par_iter().for_each(|i| {
            for j in (i + 1)..n {
                if elems[i].criterion(&elems[j]) < cutoff {
                    neighbors[i].lock().unwrap().push(j);
                    neighbors[j].lock().unwrap().push(i);
                }
            }
        });

        // Move results back into the actual elements
        for (b, m) in self.elems.iter_mut().zip(neighbors) {
            b.nb = m.into_inner().unwrap();
        }
    }
