    use serde::ser::{Error, Serializer};

    pub fn serialize_title<S>(value: &String, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        let pv = PropertyValue::Title {
            title: vec![RichTextObject {
                text: TextObject {
                    content: value.clone(),
                },
            }],
