    where
        S: Serializer,
    {
        // If you also add `skip_serializing_if = "Option::is_none"` on the field,
        // serde will omit the entire key when it's None.
        let Some(url) = value.clone() else {
            return serializer.serialize_none();
        };

        let pv = PropertyValue::Url { url };
        pv.serialize(serializer)
    }

    fn value_to_name(v: &serde_json::Value) -> String {
        match v {
            serde_json::Value::String(s) => s.clone(),
            other => other.to_string(),
        }
    }

    pub fn serialize_multiselect<S>(
        value: &Option<Vec<serde_json::Value>>,
        serializer: S,
    ) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        let Some(values) = value.as_ref() else {
            return serializer.serialize_none();
        };

        let multi_select = values
            .iter()
            .map(|v| SelectObject {
                name: value_to_name(v),
            })
            .collect();

        let pv = PropertyValue::MultiSelect { multi_select };
        pv.serialize(serializer)
    }

