    let trimmed = uri_path.trim_start_matches('/');
    let candidate = Path::new(trimmed);

    let mut out = PathBuf::new();
    for c in candidate.components() {
        match c {
            Component::Normal(part) => out.push(part),
            Component::CurDir => {}
            _ => return None, // ParentDir, RootDir, Prefix
        }
    }

    Some(out)
}

async fn file_body_response(path: &Path) -> Result<Response<BoxBody<Bytes, BoxError>>, std::io::Error> {
    let file = tokio::fs::File::open(path).await?;
    let meta = file.metadata().await.ok();

    // Turn AsyncRead (File) -> Stream<io::Result<Bytes>>
    let byte_stream = ReaderStream::new(file);

    // Stream<io::Result<Bytes>> -> Stream<io::Result<Frame<Bytes>>>
    let frame_stream = byte_stream.map_ok(Frame::data);

    // Stream<io::Result<Frame<Bytes>>> -> Body
    let body = StreamBody::new(frame_stream).boxed();

    let mut builder = Response::builder().status(StatusCode::OK);

    if let Some(len) = meta.map(|m| m.len()) {
        builder = builder.header(header::CONTENT_LENGTH, len);
    }

    if let Some(mime) = mime_guess::from_path(path).first() {
        builder = builder.header(header::CONTENT_TYPE, mime.as_ref());
    } else {
        builder = builder.header(header::CONTENT_TYPE, "application/octet-stream");
    }

    Ok(builder.body(body).unwrap())
}

async fn handle(
    req: Request<Incoming>,
    base_dir: Arc<PathBuf>,
) -> Result<Response<BoxBody<Bytes, BoxError>>, Infallible> {
    if req.method() != Method::GET && req.method() != Method::HEAD {
        return Ok(full_response(StatusCode::METHOD_NOT_ALLOWED, "Only GET/HEAD supported\n"));
    }

    let uri_path = req.uri().path();

    let rel = match sanitize_path(uri_path) {
        Some(p) => p,
        None => return Ok(full_response(StatusCode::BAD_REQUEST, "Bad path\n")),
    };

    let mut full_path = (*base_dir).clone();
    if rel.as_os_str().is_empty() {
        full_path.push("index.html");
    } else {
        full_path.push(rel);
    }

    match file_body_response(&full_path).await {
        Ok(mut resp) => {
            if req.method() == Method::HEAD {
                // Discard body for HEAD.
                *resp.body_mut() = Full::new(Bytes::new())
                    .map_err(|e| -> BoxError { Box::new(e) })
                    .boxed();
            }
            Ok(resp)
        }
        Err(e) if e.kind() == std::io::ErrorKind::NotFound => {
            Ok(full_response(StatusCode::NOT_FOUND, "Not found\n"))
        }
        Err(e) => {
            eprintln!("error opening/serving file: {e}");
            Ok(full_response(
                StatusCode::INTERNAL_SERVER_ERROR,
                "Internal server error\n",
            ))
        }
    }
}

#[tokio::main]
async fn main() -> Result<(), BoxError> {
    let addr: SocketAddr = ([127, 0, 0, 1], 3000).into();
    let base_dir = Arc::new(std::env::current_dir()?);

    eprintln!("Serving files from: {}", base_dir.display());
    eprintln!("Listening on: http://{addr}");

    let listener = TcpListener::bind(addr).await?;

    loop {
        let (stream, _) = listener.accept().await?;
        let io = TokioIo::new(stream);
        let base_dir = base_dir.clone();

        tokio::task::spawn(async move {
            let service = service_fn(move |req| handle(req, base_dir.clone()));

            if let Err(err) = http1::Builder::new()
                .serve_connection(io, service)
                .await
            {
                eprintln!("connection error: {err}");
            }
        });
    }
}
"
}
