/// Build a rotation for a rectangle gizmo that:
/// - has its local +Z pointing along the face normal
/// - has its in-plane axes aligned with the cube's rotated local axes (so it "twists" with the cube)
fn rect_rotation_from_cube_face(cube_rot: Quat, face_normal_world: Vec3) -> Quat {
    let n = face_normal_world.normalize();

    // Cube basis in world space
    let ux = (cube_rot * Vec3::X).normalize();
    let uy = (cube_rot * Vec3::Y).normalize();
    let uz = (cube_rot * Vec3::Z).normalize();

    // Identify which cube axis the face normal corresponds to (±X, ±Y, or ±Z).
    // Then pick two cube axes that span that face.
    #[derive(Copy, Clone)]
    enum Axis {
        X,
        Y,
        Z,
    }

    let (axis, _best) = [
        (Axis::X, n.dot(ux).abs()),
        (Axis::Y, n.dot(uy).abs()),
        (Axis::Z, n.dot(uz).abs()),
    ]
    .into_iter()
    .max_by(|a, b| a.1.total_cmp(&b.1))
    .unwrap();

    let (t1, t2) = match axis {
        Axis::X => (uy, uz),
        Axis::Y => (ux, uz),
        Axis::Z => (ux, uy),
    };

    // Project t1 onto the plane perpendicular to n to get a stable in-plane X axis.
    let mut x_axis = (t1 - n * n.dot(t1)).normalize();
    let mut y_axis = n.cross(x_axis).normalize();

    // Ensure the in-plane orientation matches the cube's twist (prefer y_axis aligned with t2).
    if y_axis.dot(t2) < 0.0 {
        x_axis = -x_axis;
        y_axis = -y_axis;
    }

    // Local rect basis: X right, Y up, Z out-of-rect.
    let m = Mat3::from_cols(x_axis, y_axis, n);
    Quat::from_mat3(&m)
}

