) {
    let xf = block_q.single();
    let cam_xf = cam_q.single();

    let cube_center = xf.translation;
    let cube_rot = xf.rotation;

    // Pretend this is your raycast result by picking the face most "towards" the camera.
    let to_cam = (cam_xf.translation - cube_center).normalize();
    let ux = (cube_rot * Vec3::X).normalize();
    let uy = (cube_rot * Vec3::Y).normalize();
    let uz = (cube_rot * Vec3::Z).normalize();

    let candidates = [ux, -ux, uy, -uy, uz, -uz];
    let face_normal = candidates
        .into_iter()
        .map(|n| (n, n.dot(to_cam)))
        .max_by(|a, b| a.1.total_cmp(&b.1))
        .unwrap()
        .0;

    let face_center = cube_center + face_normal * 0.5;

    // Final rect transform
    let rot = rect_rotation_from_cube_face(cube_rot, face_normal);
    let rect_xf = Transform::from_translation(face_center + face_normal * 0.01).with_rotation(rot);

    // Draw indicator and some debug aids
    gizmos.rect(rect_xf.to_isometry(), Vec2::new(1.0, 1.0), Color::WHITE);
    gizmos.ray(face_center, face_normal * 0.35, Color::srgb(1.0, 0.2, 0.2));

    // Draw cube axes (world-space) for reference
    gizmos.ray(cube_center, ux * 0.8, Color::srgb(1.0, 0.0, 0.0));
    gizmos.ray(cube_center, uy * 0.8, Color::srgb(0.0, 1.0, 0.0));
    gizmos.ray(cube_center, uz * 0.8, Color::srgb(0.2, 0.6, 1.0));
