fn spawn_keyboard_thread(tx: Sender<Message>, stop: Arc<AtomicBool>) -> thread::JoinHandle<()> {
    thread::spawn(move || {
        // Non-blocking stdin. We'll poll it and also poll the stop flag.
        let mut stdin = termion::async_stdin();
        let mut buf = [0u8; 1];

        while !stop.load(Ordering::Relaxed) {
            match stdin.read(&mut buf) {
                Ok(0) => {
