                            break;
                        }
                    }
                }
                Err(e) if e.kind() == io::ErrorKind::WouldBlock => {
                    // No data available right now.
                    thread::sleep(Duration::from_millis(10));
                }
                Err(_) => break,
            }
        }
    })
}

#[cfg(unix)]
fn spawn_signal_thread(
    tx: Sender<Message>,
) -> (
    thread::JoinHandle<()>,
    signal_hook::iterator::SignalsHandle,
) {
    use signal_hook::consts::{SIGINT, SIGTERM};
    use signal_hook::iterator::Signals;

    let mut signals = Signals::new([SIGINT, SIGTERM]).expect("create Signals");
    let handle = signals.handle();

    let join = thread::spawn(move || {
        // This blocks waiting for signals, but can be unblocked by handle.close().
        for sig in signals.forever() {
            if tx.send(Message::Signal(sig)).is_err() {
                break;
            }
        }
    });

    (join, handle)
}

fn main() {
    // Put the terminal in raw mode so keypresses are delivered immediately.
    // Keep it alive for the whole program.
    let _stdout = io::stdout().into_raw_mode().expect("raw mode");

    let (tx, rx) = mpsc::channel::<Message>();
    let stop = Arc::new(AtomicBool::new(false));

    let keyboard_join = spawn_keyboard_thread(tx.clone(), stop.clone());

    #[cfg(unix)]
    let (signal_join, signal_handle) = spawn_signal_thread(tx.clone());

    eprintln!("Press 'q' to quit. (On Unix you can also send SIGINT/SIGTERM.)");

    // Main event loop
    let mut should_quit = false;
    while let Ok(msg) = rx.recv() {
        match msg {
            Message::Key('q') => {
                eprintln!("quit requested by keyboard");
                should_quit = true;
            }
            Message::Key(c) => {
                eprintln!("key: {c:?}");
            }
            #[cfg(unix)]
            Message::Signal(sig) => {
                eprintln!("signal received: {sig}");
                should_quit = true;
            }
        }

        if should_quit {
            break;
        }
    }

    // Initiate shutdown for all worker threads.
    stop.store(true, Ordering::Relaxed);

    // Unblock the signal iterator immediately (otherwise it may stay blocked in forever()).
    #[cfg(unix)]
    signal_handle.close();

    // Dropping the sender helps workers exit if they try to send after shutdown.
    drop(tx);

    let _ = keyboard_join.join();
    #[cfg(unix)]
    let _ = signal_join.join();

    eprintln!("clean shutdown");
}
"
}
