  "main.rs": "use std::sync::{atomic::{compiler_fence, AtomicUsize, Ordering}, Arc};

/// Emulate `AtomicUsize::fetch_add` using a critical section.
///
/// Important notes (relevant to your question):
///
/// - If your original code used `fetch_add(..., Ordering::Relaxed)`, then **the correct
///   replacement is to keep it relaxed** for the internal `load`/`store`.
///   The critical section provides the *atomicity* (mutual exclusion), and you did not
///   request any synchronization/ordering with other memory accesses.
///
/// - If you *do* need Acquire/Release/SeqCst semantics (i.e. you were using
///   `fetch_add` as a synchronization primitive), then you must add fences around
///   the critical section to emulate those semantics.
///
/// - On real RP2040 (two cores): disabling interrupts alone is not sufficient to
///   synchronize with the other core. You need a critical-section implementation that
///   also locks cross-core (e.g. RP2040 SIO spinlocks). The `critical-section` crate is
///   designed so the platform provides the correct implementation.
fn fetch_add_cs(a: &AtomicUsize, val: usize, order: Ordering) -> usize {
    critical_section::with(|_| {
        // Emulate the *release* part of an RMW ordering (if requested).
        // (Release fence must be before publishing the new value.)
        match order {
            Ordering::Release | Ordering::AcqRel | Ordering::SeqCst => {
                compiler_fence(Ordering::Release)
            }
            _ => {}
        }

        // Inside a critical section, the load/store can be Relaxed: no other execution
        // context can interleave between them (given a correct CS impl for the platform).
        let old = a.load(Ordering::Relaxed);
        let new = old.wrapping_add(val); // matches atomic fetch_add wrapping behavior
        a.store(new, Ordering::Relaxed);

        // Emulate the *acquire* part of an RMW ordering (if requested).
        // (Acquire fence must be after observing the old value / completing the RMW.)
        match order {
            Ordering::Acquire | Ordering::AcqRel | Ordering::SeqCst => {
                compiler_fence(Ordering::Acquire)
            }
            _ => {}
        }

        old
    })
}

fn main() {
    // Demo: multiple host threads increment a shared counter using the CS-based fetch_add.
    // This runs with `cargo run` because the `critical-section` crate's `std` feature
    // provides a global lock implementation.

    let counter = Arc::new(AtomicUsize::new(0));
    let threads = 8;
    let iters_per_thread = 50_000;

    let mut handles = Vec::new();
    for _ in 0..threads {
        let c = Arc::clone(&counter);
        handles.push(std::thread::spawn(move || {
            for _ in 0..iters_per_thread {
                // This matches your original usage: `Ordering::Relaxed`.
                let _idx = fetch_add_cs(&c, 1, Ordering::Relaxed);
            }
        }));
    }

    for h in handles {
        h.join().unwrap();
    }

    let expected = threads * iters_per_thread;
    let got = counter.load(Ordering::Relaxed);
    println!("final counter = {got}, expected = {expected}");

    assert_eq!(got, expected);

    // Takeaway for your replacement:
    // Your original code was Relaxed, so inside the CS:
    //   load(Relaxed) + store(Relaxed)
    // is the correct analogue.
}
