use tokio::sync::Mutex;
use tokio::task::JoinHandle;
use tokio_postgres::{Client, Error, NoTls};

/// A cached admin connection that reconnects automatically if the underlying
/// connection driver has exited (or the client is closed).
///
/// Key point: tokio_postgres::Client is a cheap handle you can clone.
/// The actual IO happens in the `Connection` future ("driver"), which we spawn.
struct CachedClient {
    conn_str: String,
    state: Mutex<Option<State>>,
}

struct State {
    client: Client,
    driver: JoinHandle<Result<(), Error>>,
}

impl CachedClient {
    fn new(conn_str: impl Into<String>) -> Self {
        Self {
            conn_str: conn_str.into(),
            state: Mutex::new(None),
        }
    }

    async fn get(&self) -> Result<Client, Error> {
        let mut guard = self.state.lock().await;

        let needs_reconnect = match guard.as_ref() {
            None => true,
            Some(st) => st.client.is_closed() || st.driver.is_finished(),
        };

        if needs_reconnect {
            let (client, connection) = tokio_postgres::connect(&self.conn_str, NoTls).await?;
            let driver = tokio::spawn(async move { connection.await });
            *guard = Some(State { client, driver });
        }

        Ok(guard.as_ref().unwrap().client.clone())
    }
}

#[tokio::main]
