  "main.rs": "use std::io::{self, Read};

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum Mode {
    Unquoted,
    SingleQuoted,
    DoubleQuoted,
}

#[derive(Debug)]
enum TokenizeError {
    UnterminatedSingleQuote,
    UnterminatedDoubleQuote,
    TrailingBackslash,
}

fn tokenize_shell_like(input: &str) -> Result<Vec<String>, TokenizeError> {
    let mut out = Vec::<String>::new();
    let mut cur = String::new();
    let mut mode = Mode::Unquoted;

    let mut it = input.chars().peekable();
    while let Some(ch) = it.next() {
        match mode {
            Mode::Unquoted => match ch {
                // Token boundary
                ' ' | '\t' | '\n' => {
                    if !cur.is_empty() {
                        out.push(std::mem::take(&mut cur));
                    }
                    // swallow consecutive whitespace by continuing
                }
                '\'' => mode = Mode::SingleQuoted,
                '"' => mode = Mode::DoubleQuoted,
                // Basic backslash escaping outside quotes
                '\\' => {
                    if let Some(next) = it.next() {
                        cur.push(next);
                    } else {
                        return Err(TokenizeError::TrailingBackslash);
                    }
                }
                _ => cur.push(ch),
            },

            Mode::SingleQuoted => match ch {
                '\'' => mode = Mode::Unquoted,
                _ => cur.push(ch), // literal
            },

            Mode::DoubleQuoted => match ch {
                '"' => mode = Mode::Unquoted,
                // Minimal double-quote escaping: backslash escapes the next char
                '\\' => {
                    if let Some(next) = it.next() {
                        cur.push(next);
                    } else {
                        return Err(TokenizeError::TrailingBackslash);
                    }
                }
                _ => cur.push(ch),
            },
        }
    }

    match mode {
        Mode::Unquoted => {}
        Mode::SingleQuoted => return Err(TokenizeError::UnterminatedSingleQuote),
        Mode::DoubleQuoted => return Err(TokenizeError::UnterminatedDoubleQuote),
    }

    if !cur.is_empty() {
        out.push(cur);
    }

    Ok(out)
}

fn main() {
    // Read stdin; if empty, run a built-in demo.
    let mut buf = String::new();
    io::stdin().read_to_string(&mut buf).unwrap();
    let line = buf.trim_end_matches(['\r', '\n']);

    let input = if line.trim().is_empty() {
        " one  ' two  'three    four"
    } else {
        line
    };

    match tokenize_shell_like(input) {
        Ok(tokens) => {
            println!("{} args:", tokens.len());
            for t in tokens {
                println!("<{}>", t);
            }
        }
        Err(e) => {
            eprintln!("tokenize error: {e:?}");
            std::process::exit(2);
        }
    }
