name = "zbus_dynamic_call"
version = "0.1.0"
edition = "2021"

[dependencies]
serde = { version = "1", features = ["derive"] }
tokio = { version = "1", features = ["macros", "rt-multi-thread"] }

# zbus is the D-Bus crate; it uses zvariant for (de)serialization
zbus = { version = "4", features = ["tokio"] }
zvariant = "4"
",
  "main.rs": "use serde::Serialize;
use std::collections::HashMap;
use zbus::Connection;
use zvariant::{OwnedValue, Type, Value};

// ---- Example 1: your custom service (two string args) -----------------------
const NETCONFIG_SERVICE: &str = "com.example.NetConfig";
const NETCONFIG_PATH: &str = "/com/example/NetConfig";
const NETCONFIG_INTERFACE: &str = "com.example.Netconfig";
const NETCONFIG_METHOD: &str = "SetInterfaceIP";

#[derive(Debug, Serialize, Type)]
// Method bodies in zbus are a *structure* (same thing a tuple encodes to),
// so the signature must include parentheses.
#[zvariant(signature = "(ss)")]
struct NetConfigMethodArgs {
    interface: String,
    ip: String,
}

// ---- Example 2: org.freedesktop.Notifications.Notify -----------------------
const NOTIFICATIONS_SERVICE: &str = "org.freedesktop.Notifications";
const NOTIFICATIONS_PATH: &str = "/org/freedesktop/Notifications";
const NOTIFICATIONS_INTERFACE: &str = "org.freedesktop.Notifications";
const NOTIFICATIONS_METHOD: &str = "Notify";

#[derive(Debug, Serialize, Type)]
#[zvariant(signature = "(susssasa{sv}i)")]
struct NotificationsMethodArgs<'a> {
    app_name: String,
    replaces_id: u32,
    app_icon: String,
    summary: String,
    body: String,
    actions: Vec<String>,

    // This is the same shape as in the zbus docs example.
    // It only works if the Value(s) you reference live long enough.
    // If you need to build hints from temporary values, prefer:
    //   HashMap<String, OwnedValue>
    // or HashMap<&'a str, Value<'a>>.
    hints: HashMap<&'a str, &'a Value<'a>>,

    timeout: i32,
}

enum ReplyKind {
    Notify,
    Unknown,
}

#[tokio::main]
async fn main() -> zbus::Result<()> {
    // Use NOTIFICATIONS by default (more likely to exist on a typical desktop).
    // Set USE_NETCONFIG=1 to try the NetConfig call.
    let use_netconfig = std::env::var("USE_NETCONFIG").is_ok();

    let connection = Connection::session().await?;

    let (service, path, interface, method, body, reply_kind) = if use_netconfig {
        let args = NetConfigMethodArgs {
            interface: "enxc0470e9a117".to_string(),
            ip: "192.168.1.141".to_string(),
        };

        // This is how you can hold "either one struct or another" dynamically.
        // OwnedValue carries both the data and its signature at runtime.
        let body: OwnedValue = OwnedValue::from(args);

        (
            NETCONFIG_SERVICE,
            NETCONFIG_PATH,
            NETCONFIG_INTERFACE,
            NETCONFIG_METHOD,
            body,
            ReplyKind::Unknown,
        )
    } else {
        // Make a Value and keep it alive long enough to be referenced by the HashMap.
        let urgency: Value<'_> = Value::from(1u8);

        let mut hints: HashMap<&str, &Value<'_>> = HashMap::new();
        hints.insert("urgency", &urgency);

        let args = NotificationsMethodArgs {
            app_name: "my-app".to_string(),
            replaces_id: 0u32,
            app_icon: "dialog-information".to_string(),
            summary: "A summary".to_string(),
            body: "Some body".to_string(),
            actions: vec![],
            hints,
            timeout: 5000,
        };

        let body: OwnedValue = OwnedValue::from(args);

        (
            NOTIFICATIONS_SERVICE,
            NOTIFICATIONS_PATH,
            NOTIFICATIONS_INTERFACE,
            NOTIFICATIONS_METHOD,
            body,
            ReplyKind::Notify,
        )
    };

    let msg = connection
        .call_method(Some(service), path, Some(interface), method, &body)
        .await?;

    match reply_kind {
        ReplyKind::Notify => {
            let id: u32 = msg.body().deserialize()?;
            println!("Notify() returned id={id}");
        }
        ReplyKind::Unknown => {
            // If you don't know the reply type, you can deserialize to OwnedValue.
            let v: OwnedValue = msg.body().deserialize()?;
            println!("Reply (OwnedValue) = {v:?}");
        }
    }

    Ok(())
}
"
}

