  "main.rs": "use anyhow::{Context, Result};
use crossterm::terminal::{disable_raw_mode, enable_raw_mode};
use expectrl::spawn;
use nix::fcntl::{fcntl, FcntlArg, OFlag};
use nix::poll::{poll, PollFd, PollFlags};
use nix::unistd::dup;
use std::fs::File;
use std::io::{Read, Write};
use std::os::fd::{AsRawFd, FromRawFd, RawFd};
use std::sync::{Arc, atomic::{AtomicBool, Ordering}};
use std::thread;
use std::time::Duration;

/// RAII guard to always restore the host terminal.
struct RawModeGuard;
impl RawModeGuard {
    fn new() -> Result<Self> {
        enable_raw_mode().context("enable_raw_mode")?;
        Ok(Self)
    }
}
impl Drop for RawModeGuard {
    fn drop(&mut self) {
        let _ = disable_raw_mode();
    }
}

fn set_nonblocking(fd: RawFd) -> Result<()> {
    let current = fcntl(fd, FcntlArg::F_GETFL).context("F_GETFL")?;
    let mut flags = OFlag::from_bits_truncate(current);
    flags.insert(OFlag::O_NONBLOCK);
    fcntl(fd, FcntlArg::F_SETFL(flags)).context("F_SETFL")?;
    Ok(())
}

fn main() -> Result<()> {
    let _raw = RawModeGuard::new()?;

    eprintln!(
        "\nPTY full-duplex demo (expectrl + PTY)\n\
         - This forwards *raw keypresses* to a child shell and prints PTY output back.\n\
         - It uses dup(2) on the PTY master fd so reads and writes never contend on a mutex.\n\
         - Quit this wrapper with Ctrl-Q. Quit the child shell with 'exit' or Ctrl-D.\n"
    );

    // Spawn an interactive shell inside a PTY.
    // Using `env TERM=...` keeps things close to xterm.js expectations.
    let mut session = spawn("env TERM=xterm-256color bash --noprofile --norc -i")
        .or_else(|_| spawn("env TERM=xterm-256color sh -i"))
        .context("spawn shell")?;

    // Grab the PTY master fd from the session, then dup it into independent read/write handles.
    // This is the key part: *no mutex*, and blocking reads won't prevent writes.
    let master_fd = session.as_raw_fd();
    let rfd = dup(master_fd).context("dup(pty master) for read")?;
    let wfd = dup(master_fd).context("dup(pty master) for write")?;

    let mut pty_r = unsafe { File::from_raw_fd(rfd) };
    let mut pty_w = unsafe { File::from_raw_fd(wfd) };

    // Make the reader non-blocking and poll it; this allows a clean shutdown of the reader thread.
    set_nonblocking(pty_r.as_raw_fd())?;

    let running = Arc::new(AtomicBool::new(true));

    // Reader thread: poll/read from PTY and write to stdout.
    let running_r = running.clone();
    let reader = thread::spawn(move || -> Result<()> {
        let mut stdout = std::io::stdout().lock();
        let mut buf = [0u8; 8192];

        while running_r.load(Ordering::Relaxed) {
            let mut fds = [PollFd::new(pty_r.as_raw_fd(), PollFlags::POLLIN)];
            // Short timeout so we can notice shutdown requests quickly.
            let _ = poll(&mut fds, 100).context("poll(pty)")?;

            let ready = fds[0]
                .revents()
                .unwrap_or(PollFlags::empty())
                .intersects(PollFlags::POLLIN | PollFlags::POLLHUP | PollFlags::POLLERR);

            if !ready {
                continue;
            }

            match pty_r.read(&mut buf) {
                Ok(0) => break, // EOF (child exited)
                Ok(n) => {
                    stdout.write_all(&buf[..n])?;
                    stdout.flush()?;
                }
                Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                    // Poll said readable but we raced; try again.
                    continue;
                }
                Err(e) if e.kind() == std::io::ErrorKind::Interrupted => continue,
                Err(e) => return Err(e).context("read(pty)"),
            }
        }

        Ok(())
    });

    // Main thread: read raw bytes from stdin and write them to the PTY.
    // Ctrl-Q exits the wrapper.
    let mut stdin = std::io::stdin().lock();
    let mut inbuf = [0u8; 1024];

    loop {
        let n = match stdin.read(&mut inbuf) {
            Ok(0) => break,
            Ok(n) => n,
            Err(e) if e.kind() == std::io::ErrorKind::Interrupted => continue,
            Err(e) => return Err(e).context("read(stdin)"),
        };

        // Ctrl-Q (0x11) quits the wrapper without forwarding.
        if inbuf[..n].iter().any(|&b| b == 0x11) {
            break;
        }

        // Forward all bytes (including escape sequences, control codes, etc.).
        pty_w.write_all(&inbuf[..n]).context("write(pty)")?;
        pty_w.flush().ok();
    }

    running.store(false, Ordering::Relaxed);

    // Best-effort: ask the child to exit (won't always work if it's running a different TUI).
    let _ = pty_w.write_all(b"exit\n");
    let _ = pty_w.flush();

    // Give the reader a moment to drain output.
    thread::sleep(Duration::from_millis(150));

    // Wait for reader thread to finish.
    let _ = reader.join();

    // Keep session alive until the end (dropping it earlier may hang up the PTY and kill the child).
    drop(session);

    Ok(())
}
"
}
