        "b.json",
        r#"{
  "path_list": {
    "$ref": "./a.json#/p_list"
  }
}
"#,
    )?;

    let b_path = PathBuf::from("b.json");
    let json_data = fs::read_to_string(&b_path).context("failed to read from b.json")?;

    // Parse as Value first, resolve $ref, then deserialize into the typed struct.
    let mut root: Value = serde_json::from_str(&json_data).context("failed to parse b.json as JSON")?;

    let base_dir = b_path
        .parent()
        .map(Path::to_path_buf)
        .unwrap_or_else(|| PathBuf::from("."));

    let mut cache: HashMap<PathBuf, Value> = HashMap::new();
    let mut resolving: HashSet<String> = HashSet::new();

    root = resolve_refs(root, &base_dir, &mut cache, &mut resolving)?;

    let a_obj: A = serde_json::from_value(root).context("deserialization failed")?;

    for p in &a_obj.path_list {
        println!("{}", p.display());
    }

    Ok(())
}

fn resolve_refs(
    value: Value,
    base_dir: &Path,
    cache: &mut HashMap<PathBuf, Value>,
    resolving: &mut HashSet<String>,
) -> Result<Value> {
    match value {
        Value::Array(arr) => {
            let mut out = Vec::with_capacity(arr.len());
            for v in arr {
                out.push(resolve_refs(v, base_dir, cache, resolving)?);
            }
            Ok(Value::Array(out))
        }
        Value::Object(map) => {
            // Recognize the common "$ref" object shape.
            if map.len() == 1 {
                if let Some(Value::String(r)) = map.get("$ref") {
                    return resolve_ref(r, base_dir, cache, resolving);
                }
            }

            let mut out = serde_json::Map::with_capacity(map.len());
            for (k, v) in map {
                out.insert(k, resolve_refs(v, base_dir, cache, resolving)?);
            }
            Ok(Value::Object(out))
        }
        other => Ok(other),
    }
}

fn resolve_ref(
    ref_str: &str,
    base_dir: &Path,
    cache: &mut HashMap<PathBuf, Value>,
    resolving: &mut HashSet<String>,
) -> Result<Value> {
    // Prevent trivial cycles
    if !resolving.insert(ref_str.to_owned()) {
        bail!("cyclic $ref detected: {ref_str}");
    }

    let (file_part, pointer_part) = match ref_str.split_once('#') {
        Some((f, p)) => (f, p),
        None => (ref_str, ""),
    };

    if file_part.is_empty() {
        resolving.remove(ref_str);
        bail!("internal refs (no file part) are not supported in this demo: {ref_str}");
    }

    let file_path = base_dir.join(file_part);

    let doc = if let Some(v) = cache.get(&file_path) {
        v.clone()
    } else {
        let s = fs::read_to_string(&file_path)
            .with_context(|| format!("failed to read referenced file: {}", file_path.display()))?;
        let v: Value = serde_json::from_str(&s)
            .with_context(|| format!("failed to parse referenced JSON: {}", file_path.display()))?;
        cache.insert(file_path.clone(), v.clone());
        v
    };

    let referenced_base_dir = file_path
        .parent()
        .map(Path::to_path_buf)
        .unwrap_or_else(|| PathBuf::from("."));

    let selected = if pointer_part.is_empty() {
        doc
    } else {
        let pointer = if pointer_part.starts_with('/') {
            format!("{pointer_part}")
        } else {
            resolving.remove(ref_str);
            return Err(anyhow!(
                "invalid JSON pointer in $ref (must start with '/'): {ref_str}"
            ));
        };

        doc.pointer(&pointer)
            .cloned()
            .ok_or_else(|| anyhow!("$ref pointer not found: {ref_str}"))?
    };

    // Resolve any nested refs in the referenced value
    let resolved = resolve_refs(selected, &referenced_base_dir, cache, resolving)?;

    resolving.remove(ref_str);
    Ok(resolved)
}
"
}
