  "Cargo.toml": "[package]
name = "todo_json"
version = "0.1.0"
edition = "2021"

[dependencies]
serde = { version = "1", features = ["derive"] }
serde_json = "1"
",
  "main.rs": "use std::{env, fs, io, path::Path};

type Todo = Vec<String>;

fn load_list(path: &Path) -> io::Result<Todo> {
    match fs::read_to_string(path) {
        Ok(data) => {
            let data = data.trim();
            if data.is_empty() {
                return Ok(Vec::new());
            }
            serde_json::from_str::<Todo>(data)
                .map_err(|e| io::Error::new(io::ErrorKind::InvalidData, e))
        }
        Err(e) if e.kind() == io::ErrorKind::NotFound => Ok(Vec::new()),
        Err(e) => Err(e),
    }
}

fn save_list(path: &Path, list: &Todo) -> io::Result<()> {
    let json = serde_json::to_string_pretty(list)
        .map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;

    // Write to a temp file then rename for (mostly) atomic updates.
    // If `output.json` is the path, temp becomes `output.json.tmp`.
    let tmp = path.with_extension("json.tmp");
    fs::write(&tmp, json)?;

    match fs::rename(&tmp, path) {
        Ok(()) => Ok(()),
        Err(e) => {
            // Windows often refuses to rename over an existing file.
            let _ = fs::remove_file(path);
            fs::rename(&tmp, path).map_err(|_| e)
        }
    }
}

fn main() -> io::Result<()> {
    let path = Path::new("output.json");
    let mut list = load_list(path)?;

    let mut args = env::args().skip(1).collect::<Vec<_>>();
    if args.is_empty() {
        println!(
            "Current todo list ({} items) from {}:",
            list.len(),
            path.display()
        );
        for (i, item) in list.iter().enumerate() {
            println!("{:>3}. {}", i + 1, item);
        }
        println!("\nTo add an item: cargo run -- add \"your task\"");
        return Ok(());
    }

    let cmd = args.remove(0);
    match cmd.as_str() {
        "add" => {
            if args.is_empty() {
                eprintln!("Nothing to add. Usage: cargo run -- add \"your task\"");
                std::process::exit(2);
            }
            let item = args.join(" ");
            list.push(item);
            save_list(path, &list)?;
            println!("Saved {} items to {}", list.len(), path.display());
        }
        "list" => {
            println!(
                "{}",
                serde_json::to_string_pretty(&list)
                    .map_err(|e| io::Error::new(io::ErrorKind::Other, e))?
            );
        }
        _ => {
            eprintln!("Unknown command: {cmd}\nCommands: add, list");
            std::process::exit(2);
        }
    }

    Ok(())
}
"
}

