/// Rewrites `use` trees so that any absolute path starting with:
///     vexide::devices::...
/// becomes:
///     vexide::...
///
/// It tries to preserve formatting/comments by applying text-range edits.
fn rewrite_imports(src: &str) -> String {
    let parse = SourceFile::parse(src);
    let root = parse.tree().syntax().clone();

    let mut edits: Vec<Edit> = Vec::new();

    for use_item in root.descendants().filter_map(ast::Use::cast) {
        if let Some(tree) = use_item.use_tree() {
            collect_edits_for_tree(src, &tree, &[], &mut edits);
        }
    }

    apply_edits(src, &mut edits)
}

fn collect_edits_for_tree(src: &str, tree: &ast::UseTree, parent_abs_old: &[String], edits: &mut Vec<Edit>) {
    let rel = tree.path().map(path_segments).unwrap_or_default();

    // old absolute path to *this* use-tree (as parsed)
    let mut abs_old: Vec<String> = parent_abs_old.to_vec();
    abs_old.extend(rel.iter().cloned());

    let parent_abs_new = flatten_vexide_devices(parent_abs_old);
    let abs_new = flatten_vexide_devices(&abs_old);

    let new_rel = if abs_new
        .as_slice()
        .starts_with(parent_abs_new.as_slice())
    {
        abs_new[parent_abs_new.len()..].to_vec()
    } else {
        // Shouldn't happen in valid `use` trees, but be safe.
        rel.clone()
    };

    // If we replace the entire node text, don't recurse (avoid overlapping edits).
    let mut replaced_entire_node = false;

    if rel != new_rel {
        if new_rel.is_empty() {
            // This means the rewritten absolute path is exactly the parent's rewritten absolute path.
            // Inside a `{ ... }` list, that should become `self` (or splice children if it was `devices::{...}`).
            if let Some(list) = tree.use_tree_list() {
                // Splice: replace `devices::{ ... }` with just `...`
                if let (Some(l_curly), Some(r_curly)) = (list.l_curly_token(), list.r_curly_token()) {
                    let inside = TextRange::new(l_curly.text_range().end(), r_curly.text_range().start());
                    let replacement = slice(src, inside).to_string();
                    edits.push(Edit {
                        range: tree.syntax().text_range(),
                        replacement,
                    });
                    replaced_entire_node = true;
                }
            } else if tree.star_token().is_some() {
                // `devices::*` under `vexide::{ ... }` becomes just `*`
                edits.push(Edit {
                    range: tree.syntax().text_range(),
                    replacement: "*".to_string(),
                });
                replaced_entire_node = true;
            } else {
                // `devices` under `vexide::{ ... }` becomes `self`
                if let Some(path) = tree.path() {
                    edits.push(Edit {
                        range: path.syntax().text_range(),
                        replacement: "self".to_string(),
                    });
                }
            }
        } else {
            // Normal case: rewrite only the `path` part.
            if let Some(path) = tree.path() {
                edits.push(Edit {
                    range: path.syntax().text_range(),
                    replacement: new_rel.join("::"),
                });
            }
        }
    }

    if replaced_entire_node {
        return;
    }

    // Recurse into children using the *old* absolute path as the new parent context.
    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            collect_edits_for_tree(src, &child, &abs_old, edits);
        }
    }
}

fn flatten_vexide_devices(abs: &[String]) -> Vec<String> {
    // Transform: vexide::devices::...  ->  vexide::...
    if abs.len() >= 2 && abs[0] == "vexide" && abs[1] == "devices" {
        let mut out = Vec::with_capacity(abs.len() - 1);
        out.push(abs[0].clone());
        out.extend(abs[2..].iter().cloned());
        out
    } else {
        abs.to_vec()
    }
}

fn path_segments(path: &ast::Path) -> Vec<String> {
    path.segments()
        .map(|seg| seg.syntax().text().to_string())
        .collect()
}

fn apply_edits(src: &str, edits: &mut Vec<Edit>) -> String {
    // Apply from back to front so earlier ranges don't shift.
    edits.sort_by_key(|e| e.range.start());

    // Also discard exact-duplicate edits (can happen in some degenerate trees).
    edits.dedup_by(|a, b| a.range == b.range && a.replacement == b.replacement);

    let mut out = src.to_string();
    for e in edits.iter().rev() {
        let start: usize = e.range.start().into();
        let end: usize = e.range.end().into();
        out.replace_range(start..end, &e.replacement);
    }
    out
}

fn slice<'a>(src: &'a str, range: TextRange) -> &'a str {
    let start: usize = range.start().into();
    let end: usize = range.end().into();
    &src[start..end]
}
"
}
