    type Item = Vec<usize>;

    fn next(&mut self) -> Option<Self::Item> {
        if self.done {
            return None;
        }
        if !self.started {
            self.started = true;
            return Some(self.cur.clone());
        }

        // Increment like an odometer from the last dimension.
        for k in (0..self.dims.len()).rev() {
            self.cur[k] += 1;
            if self.cur[k] < self.dims[k] {
                return Some(self.cur.clone());
            }
            self.cur[k] = 0;
        }

        self.done = true;
        None
    }
