            Some(f) => self.matches_filter(f),
        }
    }
}

// If you have an optional value `Option<T>` and a filter `Option<F>`:
// - None filter means "no constraint" -> matches
// - Some(filter) requires that the value is present and matches recursively
impl<T, F> MatchesFilter<Option<F>> for Option<T>
where
    T: MatchesFilter<F>,
{
    fn matches_filter(&self, filter: &Option<F>) -> bool {
        match filter {
            None => true,
            Some(f) => match self {
                None => false,
                Some(v) => v.matches_filter(f),
            },
        }
    }
}

// Leaf/primitive matching: for identical types, just use PartialEq
impl<T> MatchesFilter<T> for T
where
    T: PartialEq,
{
    fn matches_filter(&self, filter: &T) -> bool {
        self == filter
    }
}

macro_rules! impl_matches_filter_struct {
    ($ty:ty, $filter:ty, { $($field:ident),* $(,)? }) => {
        impl MatchesFilter<$filter> for $ty {
            fn matches_filter(&self, filter: &$filter) -> bool {
                true $( && self.$field.matches_filter(&filter.$field) )*
            }
        }
    };
}

