        "https://login.microsoftonline.com/{tenant_id}/oauth2/v2.0/token"
    );

    let params = TokenRequest {
        grant_type: "client_credentials",
        client_id,
        client_secret,
        scope: "https://storage.azure.com/.default",
    };

    let resp = http
        .post(token_url)
        .form(&params)
        .send()
        .await
        .context("sending token request")?;

    let status = resp.status();
    let body = resp.text().await.context("reading token response body")?;
    if !status.is_success() {
        return Err(anyhow!(
            "token endpoint returned {status}. body: {body}"
        ));
    }

    let tr: TokenResponse = serde_json::from_str(&body).context("decoding token JSON")?;
    Ok(tr.access_token)
}

async fn list_blob_names(container: &ContainerClient, prefix: &str) -> Result<Vec<String>> {
    let mut out = Vec::new();
    let mut stream = container.list_blobs().prefix(prefix.to_string()).into_stream();

    while let Some(page) = stream.next().await {
        let page = page.context("list_blobs page error")?;
        for b in page.blobs.blobs() {
            let name = b.name.clone();
            if name.ends_with(".json") {
                out.push(name);
            }
        }
    }

    Ok(out)
}

async fn download_and_parse_all(
    container: Arc<ContainerClient>,
    names: Vec<String>,
    concurrency: usize,
) -> (Vec<Value>, usize, usize) {
    // Important: this creates ONE stream for all blobs and applies bounded concurrency across ALL downloads.
    // Your original Rust approach effectively put a per-page barrier by awaiting all downloads in a page
    // before moving to the next page.

    let mut ok = 0usize;
    let mut err = 0usize;

    let results: Vec<Option<Value>> = stream::iter(names.into_iter())
        .map(|name| {
            let container = container.clone();
            async move {
                let blob = container.blob_client(name);
                // get_content() returns the whole blob body; good for small JSON.
                match blob.get_content().await {
                    Ok(bytes) => match serde_json::from_slice::<Value>(bytes.as_ref()) {
                        Ok(v) => Some(v),
                        Err(_) => None,
                    },
                    Err(_) => None,
                }
            }
        })
        .buffer_unordered(concurrency)
        .collect()
        .await;

    let mut values = Vec::with_capacity(results.len());
    for r in results {
        match r {
            Some(v) => {
                ok += 1;
                values.push(v);
            }
            None => {
                err += 1;
            }
        }
    }

    (values, ok, err)
}

fn summarize_json(v: &Value) -> String {
    match v {
        Value::Object(map) => {
            let mut keys: Vec<&String> = map.keys().collect();
            keys.sort();
            let shown: Vec<&str> = keys.into_iter().take(10).map(|s| s.as_str()).collect();
            format!("object keys={shown:?}")
        }
        Value::Array(a) => format!("array len={}", a.len()),
        _ => format!("{}", v),
    }
}
"
}

