            CustomError::UpstreamBadStatus(s) => write!(f, "upstream returned bad status: {s}"),
        }
    }
}

impl ResponseError for CustomError {
    fn error_response(&self) -> HttpResponse {
        let code = match self {
            CustomError::MissingDateHeader | CustomError::InvalidDateHeader => {
                actix_web::http::StatusCode::BAD_REQUEST
            }
            CustomError::MissingAppState => actix_web::http::StatusCode::INTERNAL_SERVER_ERROR,
            CustomError::Upstream(_) | CustomError::UpstreamBadStatus(_) => {
                actix_web::http::StatusCode::BAD_GATEWAY
            }
        };

        HttpResponse::build(code).json(serde_json::json!({
            "error": self.to_string()
        }))
    }
}

impl From<reqwest::Error> for CustomError {
    fn from(value: reqwest::Error) -> Self {
        CustomError::Upstream(value)
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct AdditionalData {
    echoed_date: String,
    info: String,
}

struct CustomServiceClient {
    base_url: String,
    client: reqwest::Client,
}

impl CustomServiceClient {
    fn new(state: &AppState) -> Self {
        Self {
            base_url: state.base_url.clone(),
            client: state.client.clone(),
        }
    }

    async fn get_additional_data(&self, date_str: String) -> Result<AdditionalData, CustomError> {
        let url = format!("{}/data", self.base_url);

        let resp = self
            .client
            .get(url)
            // For demo purposes: pass the incoming date header through
            .header(header::DATE, date_str)
            .send()
            .await?;

        let status = resp.status();
        if !status.is_success() {
            return Err(CustomError::UpstreamBadStatus(status));
        }

        Ok(resp.json::<AdditionalData>().await?)
    }
}

#[derive(Debug, Serialize)]
struct AuthorizedHttpRequest {
    path: String,
    date: String,
    additional: AdditionalData,
}

impl FromRequest for AuthorizedHttpRequest {
    type Error = CustomError;
    type Future = LocalBoxFuture<'static, Result<Self, Self::Error>>;

    fn from_request(req: &HttpRequest, _payload: &mut actix_web::dev::Payload) -> Self::Future {
        // IMPORTANT: do not capture references (like Option<&HeaderValue>) into the async block.
        // Capture owned data instead so the future can be 'static.
        let path = req.path().to_owned();

        // Clone the header value (owned) so it can outlive `req`.
        let date_header = req.headers().get(header::DATE).cloned();

        // Clone the app state handle (Arc under the hood) so it can be moved into the future.
        let state = req.app_data::<web::Data<AppState>>().cloned();

        Box::pin(async move {
            let state = state.ok_or(CustomError::MissingAppState)?;

            let date = match date_header {
                Some(hv) => hv
                    .to_str()
                    .map_err(|_| CustomError::InvalidDateHeader)?
                    .to_owned(),
                None => return Err(CustomError::MissingDateHeader),
            };

            let service_client = CustomServiceClient::new(&state);
            let additional = service_client.get_additional_data(date.clone()).await?;

            Ok(AuthorizedHttpRequest {
                path,
                date,
                additional,
            })
        })
    }
}

async fn data_endpoint(req: HttpRequest) -> impl Responder {
    let echoed_date = req
        .headers()
        .get(header::DATE)
        .and_then(|h| h.to_str().ok())
        .unwrap_or("(missing)")
        .to_string();

    HttpResponse::Ok().json(AdditionalData {
        echoed_date,
        info: "extra data computed by /data".to_string(),
    })
}

async fn hello(auth: AuthorizedHttpRequest) -> Result<impl Responder, CustomError> {
    Ok(HttpResponse::Ok().json(auth))
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let addr = "127.0.0.1:8080";

    let state = web::Data::new(AppState {
        base_url: format!("http://{addr}"),
        client: reqwest::Client::new(),
    });

    println!("Server running at http://{addr}");
    println!("Try: curl -H 'Date: 2026-02-08' http://{addr}/hello");

    HttpServer::new(move || {
        App::new()
            .app_data(state.clone())
            .route("/data", web::get().to(data_endpoint))
            .route("/hello", web::get().to(hello))
    })
    .bind(addr)?
    .run()
    .await
}
"
