fn parse_lancedb_iso_to_utc(s: &str) -> Result<DateTime<Utc>, chrono::ParseError> {
    // LanceDB strings shown are like:
    //   "1970-01-01T00:00:00"
    //   "2025-08-02T17:35:41.409"
    // i.e. ISO-ish but *no timezone*. RFC3339 requires a timezone.
    // Strategy: normalize and append 'Z' (assume UTC), then parse as RFC3339.

    let mut s = s.trim().trim_matches('"').to_string();

    // If it already has an explicit timezone, let chrono parse it directly.
    // (RFC3339 timezone examples: Z, +02:00, -05:00)
    let has_tz = s.ends_with('Z')
        || s.rfind('+').map(|i| i > 10).unwrap_or(false)
        || s.rfind('-').map(|i| i > 10).unwrap_or(false);

    if !has_tz {
        // Handle a trailing decimal point, e.g. "2025-...:41." -> "2025-...:41"
        if s.ends_with('.') {
            s.pop();
        }

        // If there is a fractional part, truncate it to <= 9 digits (chrono nanoseconds).
        // Example: "...41.123456789123" -> "...41.123456789"
        if let Some(dot) = s.rfind('.') {
            let (head, frac) = s.split_at(dot + 1); // keep the dot in head
            let digits: String = frac.chars().take_while(|c| c.is_ascii_digit()).collect();
            let digits = if digits.len() > 9 {
                digits[..9].to_string()
            } else {
                digits
            };
            // Rebuild (drop any non-digit suffix after fraction, if present)
            s = format!("{}{}", head, digits);
            // If we ended up with just a dot (no digits), remove it.
            if s.ends_with('.') {
                s.pop();
            }
        }

        // Assume UTC.
        s.push('Z');
    }

    Ok(DateTime::parse_from_rfc3339(&s)?.with_timezone(&Utc))
}

fn main() {
    let samples = [
        "1970-01-01T00:00:00",
        "2025-08-02T17:35:41.409",
        "2025-08-04T01:48:44.017",
        "2025-08-04T23:02:20.584",
        "2025-08-05T00:08:57.350",
        "2025-08-10T18:31:26.628",
        // A couple extra edge cases you mentioned/implied:
        "2025-08-10T18:31:26.",
        "2025-08-10T18:31:26.123456789123", // too many fractional digits
    ];

    for s in samples {
        match parse_lancedb_iso_to_utc(s) {
