                println!("  parsed (UTC): {dt}");
                println!("  unix seconds: {}", dt.timestamp());
                println!("  unix millis : {}", dt.timestamp_millis());
            }
            Err(e) => {
                println!("input: {s}");
                println!("  parse error: {e:?}");
            }
        }
    }
