struct DragContext {
    /// Which point (by id) is currently being dragged
    active_id: Signal<Option<usize>>,
    /// Offset from pointer position to the point center at drag-start
    grab_offset: Signal<(f64, f64)>,
    /// The list of points we are allowed to mutate during dragging
    points: Signal<Vec<PointModel>>,
}

impl DragContext {
    fn start_drag(&self, id: usize, pointer: ElementPoint, point_xy: (f64, f64)) {
        let (px, py) = (pointer.x, pointer.y);
        let (x, y) = point_xy;
        self.grab_offset.set((px - x, py - y));
        self.active_id.set(Some(id));
    }

    fn stop_drag(&self) {
        self.active_id.set(None);
    }

    fn pointer_move(&self, pointer: ElementPoint) {
        let Some(id) = *self.active_id.read() else {
            return;
        };

        let (ox, oy) = *self.grab_offset.read();
        let new_x = pointer.x - ox;
        let new_y = pointer.y - oy;

