/// - Forwards PTY output -> your stdout (continuous blocking read)
/// - Forwards your stdin keystrokes -> PTY input (independent writer)
///
/// This demonstrates the core fix for "read loop holds mutex so writes block":
/// do NOT guard a single read+write handle with one mutex while doing a blocking read.
/// Instead, split the PTY into independent reader/writer handles (or single-owner event loop).
fn main() -> Result<()> {
