        .slave
        .spawn_command(cmd)
        .context("spawn_command")?;

    // Critical part: split master into a reader and a writer (no shared mutex).
    let mut pty_reader = pair.master.try_clone_reader().context("clone reader")?;
    let mut pty_writer = pair.master.take_writer().context("take writer")?;

    // Put our own terminal into raw mode so keystrokes (incl. arrows/esc sequences) flow through.
    enable_raw_mode().context("enable_raw_mode")?;
    struct RawModeGuard;
    impl Drop for RawModeGuard {
        fn drop(&mut self) {
            let _ = disable_raw_mode();
        }
    }
    let _raw_guard = RawModeGuard;

    // Channel for stdin -> PTY writer.
    let (tx, rx) = chan::unbounded::<Vec<u8>>();

    // Thread 1: PTY output -> stdout (blocking read is fine; it doesn't block writes).
    let out_thread = thread::spawn(move || -> Result<()> {
        let mut stdout = std::io::stdout().lock();
        let mut buf = [0u8; 8192];
        loop {
            let n = pty_reader.read(&mut buf).context("read from pty")?;
            if n == 0 {
                break;
            }
            stdout.write_all(&buf[..n]).context("write to stdout")?;
            stdout.flush().ok();
        }
        Ok(())
    });

    // Thread 2: stdin -> channel (blocking read is fine).
    let in_thread = thread::spawn(move || -> Result<()> {
        let mut stdin = std::io::stdin().lock();
        let mut buf = [0u8; 1024];
        loop {
            let n = stdin.read(&mut buf).context("read stdin")?;
            if n == 0 {
                break;
            }
            if tx.send(buf[..n].to_vec()).is_err() {
                break;
            }
        }
        Ok(())
    });

    // Thread 3: channel -> PTY writer.
    let write_thread = thread::spawn(move || -> Result<()> {
        while let Ok(chunk) = rx.recv() {
            pty_writer
                .write_all(&chunk)
                .context("write to pty")?;
            pty_writer.flush().ok();
        }
        Ok(())
    });

    // Wait for child to exit (Ctrl-D in the shell, or `exit`).
    let status = child.wait().context("wait child")?;

    // Dropping the master will cause reader/writer threads to unwind naturally.
    // Join threads (ignore errors if they were interrupted by PTY close).
    let _ = out_thread.join();
    let _ = in_thread.join();
    let _ = write_thread.join();

    eprintln!("\r\n[child exited: {status:?}]");
    Ok(())
}
