    // This avoids an artificial oscillation from symmetric initialization.
    let mut s2 = Local::behavior_subject::<bool, Infallible>(false); // feedback from q2 into nand "s"
    let mut r2 = Local::behavior_subject::<bool, Infallible>(true); // feedback from q1 into nand "r"

