use std::pin::Pin;
use std::task::{Context, Poll};
use std::time::Duration;

enum TryPollResult<T> {
    Ready(T),
    Pending,
}

/// Poll a future once, synchronously.
///
/// This uses a noop waker because we only want a "is it ready right now?" check.
/// If it returns Pending, you should poll it again later using a real executor
/// (e.g. by `.await`ing it in a Tokio task).
fn try_poll<F: Future>(mut fut: Pin<&mut F>) -> TryPollResult<F::Output> {
    let waker = futures::task::noop_waker_ref();
    let mut cx = Context::from_waker(waker);

    match fut.as_mut().poll(&mut cx) {
        Poll::Ready(v) => TryPollResult::Ready(v),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// Non-async function, but assumed to be called while a Tokio runtime is running.
///
/// If the future is ready immediately, we use its value here.
/// If not, we spawn a task that awaits it.
fn use_now_or_spawn<F>(mut fut: Pin<Box<F>>) -> Option<F::Output>
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
{
    match try_poll(fut.as_mut()) {
        TryPollResult::Ready(v) => Some(v),
        TryPollResult::Pending => {
            tokio::spawn(async move {
                let v = fut.await;
                println!("spawned task got value: {v:?}");
            });
            None
        }
    }
}

#[tokio::main(flavor = "multi_thread")]
async fn main() {
    // A future that completes without ever yielding.
    let immediate = Box::pin(async { 123_i32 });
    let got = use_now_or_spawn(immediate);
    println!("immediate returned from sync fn: {got:?}");

    // A future that yields (sleep), so the first poll will be Pending.
    let delayed = Box::pin(async {
        tokio::time::sleep(Duration::from_millis(200)).await;
        456_i32
    });
    let got = use_now_or_spawn(delayed);
    println!("delayed returned from sync fn: {got:?} (task spawned)");

    // Give the spawned task time to run in this demo.
    tokio::time::sleep(Duration::from_millis(300)).await;
}
