name = "enum_dispatch_cross_crate_pattern"
version = "0.1.0"
edition = "2021"

[dependencies]
enum_dispatch = "0.3"
",
  "main.rs": "mod al {
    // === abstract layer (al): traits only ===
    pub trait Rest {
        fn get(&self, url: &str) -> String;
        fn post(&self, url: &str, body: &str) -> String;
        fn delete(&self, url: &str) -> String;
    }
}

mod il {
    // === implementation layer (il): concrete types implementing al::Rest ===
    use super::al;

    #[derive(Debug, Clone)]
    pub struct Foo {
        pub name: String,
    }

    #[derive(Debug, Clone)]
    pub struct Boo {
        pub id: u32,
    }

    impl al::Rest for Foo {
        fn get(&self, url: &str) -> String {
            format!("Foo({}) GET {url}", self.name)
        }
        fn post(&self, url: &str, body: &str) -> String {
            format!("Foo({}) POST {url} body={body}", self.name)
        }
        fn delete(&self, url: &str) -> String {
            format!("Foo({}) DELETE {url}", self.name)
        }
    }

    impl al::Rest for Boo {
        fn get(&self, url: &str) -> String {
            format!("Boo({}) GET {url}", self.id)
        }
        fn post(&self, url: &str, body: &str) -> String {
            format!("Boo({}) POST {url} body={body}", self.id)
        }
        fn delete(&self, url: &str) -> String {
            format!("Boo({}) DELETE {url}", self.id)
        }
    }
}

mod bl {
    // === business layer (bl): depends on al + il; defines the enum_dispatch trait+enum ===
    use enum_dispatch::enum_dispatch;

    use super::{al, il};

    // Key idea to avoid the "trait and enum must be in the same crate" limitation:
    //
    // 1) Keep the real abstraction in `al::Rest` (so il implements it).
    // 2) In *this* crate (bl), define a local trait with the SAME API.
    // 3) Provide a blanket impl that forwards each method to `al::Rest`.
    // 4) Use enum_dispatch on this local trait + enum.
    //
    // In a real multi-crate layout:
    // - crate `al` has `trait Rest`
    // - crate `il` implements `al::Rest` for Foo/Boo
    // - crate `bl` defines `RestDispatch` + `Item` below
    // No cycles are needed.

    #[enum_dispatch]
    pub trait RestDispatch {
        fn get(&self, url: &str) -> String;
        fn post(&self, url: &str, body: &str) -> String;
        fn delete(&self, url: &str) -> String;
    }

    // Blanket forwarding impl: every `T: al::Rest` automatically becomes `RestDispatch`.
    impl<T: al::Rest + ?Sized> RestDispatch for T {
        fn get(&self, url: &str) -> String {
            al::Rest::get(self, url)
        }
        fn post(&self, url: &str, body: &str) -> String {
            al::Rest::post(self, url, body)
        }
        fn delete(&self, url: &str) -> String {
            al::Rest::delete(self, url)
        }
    }

    #[enum_dispatch(RestDispatch)]
    #[derive(Debug, Clone)]
    pub enum Item {
        Foo(il::Foo),
        Boo(il::Boo),
    }

    impl Item {
        pub fn from_config(which: &str) -> Self {
            match which {
                "foo" => Item::Foo(il::Foo {
                    name: "alpha".to_string(),
                }),
                "boo" => Item::Boo(il::Boo { id: 42 }),
                other => {
                    eprintln!("unknown config '{other}', defaulting to Boo");
                    Item::Boo(il::Boo { id: 0 })
                }
            }
        }
    }
}

fn main() {
    use bl::RestDispatch;

    let items = vec![bl::Item::from_config("foo"), bl::Item::from_config("boo")];

    for it in &items {
        // Calls are statically dispatched via the enum_dispatch-generated match.
