{
  "Cargo.toml": "[package]
name = "kitty_shm_anim"
version = "0.1.0"
edition = "2021"

[dependencies]
base64 = "0.22"
ctrlc = "3.4"
nix = { version = "0.28", features = ["mman", "fs"] }
termion = "2"
",
  "main.rs": "use base64::{engine::general_purpose::STANDARD, Engine as _};
use nix::fcntl::OFlag;
use nix::sys::mman::{mmap, munmap, shm_open, shm_unlink, MapFlags, ProtFlags};
use nix::sys::stat::Mode;
use nix::unistd::{close, ftruncate, getpid};
use std::ffi::c_void;
use std::io::{self, Write};
use std::slice;
use std::sync::{
    atomic::{AtomicBool, Ordering},
    Arc,
};
use std::time::{Duration, Instant};
use termion::terminal_size;
use termion::terminal_size_pixels;

struct ShmBuffer {
    name: String,
    fd: i32,
    ptr: *mut c_void,
    len: usize,
}

impl ShmBuffer {
    fn new(name: String, len: usize) -> nix::Result<Self> {
        // POSIX shm names must start with '/'
        assert!(name.starts_with('/'));

        // Best effort: if a previous run crashed, unlink any leftover.
        let _ = shm_unlink(name.as_str());

        let fd = shm_open(
            name.as_str(),
            OFlag::O_CREAT | OFlag::O_EXCL | OFlag::O_RDWR,
            Mode::from_bits_truncate(0o600),
        )?;

        // Ensure the shm object is large enough.
        ftruncate(fd, len as i64)?;

        let ptr = unsafe {
            mmap(
                None,
                len,
                ProtFlags::PROT_READ | ProtFlags::PROT_WRITE,
                MapFlags::MAP_SHARED,
                fd,
                0,
            )?
        };

        Ok(Self { name, fd, ptr, len })
    }

    fn as_bytes_mut(&mut self) -> &mut [u8] {
        unsafe { slice::from_raw_parts_mut(self.ptr as *mut u8, self.len) }
    }
}

impl Drop for ShmBuffer {
    fn drop(&mut self) {
        unsafe {
            let _ = munmap(self.ptr, self.len);
        }
        let _ = close(self.fd);
        let _ = shm_unlink(self.name.as_str());
    }
}

fn kitty_send<W: Write>(out: &mut W, payload: &str) -> io::Result<()> {
    // Kitty graphics protocol: ESC_G ... ESC \
    write!(out, "\x1b_G{}\x1b\\", payload)
}

fn main() -> io::Result<()> {
    let running = Arc::new(AtomicBool::new(true));
    {
        let running = running.clone();
        ctrlc::set_handler(move || {
            running.store(false, Ordering::SeqCst);
        })
        .expect("failed to set Ctrl-C handler");
    }

    let mut out = io::stdout().lock();

    let (cols, rows) = terminal_size().unwrap_or((80, 24));
    let (w_px, h_px) = terminal_size_pixels().unwrap_or((640, 480));
    let (w_px, h_px) = (w_px as usize, h_px as usize);

    let bytes_per_pixel = 3usize; // f=24 => RGB
    let frame_len = w_px
        .checked_mul(h_px)
        .and_then(|x| x.checked_mul(bytes_per_pixel))
        .expect("frame too large");

    let shm_name = format!("/kitty-shm-anim-{}", getpid());
    let mut shm = ShmBuffer::new(shm_name.clone(), frame_len)
        .expect("failed to create/mmap POSIX shared memory");

    // According to kitty protocol, the payload is base64.
    // For t=s (shared memory), kitty expects the shm object name.
    let shm_name_b64 = STANDARD.encode(shm_name.as_bytes());

    // Terminal setup.
    write!(out, "\x1b[?25l\x1b[2J\x1b[H")?; // hide cursor, clear, home

    // First: transmit + place (full terminal).
    // q=2 => no responses from kitty.
    kitty_send(
        &mut out,
        &format!(
            "q=2,a=T,t=s,f=24,s={},v={},c={},r={},i=1;{}",
            w_px, h_px, cols, rows, shm_name_b64
        ),
    )?;
    out.flush()?;

    let target_dt = Duration::from_nanos(1_000_000_000u64 / 60);
    let start = Instant::now();

    while running.load(Ordering::SeqCst) {
        let frame_start = Instant::now();
        let t = (frame_start - start).as_secs_f32();

        // Fill the shared memory buffer with an animated RGB gradient.
        let buf = shm.as_bytes_mut();
        let w = w_px as f32;
        let h = h_px as f32;
        let pi = std::f32::consts::PI;

        // Write contiguous RGB bytes.
        let mut idx = 0usize;
        for y in 0..h_px {
            let fy = y as f32 / h;
            for x in 0..w_px {
                let fx = x as f32 / w;

                let r = ((fx * pi + t).sin() * 0.5 + 0.5) * 255.0;
                let g = ((fy * pi + t * 1.3).sin() * 0.5 + 0.5) * 255.0;
                let b = (((fx + fy) * pi + t * 0.7).sin() * 0.5 + 0.5) * 255.0;

                buf[idx] = r as u8;
                buf[idx + 1] = g as u8;
                buf[idx + 2] = b as u8;
                idx += 3;
            }
        }

        // Tell kitty to re-read the shm object into the same image id.
        // (This should update all existing placements of that image id.)
        kitty_send(
            &mut out,
            &format!(
                "q=2,a=t,t=s,f=24,s={},v={},i=1;{}",
                w_px, h_px, shm_name_b64
            ),
        )?;
        out.flush()?;

        let elapsed = frame_start.elapsed();
        if elapsed < target_dt {
            std::thread::sleep(target_dt - elapsed);
        }
    }

    // Restore terminal.
    write!(out, "\x1b[?25h\x1b[0m\x1b[H\x1b[2J")?;
    out.flush()?;

    Ok(())
}
"
}
