/// Simulated queue handler that periodically starts "work" and finishes in-flight work on shutdown.
async fn queue_handler(token: CancellationToken) {
    info!("queue: started");

    let mut tick = tokio::time::interval(Duration::from_secs(1));

    // Simulate a single in-flight job counter.
    let mut in_flight_steps: u32 = 0;

    loop {
        tokio::select! {
            _ = token.cancelled() => {
                warn!("queue: shutdown requested; will finish in-flight work...");
                break;
            }
            _ = tick.tick() => {
                // Start a new "job" occasionally (only if we're idle).
                if in_flight_steps == 0 {
                    in_flight_steps = 5;
                    info!("queue: picked up a job (5 steps)");
                }

                if in_flight_steps > 0 {
                    // Do one step of work.
                    info!("queue: processing step (remaining: {})", in_flight_steps);
                    in_flight_steps -= 1;
                }
            }
        }
    }

    // Graceful drain: finish remaining steps before exiting.
    while in_flight_steps > 0 {
        info!(
            "queue: draining in-flight work (remaining steps: {})",
            in_flight_steps
        );
        sleep(Duration::from_millis(300)).await;
        in_flight_steps -= 1;
    }

    info!("queue: stopped");
}

