        _ = tokio::signal::ctrl_c() => {
            warn!("main: Ctrl+C received; starting graceful shutdown");
            shutdown.cancel();
            // true = graceful: stop accepting new connections and wait for in-flight requests.
            server_handle.stop(true).await;
        }

        res = &mut server_task => {
            server_done = true;
            warn!("main: http server finished unexpectedly: {:?}", res);
            // If the server stops, also stop the queue.
            shutdown.cancel();
        }

        res = &mut queue_task => {
