/// Middleware that blocks WebSocket upgrade requests unless the Origin header matches.
async fn check_ws_origin(req: Request<axum::body::Body>, next: Next) -> Response {
    let origin = req
        .headers()
        .get(header::ORIGIN)
        .and_then(|v| v.to_str().ok());

    match origin {
        Some(o) if o == ALLOWED_ORIGIN => {
