            next.run(req).await
        }
        Some(o) => {
            warn!(origin = %o, "blocked websocket request due to disallowed origin");
            StatusCode::FORBIDDEN.into_response()
        }
        None => {
            // Browsers normally send Origin for WS; missing Origin typically means "not a browser".
            warn!("blocked websocket request due to missing Origin header");
            StatusCode::FORBIDDEN.into_response()
        }
    }
}

async fn ws_handler(ws: WebSocketUpgrade, Path(session_id): Path<String>) -> impl IntoResponse {
