#[derive(Debug, Clone)]
pub struct EventSender {
    tx: Sender<Event>,
}

impl EventSender {
    /// Returns `true` if the event was sent, `false` if the channel is closed.
    pub fn send(&self, event: Event) -> bool {
        self.tx.send(event).is_ok()
    }
}

pub struct EventStreamFactory {
    tx: Sender<Event>,
}

impl EventStreamFactory {
    /// Stream ends when the broadcast channel is closed.
    pub fn all_events(&self) -> impl Stream<Item = Result<Event, RecvError>> + Send + 'static {
        BroadcastStream::new(self.tx.subscribe()).filter_map(|item| async move {
            match item {
                Ok(ev) => Some(Ok(ev)),
                // When the channel is closed, end the stream.
                Err(tokio_stream::wrappers::errors::BroadcastStreamRecvError::Closed) => None,
                // You can choose a policy for lagging; here we forward it as a generic error.
                Err(tokio_stream::wrappers::errors::BroadcastStreamRecvError::Lagged(_)) => {
                    Some(Err(RecvError))
                }
            }
        })
    }

    /// Important bit: this closes the channel for *all* receivers, even if there are Sender clones.
    pub fn shutdown(&self) {
        self.tx.close_channel();
    }
}

