// Usage:
//   with_context_async_boxed!(&tx, |ctx| { ctx.0 += 1; });
//   with_context_async_boxed!(&tx, |ctx| { tokio::time::sleep(...).await; ctx.0 += 1; });
macro_rules! with_context_async_boxed {
    ($tx:expr, |$ctx:ident| $body:block) => {{
        crate::with_context_async($tx, move |$ctx: &mut crate::Context| {
            async move $body.boxed()
        })
    }};
}

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::unbounded_channel::<InnerAsyncEvent>();
    let (done_tx, done_rx) = tokio::sync::oneshot::channel::<i32>();

    // "Worker" task that owns the Context and executes incoming async jobs.
    tokio::spawn(async move {
        let mut ctx = Context(0);

        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    block(&mut ctx).await;
                }
            }
        }

        let _ = done_tx.send(ctx.0);
    });

    // Send some async work.
    with_context_async_boxed!(&tx, |ctx| {
        ctx.0 += 1;
