// This simulates an "inner" REPL-like program.
// It prints asynchronous status lines while also responding to input.
fn run_child() -> io::Result<()> {
    // periodic async output
    thread::spawn(|| {
        for i in 1.. {
            println!("(async) tick {i}");
            let _ = io::stdout().flush();
            thread::sleep(Duration::from_millis(900));
        }
    });

    let stdin = io::stdin();
    let mut stdout = io::stdout();

    writeln!(stdout, "child: ready (type anything, or 'quit' to stop)")?;
    stdout.flush()?;

    for line in stdin.lock().lines() {
        let line = line?;
        if line.trim() == "quit" {
            writeln!(stdout, "child: bye")?;
            stdout.flush()?;
            break;
        }
        writeln!(stdout, "child: echo => {line}")?;
        stdout.flush()?;
    }

    Ok(())
}

fn run_parent() -> io::Result<()> {
    let exe = env::current_exe()?;

    let mut child = Command::new(exe)
        .env("CHILD", "1")
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::inherit())
        .spawn()?;

    let child_stdin = child.stdin.take().expect("child stdin");
    let child_stdout = child.stdout.take().expect("child stdout");
    let child_stdin = Arc::new(Mutex::new(child_stdin));

    let helper = CmdHelper {
        cmds: Arc::new(vec!["help", "exit", "quit"]),
    };

    let mut rl = Editor::<CmdHelper, DefaultHistory>::new().expect("create editor");
    rl.set_helper(Some(helper));

    // Key piece: this printer lets another thread print while `readline()` is blocking,
    // and rustyline will redraw the prompt/input correctly.
    let printer = rl
        .create_external_printer()
        .expect("external printer");

    // Reader thread: forward child stdout to rustyline external printer.
    let reader_handle = thread::spawn(move || {
        let mut br = BufReader::new(child_stdout);
        let mut buf = String::new();
        loop {
            buf.clear();
            match br.read_line(&mut buf) {
                Ok(0) => break, // EOF
                Ok(_) => {
                    // Keep output above the current prompt/input.
                    // `print` is the portable API across rustyline versions.
                    let _ = printer.print(format!("[child] {}", buf));
                }
                Err(_) => break,
            }
        }
    });

    println!("Parent: type lines to send to child.");
    println!("Parent: type 'exit' to stop.");

    loop {
        match rl.readline("> ") {
            Ok(line) => {
                let trimmed = line.trim();
                if !trimmed.is_empty() {
                    let _ = rl.add_history_entry(trimmed);
                }

                if trimmed == "exit" {
                    // ask child to stop
                    if let Ok(mut w) = child_stdin.lock() {
                        let _ = writeln!(w, "quit");
                        let _ = w.flush();
                    }
                    break;
                }

                if trimmed == "help" {
                    println!("Commands: help, exit  (anything else is forwarded to child)");
                    continue;
                }

                // forward to child
                if let Ok(mut w) = child_stdin.lock() {
                    writeln!(w, "{line}")?;
                    w.flush()?;
                }
            }
            Err(ReadlineError::Interrupted) => {
                // Ctrl-C: just reprompt
                continue;
            }
            Err(ReadlineError::Eof) => {
                // Ctrl-D
                break;
            }
            Err(e) => {
                eprintln!("readline error: {e}");
                break;
            }
        }
    }

    let _ = child.wait();
    let _ = reader_handle.join();

    Ok(())
}
