    /// Sequential, safe, does *one* criterion computation per pair (i < j),
    /// and updates both elements' neighbor lists.
    pub fn build_lists_sequential_pairwise(&mut self) {
        let n = self.get_nelems();
        for b in &mut self.elems {
            b.nb.clear();
        }

        for i in 0..n {
            for j in (i + 1)..n {
