    pub fn build_lists_parallel(&mut self) {
        let n = self.get_nelems();

        // Phase 1 (parallel, read-only): compute all edges (i, j) with i < j.
        let cutoff = self.cutoff;
        let elems: &Vec<B> = &self.elems;
        let edges: Vec<(usize, usize)> = (0..n)
            .into_par_iter()
            .flat_map_iter(|i| {
                let bi = &elems[i];
                (i + 1..n).filter_map(move |j| {
                    if bi.criterion(&elems[j]) < cutoff {
                        Some((i, j))
                    } else {
                        None
                    }
                })
            })
            .collect();

        // Phase 2 (sequential, mutable): clear and fill neighbor lists.
        for b in &mut self.elems {
            b.nb.clear();
        }

        for (i, j) in edges {
            // Again, safe mutable access to two distinct elements.
            let (left, right) = self.elems.split_at_mut(j);
            let bi = &mut left[i];
            let bj = &mut right[0];
            bi.nb.push(j);
            bj.nb.push(i);
        }
    }
