async fn simple_test(string: &mut String) {
    string.push_str("test result\n");
}

// A trait that can represent an async "test" which borrows its argument.
//
// Key point: the returned Future type depends on the lifetime of the borrowed
// `&mut String`, so we model that with a GAT (Generic Associated Type).
trait AsyncTest {
    type Fut<'a>: Future<Output = ()> + 'a
    where
        Self: 'a;

    fn run<'a>(&'a self, s: &'a mut String) -> Self::Fut<'a>;
}

impl<F> AsyncTest for F
where
    // F must be callable for *any* lifetime 'a...
    F: for<'a> Fn(&'a mut String),
    // ...and for each such 'a, its output must be a Future valid for 'a.
    for<'a> <F as FnOnce<(&'a mut String,)>>::Output: Future<Output = ()> + 'a,
{
    type Fut<'a> = <F as FnOnce<(&'a mut String,)>>::Output where Self: 'a;

    fn run<'a>(&'a self, s: &'a mut String) -> Self::Fut<'a> {
        (self)(s)
    }
}

async fn harness<T>(test: T)
where
    T: AsyncTest,
{
    let mut string = String::new();
    test.run(&mut string).await;
    println!("new string is:\n{string}");
}

#[tokio::main]
async fn main() {
    harness(simple_test).await;
}
"
}
