// Allow comparing a parsed Cons<'e> with an owned expected value (u64, u64)
// so the expected value does NOT need to borrow from the helper's local State.
impl<'e> PartialEq<(u64, u64)> for Cons<'e> {
    fn eq(&self, other: &(u64, u64)) -> bool {
