// ----- The key trick: represent "POut depends on 'e" via a GAT family -----

trait OutputFamily {
    type Out<'e>;
}

struct ConsFamily;
impl OutputFamily for ConsFamily {
    type Out<'e> = Cons<'e>;
}

// ----- The test helper -----

pub fn test_input_output<'i, ExOut, PF, P>(
    input: &'i str,
    expected_output: &ExOut,
    mut parser: P,
) where
    ExOut: Debug,
    PF: OutputFamily,
    // For *any* environment lifetime 'e, the parser output is comparable to ExOut.
    for<'e> PF::Out<'e>: PartialEq<ExOut> + Debug,
    // The parser itself must work for *any* 'e.
    P: for<'e> FnMut(&mut SStream<'i, 'e>) -> ModalResult<PF::Out<'e>>,
