    Ok(Cons {
        car,
        cdr,
        filename: input.state.filename,
    })
}

fn main() {
    // Expected output does NOT borrow from the helper-created State.
    // Parsed output DOES borrow from it (Cons<'e> contains filename: &'e str).
    // This works because PF models the output as a type family PF::Out<'e>.
    let expected_output = (1u64, 2u64);

