fn spawn_key_thread(msg_tx: Sender<Message>, shutdown_rx: Receiver<()>) -> thread::JoinHandle<()> {
    thread::spawn(move || {
        // Polling-based input loop so we can react to shutdown without waiting for user input.
        loop {
            if shutdown_rx.try_recv().is_ok() {
                break;
            }

            // Wait up to 100ms for a terminal event.
            match event::poll(Duration::from_millis(100)) {
                Ok(true) => match event::read() {
                    Ok(Event::Key(key_event)) => match key_event.code {
                        KeyCode::Char(c) => {
                            let _ = msg_tx.send(Message::Key(c));
                            if c == 'q' {
                                let _ = msg_tx.send(Message::Quit);
                                break;
                            }
                        }
                        KeyCode::Esc => {
                            let _ = msg_tx.send(Message::Quit);
                            break;
                        }
                        _ => {}
                    },
                    Ok(_) => {}
                    Err(_) => {
                        // If reading input fails, just exit the thread.
                        break;
                    }
                },
                Ok(false) => {
                    // Timeout, loop again and re-check shutdown.
                }
                Err(_) => {
                    // If polling fails, exit.
                    break;
                }
            }
        }
    })
}

fn spawn_signal_thread(mut signals: Signals, msg_tx: Sender<Message>) -> thread::JoinHandle<()> {
    thread::spawn(move || {
        for sig in signals.forever() {
            let _ = msg_tx.send(Message::Signal(sig));
            if sig == SIGINT || sig == SIGTERM {
                let _ = msg_tx.send(Message::Quit);
                // Let main drive shutdown; this thread will also be stoppable via signals.handle().close().
                break;
            }
        }
    })
}

fn main() -> io::Result<()> {
    terminal::enable_raw_mode()?;

    eprintln!("Press 'q' to quit (or send SIGINT/SIGTERM).");

    let (msg_tx, msg_rx) = unbounded::<Message>();
    let (shutdown_tx, shutdown_rx) = unbounded::<()>();

    // Signals: create Signals in main so we can keep a handle and close it to stop the iterator.
    let signals = Signals::new([SIGINT, SIGTERM])
        .map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;
    let signals_handle = signals.handle();

    let key_thread = spawn_key_thread(msg_tx.clone(), shutdown_rx);
    let sig_thread = spawn_signal_thread(signals, msg_tx.clone());

    // Main event loop.
    for msg in msg_rx.iter() {
        match msg {
            Message::Key(c) => {
                eprintln!("key: {c:?}");
            }
            Message::Signal(s) => {
                eprintln!("signal: {s}");
            }
            Message::Quit => {
                eprintln!("quit requested");
                break;
            }
        }
    }

    // Initiate shutdown for threads.
    let _ = shutdown_tx.send(()); // stop key thread promptly (within its poll timeout)
    signals_handle.close(); // stop signal iterator even if no further signals arrive

    let _ = key_thread.join();
    let _ = sig_thread.join();

    terminal::disable_raw_mode()?;
    Ok(())
