use tokio::time::sleep;
use tracing::{info, info_span, Instrument, Span};
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt, EnvFilter};

use opentelemetry::trace::TracerProvider as _;
use tracing_opentelemetry::{layer as otel_layer, OpenTelemetrySpanExt};

/// Per-request context you can stash in Pingora's request context.
/// The important part: store the *tracing::Span handle* for the request.
#[derive(Clone)]
struct RequestCtx {
    request_span: Span,

    /// This is frequently what people try with `.attach()`.
    /// It's useful for propagating OTEL context across boundaries, but it does NOT
    /// automatically re-establish tracing's "current span" for parent/child creation.
    otel_context: opentelemetry::Context,
}

#[async_trait]
trait Stages: Send + Sync {
    async fn stage1(&self, ctx: Arc<RequestCtx>);
    async fn stage2(&self, ctx: Arc<RequestCtx>);
    async fn upstream(&self, ctx: Arc<RequestCtx>);
}

struct Handler;

#[async_trait]
impl Stages for Handler {
    async fn stage1(&self, ctx: Arc<RequestCtx>) {
        // Rehydrate the request span as "current" for this async computation.
        // IMPORTANT: don't hold `span.enter()` guards across `.await` in Send futures.
        // Use `.instrument(span)` instead.
        async move {
            let stage_span = info_span!("stage1");
            async move {
                info!("stage1 work begin");
                sleep(Duration::from_millis(80)).await;
                info!("stage1 work end");
            }
            .instrument(stage_span)
            .await;
        }
        .instrument(ctx.request_span.clone())
        .await;
    }

    async fn stage2(&self, ctx: Arc<RequestCtx>) {
        // Alternative: explicitly parent this span to the stored request span.
        // This works even if the request span is not currently entered.
        let stage2_span = info_span!(parent: &ctx.request_span, "stage2");

        async move {
            info!("stage2 work begin");
            sleep(Duration::from_millis(50)).await;
            info!("stage2 scheduling upstream");

            // Simulate Pingora calling another stage later/on another task.
            let h = Handler;
            let ctx2 = ctx.clone();
            tokio::spawn(async move {
                sleep(Duration::from_millis(30)).await;
                h.upstream(ctx2).await;
            })
            .await
            .unwrap();

            info!("stage2 work end");
        }
        .instrument(stage2_span)
        .await;
    }

    async fn upstream(&self, ctx: Arc<RequestCtx>) {
        // This stage might be called on an arbitrary worker thread later.
        // Make the request span current again, then create a child span under it.
        async move {
            let upstream_span = info_span!("upstream");
            async move {
                info!("connecting to upstream");
                sleep(Duration::from_millis(40)).await;
                info!("upstream response received");
            }
            .instrument(upstream_span)
            .await;
        }
        .instrument(ctx.request_span.clone())
        .await;

        // Demonstration of the common pitfall:
        // Attaching OTEL context does not make tracing's current span be the request span.
        // (Also, you cannot hold the attach guard across `.await` in a Send future.)
        {
            let _otel_guard = ctx.otel_context.clone().attach();
            let span = info_span!("otel_attach_only_not_parented_in_tracing");
            let _e = span.enter();
            info!("this span is NOT a child of request in tracing unless you also instrument/parent with tracing::Span");
