        .with_target(false)
        .with_thread_names(true)
        .with_thread_ids(true)
        .with_span_events(tracing_subscriber::fmt::format::FmtSpan::NEW
            | tracing_subscriber::fmt::format::FmtSpan::CLOSE)
        .compact();

    tracing_subscriber::registry()
        .with(filter)
        .with(fmt)
        .with(otel_layer().with_tracer(tracer))
        .init();
}

#[tokio::main(flavor = "multi_thread", worker_threads = 4)]
async fn main() {
    init_tracing_and_otel();

    let handler = Arc::new(Handler);

    // Simulate a request starting (root span created once).
    let request_span = info_span!("request", request_id = 1u64);

    let ctx = Arc::new(RequestCtx {
        otel_context: request_span.context(),
        request_span,
    });

    // Simulate Pingora/tokio calling stages at arbitrary times/tasks/threads.
    let h1 = {
        let h = handler.clone();
        let ctx = ctx.clone();
        tokio::spawn(async move {
            sleep(Duration::from_millis(10)).await;
