const PIXELS_PER_LINE: usize = PIXELS_PER_SIDE;
const BYTES_PER_PIXEL: usize = 4;

/// Flip a single line of 4-byte pixels in-place.
///
/// Fast path: reinterpret as `&mut [u32]` (when aligned) and `reverse()`.
/// Fallback: swap 4 bytes at a time using `swap_nonoverlapping`.
pub fn flip_line(line_bytes: &mut [u8]) {
    assert_eq!(line_bytes.len(), PIXELS_PER_LINE * BYTES_PER_PIXEL);
    assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0);

