    let mut left = 0usize;
    let mut right = (pixels - 1) * BYTES_PER_PIXEL;

    while left < right {
        unsafe {
            ptr::swap_nonoverlapping(
                line_bytes.as_mut_ptr().add(left),
                line_bytes.as_mut_ptr().add(right),
                BYTES_PER_PIXEL,
