            material: materials.add(Color::srgb(0.2, 0.45, 0.9)),
            ..default()
        })
        .insert(RotatingCube);
}

fn rotate_cube(time: Res<Time>, mut q: Query<&mut Transform, With<RotatingCube>>) {
    let mut t = q.single_mut();
    let a = time.delta_seconds();
    t.rotate_y(0.8 * a);
    t.rotate_x(0.55 * a);
}

fn draw_face_gizmo(
    mut gizmos: Gizmos,
    windows: Query<&Window, With<bevy::window::PrimaryWindow>>,
    camera_q: Query<(&Camera, &GlobalTransform), With<Camera3d>>,
    cube_q: Query<&GlobalTransform, With<RotatingCube>>,
) {
    let window = windows.single();
    let Some(cursor_pos) = window.cursor_position() else {
        return;
    };

    let (camera, camera_xf) = camera_q.single();
    let Some(ray) = camera.viewport_to_world(camera_xf, cursor_pos) else {
        return;
    };

    let cube_global = cube_q.single();
    let cube_xf = cube_global.compute_transform();

    let origin = ray.origin;
    let dir = ray.direction.as_vec3();

    let Some((hit_point_world, hit_normal_world)) = ray_hit_unit_cube_obb(origin, dir, &cube_xf) else {
        return;
    };

    // Face center (unit cube => half-extent is 0.5)
    let normal = hit_normal_world.normalize();
    let face_center = cube_xf.translation + normal * 0.5;

    // Build a rotation that:
    // - points the gizmo's +Z along the hit normal
    // - aligns the gizmo's X/Y with the cube's own local axes projected onto the face plane
    let rot = face_aligned_rotation(&cube_xf, normal);

    // Draw a 1x1 rect slightly above the face to avoid z-fighting
    let rect_xf = Transform::from_translation(face_center + normal * 0.01)
        .with_rotation(rot)
        .to_isometry();

    gizmos.rect(rect_xf, Vec2::splat(1.0), Color::WHITE);

    // Also draw the ray hit point and normal for clarity
    gizmos.sphere(hit_point_world, 0.03, Color::srgb(1.0, 0.2, 0.2));
    gizmos.line(hit_point_world, hit_point_world + normal * 0.35, Color::srgb(0.2, 1.0, 0.2));
}

fn face_aligned_rotation(cube_xf: &Transform, normal_world: Vec3) -> Quat {
    let n = normal_world.normalize();

    // Candidate tangents from the cube's local axes in world space.
    let mut t = cube_xf.rotation * Vec3::X;
    t = t - n * t.dot(n);
    if t.length_squared() < 1e-6 {
        t = cube_xf.rotation * Vec3::Y;
        t = t - n * t.dot(n);
    }
    let t = t.normalize();

    let b = n.cross(t).normalize();

    // Local gizmo axes: X=tangent, Y=bitangent, Z=normal
    Quat::from_mat3(&Mat3::from_cols(t, b, n))
}

/// Ray vs oriented unit cube (centered at cube_xf.translation, rotated by cube_xf.rotation).
/// The cube is the unit box in its local space: [-0.5, 0.5]^3.
/// Returns (hit_point_world, hit_normal_world).
fn ray_hit_unit_cube_obb(origin_world: Vec3, dir_world: Vec3, cube_xf: &Transform) -> Option<(Vec3, Vec3)> {
    // Transform the ray into the cube's local space.
    let inv_rot = cube_xf.rotation.conjugate();
    let origin_local = inv_rot * (origin_world - cube_xf.translation);
    let dir_local = (inv_rot * dir_world).normalize();

    let min = Vec3::splat(-0.5);
    let max = Vec3::splat(0.5);

    let mut tmin = f32::NEG_INFINITY;
    let mut tmax = f32::INFINITY;
    let mut hit_normal_local = Vec3::ZERO;

    // Slab intersection on X/Y/Z.
    for (axis, o, d, mn, mx) in [
        (Vec3::X, origin_local.x, dir_local.x, min.x, max.x),
        (Vec3::Y, origin_local.y, dir_local.y, min.y, max.y),
        (Vec3::Z, origin_local.z, dir_local.z, min.z, max.z),
    ] {
        if d.abs() < 1e-8 {
            // Ray parallel to slab: must be inside.
            if o < mn || o > mx {
                return None;
            }
            continue;
        }

        let t1 = (mn - o) / d;
        let t2 = (mx - o) / d;

        // Near/far and the corresponding entering normal.
        let (t_near, t_far, n_near) = if t1 < t2 {
            (t1, t2, -axis) // entering through min plane
        } else {
            (t2, t1, axis) // entering through max plane
        };

        if t_near > tmin {
            tmin = t_near;
            hit_normal_local = n_near;
        }
        tmax = tmax.min(t_far);

        if tmin > tmax {
            return None;
        }
    }

    // If the cube is in front of the ray origin.
    if tmax < 0.0 {
        return None;
    }

