// --------------------
// A very small "zip-like" pack format + lazy reader
// --------------------
// File layout:
// u32 entry_count
// repeated entry_count times:
//   u32 name_len
//   [u8; name_len] name (utf8)
//   u64 offset
//   u64 len
// then concatenated file data at those offsets

#[derive(Debug, Clone)]
struct PackIndex {
    entries: HashMap<String, (u64, u64)>,
}

#[derive(Clone)]
struct PackAssetReader {
    asset_root: PathBuf,
    // Cache indexes per pack file so we only read the index once.
    index_cache: Arc<Mutex<HashMap<PathBuf, PackIndex>>>,
}

impl PackAssetReader {
    fn new(asset_root: PathBuf) -> Self {
        Self {
            asset_root,
            index_cache: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    fn split_pack_path<'a>(&self, path: &'a Path) -> Result<(PathBuf, String), AssetReaderError> {
        let mut it = path.iter();
        let pack_name = it
            .next()
            .ok_or_else(|| AssetReaderError::NotFound(path.to_owned()))?;
        let entry_rel = PathBuf::from_iter(it);

        if entry_rel.as_os_str().is_empty() {
            return Err(AssetReaderError::NotFound(path.to_owned()));
        }

        let pack_path = self.asset_root.join(pack_name);
        // Normalize separators so the index uses forward slashes.
        let entry_name = entry_rel.to_string_lossy().replace('\\', "/");
        Ok((pack_path, entry_name))
    }

    fn read_index_from_file(pack_path: &Path) -> Result<PackIndex, AssetReaderError> {
        let mut file = fs::File::open(pack_path)
            .map_err(|e| if e.kind() == std::io::ErrorKind::NotFound {
                AssetReaderError::NotFound(pack_path.to_owned())
            } else {
                AssetReaderError::Io(e)
            })?;

        let mut read_u32 = |f: &mut fs::File| -> std::io::Result<u32> {
            let mut b = [0u8; 4];
            f.read_exact(&mut b)?;
            Ok(u32::from_le_bytes(b))
        };
        let mut read_u64 = |f: &mut fs::File| -> std::io::Result<u64> {
            let mut b = [0u8; 8];
            f.read_exact(&mut b)?;
            Ok(u64::from_le_bytes(b))
        };

        let count = read_u32(&mut file).map_err(AssetReaderError::Io)? as usize;
        let mut entries = HashMap::with_capacity(count);

        for _ in 0..count {
            let name_len = read_u32(&mut file).map_err(AssetReaderError::Io)? as usize;
            let mut name_bytes = vec![0u8; name_len];
            file.read_exact(&mut name_bytes)
                .map_err(AssetReaderError::Io)?;
            let name = String::from_utf8(name_bytes)
                .map_err(|e| AssetReaderError::Io(std::io::Error::new(std::io::ErrorKind::InvalidData, e)))?;

            let offset = read_u64(&mut file).map_err(AssetReaderError::Io)?;
            let len = read_u64(&mut file).map_err(AssetReaderError::Io)?;
            entries.insert(name, (offset, len));
        }

        Ok(PackIndex { entries })
    }

    fn get_or_load_index(&self, pack_path: &Path) -> Result<PackIndex, AssetReaderError> {
        if let Some(idx) = self.index_cache.lock().get(pack_path).cloned() {
            return Ok(idx);
        }

        eprintln!("[pack reader] reading index: {}", pack_path.display());
        let idx = Self::read_index_from_file(pack_path)?;
        self.index_cache
            .lock()
            .insert(pack_path.to_owned(), idx.clone());
        Ok(idx)
    }
}

impl AssetReader for PackAssetReader {
    fn read<'a>(&'a self, path: &'a Path) -> BoxedFuture<'a, Result<Box<dyn Reader>, AssetReaderError>> {
        Box::pin(async move {
            let (pack_path, entry_name) = self.split_pack_path(path)?;
            let idx = self.get_or_load_index(&pack_path)?;

            let (offset, len) = idx
                .entries
                .get(&entry_name)
                .copied()
                .ok_or_else(|| AssetReaderError::NotFound(path.to_owned()))?;

            eprintln!(
                "[pack reader] reading entry '{}' ({} bytes) from {}",
                entry_name,
                len,
                pack_path.display()
            );

            let mut file = fs::File::open(&pack_path).map_err(AssetReaderError::Io)?;
            file.seek(SeekFrom::Start(offset))
                .map_err(AssetReaderError::Io)?;

            let mut buf = vec![0u8; len as usize];
            file.read_exact(&mut buf).map_err(AssetReaderError::Io)?;

            Ok(Box::new(Cursor::new(buf)) as Box<dyn Reader>)
        })
    }

    fn read_meta<'a>(&'a self, path: &'a Path) -> BoxedFuture<'a, Result<Box<dyn Reader>, AssetReaderError>> {
        // We disable meta checks in AssetPlugin (AssetMetaCheck::Never),
        // so this shouldn't be called.
        Box::pin(async move { Err(AssetReaderError::NotFound(path.to_owned())) })
    }

    fn read_directory<'a>(&'a self, _path: &'a Path) -> BoxedFuture<'a, Result<PathStream, AssetReaderError>> {
        Box::pin(async move {
            // Not needed for this demo.
            Ok(Box::pin(futures_lite::stream::empty()))
        })
    }

    fn is_directory<'a>(&'a self, _path: &'a Path) -> BoxedFuture<'a, Result<bool, AssetReaderError>> {
        Box::pin(async move { Ok(false) })
    }

    fn path_exists<'a>(&'a self, path: &'a Path) -> BoxedFuture<'a, Result<bool, AssetReaderError>> {
        Box::pin(async move {
            let Ok((pack_path, entry_name)) = self.split_pack_path(path) else {
                return Ok(false);
            };
            if !pack_path.exists() {
                return Ok(false);
            }
            let idx = self.get_or_load_index(&pack_path)?;
            Ok(idx.entries.contains_key(&entry_name))
        })
    }
}

// --------------------
// App
// --------------------

#[derive(Resource)]
struct DemoHandles {
    hello: Handle<PackedText>,
    numbers: Handle<PackedText>,
}

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
    // NOTE: "pack://" is a *custom asset source* registered below.
    // The first path segment is the pack file name, the rest is the entry name.
    let hello: Handle<PackedText> = asset_server.load("pack://demo.pack/hello.txt");
    let numbers: Handle<PackedText> = asset_server.load("pack://demo.pack/numbers.txt");
    commands.insert_resource(DemoHandles { hello, numbers });
}

fn print_when_ready(
    handles: Res<DemoHandles>,
    assets: Res<Assets<PackedText>>,
    mut exit: EventWriter<AppExit>,
) {
    let Some(h) = assets.get(&handles.hello) else {
        return;
    };
    let Some(n) = assets.get(&handles.numbers) else {
        return;
    };

    println!("hello.txt => {}", h.0);
    println!("numbers.txt => {}", n.0);

    exit.send(AppExit);
}

fn ensure_demo_assets_exist() -> PathBuf {
    // This is effectively the same root Bevy uses by default for the filesystem source.
    // You can also set it explicitly via AssetPlugin { file_path: "assets".into(), .. }.
    let asset_root = std::env::current_dir().unwrap().join("assets");
    let _ = fs::create_dir_all(&asset_root);

    let pack_path = asset_root.join("demo.pack");
    if !pack_path.exists() {
        write_demo_pack(&pack_path).expect("failed to write demo.pack");
    }

    asset_root
}

fn write_demo_pack(path: &Path) -> std::io::Result<()> {
    let entries: Vec<(&str, &[u8])> = vec![
        ("hello.txt", b"Hello from inside a pack file!"),
        ("numbers.txt", b"1 2 3 4 5"),
    ];

    // Compute index size first.
    // total = u32 count + sum(u32 name_len + name + u64 offset + u64 len)
    let mut index_len: usize = 4;
    for (name, data) in &entries {
        index_len += 4 + name.as_bytes().len() + 8 + 8;
        let _ = data;
    }

    // Build the whole file.
    let mut out = Vec::<u8>::new();
    out.extend_from_slice(&(entries.len() as u32).to_le_bytes());

    // Write index with correct offsets.
    let mut offset = index_len as u64;
    for (name, data) in &entries {
        let name_bytes = name.as_bytes();
        out.extend_from_slice(&(name_bytes.len() as u32).to_le_bytes());
        out.extend_from_slice(name_bytes);
        out.extend_from_slice(&offset.to_le_bytes());
        out.extend_from_slice(&(data.len() as u64).to_le_bytes());
        offset += data.len() as u64;
    }

    // Write data blob.
    for (_name, data) in &entries {
        out.extend_from_slice(data);
    }

    let mut f = fs::File::create(path)?;
    f.write_all(&out)?;
    Ok(())
}

fn main() {
    let asset_root = ensure_demo_assets_exist();

    App::new()
        // No window, but still use DefaultPlugins for simplicity.
        .add_plugins(
            DefaultPlugins
                .set(WindowPlugin {
                    primary_window: None,
                    ..default()
                })
                .set(AssetPlugin {
                    file_path: "assets".to_string(),
                    watch_for_changes: false,
                    meta_check: AssetMetaCheck::Never,
                    ..default()
                }),
        )
        // Register our asset type + loader
        .init_asset::<PackedText>()
        .init_asset_loader::<PackedTextLoader>()
        // Register a custom asset source called "pack".
        // Asset paths like "pack://demo.pack/hello.txt" will be routed here.
        .register_asset_source(
            "pack",
            AssetSource::build().with_reader(move || Box::new(PackAssetReader::new(asset_root.clone()))),
        )
        .add_systems(Startup, setup)
        .add_systems(Update, print_when_ready)
        .run();
}
"
}
