    let frame_stream = byte_stream.map(|res| res.map(Frame::data));

    // Convert Stream of frames -> HTTP body.
    let body = StreamBody::new(frame_stream).boxed();

    let mut resp = Response::new(body);
    *resp.status_mut() = StatusCode::OK;
