  "main.rs": "//! Single-file demo crate that is *both*:
//! - a `proc-macro` library (when compiled as the lib target), and
//! - a normal binary (when compiled as the bin target).
//!
//! The important part: doc comments cannot interpolate `#typ` inside `/// ...` text.
//! Instead, generate a `#[doc = "..."]` attribute with a string you build at macro-expansion time.

// -------------------------
// Proc-macro implementation
// -------------------------

#[cfg(proc_macro)]
extern crate proc_macro;

#[cfg(proc_macro)]
use proc_macro::TokenStream;
#[cfg(proc_macro)]
use proc_macro2::Span;
#[cfg(proc_macro)]
use quote::{quote, ToTokens};
#[cfg(proc_macro)]
use syn::parse::{Parse, ParseStream};
#[cfg(proc_macro)]
use syn::token::Comma;
#[cfg(proc_macro)]
use syn::{parse_macro_input, Data, DeriveInput, Ident, Type};

#[cfg(proc_macro)]
const DEFAULT_DISCRIMINANT_METHOD_NAME: &str = "discriminant";

/// Attribute macro to implement a discriminant method for enums with a specific representation type.
///
/// Usage:
///
/// ```
/// #[repr_discriminant(u8, id)]
/// enum Foo { A = 0 }
/// ```
#[cfg(proc_macro)]
#[proc_macro_attribute]
pub fn repr_discriminant(args: TokenStream, input: TokenStream) -> TokenStream {
    let args: Args = parse_macro_input!(args as Args);
    let typ: Type = args.typ;

    // Build a string version of the type for use in doc attributes.
    // Note: `to_string()` may include spaces (e.g. ":: core :: ..."); that's fine for docs.
    let typ_doc: String = typ.to_token_stream().to_string();
    let safety_doc = format!(
        "This method is safe, because the macro guarantees that the enum is repr({}).",
        typ_doc
    );

    let method_name = args
        .method_name
        .unwrap_or_else(|| Ident::new(DEFAULT_DISCRIMINANT_METHOD_NAME, Span::call_site()));

    let input_ast: DeriveInput = parse_macro_input!(input as DeriveInput);
    let generics = &input_ast.generics;
    let (impl_generics, ty_generics, where_clause) = generics.split_for_impl();
    let name = &input_ast.ident;

    if !matches!(input_ast.data, Data::Enum(_)) {
        return syn::Error::new_spanned(
            &input_ast.ident,
            "repr_discriminant can only be used on enums",
        )
        .to_compile_error()
        .into();
    }

    let body = quote! {
        /// Returns the discriminant value of the enum.
        ///
        /// # Safety
        ///
        #[doc = #safety_doc]
        pub const fn #method_name(&self) -> #typ {
            #[allow(unsafe_code)]
            unsafe {
                *::core::ptr::from_ref(self)
                    .cast::<#typ>()
            }
        }
    };

    TokenStream::from(quote! {
        #[repr(#typ)]
        #input_ast

        impl #impl_generics #name #ty_generics #where_clause {
            #body
        }
    })
}

/// Arguments for the `repr_discriminant` macro.
#[cfg(proc_macro)]
struct Args {
    typ: Type,
    method_name: Option<Ident>,
}

#[cfg(proc_macro)]
impl Parse for Args {
    fn parse(input: ParseStream<'_>) -> syn::Result<Self> {
        let typ: Type = input.parse()?;

        if input.is_empty() {
            return Ok(Self {
                typ,
                method_name: None,
            });
        }

        let _: Comma = input.parse()?;
        let method_name: Ident = input.parse()?;

        if !input.is_empty() {
            return Err(input.error("Unexpected tokens after method name"));
        }

        Ok(Self {
            typ,
            method_name: Some(method_name),
        })
    }
}

// -------------------------
// Binary demo
// -------------------------

#[cfg(not(proc_macro))]
use repr_discriminant::repr_discriminant;

#[cfg(not(proc_macro))]
#[repr_discriminant(u8, id)]
enum Foo {
    Bar(String) = 0x02,
}

#[cfg(not(proc_macro))]
fn main() {
    let foo = Foo::Bar("Hello, world!".into());
    println!("{}", foo.id());

    // To verify the doc output, run:
    //   cargo rustc --bin demo -- -Zunpretty=expanded
    // (requires nightly)
}
"
}
