  "main.rs": "use std::io::{self, Read};

/// Tokenize like a very small subset of a POSIX shell:
/// - splits on ASCII whitespace when *not* inside single quotes
/// - single quotes (') start/end a quoted region
/// - quoted and unquoted parts concatenate into the same token
/// - an empty quoted string ('') produces an empty token
///
/// This intentionally does **not** implement: backslash escapes, double quotes,
/// $-expansions, command substitutions, etc.
fn tokenize(input: &str) -> Result<Vec<String>, String> {
    let mut tokens: Vec<String> = Vec::new();
    let mut cur = String::new();

    let mut in_single_quote = false;
    // Tracks whether we're currently building a token, even if it's empty (e.g. "''").
    let mut in_token = false;

    for ch in input.chars() {
        if in_single_quote {
            match ch {
                '\'' => in_single_quote = false,
                _ => cur.push(ch),
            }
            continue;
        }

        // Not in quotes
        match ch {
            '\'' => {
                in_single_quote = true;
                in_token = true; // "''" is a token even though it contributes no chars
            }
            c if c.is_ascii_whitespace() => {
                if in_token {
                    tokens.push(std::mem::take(&mut cur));
                    in_token = false;
                }
            }
            _ => {
                in_token = true;
                cur.push(ch);
            }
        }
    }

    if in_single_quote {
        return Err("unterminated single quote".to_string());
    }

    if in_token {
        tokens.push(cur);
    }

    Ok(tokens)
}

fn main() {
    // Read stdin; if empty, use the example.
    let mut buf = String::new();
    io::stdin().read_to_string(&mut buf).unwrap();
    let line = {
        let trimmed = buf.trim_end_matches(['\n', '\r']);
        if trimmed.is_empty() {
            " one  ' two  'three    four"
        } else {
            trimmed
        }
    };

    match tokenize(line) {
        Ok(args) => {
            println!("{} args:", args.len());
            for a in args {
                println!("<{}>", a);
            }
        }
        Err(e) => {
            eprintln!("error: {e}");
            std::process::exit(2);
        }
    }
}
"
