            self.host, self.port, self.admin_user, self.admin_password
        )
    }

    fn conn_str_for_db(&self, dbname: &str) -> String {
        format!(
            "host={} port={} user={} password={} dbname={}",
            self.host, self.port, self.admin_user, self.admin_password, dbname
        )
    }
}

struct CachedClient {
    client: Client,
    // Keeping this handle lets us detect if the connection task ended (fatal IO error, etc.).
    task: JoinHandle<()>,
}

/// Admin client cache that can *reconnect* if the cached connection was closed.
///
/// Key point: a cached `Client` can become unusable if its background `Connection` task ends
/// (fatal error / server closes connection / network hiccup). If you cache forever (OnceCell),
/// you can't recover.
struct PgAdmin {
    cfg: DbConfig,
    admin_cache: Mutex<Option<CachedClient>>,
}

impl PgAdmin {
    fn new(cfg: DbConfig) -> Self {
        Self {
            cfg,
            admin_cache: Mutex::new(None),
        }
    }

    async fn admin_client(&self) -> Result<Client, Error> {
        let mut guard = self.admin_cache.lock().await;

        let need_new = match guard.as_ref() {
            None => true,
            Some(c) => c.client.is_closed() || c.task.is_finished(),
        };

        if need_new {
            let conn_str = self.cfg.admin_conn_str();
            let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;

            let task = tokio::spawn(async move {
                if let Err(e) = conn.await {
                    eprintln!("admin connection task ended with error: {e}");
                }
            });

            *guard = Some(CachedClient { client, task });
        }

        // `Client` is a cheap, clonable handle.
        Ok(guard.as_ref().unwrap().client.clone())
    }

    async fn connect_db(&self, name: &str) -> Result<(Client, JoinHandle<()>), Error> {
        let conn_str = self.cfg.conn_str_for_db(name);
        let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;
        let task = tokio::spawn(async move {
            if let Err(e) = conn.await {
                eprintln!("db connection task ended with error: {e}");
            }
        });
        Ok((client, task))
    }

    async fn create_database(&self, name: &str) -> Result<(), Error> {
        let admin = self.admin_client().await?;
        admin
            .execute(&format!("CREATE DATABASE {name}"), &[])
            .await?;

        // Connect to the new db to load schema, then drop that connection.
        let (client, task) = self.connect_db(name).await?;
        client.batch_execute(load_schema()).await?;
        drop(client);
        let _ = task.await;

        Ok(())
    }

    async fn drop_database(&self, name: &str) -> Result<u64, Error> {
        let admin = self.admin_client().await?;

        // Terminate any other connections to the target DB.
        let terminate_sql = format!(
            "
            SELECT pg_terminate_backend(pid)
            FROM pg_stat_activity
            WHERE datname = '{name}' AND pid <> pg_backend_pid();
            "
        );
        admin.execute(&terminate_sql, &[]).await?;

        // DROP DATABASE can race with termination; retry on "object in use".
        const RETRIES: usize = 20;
        for i in 0..RETRIES {
            match admin
                .execute(&format!("DROP DATABASE {name}"), &[])
                .await
            {
                Ok(n) => return Ok(n),
                Err(e) => {
                    // 55006 = object_in_use
                    let in_use = e
                        .code()
                        .map(|c| c.code() == "55006")
                        .unwrap_or(false);
                    if in_use && i + 1 < RETRIES {
                        tokio::time::sleep(Duration::from_millis(50)).await;
                        continue;
                    }
                    return Err(e);
                }
            }
        }

        unreachable!()
    }
