}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let cfg = DbConfig::from_env();
    let admin = PgAdmin::new(cfg);

    let db_name = format!("test_{}", Uuid::new_v4().simple());
    println!("creating db: {db_name}");
