fn resolve_ref_string(ref_str: &str, base_dir: &Path) -> Result<Value, Box<dyn Error>> {
    let (file_part, pointer_part) = match ref_str.split_once('#') {
        Some((f, p)) => (f, p),
        None => (ref_str, ""),
    };

    let target_path = base_dir.join(file_part);
    let json_data = fs::read_to_string(&target_path)?;
    let mut doc: Value = serde_json::from_str(&json_data)?;

    if !pointer_part.is_empty() {
        doc = doc
            .pointer(pointer_part)
            .ok_or_else(|| format!("JSON pointer not found: #{pointer_part}"))?
            .clone();
    }

    let new_base_dir = target_path.parent().unwrap_or(base_dir);
    resolve_refs(doc, new_base_dir)
}

fn resolve_refs(value: Value, base_dir: &Path) -> Result<Value, Box<dyn Error>> {
    match value {
        Value::Object(mut map) => {
            // Treat {"$ref": "..."} as a reference object.
            if map.len() == 1 && map.contains_key("$ref") {
                match map.remove("$ref").unwrap() {
                    Value::String(s) => return resolve_ref_string(&s, base_dir),
                    other => {
                        return Err(format!("$ref must be a string, got: {other}").into());
                    }
                }
            }

            let mut out = serde_json::Map::with_capacity(map.len());
            for (k, v) in map {
                out.insert(k, resolve_refs(v, base_dir)?);
            }
            Ok(Value::Object(out))
        }
        Value::Array(arr) => {
            let mut out = Vec::with_capacity(arr.len());
            for v in arr {
                out.push(resolve_refs(v, base_dir)?);
            }
            Ok(Value::Array(out))
        }
        other => Ok(other),
