/// For example, `use vexide::{devices::smart::*, prelude::*};` has a parent prefix
/// `vexide` and a child local path `devices::smart`.
fn rewrite_use_tree(tree: &ast::UseTree, prefix: &mut Vec<String>, edits: &mut Vec<Edit>) {
    // Determine the local path segments for this node.
    let local_path = tree.path();
    let local_segments = local_path
        .as_ref()
        .map(|p| split_path_segments(&p.syntax().text().to_string()))
        .unwrap_or_default();

    let mut new_local_segments = local_segments.clone();
    let mut remove_local_path_entirely = false;

    // Rule A (nested case): parent prefix ends with `vexide`, and local path starts with `devices`.
    // Example: `use vexide::{devices::smart::*};` => local path `devices::smart` becomes `smart`.
    if prefix.last().map(|s| s.as_str()) == Some("vexide")
        && new_local_segments.first().map(|s| s.as_str()) == Some("devices")
    {
        // Only rewrite if there's something after `devices` OR if this node has a subtree (`::*` or `::{...}`).
        let has_subtree = tree.star_token().is_some() || tree.use_tree_list().is_some();
        if new_local_segments.len() >= 2 || has_subtree {
            new_local_segments.remove(0);

            // If it becomes empty (was just `devices`), we can only drop it if it had a subtree.
            if new_local_segments.is_empty() {
                if has_subtree {
                    remove_local_path_entirely = true;
                } else {
