    let mut child_prefix = prefix.clone();
    if local_path.is_some() {
        if remove_local_path_entirely {
            // path is removed, prefix stays as-is
        } else {
            child_prefix.extend(new_local_segments.iter().cloned());
        }
    }

    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
