use std::cell::{Cell, RefCell};
use std::collections::BTreeSet;
use std::mem::ManuallyDrop;
use std::sync::{Mutex, MutexGuard};
use std::thread;

// --- A std-only Critical Section implementation so this example can run with `cargo run`.
//
// On embedded (e.g. RP2040), your HAL typically provides an implementation that disables
// interrupts and/or uses a HW spinlock across cores, plus the needed fences.
static CS_MUTEX: Mutex<()> = Mutex::new(());

thread_local! {
    static CS_DEPTH: Cell<u32> = const { Cell::new(0) };
    static CS_GUARD: RefCell<Option<ManuallyDrop<MutexGuard<'static, ()>>>> = const { RefCell::new(None) };
}

struct StdCriticalSection;

unsafe impl critical_section::Impl for StdCriticalSection {
    unsafe fn acquire() -> RawRestoreState {
        CS_DEPTH.with(|depth| {
            let d = depth.get();
            if d == 0 {
                // Lock for the duration of the outermost critical section.
                let guard = CS_MUTEX.lock().unwrap();
                CS_GUARD.with(|slot| {
                    *slot.borrow_mut() = Some(ManuallyDrop::new(guard));
                });
            }
            depth.set(d + 1);
        });
        0
    }

    unsafe fn release(_state: RawRestoreState) {
        CS_DEPTH.with(|depth| {
            let d = depth.get();
            debug_assert!(d > 0);
            let new_d = d - 1;
            depth.set(new_d);
            if new_d == 0 {
                // Drop the guard to unlock.
                CS_GUARD.with(|slot| {
                    let guard = slot.borrow_mut().take().expect("missing guard");
                    drop(ManuallyDrop::into_inner(guard));
                });
            }
        });
    }
}

set_impl!(StdCriticalSection);

// --- The pattern you're asking about.
//
// This mimics atomic_polyfill::AtomicUsize::fetch_add(1, Relaxed) using a critical section.
// The important point: the *ordering* of the original operation was Relaxed, so the correct
// translation keeps it Relaxed; the critical section provides mutual exclusion (atomicity of
// the read-modify-write) but does not need stronger atomic orderings for equivalence.
struct ChannelIndex {
    idx: std::sync::atomic::AtomicUsize,
}

impl ChannelIndex {
    fn new(v: usize) -> Self {
        Self {
            idx: std::sync::atomic::AtomicUsize::new(v),
        }
    }

    fn fetch_add_cs_relaxed(&self) -> usize {
        use std::sync::atomic::Ordering;

        critical_section::with(|_| {
            // Using Relaxed here matches the semantics of fetch_add(Relaxed):
            // it guarantees atomicity of the counter update, but does not impose
            // ordering on other memory operations.
            let old = self.idx.load(Ordering::Relaxed);
            self.idx.store(old.wrapping_add(1), Ordering::Relaxed);
            old
        })
    }
}

fn main() {
    // Demonstrate that the CS-based fetch_add produces unique indices across threads.
    // (In your embedded case, this corresponds to multiple cores / interrupt contexts,
    // as long as *all* accesses to the counter participate in the same critical section.)

    let counter = std::sync::Arc::new(ChannelIndex::new(0));
    let results = std::sync::Arc::new(Mutex::new(Vec::new()));

    let threads = 4;
    let iters_per_thread = 20_000;

    let mut handles = Vec::new();
    for _ in 0..threads {
        let c = counter.clone();
        let r = results.clone();
        handles.push(thread::spawn(move || {
            let mut local = Vec::with_capacity(iters_per_thread);
            for _ in 0..iters_per_thread {
                local.push(c.fetch_add_cs_relaxed());
            }
            r.lock().unwrap().extend(local);
        }));
    }

    for h in handles {
        h.join().unwrap();
    }

    let mut v = results.lock().unwrap().clone();
    v.sort_unstable();

    let total = threads * iters_per_thread;
    assert_eq!(v.len(), total);
    assert_eq!(v[0], 0);
    assert_eq!(v[total - 1], total - 1);

    // Uniqueness check
    let set: BTreeSet<_> = v.into_iter().collect();
    assert_eq!(set.len(), total);

    println!(
        "OK: got {} unique indices (0..{}), using critical_section + Relaxed load/store",
        total,
        total - 1
    );

    // Notes (re: the question):
    // - If the original code used fetch_add(Relaxed), then Relaxed is the correct ordering
    //   to use for the translated load/store. Stronger orderings (Acquire/Release/SeqCst)
    //   would change semantics (add unnecessary ordering constraints) and generally isn't
    //   what you want for a plain counter.
    // - The real correctness requirement is: every access that participates in the RMW
    //   must be under the same critical section (or otherwise synchronized). If some other
    //   code does an atomic fetch_add concurrently *without* the critical section, then this
    //   load+store can lose increments.
}
"
}
