                None,
            )
        }
    }

    #[derive(Copy, Clone, Debug)]
    pub struct MessageArgs<'a> {
        pub content: Option<WIPOffset<&'a str>>,
        pub ignored_parsers: Option<WIPOffset<Vector<'a, ForwardsUOffset<&'a str>>>>,
    }

    impl<'a> Default for MessageArgs<'a> {
        fn default() -> Self {
            Self {
                content: None,
                ignored_parsers: None,
            }
        }
    }

    pub struct MessageBuilder<'a: 'b, 'b> {
        fbb: &'b mut FlatBufferBuilder<'a>,
        start: WIPOffset<flatbuffers::TableUnfinishedWIPOffset>,
    }

    impl<'a: 'b, 'b> MessageBuilder<'a, 'b> {
        #[inline]
        pub fn new(fbb: &'b mut FlatBufferBuilder<'a>) -> Self {
            let start = fbb.start_table();
            Self { fbb, start }
        }

        #[inline]
        pub fn add_content(&mut self, content: WIPOffset<&'a str>) {
            self.fbb
                .push_slot_always::<WIPOffset<_>>(Message::VT_CONTENT, content);
        }

        #[inline]
        pub fn add_ignored_parsers(
            &mut self,
            ignored: WIPOffset<Vector<'a, ForwardsUOffset<&'a str>>>,
        ) {
            self.fbb.push_slot_always::<WIPOffset<_>>(
                Message::VT_IGNORED_PARSERS,
                ignored,
