    pub fn create_message<'a: 'b, 'b>(
        fbb: &'b mut FlatBufferBuilder<'a>,
        args: &MessageArgs<'a>,
    ) -> WIPOffset<Message<'a>> {
        let mut b = MessageBuilder::new(fbb);
        if let Some(c) = args.content {
            b.add_content(c);
        }
