fn serialize_to_flatbuffer(input: &Input) -> Vec<u8> {
    // Important: FlatBufferBuilder is NOT designed to be mutated from multiple threads.
    // Even if you put it behind Arc<Mutex<_>>, you'd serialize everything anyway,
    // and the offset-based nature means you can't trivially "merge" parallel sub-builders.
    //
    // What you *can* do: compute/transform data in parallel, then build the flatbuffer
    // sequentially.

    // Parallel preprocessing (pure CPU work, no FlatBufferBuilder involved):
    let normalized_ignored: Vec<String> = input
        .ignored_parsers
        .par_iter()
        .map(|s| s.trim().to_ascii_lowercase())
        .collect();

    // Now build the flatbuffer single-threaded:
    let mut builder = FlatBufferBuilder::new();

    let content_off = builder.create_string(&input.content);

    // NOTE: This must be sequential because create_string needs &mut builder.
    // Attempting to do this with par_iter/map will fail (and would be unsound anyway).
    let ignored_str_offsets: Vec<WIPOffset<&str>> = normalized_ignored
        .iter()
        .map(|s| builder.create_string(s.as_str()))
        .collect();

    let ignored_vec_off = builder.create_vector(&ignored_str_offsets);

    let msg_off = message_fb::create_message(
        &mut builder,
        &message_fb::MessageArgs {
            content: Some(content_off),
            ignored_parsers: Some(ignored_vec_off),
        },
    );

    builder.finish(msg_off, None);
    builder.finished_data().to_vec()
}

fn main() {
