use std::fmt::Debug;
use std::marker::PhantomData;
use std::ops::{Index, IndexMut};
use std::ptr::NonNull;

// -------------------------
// Array + indexing utilities
// -------------------------

#[derive(Debug, Clone)]
pub struct Array<T> {
    store: Vec<T>,
    dims: Vec<usize>,
}

impl<T> Array<T> {
    pub fn new(dims: Vec<usize>, store: Vec<T>) -> Self {
        let expected = dims.iter().product::<usize>();
        assert_eq!(expected, store.len(), "store length must match dims product");
        Self { store, dims }
    }

    fn offset(&self, idx: &[usize]) -> usize {
        assert_eq!(idx.len(), self.dims.len(), "index rank must match dims");
        // Row-major offset.
        let mut stride = 1;
        let mut off = 0;
        for (i, &dim) in self.dims.iter().rev().enumerate() {
            let axis = self.dims.len() - 1 - i;
            let v = idx[axis];
            assert!(v < dim, "index out of bounds on axis {axis}");
            off += v * stride;
            stride *= dim;
        }
        off
    }

    pub fn dims(&self) -> &[usize] {
        &self.dims
    }
}

impl<T> Index<&[usize]> for Array<T> {
    type Output = T;
    fn index(&self, idx: &[usize]) -> &Self::Output {
        let off = self.offset(idx);
        &self.store[off]
    }
}

impl<T> IndexMut<&[usize]> for Array<T> {
    fn index_mut(&mut self, idx: &[usize]) -> &mut Self::Output {
        let off = self.offset(idx);
        &mut self.store[off]
    }
}

// ---------------------------------
// Dyn-cloneable index iterators
// ---------------------------------

pub trait ArrayViewIterator: Iterator<Item = usize> + Debug + DynClone {}

impl<T> ArrayViewIterator for T where T: Iterator<Item = usize> + Debug + Clone + 'static {}

dyn_clone::clone_trait_object!(ArrayViewIterator);

fn clone_iter(it: &Box<dyn ArrayViewIterator>) -> Box<dyn ArrayViewIterator> {
    dyn_clone::clone_box(&**it)
}

// ------------------------------------------------------------
// Helper: advance cartesian-product iterators (nested loops)
// ------------------------------------------------------------

fn cartesian_next(
    selection_iters: &[Box<dyn ArrayViewIterator>],
    current_iters: &mut [Box<dyn ArrayViewIterator>],
    current_vals: &mut [Option<usize>],
) -> Option<Vec<usize>> {
    let n = selection_iters.len();
    if n == 0 {
        return None;
    }

    // First call: initialize all dimensions to their first element.
    if current_vals[0].is_none() {
        for d in 0..n {
            current_iters[d] = clone_iter(&selection_iters[d]);
            current_vals[d] = current_iters[d].next();
            if current_vals[d].is_none() {
                return None;
            }
        }
        return Some(current_vals.iter().map(|x| x.unwrap()).collect());
    }

    // Subsequent calls: advance like nested loops (last axis fastest).
    for d in (0..n).rev() {
        if let Some(v) = current_iters[d].next() {
            current_vals[d] = Some(v);
            // Reset following dimensions to their first element.
            for j in (d + 1)..n {
                current_iters[j] = clone_iter(&selection_iters[j]);
                current_vals[j] = current_iters[j].next();
                if current_vals[j].is_none() {
                    return None;
                }
            }
            return Some(current_vals.iter().map(|x| x.unwrap()).collect());
        }
    }

    None
}

// -------------------------
// Immutable iterator (safe)
// -------------------------

#[derive(Debug)]
pub struct ArrayIteratorFromDyn<'a, T> {
    array: &'a Array<T>,
    selection_iterators: Vec<Box<dyn ArrayViewIterator>>,
    current_iterators: Vec<Box<dyn ArrayViewIterator>>,
    current_index_option: Vec<Option<usize>>,
}

impl<'a, T> ArrayIteratorFromDyn<'a, T> {
    pub fn new(array: &'a Array<T>, selection_iterators: Vec<Box<dyn ArrayViewIterator>>) -> Self {
        let current_iterators = selection_iterators.iter().map(clone_iter).collect();
        let current_index_option = vec![None; selection_iterators.len()];
        Self {
            array,
            selection_iterators,
            current_iterators,
            current_index_option,
        }
    }
}

impl<'a, T> Iterator for ArrayIteratorFromDyn<'a, T> {
    type Item = (Vec<usize>, &'a T);

    fn next(&mut self) -> Option<Self::Item> {
        let idx = cartesian_next(
            &self.selection_iterators,
            &mut self.current_iterators,
            &mut self.current_index_option,
        )?;
        let v = &self.array[&idx[..]];
        Some((idx, v))
    }
}

// ----------------------------------------------------------
// Mutable iterator (requires raw pointer + unsafe)
// ----------------------------------------------------------
//
// Why this is necessary:
// - Iterator::next takes `&mut self`.
// - If you try to return `&'a mut T` by doing `&mut self.array[...]`,
//   the borrow of `self.array` is only proven valid for the `&mut self`
//   call (a shorter lifetime), not for `'a`.
//
// slice::IterMut solves this by storing a raw pointer and creating
// disjoint `&mut T` references in `next()` using `unsafe`.

#[derive(Debug)]
pub struct ArrayIteratorFromDynMut<'a, T> {
    ptr: NonNull<T>,
    len: usize,
    dims: Vec<usize>,

    selection_iterators: Vec<Box<dyn ArrayViewIterator>>,
    current_iterators: Vec<Box<dyn ArrayViewIterator>>,
    current_index_option: Vec<Option<usize>>,

    _marker: PhantomData<&'a mut T>,
}

impl<'a, T> ArrayIteratorFromDynMut<'a, T> {
    pub fn new(array: &'a mut Array<T>, selection_iterators: Vec<Box<dyn ArrayViewIterator>>) -> Self {
        let slice = array.store.as_mut_slice();
        let ptr = NonNull::new(slice.as_mut_ptr()).unwrap_or_else(NonNull::dangling);

        let current_iterators = selection_iterators.iter().map(clone_iter).collect();
        let current_index_option = vec![None; selection_iterators.len()];

        Self {
            ptr,
            len: slice.len(),
            dims: array.dims.clone(),
            selection_iterators,
            current_iterators,
            current_index_option,
            _marker: PhantomData,
        }
    }

    fn offset(&self, idx: &[usize]) -> usize {
        assert_eq!(idx.len(), self.dims.len());
        let mut stride = 1;
        let mut off = 0;
        for (i, &dim) in self.dims.iter().rev().enumerate() {
            let axis = self.dims.len() - 1 - i;
            let v = idx[axis];
            assert!(v < dim);
            off += v * stride;
            stride *= dim;
        }
        off
    }
}

impl<'a, T> Iterator for ArrayIteratorFromDynMut<'a, T> {
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        let idx = cartesian_next(
            &self.selection_iterators,
            &mut self.current_iterators,
            &mut self.current_index_option,
        )?;

        let off = self.offset(&idx);
        assert!(off < self.len);

        // SAFETY:
        // - `self` was constructed from `&'a mut Array<T>`, so the underlying
        //   memory is valid for `'a`.
        // - This iterator must not yield the same element more than once.
        //   (If it does, two `&'a mut T` aliases could exist simultaneously.)
        //   The cartesian-product logic over index sets should ensure uniqueness.
        let current_value: &'a mut T = unsafe { &mut *self.ptr.as_ptr().add(off) };
        Some((idx, current_value))
    }
}

fn main() {
    let mut a = Array::new(vec![2, 3], (0..6).collect::<Vec<i32>>());

    // Iterate mutably and modify elements.
    let iters: Vec<Box<dyn ArrayViewIterator>> = vec![Box::new(0..2), Box::new(0..3)];
    for (_idx, v) in ArrayIteratorFromDynMut::new(&mut a, iters) {
        *v += 10;
    }

    // Iterate immutably and print.
    let iters: Vec<Box<dyn ArrayViewIterator>> = vec![Box::new(0..2), Box::new(0..3)];
