# `cargo run --features broken` => shows the desired compile error when the inherent method is missing.
broken = []
# `cargo run --features naive`  => shows the naive impl that compiles but recurses at runtime.
naive = []

[dependencies]
",
  "main.rs": "trait Foo {
    fn go(&self);
}

// ------------------------------
// Example that works
// ------------------------------

struct ConcreteFoo<T>(T);

impl<T> ConcreteFoo<T>
where
    T: ::core::fmt::Display,
{
    // The "concrete" method the derive is supposed to forward to.
    pub fn go(&self) {
        println!("ConcreteFoo::go says: {}", self.0);
    }
}

// What the derive can generate to ensure it calls the inherent method:
// put the forwarding call in a module where `Foo` is NOT in scope.
//
// If `ConcreteFoo::go` does not exist, this becomes a hard compile error.
mod __foo_derive_concretefoo {
    use super::ConcreteFoo;

    #[inline]
    pub fn go<T>(this: &ConcreteFoo<T>)
    where
        T: ::core::fmt::Display,
    {
        // No `use super::Foo;` here, so the trait method is not considered.
        ConcreteFoo::go(this);
    }
}

impl<T> Foo for ConcreteFoo<T>
where
    T: ::core::fmt::Display,
{
    fn go(&self) {
        __foo_derive_concretefoo::go(self)
    }
}

// ------------------------------
// Demonstrations
// ------------------------------

#[cfg(feature = "naive")]
mod naive_demo {
    use super::{Foo, ConcreteFoo};

    // This compiles even if there's no inherent `go`, and then it recurses forever.
    impl<T> Foo for ConcreteFoo<T> {
        fn go(&self) {
            // Calls Foo::go again if no inherent method exists in scope.
            self.go();
        }
    }
}

#[cfg(feature = "broken")]
mod broken_demo {
    use super::Foo;

    struct Broken;

    // NOTE: no inherent `impl Broken { fn go(&self) { ... } }`

    mod __foo_derive_broken {
        use super::Broken;

        pub fn go(this: &Broken) {
            // Because `Foo` is not in scope here, this MUST resolve to an inherent method.
            // Since it doesn't exist, enabling this feature causes a compile error.
            Broken::go(this);
        }
    }

    impl Foo for Broken {
        fn go(&self) {
            __foo_derive_broken::go(self)
        }
    }
}

fn main() {
    let x = ConcreteFoo(123);
    Foo::go(&x);
}
