#[derive(Clone, Copy)]
struct DragState {
    /// Pointer position in *SVG coordinate space* (we keep it the same as the SVG viewBox).
    pointer: Signal<Pt>,
    /// Which point is currently being dragged.
    active_id: Signal<Option<usize>>,
    /// Offset from pointer -> point center, so the point doesn't jump when you grab it.
    offset: Signal<Pt>,
}

impl DragState {
    fn new() -> Self {
        Self {
            pointer: Signal::new(Pt::default()),
            active_id: Signal::new(None),
            offset: Signal::new(Pt::default()),
        }
    }
