#[component]
fn DragSvg(children: Element) -> Element {
    let mut drag = use_context_provider(DragState::new);

    rsx! {
        div {
            class: "frame",
            svg {
                class: "canvas",
                width: "800",
                height: "500",
                view_box: "0 0 800 500",

                // Track the pointer over the whole SVG.
                // `element_coordinates()` are relative to the currentTarget (the svg),
                // which matches our viewBox.
                onpointermove: move |e| {
                    let p = e.element_coordinates();
                    drag.pointer.set(Pt { x: p.x as f64, y: p.y as f64 });
                },

                // End drag if pointer is released over the SVG.
                onpointerup: move |_| {
                    drag.active_id.set(None);
                },

                // End drag if the pointer leaves the SVG.
                onpointerleave: move |_| {
                    drag.active_id.set(None);
                },

                rect {
                    x: "0",
                    y: "0",
                    width: "800",
                    height: "500",
                    fill: "white",
                }

                g {
                    {children}
                }
            }
        }
    }
}

#[component]
fn Point(id: usize, x: f64, y: f64, r: f64) -> Element {
    let mut pos = use_signal(|| Pt { x, y });
    let drag = use_context::<DragState>();

    // Only subscribe to pointer updates while *this* point is active.
    // When inactive, we only read `active_id`, so pointer moves won't rerender this component.
    use_effect(move || {
        if *drag.active_id.read() == Some(id) {
            let p = *drag.pointer.read();
            let off = *drag.offset.read();
            pos.set(Pt {
                x: p.x + off.x,
                y: p.y + off.y,
            });
        }
    });

    let cx = pos.read().x;
    let cy = pos.read().y;

    rsx! {
        circle {
            class: "point",
            cx: "{cx}",
            cy: "{cy}",
            r: "{r}",

            // Start drag.
            // We compute the pointer position in SVG coordinates using the circle's bbox.
            onpointerdown: move |e| {
                e.stop_propagation();
                e.prevent_default();

                // `element_coordinates()` here are relative to the circle's bounding box.
                // For a circle: bbox top-left is (cx - r, cy - r).
                let local = e.element_coordinates();
                let current = *pos.peek();
                let pointer_svg = Pt {
                    x: current.x - r + local.x as f64,
                    y: current.y - r + local.y as f64,
                };

                drag.pointer.set(pointer_svg);
                drag.offset.set(Pt {
                    x: current.x - pointer_svg.x,
                    y: current.y - pointer_svg.y,
                });
                drag.active_id.set(Some(id));
            },
        }
    }
}

