/// A base trait for parsers that want to support lifetimed input tokens.
///
/// Note: if you pick `Input<'src> = &'src [Token<'src>]`, then the *borrow of the slice*
/// must live for `'src`. That makes it impossible to build that slice from a locally-owned
/// `Vec<Token<'src>>` inside `parse_this_owned`, because the local `Vec` doesn't live for `'src`.
///
/// The workaround shown here is: use an *owned* Chumsky input (`Stream`) for `parse_this_owned`.
pub trait BaseParser {
    type InputToken<'src>: PartialEq + Clone + fmt::Display + 'src;
    type Input<'src>: Input<'src, Token = Self::InputToken<'src>, Span = SimpleSpan>;
    type Output;

    fn parser<'src>() -> impl Parser<
        'src,
        Self::Input<'src>,
        Self::Output,
        extra::Err<Rich<'src, Self::InputToken<'src>, SimpleSpan>>,
    >;

