    fn input_from_tokens<'src>(tokens: Vec<Self::InputToken<'src>>) -> Self::Input<'src>;

    fn parse_this_owned<'src>(tokens: Vec<Self::InputToken<'src>>) -> Result<Self::Output, Vec<String>> {
        Self::parse_this(Self::input_from_tokens(tokens))
    }
}

