/// Parse the kind of ISO-like strings LanceDB returns, e.g.
/// - "1970-01-01T00:00:00"
/// - "2025-08-02T17:35:41.409"  (fractional seconds, variable length)
///
/// Returns a UTC DateTime.
fn parse_lancedb_datetime(s: &str) -> Result<DateTime<Utc>, chrono::ParseError> {
    let s = s.trim().trim_matches('"');

    // If there's an explicit offset (Z or +/-hh:mm), parse as RFC3339.
    // (Your examples don't have an offset, but this makes it more robust.)
    if s.ends_with('Z') || s.contains('+') || (s.rfind('-').unwrap_or(0) > "YYYY-MM-DD".len()) {
        if let Ok(dt) = DateTime::parse_from_rfc3339(s) {
            return Ok(dt.with_timezone(&Utc));
        }
    }

    // Otherwise parse as a naive datetime and assume UTC.
    // Important: chrono's "%.f" REQUIRES fractional seconds when present;
    // it will fail with ParseError(NotEnough) if there's no fraction.
    let naive = if s.contains('.') {
        NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S%.f")?
    } else {
        NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S")?
    };

    Ok(DateTime::<Utc>::from_naive_utc_and_offset(naive, Utc))
}

