  "main.rs": "use crossbeam_channel::{Receiver, Sender};
use expectrl::spawn;
use nix::fcntl::{fcntl, FcntlArg, OFlag};
use std::io::{self, Read, Write};
use std::os::unix::io::AsRawFd;
use std::thread;
use std::time::Duration;

fn set_nonblocking(fd: i32) -> nix::Result<()> {
    let flags = OFlag::from_bits_truncate(fcntl(fd, FcntlArg::F_GETFL)?);
    let new_flags = flags | OFlag::O_NONBLOCK;
    fcntl(fd, FcntlArg::F_SETFL(new_flags))?;
    Ok(())
}

/// Single-owner PTY loop:
/// - owns the expectrl Session (no mutex)
/// - sets the PTY to O_NONBLOCK
/// - continuously drains output (read) and forwards it
/// - consumes input from a channel and writes it
fn pty_loop(mut session: expectrl::Session, rx_in: Receiver<Vec<u8>>, tx_out: Sender<Vec<u8>>) {
    // Make reads non-blocking so we never get stuck in read() and can still process incoming writes.
    let fd = session.as_raw_fd();
    if let Err(e) = set_nonblocking(fd) {
        let _ = tx_out.send(format!("[failed to set O_NONBLOCK: {e}]\r\n").into_bytes());
        // Continue anyway; worst case you'll reproduce the original blocking behavior.
    }

    let mut buf = [0u8; 8192];

    loop {
        // 1) Drain any queued input and write it.
        while let Ok(data) = rx_in.try_recv() {
            if let Err(e) = session.write_all(&data) {
                let _ = tx_out.send(format!("[write error: {e}]\r\n").into_bytes());
                return;
            }
        }

        // 2) Read all currently-available output (non-blocking).
        let mut saw_output = false;
        loop {
            match session.read(&mut buf) {
                Ok(0) => {
                    let _ = tx_out.send(b"[child exited]\r\n".to_vec());
                    return;
                }
                Ok(n) => {
                    saw_output = true;
                    let _ = tx_out.send(buf[..n].to_vec());
                }
                Err(e) if e.kind() == io::ErrorKind::WouldBlock => break,
                Err(e) => {
                    let _ = tx_out.send(format!("[read error: {e}]\r\n").into_bytes());
                    return;
                }
            }
        }

        // 3) If nothing happened, block briefly waiting for input (keeps CPU low).
        //    When the child is waiting for input and producing no output, this is the key:
        //    we *still* wake up immediately when UI input arrives.
        if !saw_output {
            match rx_in.recv_timeout(Duration::from_millis(50)) {
                Ok(data) => {
                    if let Err(e) = session.write_all(&data) {
                        let _ = tx_out.send(format!("[write error: {e}]\r\n").into_bytes());
                        return;
                    }
                }
                Err(crossbeam_channel::RecvTimeoutError::Timeout) => {}
                Err(crossbeam_channel::RecvTimeoutError::Disconnected) => return,
            }
        }
    }
}

fn main() -> anyhow::Result<()> {
    // Spawn a PTY-based interactive program.
    // bash is easy to test: it will often sit waiting for input with no output.
    let session = spawn("bash -i")?;

    let (tx_in, rx_in) = crossbeam_channel::unbounded::<Vec<u8>>();
    let (tx_out, rx_out) = crossbeam_channel::unbounded::<Vec<u8>>();

    // PTY owner thread
    thread::spawn(move || pty_loop(session, rx_in, tx_out));

    // Forward PTY output to our stdout
    let out_thread = thread::spawn(move || {
        let mut stdout = io::stdout().lock();
        while let Ok(chunk) = rx_out.recv() {
            let _ = stdout.write_all(&chunk);
            let _ = stdout.flush();
        }
    });

    // Forward our stdin to the PTY (line-buffered by your terminal unless you put stdin in raw mode).
    // In a Tauri app, this is analogous to your IPC command handler sending bytes into tx_in.
    let tx_in2 = tx_in.clone();
    let in_thread = thread::spawn(move || {
        let mut stdin = io::stdin().lock();
        let mut buf = [0u8; 4096];
        loop {
            match stdin.read(&mut buf) {
                Ok(0) => break,
                Ok(n) => {
                    // Send bytes as-is; this preserves control sequences if your stdin is in raw mode.
                    if tx_in2.send(buf[..n].to_vec()).is_err() {
                        break;
                    }
                }
                Err(_) => break,
            }
        }
    });

    // A couple of helpful initial commands.
    // (If you don't want these, delete them.)
    let _ = tx_in.send(b"export TERM=xterm-256color\r".to_vec());
    let _ = tx_in.send(b"echo 'PTY ready. Type into this terminal; output is full-duplex.'\r".to_vec());
    let _ = tx_in.send(b"echo 'Try: read -p \"prompt> \" x; echo you typed: $x'\r".to_vec());

    let _ = in_thread.join();
    drop(tx_in);
    let _ = out_thread.join();

    Ok(())
}
"
}

