/// A minimal Unix datagram DogStatsD sink for cadence.
///
/// This sends one UDP-like datagram per metric string to a connected unix socket path.
#[derive(Clone)]
struct UnixDogstatsdSink {
    sock: Arc<UnixDatagram>,
}

impl UnixDogstatsdSink {
    fn connect<P: AsRef<Path>>(path: P) -> io::Result<Self> {
        let sock = UnixDatagram::unbound()?;
        sock.connect(path)?;
        Ok(Self {
            sock: Arc::new(sock),
        })
    }
}

impl MetricSink for UnixDogstatsdSink {
    fn emit(&self, metric: &str) -> io::Result<()> {
        // DogStatsD expects one metric per line; we send one metric per datagram.
        // cadence already formats the metric line.
        let _ = self.sock.send(metric.as_bytes())?;
        Ok(())
    }
}

fn env_u64(name: &str, default: u64) -> u64 {
    env::var(name)
        .ok()
        .and_then(|v| v.parse::<u64>().ok())
        .unwrap_or(default)
}

fn env_usize(name: &str, default: usize) -> usize {
    env::var(name)
        .ok()
        .and_then(|v| v.parse::<usize>().ok())
        .unwrap_or(default)
}

fn env_string(name: &str, default: &str) -> String {
    env::var(name).unwrap_or_else(|_| default.to_string())
}

fn build_client(prefix: &str, socket_path: &str) -> io::Result<StatsdClient> {
    let sink = UnixDogstatsdSink::connect(socket_path)?;

    Ok(StatsdClient::builder(prefix, sink)
        .with_error_handler(|e| eprintln!("[cadence error] {e:?}"))
        .build())
