    let sock = UnixDatagram::bind(socket_path)?;
    println!("Receiver bound to unix datagram socket: {socket_path}");

    let mut buf = vec![0u8; 64 * 1024];
    let total_datagrams = AtomicU64::new(0);
    let total_lines = AtomicU64::new(0);

    let reporter = thread::spawn({
        let total_datagrams = &total_datagrams;
        let total_lines = &total_lines;
        move || {
            let mut last_d = 0u64;
            let mut last_l = 0u64;
            loop {
                thread::sleep(Duration::from_secs(1));
                let d = total_datagrams.load(Ordering::Relaxed);
                let l = total_lines.load(Ordering::Relaxed);
                let dd = d - last_d;
                let dl = l - last_l;
                last_d = d;
                last_l = l;
                println!("recv: {dd} datagrams/s, {dl} metric-lines/s (total lines={l})");
            }
        }
    });

