    let metric = env_string("METRIC", "operations.count");
    let threads = env_usize("THREADS", 4);
    let rate_total = env_u64("RATE", 50_000); // metrics/sec total across threads
    let duration_s = env_u64("DURATION", 30);
    let cardinality = env_u64("CARDINALITY", 100); // number of distinct tag values

