        0
    } else {
        rate_total / (threads as u64)
    };

    println!("Sending DogStatsD metrics via unix socket");
    println!("  socket_path = {socket_path}");
    println!("  prefix      = {prefix}");
    println!("  metric      = {metric}");
    println!("  threads     = {threads}");
    println!("  rate_total  = {rate_total} metrics/s (~{per_thread_rate}/s per thread)");
    println!("  duration    = {duration_s}s");
    println!("  cardinality = {cardinality}");

    let sent = Arc::new(AtomicU64::new(0));
    let errs = Arc::new(AtomicU64::new(0));

    let stop_at = Instant::now() + Duration::from_secs(duration_s);

