                    errs.fetch_add(1, Ordering::Relaxed);
                    return;
                }
            };

            // Simple pacing loop.
            let tick = if per_thread_rate > 0 {
                Duration::from_secs_f64(1.0 / per_thread_rate as f64)
            } else {
                Duration::from_secs(0)
            };

            let mut i: u64 = 0;
            let mut next = Instant::now();

            while Instant::now() < stop_at {
                // Create some tag cardinality; change values per metric.
                let c = (i % cardinality) as u64;
                let client_name = format!("client_{c}");
                let query = format!("op_{c}");

                let res = client
                    .incr_with_tags(&metric)
                    .with_tag("thread", &tid.to_string())
                    .with_tag("client_name", &client_name)
                    .with_tag("client_version", "1.0.0")
                    .with_tag("network", "testnet")
                    .with_tag("query", &query)
                    .with_tag("runtime", "rust")
                    .try_send();

                match res {
                    Ok(()) => {
                        sent.fetch_add(1, Ordering::Relaxed);
                    }
                    Err(_e) => {
                        // cadence will also invoke the error handler if configured.
                        errs.fetch_add(1, Ordering::Relaxed);
                    }
                }

                i = i.wrapping_add(1);

                if !tick.is_zero() {
                    next += tick;
                    let now = Instant::now();
                    if next > now {
                        thread::sleep(next - now);
                    } else {
                        // We're behind; reset pacing baseline.
                        next = now;
                    }
                }
            }
        });

        handles.push(h);
    }

    // Report once per second.
    let mut last_sent = 0u64;
    let mut last_errs = 0u64;
    while Instant::now() < stop_at {
        thread::sleep(Duration::from_secs(1));
        let s = sent.load(Ordering::Relaxed);
        let e = errs.load(Ordering::Relaxed);
        let ds = s - last_sent;
        let de = e - last_errs;
        last_sent = s;
        last_errs = e;
        println!("sent: {ds}/s (total={s}), errors: {de}/s (total={e})");
    }

    for h in handles {
        let _ = h.join();
    }

    println!(
        "done. total_sent={}, total_errors={} (note: errors here only reflect local send failures)",
        sent.load(Ordering::Relaxed),
        errs.load(Ordering::Relaxed)
    );

    Ok(())
}

fn main() -> io::Result<()> {
    // Usage examples:
    //   MODE=send SOCKET_PATH=/var/run/datadog/dsd.socket RATE=50000 THREADS=4 DURATION=30 cargo run
    //   MODE=recv SOCKET_PATH=/tmp/dsd.socket cargo run

