futures = "0.3"
",
  "main.rs": "use futures::task::noop_waker_ref;
use std::{
    future::Future,
    pin::Pin,
    task::{Context, Poll},
    time::Duration,
};

#[derive(Debug)]
enum TryPollResult<T> {
    Ready(T),
    Pending,
}

fn try_poll<T>(mut fut: Pin<&mut impl Future<Output = T>>) -> TryPollResult<T> {
    // We only want to know whether the future is *immediately* ready.
    // A no-op waker is fine because:
    // - if Ready: we're done
    // - if Pending: we'll hand the future to Tokio, which will poll it again with a real waker
    let waker = noop_waker_ref();
    let mut cx = Context::from_waker(waker);

    match fut.as_mut().poll(&mut cx) {
        Poll::Ready(v) => TryPollResult::Ready(v),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// A non-async function (but expected to be called from within a Tokio runtime).
///
/// - If the future is ready immediately, return the value.
/// - If not, spawn a Tokio task that awaits it, and return None.
fn eval_or_spawn<F>(fut: F) -> Option<F::Output>
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
{
    // Box+Pin so we can (1) poll once, then (2) move it into a spawned task if needed.
    let mut fut = Box::pin(fut);

    match try_poll(fut.as_mut()) {
        TryPollResult::Ready(v) => Some(v),
        TryPollResult::Pending => {
            tokio::spawn(async move {
                let v = fut.await;
                println!("spawned task: future completed with: {v:?}");
            });
            None
        }
    }
}

#[tokio::main]
