fn column_means(m: &DMatrix<f64>) -> RowDVector<f64> {
    let nrows = m.nrows() as f64;
    let mut mean = RowDVector::zeros(m.ncols());

    for j in 0..m.ncols() {
        let sum: f64 = m.column(j).iter().copied().sum();
        mean[(0, j)] = sum / nrows;
    }

    mean
