fn center_columns(m: &DMatrix<f64>) -> (RowDVector<f64>, DMatrix<f64>) {
    let mean = column_means(m);

    // “Broadcast” the 1×k mean across all rows by subtracting it from each row.
    let mut centered = m.clone();
    for i in 0..centered.nrows() {
        for j in 0..centered.ncols() {
            centered[(i, j)] -= mean[(0, j)];
        }
    }

    (mean, centered)
