#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct Filename<'e>(&'e str);

#[derive(Debug)]
struct FilenameInterner;
impl FilenameInterner {
    fn new() -> Self {
        Self
    }

    fn intern<'e>(&'e self, s: &'e str) -> Filename<'e> {
        Filename(s)
    }
}

#[derive(Debug)]
struct State<'e> {
    filename: Filename<'e>,
    symbol_interner: &'e SymbolInterner,
}

#[derive(Debug)]
struct SStream<'i, 'e> {
    input: &'i str,
    state: State<'e>,
}

// --- Output type that *does* carry the environment lifetime -----------------

#[derive(Debug)]
struct Cons<'e> {
    car: u64,
    cdr: u64,
    filename: Filename<'e>,
}

// Allow comparing to a differently-typed expected output (like the OP wanted).
impl<'e> PartialEq<(u64, u64)> for Cons<'e> {
    fn eq(&self, other: &(u64, u64)) -> bool {
        (self.car, self.cdr) == *other
    }
}

impl<'e> PartialEq<String> for Cons<'e> {
    fn eq(&self, other: &String) -> bool {
        other == &format!("({} . {})", self.car, self.cdr)
    }
}

// --- A parser abstraction using a GAT for the output ------------------------
//
// The key is: the output type depends on the environment lifetime `'e`.
// A plain type parameter `POut` can't express that, but a GAT can.
trait TestParser<'i> {
    type Out<'e>: Debug;

    fn parse<'e>(&mut self, input: &mut SStream<'i, 'e>) -> ModalResult<Self::Out<'e>>;
}

// Implement the trait for any function/closure that can parse for *any* `'e`.
impl<'i, F> TestParser<'i> for F
where
    F: for<'e> FnMut(&mut SStream<'i, 'e>) -> ModalResult<Cons<'e>>,
{
    type Out<'e> = Cons<'e>;

    fn parse<'e>(&mut self, input: &mut SStream<'i, 'e>) -> ModalResult<Self::Out<'e>> {
        self(input)
    }
}

// --- Example parser (like `parse_cons`) -------------------------------------

fn parse_cons<'i, 'e>(input: &mut SStream<'i, 'e>) -> ModalResult<Cons<'e>> {
    // Extremely dumb "parser" for demonstration.
    // Accepts only the exact input "(1 . 2)".
    let s = input.input.trim();
    if s != "(1 . 2)" {
        return Err(format!("expected '(1 . 2)', got {s:?}"));
    }

    // Crucially: the output carries `'e` by borrowing from the stream's state.
    Ok(Cons {
        car: 1,
        cdr: 2,
        filename: input.state.filename,
    })
}

// --- The testing helper ------------------------------------------------------

pub fn test_input_output<'i, ExOut, P>(
    input: &'i str,
    expected_output: &ExOut,
    mut parser: P,
) where
    ExOut: Debug,
    P: TestParser<'i>,
    for<'e> P::Out<'e>: PartialEq<ExOut> + Debug,
{
    // These live only for this function body, and `'e` is exactly that lifetime.
    let symbol_interner = SymbolInterner::new();
    let filename_interner = FilenameInterner::new();
    let filename = filename_interner.intern("<test>");

    let state = State {
        filename,
        symbol_interner: &symbol_interner,
    };

    let mut stream = SStream { input, state };

    let parsed = match parser.parse(&mut stream) {
        Ok(p) => p,
        Err(e) => panic!(
            "Failed on:\n\tinput: {input:?}\n\texpected output: {expected_output:?}\n\n{e}"
        ),
    };

    println!(
        "Testing:\n\tinput: {input:?}\n\texpected output: {expected_output:?}\n\tparsed: {parsed:?}"
    );

    assert_eq!(&parsed, expected_output);
}

fn main() {
    // Expected output can be a different type than the parser output.
    let expected_tuple = (1u64, 2u64);
    test_input_output("(1 . 2)", &expected_tuple, parse_cons);

    let expected_string = "(1 . 2)".to_string();
    test_input_output("(1 . 2)", &expected_string, parse_cons);

    println!("All good");
}
"
}
```

