/// A background worker that keeps doing "jobs" until shutdown.
/// On shutdown, it stops taking new work and exits after finishing the current job.
async fn queue_worker(token: CancellationToken) -> std::io::Result<()> {
    let mut job_id: u64 = 0;

    loop {
        // If we're asked to shut down, stop taking new jobs.
        if token.is_cancelled() {
            eprintln!("[queue] shutdown requested; stopping intake");
            break;
        }

        // Simulate: receiving a job
        job_id += 1;
        eprintln!("[queue] picked up job #{job_id}");

        // Simulate: processing that job (this is the "pending work" we want to finish)
        // If you want to be interruptible mid-job, you'd check token inside as well.
        sleep(Duration::from_millis(800)).await;
        eprintln!("[queue] finished job #{job_id}");

        // Small delay between jobs
        sleep(Duration::from_millis(200)).await;
    }

    eprintln!("[queue] exited cleanly");
    Ok(())
}

#[tokio::main(flavor = "multi_thread")]
async fn main() -> std::io::Result<()> {
    // One shutdown signal shared by all tasks.
    let token = CancellationToken::new();

    // Build server future (do NOT spawn-and-forget; keep the future so we can await it).
    // disable_signals(): we handle Ctrl+C ourselves to coordinate all tasks.
    let server = HttpServer::new(|| {
        App::new()
            .route("/", web::get().to(index))
            .route("/health", web::get().to(|| async { "healthy" }))
    })
    .disable_signals()
    .bind(("127.0.0.1", 8080))?
    .run();

    let server_handle = server.handle();

    // Background worker future (also not spawn-and-forget; we want to await it).
    let queue = queue_worker(token.clone());

    // Pin the futures so we can await them after select! triggers.
    tokio::pin!(server);
    tokio::pin!(queue);

    eprintln!("[main] server running on http://127.0.0.1:8080");
    eprintln!("[main] press Ctrl+C to shut down");

    // Wait for Ctrl+C OR one of the tasks to finish unexpectedly.
    tokio::select! {
        _ = tokio::signal::ctrl_c() => {
            eprintln!("[main] Ctrl+C received; starting graceful shutdown");
        }
        res = &mut server => {
            // Server ended on its own (bind error would have happened earlier).
            eprintln!("[main] server finished: {res:?}; shutting down worker");
        }
        res = &mut queue => {
            eprintln!("[main] queue worker finished: {res:?}; shutting down server");
        }
    }

    // Coordinate shutdown.
    token.cancel();

    // Gracefully stop Actix server (waits for in-flight requests).
    // true => graceful.
    server_handle.stop(true).await;

    // Now wait for both to complete, so nothing is left running in the background.
    let (server_res, queue_res) = tokio::join!(server, queue);

    eprintln!("[main] server result: {server_res:?}");
    eprintln!("[main] queue result: {queue_res:?}");
    eprintln!("[main] shutdown complete");

    Ok(())
}
