        // Wait until either (1) an input event arrives or (2) the next tick is due.
        let now = Instant::now();
        let timeout = next_tick.saturating_duration_since(now);

        if event::poll(timeout)? {
            // An input event is ready.
            let ev = event::read()?;

            if let Event::Key(key) = ev {
                match key.code {
                    KeyCode::Char('q') => {
                        println!("\n'q' pressed, quitting.");
                        return Ok(());
                    }
                    _ => {
                        println!("Input: {:?}", key.code);
                        io::stdout().flush()?;
                    }
                }
            }
        } else {
            // poll() timed out => tick
            println!("Tick! {:?}", Instant::now());
            io::stdout().flush()?;

            // Schedule the next tick, avoiding drift if we got delayed.
            let mut t = next_tick + tick_rate;
            let now = Instant::now();
            while t <= now {
                t += tick_rate;
            }
            next_tick = t;
