use rustyline::error::ReadlineError;
use rustyline::history::DefaultHistory;
use rustyline::{Context, Editor, Result};
use rustyline_derive::Helper;

struct ShellCompleter {
    file: FilenameCompleter,
    commands: Vec<String>,
}

impl ShellCompleter {
    fn new() -> Self {
        Self {
            file: FilenameCompleter::new(),
            commands: vec![
                "cd".into(),
                "echo".into(),
                "exit".into(),
                "pwd".into(),
                "type".into(),
            ],
        }
    }

    fn word_start(line: &str, pos: usize) -> usize {
        let upto = &line[..pos];
        match upto.rfind(|c: char| c.is_whitespace()) {
            Some(i) => i + 1,
            None => 0,
        }
    }

    fn is_first_word(line: &str, start: usize) -> bool {
        line[..start].trim().is_empty()
    }
}

impl Completer for ShellCompleter {
    type Candidate = Pair;

    fn complete(&self, line: &str, pos: usize, ctx: &Context<'_>) -> Result<(usize, Vec<Pair>)> {
        let start = Self::word_start(line, pos);

        if Self::is_first_word(line, start) {
            let prefix = &line[start..pos];
            let mut out = Vec::new();

            for cmd in &self.commands {
                if cmd.starts_with(prefix) {
                    out.push(Pair {
                        display: cmd.clone(),
                        replacement: cmd.clone(),
                    });
                }
            }

            return Ok((start, out));
        }

        // Not the first word: fall back to filename completion.
        self.file.complete(line, pos, ctx)
    }
}

#[derive(Helper)]
struct ShellHelper {
    #[rustyline(Completer)]
    completer: ShellCompleter,
}

fn main() -> Result<()> {
    // IMPORTANT: don't use DefaultEditor here, because DefaultEditor fixes the helper type to `()`.
    // Instead, create an Editor with your helper type.
    let mut rl: Editor<ShellHelper, DefaultHistory> = Editor::new()?;
    rl.set_helper(Some(ShellHelper {
        completer: ShellCompleter::new(),
    }));

    if rl.load_history("history.txt").is_err() {
