tracing-subscriber = { version = "0.3", features = ["env-filter"] }
",
  "main.rs": "use axum::{
    extract::{ws::WebSocket, ws::WebSocketUpgrade, Path},
    http::{header, Request, StatusCode},
    middleware::{self, Next},
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use tower_http::cors::{Any, CorsLayer};
use tracing::{info, warn};

const ALLOWED_ORIGIN: &str = "https://www.example.com";

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt()
        .with_env_filter("info")
        .init();

    // Normal CORS (HTTP) still works as usual.
    // WebSocket origin filtering is handled by the route middleware below.
    let cors = CorsLayer::new()
        .allow_origin(Any)
        .allow_methods(Any)
        .allow_headers(Any);

    let app = Router::new()
        .route("/", get(|| async { "ok\n" }))
        .route(
            "/client/:session_id",
            get(client_ws_handler)
                // Apply origin checks to this route only.
                .route_layer(middleware::from_fn(check_ws_origin)),
        )
        .layer(cors);

    let listener = tokio::net::TcpListener::bind("127.0.0.1:3000")
        .await
        .unwrap();

    info!("listening on http://127.0.0.1:3000");
    axum::serve(listener, app).await.unwrap();
}

// Middleware that rejects WebSocket handshake requests unless Origin matches.
async fn check_ws_origin(req: Request<axum::body::Body>, next: Next) -> Response {
    // Most browsers always send Origin for WS. Non-browser clients might omit it.
    // Decide your policy: here we *require* it.
    let origin = req
        .headers()
        .get(header::ORIGIN)
        .and_then(|v| v.to_str().ok());

    match origin {
        Some(v) if v == ALLOWED_ORIGIN => next.run(req).await,
        Some(v) => {
            warn!("rejecting websocket due to invalid origin: {v}");
            StatusCode::FORBIDDEN.into_response()
        }
        None => {
            warn!("rejecting websocket due to missing Origin header");
            StatusCode::FORBIDDEN.into_response()
        }
    }
}

async fn client_ws_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

async fn handle_socket(mut socket: WebSocket, session_id: String) {
    use axum::extract::ws::Message;

    info!(%session_id, "websocket connected");

    while let Some(Ok(msg)) = socket.recv().await {
        match msg {
            Message::Text(text) => {
                let reply = format!("session={session_id} echo: {text}");
                let _ = socket.send(Message::Text(reply)).await;
            }
            Message::Binary(bytes) => {
                let _ = socket.send(Message::Binary(bytes)).await;
            }
            Message::Ping(p) => {
                let _ = socket.send(Message::Pong(p)).await;
            }
            Message::Close(_) => break,
            _ => {}
        }
    }

    info!(%session_id, "websocket disconnected");
}
"
}
