```json
{
  "Cargo.toml": "[package]
name = "asyncfnonce_wrap"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["macros", "rt-multi-thread", "sync"] }
",
  "main.rs": "use std::future::Future;
use std::pin::Pin;
use tokio::sync::mpsc;

#[derive(Debug)]
pub struct Context(i32);

// A boxed, Send future with some borrow of the context.
type BoxFuture<'a> = Pin<Box<dyn Future<Output = ()> + Send + 'a>>;

// A boxed, Send callable that can be invoked once, producing a BoxFuture
// tied to the borrow of `&mut Context`.
type BoxCtxFnOnce = Box<dyn for<'a> FnOnce(&'a mut Context) -> BoxFuture<'a> + Send>;

pub enum InnerAsyncEvent {
    DoWithContext { block: BoxCtxFnOnce },
    Stop,
}

// Stable replacement for `AsyncFnOnce(&mut Context)` *with an explicit Send bound*
// on the returned future.
pub trait AsyncCtxFnOnce: Send + 'static {
    type Fut<'a>: Future<Output = ()> + Send + 'a
    where
        Self: 'a;

    fn call_once<'a>(self, ctx: &'a mut Context) -> Self::Fut<'a>;
}

impl<F> AsyncCtxFnOnce for F
where
    F: Send + 'static,
    // The closure can be called for any borrow of the context...
    for<'a> F: FnOnce<(&'a mut Context,)>,
    // ...and the produced future is Send for any such borrow.
    for<'a> <F as FnOnce<(&'a mut Context,)>>::Output: Future<Output = ()> + Send + 'a,
{
    type Fut<'a> = <F as FnOnce<(&'a mut Context,)>>::Output
    where
        Self: 'a;

    fn call_once<'a>(self, ctx: &'a mut Context) -> Self::Fut<'a> {
        self(ctx)
    }
}

pub fn with_context_async<F>(sender: &mpsc::UnboundedSender<InnerAsyncEvent>, block: F)
where
    F: AsyncCtxFnOnce,
{
    let _ = sender.send(InnerAsyncEvent::DoWithContext {
        // Wrap the user-provided async closure and do the pin+box here.
        block: Box::new(move |ctx| Box::pin(block.call_once(ctx))),
    });
}

#[tokio::main(flavor = "multi_thread")]
async fn main() {
    let (tx, mut rx) = mpsc::unbounded_channel::<InnerAsyncEvent>();

    // Worker task (can run on any tokio worker thread)
    let worker = tokio::spawn(async move {
        let mut ctx = Context(0);

        while let Some(ev) = rx.recv().await {
            match ev {
                InnerAsyncEvent::DoWithContext { block } => {
                    let fut = block(&mut ctx);
                    fut.await;
                }
                InnerAsyncEvent::Stop => break,
            }
        }

        ctx.0
    });

    // Send work from a different OS thread.
    let tx2 = tx.clone();
    std::thread::spawn(move || {
        with_context_async(&tx2, |ctx| async move {
            ctx.0 += 1;
        });

        with_context_async(&tx2, |ctx| async move {
            ctx.0 += 41;
        });

        let _ = tx2.send(InnerAsyncEvent::Stop);
    })
    .join()
    .unwrap();

    let final_value = worker.await.unwrap();
    println!("final ctx.0 = {final_value}");
}
"
}
