  "main.rs": "use enum_dispatch::enum_dispatch;

// ---- Shared API definition (would live in your `al` crate) ----
// X-macro listing the REST API once, reused to generate:
// - the `al::Rest` trait
// - the `bl::RestDispatch` trait (for enum_dispatch)
// - forwarding impls
#[macro_export]
macro_rules! rest_api {
    ($m:ident) => {
        $m!(get(path: &str) -> String);
        $m!(post(path: &str, body: Vec<u8>) -> u16);
        $m!(delete(id: u64) -> bool);
        $m!(set_header(key: &str, value: &str) -> Option<String>);
        $m!(batch(ids: &[u32]) -> Vec<String>);
    };
}

macro_rules! decl_method {
    ($name:ident ( $( $arg:ident : $ty:ty ),* $(,)? ) -> $ret:ty) => {
        fn $name(&self, $( $arg : $ty ),* ) -> $ret;
    };
}

// Forward a method to the implementation-layer trait impl (al::Rest)
macro_rules! fwd_to_al_rest_method {
    ($name:ident ( $( $arg:ident : $ty:ty ),* $(,)? ) -> $ret:ty) => {
        fn $name(&self, $( $arg : $ty ),* ) -> $ret {
            <Self as crate::al::Rest>::$name(self, $( $arg ),* )
        }
    };
}

// Forward a method to the enum-dispatch trait impl (bl::RestDispatch)
macro_rules! fwd_to_dispatch_method {
    ($name:ident ( $( $arg:ident : $ty:ty ),* $(,)? ) -> $ret:ty) => {
        fn $name(&self, $( $arg : $ty ),* ) -> $ret {
            <Self as crate::bl::RestDispatch>::$name(self, $( $arg ),* )
        }
    };
}

pub mod al {
    pub trait Rest {
        crate::rest_api!(decl_method);
    }
}

// ---- Implementation layer (would live in your `il` crate) ----
pub mod il {
    use crate::al;

    #[derive(Debug, Clone)]
    pub struct Foo {
        pub name: String,
    }

    #[derive(Debug, Clone)]
    pub struct Boo {
        pub factor: u32,
    }

    impl al::Rest for Foo {
        fn get(&self, path: &str) -> String {
            format!("Foo({}) GET {}", self.name, path)
        }
        fn post(&self, path: &str, body: Vec<u8>) -> u16 {
            let _ = (path, body);
            201
        }
        fn delete(&self, id: u64) -> bool {
            id % 2 == 0
        }
        fn set_header(&self, key: &str, value: &str) -> Option<String> {
            Some(format!("Foo header set: {key}={value}"))
        }
        fn batch(&self, ids: &[u32]) -> Vec<String> {
            ids.iter()
                .map(|id| format!("Foo({}) item={}", self.name, id))
                .collect()
        }
    }

    impl al::Rest for Boo {
        fn get(&self, path: &str) -> String {
            format!("Boo(factor={}) GET {}", self.factor, path)
        }
        fn post(&self, path: &str, body: Vec<u8>) -> u16 {
            let _ = (path, body);
            200 + (self.factor as u16 % 50)
        }
        fn delete(&self, id: u64) -> bool {
            (id as u32) % self.factor.max(1) == 0
        }
        fn set_header(&self, key: &str, value: &str) -> Option<String> {
            Some(format!("Boo header set: {key}={value}"))
        }
        fn batch(&self, ids: &[u32]) -> Vec<String> {
            ids.iter()
                .map(|id| format!("Boo(f={}) item={}", self.factor, id))
                .collect()
        }
    }
}

// ---- Business layer (would live in your `bl` crate) ----
// Key idea:
// - You *cannot* apply `#[enum_dispatch]` to an external trait.
// - So define a local dispatch trait with the same API (generated from the same macro list).
// - Implement that local trait for il::Foo/il::Boo by forwarding to al::Rest.
// - Use enum_dispatch on the local trait + local enum.
// - Optionally, implement al::Rest for the enum by forwarding to the dispatch trait, so the
//   enum can be used wherever al::Rest is expected.
pub mod bl {
    use super::*;

    #[enum_dispatch]
    pub trait RestDispatch {
        crate::rest_api!(decl_method);
    }

    #[enum_dispatch(RestDispatch)]
    pub enum Item {
        Foo,
        Boo,
    }

    // Forward RestDispatch -> al::Rest for each concrete implementation type.
    impl RestDispatch for crate::il::Foo {
        crate::rest_api!(fwd_to_al_rest_method);
    }

    impl RestDispatch for crate::il::Boo {
        crate::rest_api!(fwd_to_al_rest_method);
    }

    // Optional: make Item usable as an `al::Rest` by forwarding to RestDispatch.
    impl crate::al::Rest for Item {
        crate::rest_api!(fwd_to_dispatch_method);
    }
}

fn run_generic<R: al::Rest>(rest: &R) {
    println!("generic get: {}", rest.get("/health"));
    println!("generic delete(10): {}", rest.delete(10));
}

fn main() {
    let foo = il::Foo {
        name: "alpha".to_string(),
    };
    let boo = il::Boo { factor: 3 };

    // enum_dispatch gives you From<Foo> for Item, etc.
    let mut items: Vec<bl::Item> = vec![foo.into(), boo.into()];

    for it in &items {
        println!("get: {}", it.get("/v1/data"));
        println!("post status: {}", it.post("/v1/data", vec![1, 2, 3]));
        println!("set_header: {:?}", it.set_header("x-token", "t123"));
        println!("batch: {:?}", it.batch(&[1, 2, 5]));
        println!();

        // Works because we also implemented al::Rest for Item (forwarding to RestDispatch).
        run_generic(it);
        println!("---");
    }

    // Just to show we can still move items around as a sum type.
    items.reverse();
    println!("after reverse: {}", items[0].get("/reordered"));
}
"
}
