use tokio::task::JoinHandle;
use tokio_postgres::{Client, NoTls};

/// Holds the cached admin connection *and* the task that drives it.
///
/// Important: the `Connection` future must keep running on the same Tokio runtime.
/// If you create this in one runtime and try to use the `Client` from another
/// (e.g. across different `#[tokio::test]` runtimes), you'll get `Error { kind: Closed, .. }`.
struct CachedConn {
    client: Client,
    _driver: JoinHandle<()>,
}

impl CachedConn {
    async fn new(conn_str: &str) -> Result<Self, tokio_postgres::Error> {
        let (client, connection) = tokio_postgres::connect(conn_str, NoTls).await?;

        // Drive the connection in the background.
        let driver = tokio::spawn(async move {
            if let Err(e) = connection.await {
                eprintln!("connection error: {e}");
            }
        });

        Ok(Self {
            client,
            _driver: driver,
        })
    }
}

pub struct DbContainer {
    admin_conn_str: String,
    admin: OnceCell<CachedConn>,
}

impl DbContainer {
    pub fn new(admin_conn_str: String) -> Self {
        Self {
            admin_conn_str,
            admin: OnceCell::const_new(),
        }
    }

    /// Returns an owned `Client` handle by cloning the cached one.
    /// Cloning does *not* create a new TCP connection; it just creates another handle
    /// to the same underlying connection.
    async fn admin_client(&self) -> Result<Client, tokio_postgres::Error> {
        let cached = self
            .admin
            .get_or_init(|| async {
                CachedConn::new(&self.admin_conn_str)
                    .await
                    .expect("failed to connect admin client")
            })
            .await;

        Ok(cached.client.clone())
    }

    async fn connect_to_db(&self, dbname: &str) -> Result<Client, tokio_postgres::Error> {
        // This is a separate connection (not cached) because it changes per db.
        let conn_str = format!("{} dbname={}", self.admin_conn_str, dbname);
        let (client, connection) = tokio_postgres::connect(&conn_str, NoTls).await?;
        tokio::spawn(async move {
            if let Err(e) = connection.await {
                eprintln!("connection error: {e}");
            }
        });
        Ok(client)
    }

    pub async fn create_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        let admin = self.admin_client().await?;
        admin
            .execute(&format!("CREATE DATABASE {name}"), &[])
            .await?;

        let db = self.connect_to_db(name).await?;
        db.batch_execute(load_schema()).await?;
        Ok(())
    }

    pub async fn drop_database(&self, name: &str) -> Result<u64, tokio_postgres::Error> {
        let admin = self.admin_client().await?;

        let terminate_sql = format!(
            "
            SELECT pg_terminate_backend(pid)
            FROM pg_stat_activity
            WHERE datname = '{name}' AND pid <> pg_backend_pid();
            "
        );

        admin.execute(&terminate_sql, &[]).await?;
        admin.execute(&format!("DROP DATABASE {name}"), &[]).await
    }
}

fn load_schema() -> &'static str {
    // Keep it simple for the demo.
    "CREATE TABLE IF NOT EXISTS demo(id INT PRIMARY KEY);"
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    // Provide a libpq-style connection string.
    // Example:
    //   PG_ADMIN_CONN='host=localhost port=5432 user=postgres password=postgres'
    let admin_conn_str = env::var("PG_ADMIN_CONN")
        .unwrap_or_else(|_| "host=localhost port=5432 user=postgres password=postgres".to_string());

    let container = DbContainer::new(admin_conn_str);

    // Use a somewhat-unique name.
    let dbname = format!("tmp_test_db_{}", std::process::id());

    println!("creating db: {dbname}");
    container
        .create_database(&dbname)
        .await
        .with_context(|| "create_database failed")?;

    println!("dropping db: {dbname}");
    container
        .drop_database(&dbname)
        .await
        .with_context(|| "drop_database failed")?;

    println!("done");
    Ok(())
}
"
}
