// A trait that can represent "an async function taking &mut String".
//
// Key idea: the returned Future type depends on the input lifetime,
// so we model it with a GAT (generic associated type) Fut<'a>.
trait AsyncTest {
    type Fut<'a>: Future<Output = ()> + 'a
    where
        Self: 'a;

    fn run<'a>(&'a self, s: &'a mut String) -> Self::Fut<'a>;
}

// Blanket-impl for any function/closure that can be called for *any* lifetime 'a
// and returns a Future that is valid for that same 'a.
impl<F> AsyncTest for F
where
    for<'a> F: Fn(&'a mut String),
    for<'a> <F as FnOnce<(&'a mut String,)>>::Output: Future<Output = ()> + 'a,
{
    type Fut<'a> = <F as FnOnce<(&'a mut String,)>>::Output
    where
        Self: 'a;

    fn run<'a>(&'a self, s: &'a mut String) -> Self::Fut<'a> {
        self(s)
    }
}

async fn harness<T>(test: T)
where
    T: AsyncTest,
{
    let mut string = String::new();

    string.push_str("=== preamble ===\n");
    test.run(&mut string).await;
    string.push_str("=== postamble ===\n");

    println!("new string is:\n{string}");
}

#[tokio::main]
async fn main() {
    harness(simple_test).await;
}
"
