name = "rehydrate_span_demo"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["macros", "rt-multi-thread", "time"] }
tracing = "0.1"
tracing-subscriber = { version = "0.3", features = ["fmt", "registry"] }
tracing-opentelemetry = "0.23"
opentelemetry = "0.22"
opentelemetry_sdk = { version = "0.22", features = ["trace"] }
async-trait = "0.1"
",
  "main.rs": "use async_trait::async_trait;
use opentelemetry::trace::TracerProvider as _;
use std::{sync::Arc, time::Duration};
use tracing::{info, Instrument};
use tracing_opentelemetry::OpenTelemetrySpanExt;
use tracing_subscriber::fmt::format::FmtSpan;

#[derive(Clone)]
struct RequestCtx {
    request_id: u64,

    // Option A (most common with tracing): store the parent tracing::Span and use it later.
    tracing_parent: tracing::Span,

    // Option B (otel-style propagation): store the OpenTelemetry Context and set it as parent.
    // This is useful if you want to propagate across boundaries that don't (or shouldn't)
    // carry a tracing::Span.
    otel_parent: opentelemetry::Context,
}

#[async_trait]
trait ProxyStages: Send + Sync + 'static {
    async fn stage1(&self, ctx: RequestCtx);
    async fn stage2(&self, ctx: RequestCtx);
    async fn upstream(&self);
}

struct Proxy;

#[async_trait]
impl ProxyStages for Proxy {
    async fn stage1(&self, ctx: RequestCtx) {
        // Rehydrate the parent span explicitly.
        let span = tracing::info_span!(parent: &ctx.tracing_parent, "stage1", request_id = ctx.request_id);

        async move {
            info!("handling stage1 on some task/thread");
            tokio::time::sleep(Duration::from_millis(80)).await;
            info!("stage1 done");
        }
        .instrument(span)
        .await;
    }

    async fn stage2(&self, ctx: RequestCtx) {
        // You can also restore parenthood from a stored OpenTelemetry Context.
        // (Here we set BOTH the tracing parent and the otel parent; the tracing parent
        // is what makes the fmt output show correct nesting, while set_parent shows how
        // to propagate otel context explicitly.)
        let span = tracing::info_span!(parent: &ctx.tracing_parent, "stage2", request_id = ctx.request_id);
        span.set_parent(ctx.otel_parent.clone());

        async move {
            info!("handling stage2 on some other task/thread");
            tokio::time::sleep(Duration::from_millis(60)).await;

            // Because we're *inside* stage2's span here, a child span will automatically nest.
            self.upstream().await;

            info!("stage2 done");
        }
        .instrument(span)
        .await;
    }

    async fn upstream(&self) {
        let span = tracing::info_span!("upstream");
        async {
            info!("calling upstream...");
            tokio::time::sleep(Duration::from_millis(40)).await;
            info!("upstream done");
        }
        .instrument(span)
        .await;
    }
}

fn init_tracing() {
    // Minimal OpenTelemetry setup (no exporter here; we mainly want parent context APIs
    // like span.context() / span.set_parent(..) to work).
    let provider = opentelemetry_sdk::trace::TracerProvider::builder().build();
    let tracer = provider.tracer("rehydrate-span-demo");
    let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);

    let fmt_layer = tracing_subscriber::fmt::layer()
        .with_target(false)
        .with_thread_ids(true)
        .with_span_events(FmtSpan::NEW | FmtSpan::ENTER | FmtSpan::EXIT | FmtSpan::CLOSE);

    tracing_subscriber::registry()
        .with(fmt_layer)
        .with(otel_layer)
        .init();

    // Keep provider alive for the duration of the program.
    std::mem::forget(provider);
}

async fn handle_request(proxy: Arc<Proxy>, request_id: u64) {
    // This is the "request/parent" span you want to parent everything under.
    let request_span = tracing::info_span!("request", request_id);

    // The request span must live until the request is truly complete.
    // (Even if callbacks happen on other tasks/threads, you'll re-parent explicitly.)
    let ctx = {
        let _g = request_span.enter();
        info!("request started");

        RequestCtx {
            request_id,
            tracing_parent: request_span.clone(),
            otel_parent: request_span.context(),
        }
    };

    // Simulate a system (Pingora/Tokio) calling stages later / anywhere.
    // Stage 1: normal spawned task.
    let p1 = proxy.clone();
    let c1 = ctx.clone();
    let t1 = tokio::spawn(async move {
        tokio::time::sleep(Duration::from_millis(10)).await;
        p1.stage1(c1).await;
    });

    // Stage 2: run from a blocking threadpool thread (different thread).
    let handle = tokio::runtime::Handle::current();
    let p2 = proxy.clone();
    let c2 = ctx.clone();
    let t2 = tokio::task::spawn_blocking(move || {
        std::thread::sleep(Duration::from_millis(30));
        handle.block_on(async move {
            p2.stage2(c2).await;
        });
    });

    let _ = tokio::join!(t1, t2);

    // Drop request span only when everything is done.
    drop(ctx);
    drop(request_span);
}

#[tokio::main(flavor = "multi_thread", worker_threads = 2)]
async fn main() {
    init_tracing();

    let proxy = Arc::new(Proxy);
    handle_request(proxy, 42).await;

    // If you had a real exporter, you'd want shutdown/flush here.
    opentelemetry::global::shutdown_tracer_provider();
}
"
}
