serde = { version = "1", features = ["derive"] }
serde_json = "1"
self_cell = "1"
",
  "main.rs": "use serde::Deserialize;
use std::sync::Arc;
use tokio::sync::mpsc;

#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

// A self-referential container that owns the JSON string (owner)
// and stores a deserialized struct that *borrows from that string* (dependent).
//
// This solves "tie the lifetime of the borrowed fields to the owned buffer"
// without cloning the string and without requiring DeserializeOwned.
self_cell::self_cell! {
    struct MyDataCell {
        owner: String,
        #[covariant]
        dependent: MyData,
    }
}

fn parse_once(json: String) -> MyDataCell {
    MyDataCell::new(json, |s| {
        serde_json::from_str::<MyData>(s).expect("valid JSON")
    })
}

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::channel::<String>(8);

    // Simulate an incoming JSON payload from TCP, etc.
    tx.send(r#"{"data":"hello","more_data":"world"}"#.to_string())
        .await
        .unwrap();
    drop(tx);

    while let Some(json_payload) = rx.recv().await {
        // Deserialize exactly once into a borrowed struct tied to the owned string.
        let cell = Arc::new(parse_once(json_payload));

        // Now you can move `Arc<MyDataCell>` into multiple spawned tasks.
        // No cloning of the underlying JSON string; the Arc clone is cheap.
        let t1_cell = Arc::clone(&cell);
        let t1 = tokio::spawn(async move {
            t1_cell.with_dependent(|_json, parsed| {
                println!("task1: data='{}'", parsed.data);
            });
        });

        let t2_cell = Arc::clone(&cell);
        let t2 = tokio::spawn(async move {
            t2_cell.with_dependent(|_json, parsed| {
                println!("task2: more_data='{}'", parsed.more_data);
            });
        });

        t1.await.unwrap();
        t2.await.unwrap();

        // You can also access both the raw JSON and the parsed view together.
        cell.with_dependent(|json, parsed| {
            println!("main: raw_json={json}");
            println!("main: parsed={parsed:?}");
        });
    }
}
"
}
