use rustyline::history::DefaultHistory;
use rustyline::Editor;
use std::error::Error;
use std::io::{self, BufRead, BufReader, Write};
use std::process::{Command, Stdio};
use std::sync::mpsc;
use std::thread;
use std::time::Duration;

fn run_child() -> io::Result<()> {
    let (stop_tx, stop_rx) = mpsc::channel::<()>();

    // Periodic output, independent of stdin.
    let ticker = thread::spawn(move || {
        let mut n = 0u64;
        let mut out = io::stdout();
        loop {
            if stop_rx.try_recv().is_ok() {
                break;
            }
            n += 1;
            let _ = writeln!(out, "child: tick {n}");
            let _ = out.flush();
            thread::sleep(Duration::from_millis(1200));
        }
    });

    // Initial banner
    {
        let mut out = io::stdout();
        writeln!(out, "child: ready (type 'exit' to quit)")?;
        out.flush()?;
    }

    let stdin = io::stdin();
    let mut out = io::stdout();
    for line in stdin.lock().lines() {
        let line = match line {
            Ok(l) => l,
            Err(_) => break,
        };
        let cmd = line.trim_end();
        if cmd.eq_ignore_ascii_case("exit") || cmd.eq_ignore_ascii_case("quit") {
            writeln!(out, "child: bye")?;
            out.flush()?;
            break;
        }
        writeln!(out, "child: got -> {cmd}")?;
        out.flush()?;
    }

    let _ = stop_tx.send(());
    let _ = ticker.join();
    Ok(())
}

fn run_parent() -> Result<(), Box<dyn Error>> {
    let exe = std::env::current_exe()?;

    let mut child = Command::new(exe)
        .arg("--child")
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .spawn()?;

    let mut child_stdin = child.stdin.take().ok_or("missing child stdin")?;
    let child_stdout = child.stdout.take().ok_or("missing child stdout")?;

    let mut rl = Editor::<(), DefaultHistory>::new()?;

    // Key part: an ExternalPrinter lets another thread print while readline() is active.
    // Rustyline will redraw the prompt + current input buffer afterwards.
    let printer = rl.create_external_printer()?;

    let reader_handle = thread::spawn(move || {
        let reader = BufReader::new(child_stdout);
        for line in reader.lines().flatten() {
            // If the main thread exits, this may fail; ignore.
            let _ = printer.print(line);
        }
    });

    loop {
        match rl.readline("> ") {
            Ok(line) => {
                let line = line.trim_end().to_string();
                if !line.is_empty() {
                    let _ = rl.add_history_entry(line.as_str());
                }

                writeln!(child_stdin, "{line}")?;
                child_stdin.flush()?;

                if line.eq_ignore_ascii_case("exit") || line.eq_ignore_ascii_case("quit") {
                    break;
                }
            }
            Err(ReadlineError::Interrupted) => {
                // Ctrl-C: keep going
                continue;
            }
            Err(ReadlineError::Eof) => {
                // Ctrl-D: exit
                break;
            }
            Err(e) => {
                eprintln!("readline error: {e}");
                break;
            }
        }
    }

    // Close child's stdin so it can exit if it wants.
    drop(child_stdin);
    let _ = child.wait();
    let _ = reader_handle.join();

    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    if std::env::args().any(|a| a == "--child") {
        run_child()?;
        return Ok(());
    }

    run_parent()
}
"
}
