    // Prevent `..` traversal.
    for c in rel_path.components() {
        if matches!(c, Component::ParentDir | Component::Prefix(_)) {
            return None;
        }
    }

    Some(root.join(rel_path))
}

async fn file_response(path: &Path) -> Result<Response<BoxedBody>, io::Error> {
    let meta = tokio::fs::metadata(path).await?;
    if !meta.is_file() {
        return Ok(simple_response(StatusCode::NOT_FOUND, "Not Found"));
    }

    let len = meta.len();
    let file = tokio::fs::File::open(path).await?;

    // Turn AsyncRead (File) -> Stream<Bytes> -> Stream<Frame<Bytes>> -> Body
    let stream = ReaderStream::new(file).map_ok(Frame::data);
    let body = StreamBody::new(stream).boxed();

