tokio::sync::broadcast::{self, Sender};
tokio_stream::{wrappers::BroadcastStream, Stream, StreamExt};

#[derive(Debug, Clone)]
struct Event {
    n: u64,
}

/// The only strong owner of the broadcast sender.
/// Dropping this handle closes the channel for all receivers.
struct EventChannelOwner {
    tx: Arc<Sender<Event>>,
}

pub fn events_channel() -> (EventSender, EventStreamFactory, EventChannelOwner) {
    let (tx, _) = broadcast::channel(20);
    let tx = Arc::new(tx);

    let owner = EventChannelOwner { tx: tx.clone() };

    // Everyone else only gets Weak references so they don't keep the channel alive.
    let weak = Arc::downgrade(&tx);
    (
        EventSender { tx: weak.clone() },
        EventStreamFactory { tx: weak },
        owner,
    )
}

#[derive(Debug, Clone)]
pub struct EventSender {
    tx: std::sync::Weak<Sender<Event>>,
}

impl EventSender {
    /// Returns false if the channel is already shut down.
    pub fn send(&self, event: Event) -> bool {
        let Some(tx) = self.tx.upgrade() else {
            return false;
        };

        // For broadcast, send() can also fail if there are no receivers.
        // Here we treat any error as "stop trying".
        tx.send(event).is_ok()
    }
}

pub struct EventStreamFactory {
    tx: std::sync::Weak<Sender<Event>>,
}

impl EventStreamFactory {
    pub fn all_events(
        &self,
    ) -> impl Stream<Item = Result<Event, ()>> + Send + Unpin + 'static {
        let Some(tx) = self.tx.upgrade() else {
            // Already shut down; return an empty stream.
            return tokio_stream::empty();
        };

        // When the last Sender is dropped, the underlying Receiver returns Closed,
        // and BroadcastStream ends (returns None).
        BroadcastStream::new(tx.subscribe()).filter_map(|item| async move {
            match item {
                Ok(ev) => Some(Ok(ev)),
                Err(_lagged) => {
                    // For SSE you'd probably log and continue.
                    Some(Err(()))
                }
            }
        })
    }
}

#[tokio::main]
async fn main() {
    let (event_sender, event_stream_factory, owner) = events_channel();

    // Create a stream consumer (think: SSE response body task).
    let mut stream = event_stream_factory.all_events();
    let consumer = tokio::spawn(async move {
        while let Some(item) = stream.next().await {
            match item {
                Ok(ev) => println!("SSE got event: {:?}", ev),
                Err(()) => println!("SSE stream lagged"),
            }
        }
        println!("SSE stream ended (channel closed)");
    });

    // Spawn a producer that holds only a Weak reference (via EventSender clone).
    let producer_sender = event_sender.clone();
    let producer = tokio::spawn(async move {
        let mut n = 0u64;
        loop {
            n += 1;
            if !producer_sender.send(Event { n }) {
                println!("Producer stopping: channel is shut down");
                break;
            }
            tokio::time::sleep(Duration::from_millis(300)).await;
        }
    });

    println!("Running. Press Ctrl+C to shut down...");
    let _ = tokio::signal::ctrl_c().await;
    println!("Ctrl+C received. Dropping the last strong Sender...");

    // The key: drop the only strong owner. All Weak clones stop keeping the channel alive.
    drop(owner);

    let _ = producer.await;
    let _ = consumer.await;

    println!("Shutdown complete");
}
