const BYTES_PER_PIXEL: usize = 4;

/// Flip a single line of 4-byte pixels in-place.
///
/// This prefers swapping `u32` pixels (fewer operations, often better codegen),
/// with a safe fallback to swapping 4 bytes when the input isn't 4-byte aligned.
fn flip_line(line_bytes: &mut [u8]) {
    assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0);

    // Fast path: treat as u32 pixels if properly aligned.
    let p = line_bytes.as_mut_ptr();
    let aligned_to_u32 = (p as usize) % std::mem::align_of::<u32>() == 0;

