    let mut left = 0usize;
    let mut right = line_bytes.len() - BYTES_PER_PIXEL;
    while left < right {
        unsafe {
            ptr::swap_nonoverlapping(p.add(left), p.add(right), BYTES_PER_PIXEL);
        }
        left += BYTES_PER_PIXEL;
        right -= BYTES_PER_PIXEL;
