        // These can be Relaxed because mutual exclusion is provided by the CS.
        // No other thread/core can read or write `x` concurrently *if all access
        // is done under the same CS*.
        let old = x.load(Ordering::Relaxed);
        x.store(old.wrapping_add(inc), Ordering::Relaxed);
        old
    })
}

fn main() {
    // We'll stress this from multiple OS threads to show that the CS-based
    // implementation produces unique indices.
    //
    // On desktop, `critical-section` with feature `std` uses a global lock.
    let counter = Arc::new(AtomicUsize::new(0));

    let seen = Arc::new(Mutex::new(HashSet::new()));

    let threads = 8;
    let per_thread = 50_000;

    let mut handles = Vec::new();
    for _ in 0..threads {
        let counter = Arc::clone(&counter);
        let seen = Arc::clone(&seen);

        handles.push(thread::spawn(move || {
            for _ in 0..per_thread {
                let idx = fetch_add_via_critical_section(&counter, 1);
                let mut set = seen.lock().unwrap();
                if !set.insert(idx) {
                    panic!("duplicate index observed: {idx}");
                }
            }
        }));
    }

    for h in handles {
        h.join().unwrap();
    }

    let final_val = counter.load(Ordering::Relaxed);
    let expected = threads * per_thread;
    assert_eq!(final_val, expected, "final counter value mismatch");

    let set_len = seen.lock().unwrap().len();
    assert_eq!(set_len, expected, "did not observe all unique indices");

    println!(
        "OK: observed {set_len} unique indices; final counter = {final_val}."
    );

    // For comparison, the plain atomic version on platforms with native atomics:
    let a = AtomicUsize::new(0);
    let r0 = a.fetch_add(1, Ordering::Relaxed);
    let r1 = a.fetch_add(1, Ordering::Relaxed);
    println!("native fetch_add(Relaxed): returned {r0}, {r1}; now {}", a.load(Ordering::Relaxed));
}
