fn spawn_signals(msg_tx: Sender<Message>) -> (SignalsHandle, thread::JoinHandle<()>) {
    let mut signals = Signals::new([SIGINT, SIGTERM]).expect("signals");
    let handle = signals.handle();

    let join = thread::spawn(move || {
        // This blocks waiting for OS signals.
        // Calling `handle.close()` from another thread will unblock and end the iterator.
        for sig in signals.forever() {
