    let (shutdown_keys_tx, shutdown_keys_rx) = unbounded::<()>();
    let (shutdown_tick_tx, shutdown_tick_rx) = unbounded::<()>();

    let keys_join = spawn_keys(msg_tx.clone(), shutdown_keys_rx);
    let tick_join = spawn_ticker(msg_tx.clone(), shutdown_tick_rx);

    #[cfg(unix)]
    let (signals_handle, signals_join) = spawn_signals(msg_tx.clone());
    #[cfg(not(unix))]
    let (_signals_handle, signals_join) = spawn_signals(msg_tx.clone());

    // Event loop.
    let mut shutting_down = false;
    while let Ok(msg) = msg_rx.recv() {
        match msg {
            Message::Tick => {
                eprintln!("tick");
            }
            Message::Key('q') => {
