            }
            Message::Signal(sig) => {
                eprintln!("signal {sig} -> shutdown");
                shutting_down = true;
            }
        }

        if shutting_down {
            // Stop the threads that are polling.
            let _ = shutdown_keys_tx.send(());
            let _ = shutdown_tick_tx.send(());

            // Stop the signal iterator (this is the key piece for a blocking iterator).
            #[cfg(unix)]
            signals_handle.close();

            break;
        }
    }

    let _ = keys_join.join();
    let _ = tick_join.join();
    let _ = signals_join.join();

    eprintln!("bye");
