use serde_json::Value;
use std::collections::HashMap;
use std::error::Error;
use std::fs;
use std::path::{Path, PathBuf};

#[derive(Deserialize, Debug)]
struct A {
    path_list: Vec<PathBuf>,
}

fn main() -> Result<(), Box<dyn Error>> {
    // Self-contained demo: create the example files next to the binary's cwd.
    // Remove these writes if you already have your own a.json / b.json.
    fs::write(
        "a.json",
        r#"{
