        "./a/b/c/def",
        "./g/h/i/jkl"
    ]
}"#,
    )?;

    fs::write(
        "b.json",
        r#"{
    "path_list": {
        "$ref": "./a.json#/p_list"
    }
}"#,
    )?;

    let a_obj = load_with_refs("b.json")?;
    for p in &a_obj.path_list {
        println!("{}", p.display());
    }

    Ok(())
}

fn load_with_refs(path: impl AsRef<Path>) -> Result<A, Box<dyn Error>> {
    let path = path.as_ref();
    let base_dir = path.parent().unwrap_or_else(|| Path::new("."));

    let root_text = fs::read_to_string(path)?;
    let mut root: Value = serde_json::from_str(&root_text)?;

    let mut cache: HashMap<PathBuf, Value> = HashMap::new();
    resolve_refs_in_place(&mut root, base_dir, &mut cache)?;

    let a: A = serde_json::from_value(root)?;
    Ok(a)
}

/// Recursively resolves objects of the form { "$ref": "file.json#/pointer" }.
fn resolve_refs_in_place(
    v: &mut Value,
    base_dir: &Path,
    cache: &mut HashMap<PathBuf, Value>,
) -> Result<(), Box<dyn Error>> {
    match v {
        Value::Object(map) => {
            // JSON Reference object?
            if map.len() == 1 {
                if let Some(Value::String(r)) = map.get("$ref") {
                    let resolved = resolve_ref(r, base_dir, cache)?;
                    *v = resolved;
                    // The resolved value may contain further $ref.
                    resolve_refs_in_place(v, base_dir, cache)?;
                    return Ok(());
                }
            }

            // Otherwise recurse into members.
            for (_, child) in map.iter_mut() {
                resolve_refs_in_place(child, base_dir, cache)?;
            }
            Ok(())
        }
        Value::Array(arr) => {
            for child in arr.iter_mut() {
                resolve_refs_in_place(child, base_dir, cache)?;
            }
            Ok(())
        }
        _ => Ok(()),
    }
}

fn resolve_ref(
    r: &str,
    base_dir: &Path,
    cache: &mut HashMap<PathBuf, Value>,
) -> Result<Value, Box<dyn Error>> {
    // Format: "./a.json#/p_list" (file part optional; fragment optional)
    let (file_part, frag_part) = match r.split_once('#') {
        Some((f, frag)) => (f, Some(frag)),
        None => (r, None),
    };

    // Resolve referenced file path relative to the current document.
    let file_path = if file_part.is_empty() {
        return Err("$ref without a file path is not supported in this demo".into());
    } else {
        base_dir.join(file_part)
    };

    // Load referenced document (cached).
    let doc = if let Some(v) = cache.get(&file_path) {
        v.clone()
    } else {
        let txt = fs::read_to_string(&file_path)?;
        let parsed: Value = serde_json::from_str(&txt)?;
        cache.insert(file_path.clone(), parsed.clone());
        parsed
    };

    // Apply JSON Pointer fragment, if present.
    let out = match frag_part {
        None | Some("") => doc,
        Some(frag) => {
            // In refs, fragment is typically like "/p_list" or "p_list".
            let pointer = if frag.starts_with('/') {
                frag.to_string()
            } else {
                format!("/{}", frag)
            };

            doc.pointer(&pointer)
                .cloned()
                .ok_or_else(|| format!("JSON pointer '{}' not found in {}", pointer, file_path.display()))?
        }
    };

    Ok(out)
}
"
}
