#[derive(Debug, Clone)]
struct UseTreeRepr {
    // Path segments *relative to the parent use-tree*.
    // None means this node is a pure group like `{a, b}`.
    path: Option<Vec<String>>,

    // Leaf modifiers
    glob: bool,              // `*`
    rename: Option<String>,  // `as Foo`

    // Nested group: `path::{...}` or `{...}`
    list: Option<Vec<UseTreeRepr>>,
}

fn main() {
    let code = r#"
// before
use vexide::{devices::smart::*, prelude::*};
use vexide::devices::*;
use vexide::devices::smart::Motor;
use vexide::{devices, fs};
use vexide::devices;
use vexide::devices::{smart, adi};
use {vexide::{devices::{smart, adi}, fs}, core::borrow};
"#;

    println!("INPUT:\n{}", code);

    let parse = SourceFile::parse(code);
    let mut root = parse.tree().syntax().clone_for_update();

    // Collect pointers first; edits invalidate direct references.
    let use_tree_ptrs: Vec<SyntaxNodePtr> = root
        .descendants()
        .filter_map(ast::Use::cast)
        .filter_map(|u| u.use_tree())
        .map(|t| SyntaxNodePtr::new(t.syntax()))
        .collect();

    for ptr in use_tree_ptrs {
        let node = ptr.to_node(&root);
        let Some(old_tree) = ast::UseTree::cast(node) else { continue };

        let old_repr = repr_from_use_tree(&old_tree);
        let mut new_trees = transform(old_repr, &[]);
        if new_trees.is_empty() {
            continue;
        }
        // A top-level use-tree is a single tree; if we ever end up with multiple,
        // wrap them in a `{...}` group.
        let new_repr = if new_trees.len() == 1 {
            new_trees.remove(0)
        } else {
            UseTreeRepr {
                path: None,
                glob: false,
                rename: None,
                list: Some(new_trees),
            }
        };

        let new_tree_text = render(&new_repr);
        let old_tree_text = old_tree.syntax().text().to_string();

        if normalize_ws(&new_tree_text) == normalize_ws(&old_tree_text) {
            continue;
        }

        let replacement = parse_use_tree(&new_tree_text);
        ted::replace(old_tree.syntax(), replacement.syntax());
    }

    let out = root.text().to_string();
    println!("\nOUTPUT:\n{}", out);
}

fn normalize_ws(s: &str) -> String {
    s.split_whitespace().collect::<Vec<_>>().join(" ")
}

fn repr_from_use_tree(t: &ast::UseTree) -> UseTreeRepr {
    let path = t.path().map(|p| split_path(&p));
    let glob = t.star_token().is_some();

    // `Rename` is an AST node; we only need the name on the right side of `as`.
    let rename = t.rename().and_then(|r| r.name()).map(|n| n.text().to_string());

    let list = t.use_tree_list().map(|l| l.use_trees().map(|c| repr_from_use_tree(&c)).collect());

    UseTreeRepr {
        path,
        glob,
        rename,
        list,
    }
}

fn split_path(p: &ast::Path) -> Vec<String> {
    // This is intentionally simple. For `use` paths, splitting by `::` is usually fine.
    p.syntax()
        .text()
        .to_string()
        .split("::")
        .filter(|s| !s.is_empty())
        .map(|s| s.trim().to_string())
        .collect()
}

/// Apply the migration rule: flatten `vexide::devices::X` into `vexide::X`.
///
/// `ctx` is the *full* prefix path accumulated from parents.
///
/// Returns 0+ trees because we sometimes *hoist* children when we delete a path node.
fn transform(mut t: UseTreeRepr, ctx: &[String]) -> Vec<UseTreeRepr> {
    let segs = t.path.clone().unwrap_or_default();
    let full: Vec<String> = ctx.iter().cloned().chain(segs.iter().cloned()).collect();

    let has_list = t.list.is_some();
    let desired_full = drop_devices_after_vexide(&full, has_list, t.glob);

    if let Some(desired_full) = desired_full {
        // Compute new relative segments by stripping the (already-rewritten) ctx.
        let new_segs = if desired_full.starts_with(ctx) {
            desired_full[ctx.len()..].to_vec()
        } else {
            // Fallback: should be rare with top-down rewriting.
            desired_full
        };

        // If removing `devices` would make this node's path empty and it has a list,
        // the correct transformation is to remove the node and lift its children into
        // the parent list: `vexide::{devices::{a,b}}` => `vexide::{a,b}`.
        if new_segs.is_empty() {
            if let Some(children) = t.list.take() {
                return children.into_iter().flat_map(|c| transform(c, ctx)).collect();
            }
            // If it's `...devices::*` inside a list, turning it into `*` is valid.
            // For plain `...{devices}` (no list/glob), we avoid rewriting in
            // `drop_devices_after_vexide`, so we shouldn't end up here.
        }

        t.path = if new_segs.is_empty() { None } else { Some(new_segs) };
    }

    // Recurse (with updated ctx).
    let segs2 = t.path.clone().unwrap_or_default();
    let ctx2: Vec<String> = ctx.iter().cloned().chain(segs2.iter().cloned()).collect();

    if let Some(children) = t.list.take() {
        let new_children: Vec<UseTreeRepr> = children
            .into_iter()
            .flat_map(|c| transform(c, &ctx2))
            .collect();
        t.list = Some(new_children);
    }

    vec![t]
}

fn drop_devices_after_vexide(
    full: &[String],
    has_list: bool,
    is_glob: bool,
) -> Option<Vec<String>> {
    if full.len() >= 2 && full[0] == "vexide" && full[1] == "devices" {
        if full.len() == 2 {
            // Only rewrite `vexide::devices` if it is being used as a prefix
            // (`vexide::devices::{...}` or `vexide::devices::*`).
            if has_list || is_glob {
                return Some(vec!["vexide".to_string()]);
            }
            return None;
        }

        let mut out = Vec::with_capacity(full.len() - 1);
        out.push("vexide".to_string());
        out.extend(full[2..].iter().cloned());
        return Some(out);
    }

    None
}

fn render(t: &UseTreeRepr) -> String {
    // Render children first (if any)
    let children = t
        .list
        .as_ref()
        .map(|xs| xs.iter().map(render).collect::<Vec<_>>().join(", "));

    let path_str = t.path.as_ref().map(|segs| segs.join("::"));

    match (&path_str, children, t.glob, &t.rename) {
        // group
        (Some(p), Some(kids), false, None) => format!("{}::{{{}}}", p, kids),
        (None, Some(kids), false, None) => format!("{{{}}}", kids),

        // glob
        (Some(p), None, true, None) => format!("{}::*", p),
        (None, None, true, None) => "*".to_string(),

        // rename
        (Some(p), None, false, Some(r)) => format!("{} as {}", p, r),

        // simple path
        (Some(p), None, false, None) => p.clone(),

        // Anything else is odd; fall back to something readable.
        _ => {
            let mut s = String::new();
            if let Some(p) = path_str {
                s.push_str(&p);
            }
            if t.glob {
                if !s.is_empty() {
                    s.push_str("::");
                }
                s.push('*');
            }
            if let Some(r) = &t.rename {
                s.push_str(" as ");
                s.push_str(r);
            }
            if let Some(kids) = t.list.as_ref() {
                let kids = kids.iter().map(render).collect::<Vec<_>>().join(", ");
                if !s.is_empty() {
                    s.push_str("::");
                }
                s.push('{');
                s.push_str(&kids);
                s.push('}');
            }
            if s.is_empty() {
                "{}".to_string()
            } else {
                s
            }
        }
    }
}

fn parse_use_tree(tree_text: &str) -> ast::UseTree {
    // Parse a tiny snippet and steal its UseTree node.
    let snippet = format!("use {};", tree_text);
    let parse = SourceFile::parse(&snippet);
    let file = parse.tree();
    let use_item = file
        .syntax()
        .descendants()
        .find_map(ast::Use::cast)
        .expect("snippet must contain a use item");
    use_item
        .use_tree()
        .expect("use item must have a use tree")
}
"
