#[serde(rename_all = "PascalCase")]
enum Gender {
    Masculine,
    Feminine,
}

#[derive(Debug, Default, Clone, PartialEq, Eq, Serialize, Deserialize)]
struct NounData {
    plural: Option<String>,
    gender: Option<Gender>,
}

#[derive(Debug, Default, Clone, PartialEq, Eq, Serialize, Deserialize)]
struct DictWordMetadata {
    noun: Option<NounData>,

    // In your real struct there are many more fields.
    stress: Option<Stress>,
    gender: Option<Gender>,

    // Non-Option fields exist in your real struct; those are *hard* to filter
    // with the same type because JSON omission becomes indistinguishable from
    // "false" / default. We'll handle those via Option<> in the filter type.
    common: bool,
    preposition: bool,
}

// --- Filter types (key idea: everything is optional so "missing" is representable) ---

#[derive(Debug, Default, Clone, PartialEq, Eq, Deserialize)]
#[serde(default)]
struct NounFilter {
    plural: Option<String>,
    gender: Option<Gender>,
}

#[derive(Debug, Default, Clone, PartialEq, Eq, Deserialize)]
#[serde(default)]
struct MetadataFilter {
    noun: Option<NounFilter>,
    stress: Option<Stress>,
    gender: Option<Gender>,
    common: Option<bool>,
    preposition: Option<bool>,
}

// --- Matching helpers ---

trait Matches<F> {
    fn matches_filter(&self, filter: &F) -> bool;
}

fn match_eq<T: PartialEq>(value: &T, filter_value: &Option<T>) -> bool {
    match filter_value {
        None => true,
        Some(wanted) => value == wanted,
    }
}

fn match_opt_eq<T: PartialEq>(value: &Option<T>, filter_value: &Option<T>) -> bool {
    match filter_value {
        None => true,
        Some(wanted) => value.as_ref() == Some(wanted),
    }
}

fn match_opt_nested<T, F>(value: &Option<T>, filter_value: &Option<F>) -> bool
where
    T: Matches<F>,
{
    match filter_value {
        None => true,
        Some(f) => match value {
            Some(v) => v.matches_filter(f),
            None => false,
        },
    }
}

impl Matches<NounFilter> for NounData {
    fn matches_filter(&self, filter: &NounFilter) -> bool {
        match_opt_eq(&self.plural, &filter.plural)
            && match_opt_eq(&self.gender, &filter.gender)
    }
}

impl Matches<MetadataFilter> for DictWordMetadata {
    fn matches_filter(&self, filter: &MetadataFilter) -> bool {
        match_opt_nested(&self.noun, &filter.noun)
            && match_opt_eq(&self.stress, &filter.stress)
            && match_opt_eq(&self.gender, &filter.gender)
            && match_eq(&self.common, &filter.common)
            && match_eq(&self.preposition, &filter.preposition)
    }
}

fn main() {
    // Imagine these are your dictionary entries.
    let m1 = DictWordMetadata {
        noun: Some(NounData {
            plural: Some("casas".to_string()),
            gender: Some(Gender::Feminine),
