    let m2 = DictWordMetadata {
        noun: Some(NounData {
            plural: Some("livros".to_string()),
            gender: Some(Gender::Masculine),
        }),
        stress: Some(Stress::Paroxitona),
        gender: Some(Gender::Masculine),
        common: false,
        preposition: false,
    };

    // Your example filter JSON: only check stress.
    let filter_json = r#"{ "stress": "Oxitona" }"#;
    let filter: MetadataFilter = serde_json::from_str(filter_json).unwrap();

    println!("filter = {filter:?}");
    println!("m1 matches? {}", m1.matches_filter(&filter));
    println!("m2 matches? {}", m2.matches_filter(&filter));

    // Recursive/nested filter example: check noun.gender.
    let nested_filter_json = r#"{ "noun": { "gender": "Feminine" } }"#;
    let nested_filter: MetadataFilter = serde_json::from_str(nested_filter_json).unwrap();

    println!("\nnested_filter = {nested_filter:?}");
    println!("m1 matches? {}", m1.matches_filter(&nested_filter));
    println!("m2 matches? {}", m2.matches_filter(&nested_filter));

    // Mixed filter example: check stress + common flag.
    let mixed_filter_json = r#"{ "stress": "Oxitona", "common": true }"#;
    let mixed_filter: MetadataFilter = serde_json::from_str(mixed_filter_json).unwrap();

