fn load_todos() -> Result<Vec<Todo>, Box<dyn Error>> {
    match fs::read_to_string(FILE_PATH) {
        Ok(s) => {
            let s = s.trim();
            if s.is_empty() {
                return Ok(Vec::new());
            }
            Ok(serde_json::from_str(s)?)
        }
        Err(e) if e.kind() == io::ErrorKind::NotFound => Ok(Vec::new()),
        Err(e) => Err(e.into()),
    }
}

fn save_todos(todos: &[Todo]) -> Result<(), Box<dyn Error>> {
    let json = serde_json::to_string_pretty(todos)?;
    fs::write(FILE_PATH, format!("{}\n", json))?;
    Ok(())
}

fn next_id(todos: &[Todo]) -> u64 {
    todos.iter().map(|t| t.id).max().unwrap_or(0) + 1
}

fn print_usage(program: &str) {
    eprintln!(
        "Usage:\n  {0} list\n  {0} add <text...>\n  {0} done <id>\n  {0} rm <id>",
        program
    );
}

fn main() -> Result<(), Box<dyn Error>> {
    let mut args = std::env::args();
    let program = args.next().unwrap_or_else(|| "todo".to_string());

    let cmd = match args.next() {
        Some(c) => c,
        None => {
            print_usage(&program);
            return Ok(());
        }
    };

    let mut todos = load_todos()?;

    match cmd.as_str() {
        "list" => {
            if todos.is_empty() {
                println!("(no todos)");
            } else {
                for t in &todos {
                    println!(
                        "[{done}] {id}: {text}",
                        done = if t.done { "x" } else { " " },
                        id = t.id,
                        text = t.text
                    );
