                    return Ok(());
                }
            };

            if let Some(t) = todos.iter_mut().find(|t| t.id == id) {
                t.done = true;
                save_todos(&todos)?;
                println!("Marked {id} done");
            } else {
                println!("No todo with id {id}");
            }
        }
        "rm" => {
            let id: u64 = match args.next() {
                Some(s) => s.parse()?,
                None => {
