{
  "Cargo.toml": "[package]
name = "bevy_lazy_archive_loader_demo"
version = "0.1.0"
edition = "2021"

[dependencies]
bevy = "0.14.2"
futures-lite = "2.3"
thiserror = "1.0"
",
  "main.rs": "use bevy::{
    asset::{
        io::{
            file::FileAssetReader, AssetReader, AssetReaderError, AssetSource, AssetSourceId, Reader,
            VecReader,
        },
        AssetApp, AssetLoader, LoadContext,
    },
    prelude::*,
    tasks::IoTaskPool,
    utils::BoxedFuture,
};
use futures_lite::AsyncReadExt;
use std::{
    collections::HashMap,
    io::{Read as _, Seek as _, SeekFrom},
    path::{Path, PathBuf},
};
use thiserror::Error;

/// --- Demo archive format ---
///
/// File layout:
///   magic: [u8; 4] = b"LZAR"
///   entry_count: u32 LE
///   entries: repeated entry_count times
///     name_len: u8
///     name_bytes: [u8; name_len]
///     offset: u64 LE (from start of file)
///     len: u64 LE
///   payload bytes...
const MAGIC: &[u8; 4] = b"LZAR";

fn main() {
    let asset_root = std::env::current_dir().unwrap().join("assets");
    std::fs::create_dir_all(&asset_root).unwrap();

    // Write a demo archive into assets/ so `cargo run` works with no extra files.
    write_demo_archive(&asset_root.join("example.lzar"));

    let mut app = App::new();

    // Install our custom reader for the *default* asset source.
    // This lets you do:
    //   asset_server.load("example.lzar")              -> loads archive index only (loader reads only header+directory)
    //   asset_server.load("example.lzar/hello.etxt")  -> reads only that embedded entry (lazy)
    let base = asset_root.clone();
    app.register_asset_source(
        AssetSourceId::Default,
        AssetSource::build().with_reader(move || Box::new(HybridAssetReader::new(base.clone()))),
    );

    // Headless: no window.
    app.add_plugins(
        DefaultPlugins
            .set(WindowPlugin {
                primary_window: None,
                ..default()
            })
            .set(AssetPlugin {
                // This is still useful for diagnostics and for the default file-based conventions.
                // Our HybridAssetReader also uses this same base directory.
                file_path: asset_root.to_string_lossy().to_string(),
                watch_for_changes: false,
                ..default()
            }),
    );

    app.init_asset::<LazyArchive>();
    app.init_asset::<EmbeddedText>();
    app.register_asset_loader(LazyArchiveLoader);
    app.register_asset_loader(EmbeddedTextLoader);

    app.add_systems(Startup, setup);
    app.add_systems(Update, poll_loaded_and_exit);

    app.run();
}

#[derive(Resource)]
struct Handles {
    archive: Handle<LazyArchive>,
    hello: Handle<EmbeddedText>,
    bye: Handle<EmbeddedText>,
}

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
    // Loads just the index (the loader reads only header+directory and stops).
    let archive: Handle<LazyArchive> = asset_server.load("example.lzar");

    // Loads embedded entries lazily: our AssetReader reads only the needed byte range.
    let hello: Handle<EmbeddedText> = asset_server.load("example.lzar/hello.etxt");
    let bye: Handle<EmbeddedText> = asset_server.load("example.lzar/bye.etxt");

    info!("Requested handles. Waiting for async asset loading...");

    commands.insert_resource(Handles { archive, hello, bye });
}

fn poll_loaded_and_exit(
    handles: Option<Res<Handles>>,
    archives: Res<Assets<LazyArchive>>,
    texts: Res<Assets<EmbeddedText>>,
    mut exit: EventWriter<AppExit>,
) {
    let Some(handles) = handles else { return };

    let archive = archives.get(&handles.archive);
    let hello = texts.get(&handles.hello);
    let bye = texts.get(&handles.bye);

    if let (Some(archive), Some(hello), Some(bye)) = (archive, hello, bye) {
        info!("--- Loaded archive index (without reading payload eagerly) ---");
        info!("Archive path: {:?}", archive.archive_asset_path);
        info!("Entries: {:?}", archive.entries.keys().collect::<Vec<_>>());

        info!("--- Loaded embedded entries (lazy per-entry reads) ---");
        info!("hello.etxt = {:?}", hello.0);
        info!("bye.etxt   = {:?}", bye.0);

        exit.send(AppExit::Success);
    }
}

// -------------------------------------------------------------------------------------------------
// Asset types

#[derive(Asset, TypePath, Debug)]
struct LazyArchive {
    /// Asset-relative path to the archive (e.g. "example.lzar")
    archive_asset_path: PathBuf,
    /// Entry name -> (offset, len)
    entries: HashMap<String, (u64, u64)>,
}

#[derive(Asset, TypePath, Debug)]
struct EmbeddedText(String);

// -------------------------------------------------------------------------------------------------
// Asset loaders

#[derive(Default)]
struct LazyArchiveLoader;

#[derive(Error, Debug)]
enum LazyArchiveLoadError {
    #[error("I/O: {0}")]
    Io(#[from] std::io::Error),
    #[error("Invalid archive: {0}")]
    Invalid(String),
}

impl AssetLoader for LazyArchiveLoader {
    type Asset = LazyArchive;
    type Settings = ();
    type Error = LazyArchiveLoadError;

    fn extensions(&self) -> &[&str] {
        &["lzar"]
    }

    fn load<'a>(
        &'a self,
        reader: &'a mut dyn Reader,
        _settings: &'a Self::Settings,
        load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            // Key point: we only read what we need (header + directory), and do NOT read payload bytes.
            let mut magic = [0u8; 4];
            reader.read_exact(&mut magic).await?;
            if &magic != MAGIC {
                return Err(LazyArchiveLoadError::Invalid(
                    "bad magic (not LZAR)".to_string(),
                ));
            }

            let entry_count = read_u32_le_async(reader).await?;

            let mut entries = HashMap::new();
            for _ in 0..entry_count {
                let name_len = read_u8_async(reader).await? as usize;
                let mut name_bytes = vec![0u8; name_len];
                reader.read_exact(&mut name_bytes).await?;
                let name = String::from_utf8_lossy(&name_bytes).to_string();

                let offset = read_u64_le_async(reader).await?;
                let len = read_u64_le_async(reader).await?;
                entries.insert(name, (offset, len));
            }

            info!(
                "LazyArchiveLoader: read index for {:?} ({} entries); payload not read",
                load_context.path(),
                entries.len()
            );

            Ok(LazyArchive {
                archive_asset_path: load_context.path().to_path_buf(),
                entries,
            })
        })
    }
}

#[derive(Default)]
struct EmbeddedTextLoader;

#[derive(Error, Debug)]
enum EmbeddedTextLoadError {
    #[error("I/O: {0}")]
    Io(#[from] std::io::Error),
    #[error("UTF-8: {0}")]
    Utf8(#[from] std::string::FromUtf8Error),
}

impl AssetLoader for EmbeddedTextLoader {
    type Asset = EmbeddedText;
    type Settings = ();
    type Error = EmbeddedTextLoadError;

    fn extensions(&self) -> &[&str] {
        &["etxt"]
    }

    fn load<'a>(
        &'a self,
        reader: &'a mut dyn Reader,
        _settings: &'a Self::Settings,
        load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            // For embedded assets, our AssetReader already returned only the slice for this entry.
            let mut bytes = Vec::new();
            reader.read_to_end(&mut bytes).await?;
            let s = String::from_utf8(bytes)?;
            info!("EmbeddedTextLoader: loaded {:?}", load_context.path());
            Ok(EmbeddedText(s))
        })
    }
}

// -------------------------------------------------------------------------------------------------
// Custom AssetReader that supports `archive.lzar/inner/path.etxt` as a virtual file.

struct HybridAssetReader {
    base_path: PathBuf,
    fallback: FileAssetReader,
}

impl HybridAssetReader {
    fn new(base_path: PathBuf) -> Self {
        Self {
            fallback: FileAssetReader::new(base_path.clone()),
            base_path,
        }
    }
}

impl AssetReader for HybridAssetReader {
    fn read<'a>(&'a self, path: &'a Path) -> BoxedFuture<'a, Result<Box<dyn Reader>, AssetReaderError>> {
        // If the path contains a `.lzar` component and then more components, treat it as an embedded entry.
        if let Some((archive_rel, inner_rel)) = split_archive_path(path) {
            let archive_fs_path = self.base_path.join(&archive_rel);
            let inner_key = normalize_inner_key(&inner_rel);

            info!(
                "HybridAssetReader: virtual read {:?} (archive={:?}, inner={:?})",
                path, archive_rel, inner_key
            );

            return Box::pin(async move {
                let task = IoTaskPool::get().spawn(async move {
                    load_entry_bytes(archive_fs_path, &inner_key)
                });
                let bytes = task.await??;
                Ok(Box::new(VecReader::new(bytes)) as Box<dyn Reader>)
            });
        }

        // Otherwise, fall back to the normal filesystem reader.
        self.fallback.read(path)
    }

    fn read_meta<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<Box<dyn Reader>, AssetReaderError>> {
        // Embedded assets don't have sidecar `.meta` files in this demo.
        if split_archive_path(path).is_some() {
            return Box::pin(async { Ok(Box::new(VecReader::new(Vec::new())) as Box<dyn Reader>) });
        }
        self.fallback.read_meta(path)
    }

    fn is_directory<'a>(&'a self, path: &'a Path) -> BoxedFuture<'a, Result<bool, AssetReaderError>> {
        // Anything inside an archive is treated as a file-like virtual asset.
        if split_archive_path(path).is_some() {
            return Box::pin(async { Ok(false) });
        }
        self.fallback.is_directory(path)
    }

    fn read_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<Box<dyn bevy::asset::io::PathStream>, AssetReaderError>> {
        // Not needed for this demo.
        // If you want directory listing inside archives, implement it here.
        self.fallback.read_directory(path)
    }

    fn watch_for_changes(
        &self,
        _sender: bevy::asset::io::AssetSourceEventSender,
    ) -> Result<(), AssetReaderError> {
        // Disabled for this demo.
        Ok(())
    }

    fn watch_path_for_changes(
        &self,
        _path: &Path,
        _sender: bevy::asset::io::AssetSourceEventSender,
    ) -> Result<(), AssetReaderError> {
        // Disabled for this demo.
        Ok(())
    }
}

fn split_archive_path(path: &Path) -> Option<(PathBuf, PathBuf)> {
    let mut archive = PathBuf::new();
    let mut iter = path.iter().peekable();

    while let Some(comp) = iter.next() {
        archive.push(comp);
        if archive.extension().is_some_and(|e| e == "lzar") {
            // remainder is the inner path
            let mut inner = PathBuf::new();
            for rest in iter {
                inner.push(rest);
            }
            if inner.as_os_str().is_empty() {
                return None;
            }
            return Some((archive, inner));
        }
    }

    None
}

fn normalize_inner_key(inner: &Path) -> String {
    // Store archive entry keys using forward slashes.
    inner
        .to_string_lossy()
        .replace('\\', "/")
        .trim_start_matches('/')
        .to_string()
}

fn load_entry_bytes(
    archive_fs_path: PathBuf,
    inner_key: &str,
) -> Result<Vec<u8>, AssetReaderError> {
    let index = read_archive_index_blocking(&archive_fs_path)?;

    let (offset, len) = index
        .get(inner_key)
        .copied()
        .ok_or_else(|| AssetReaderError::NotFound(PathBuf::from(inner_key)))?;

    let mut f = std::fs::File::open(&archive_fs_path)?;
    f.seek(SeekFrom::Start(offset))?;

    let mut buf = vec![0u8; len as usize];
    f.read_exact(&mut buf)?;

    Ok(buf)
}

fn read_archive_index_blocking(
    archive_fs_path: &Path,
) -> Result<HashMap<String, (u64, u64)>, AssetReaderError> {
    let mut f = std::fs::File::open(archive_fs_path)?;

    let mut magic = [0u8; 4];
    f.read_exact(&mut magic)?;
    if &magic != MAGIC {
        return Err(AssetReaderError::Io(std::io::Error::new(
            std::io::ErrorKind::InvalidData,
            "bad archive magic",
        )));
    }

    let entry_count = read_u32_le_blocking(&mut f)?;
    let mut map = HashMap::new();

    for _ in 0..entry_count {
        let mut name_len = [0u8; 1];
        f.read_exact(&mut name_len)?;
        let name_len = name_len[0] as usize;

        let mut name_bytes = vec![0u8; name_len];
        f.read_exact(&mut name_bytes)?;
        let name = String::from_utf8_lossy(&name_bytes).to_string();

        let offset = read_u64_le_blocking(&mut f)?;
        let len = read_u64_le_blocking(&mut f)?;
        map.insert(name, (offset, len));
    }

    Ok(map)
}

// -------------------------------------------------------------------------------------------------
// Async helpers (for AssetLoader)

async fn read_u8_async(reader: &mut dyn Reader) -> std::io::Result<u8> {
    let mut b = [0u8; 1];
    reader.read_exact(&mut b).await?;
    Ok(b[0])
}

async fn read_u32_le_async(reader: &mut dyn Reader) -> std::io::Result<u32> {
    let mut b = [0u8; 4];
    reader.read_exact(&mut b).await?;
    Ok(u32::from_le_bytes(b))
}

async fn read_u64_le_async(reader: &mut dyn Reader) -> std::io::Result<u64> {
    let mut b = [0u8; 8];
    reader.read_exact(&mut b).await?;
    Ok(u64::from_le_bytes(b))
}

// Blocking helpers (for archive slicing)

fn read_u32_le_blocking<R: Read>(r: &mut R) -> std::io::Result<u32> {
    let mut b = [0u8; 4];
    r.read_exact(&mut b)?;
    Ok(u32::from_le_bytes(b))
}

fn read_u64_le_blocking<R: Read>(r: &mut R) -> std::io::Result<u64> {
    let mut b = [0u8; 8];
    r.read_exact(&mut b)?;
    Ok(u64::from_le_bytes(b))
}

