fn write_demo_archive(path: &Path) {
    let entries: Vec<(String, Vec<u8>)> = vec![
        (
            "hello.etxt".to_string(),
            b"Hello from inside the archive!\n".to_vec(),
        ),
        (
            "bye.etxt".to_string(),
            b"Goodbye from inside the archive!\n".to_vec(),
        ),
        (
            "nested/folder/also.etxt".to_string(),
            b"Nested entry works too.\n".to_vec(),
        ),
    ];

    let entry_count = entries.len() as u32;

    let directory_len: usize = entries
        .iter()
        .map(|(name, _)| 1 + name.as_bytes().len() + 8 + 8)
        .sum();

    let header_len = 4 + 4;
    let payload_start = (header_len + directory_len) as u64;

    let mut out: Vec<u8> = Vec::new();
    out.extend_from_slice(MAGIC);
    out.extend_from_slice(&entry_count.to_le_bytes());

    // Compute offsets.
    let mut cursor = payload_start;
    let mut offsets: Vec<(u64, u64)> = Vec::new();
    for (_, data) in &entries {
        let len = data.len() as u64;
        offsets.push((cursor, len));
        cursor += len;
    }

    // Directory
    for ((name, _data), (offset, len)) in entries.iter().zip(offsets.iter()) {
        let nb = name.as_bytes();
        assert!(nb.len() <= u8::MAX as usize);
        out.push(nb.len() as u8);
        out.extend_from_slice(nb);
        out.extend_from_slice(&offset.to_le_bytes());
        out.extend_from_slice(&len.to_le_bytes());
    }

    // Payload
    for (_name, data) in entries {
        out.extend_from_slice(&data);
    }

    std::fs::write(path, out).unwrap();
}
"
