#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum Mode {
    Normal,
    SingleQuoted,
    DoubleQuoted,
}

/// Tokenize a shell-like command line.
///
/// Features:
/// - Whitespace splits tokens (only in Normal mode).
/// - Single quotes preserve everything literally until the next single quote.
/// - Double quotes prevent splitting on whitespace.
/// - Backslash escapes the next character in Normal and DoubleQuoted modes.
/// - Adjacent quoted/unquoted parts are concatenated into the same token.
/// - Empty quoted strings produce empty tokens: "''" -> [""]
fn tokenize(input: &str) -> Result<Vec<String>, String> {
    let mut tokens: Vec<String> = Vec::new();
    let mut cur = String::new();
    let mut started = false; // whether we've started a token (even if cur is empty)

    let mut mode = Mode::Normal;
    let mut it = input.chars().peekable();

    while let Some(ch) = it.next() {
        match mode {
            Mode::Normal => match ch {
                // Token separator
                c if c.is_whitespace() => {
                    if started {
                        tokens.push(std::mem::take(&mut cur));
                        started = false;
                    }
                }
                '\'' => {
                    started = true;
                    mode = Mode::SingleQuoted;
                }
                '"' => {
                    started = true;
                    mode = Mode::DoubleQuoted;
                }
                '\\' => {
                    started = true;
                    match it.next() {
                        Some(next) => cur.push(next),
                        None => cur.push('\\'),
                    }
                }
                _ => {
                    started = true;
                    cur.push(ch);
                }
            },

            Mode::SingleQuoted => {
                if ch == '\'' {
                    mode = Mode::Normal;
                } else {
                    started = true;
                    cur.push(ch);
                }
            }

            Mode::DoubleQuoted => match ch {
                '"' => {
                    mode = Mode::Normal;
                }
                '\\' => {
                    started = true;
                    // Simplified double-quote escaping: keep it straightforward.
                    match it.next() {
                        Some('\n') => { /* line continuation */ }
                        Some(next) => cur.push(next),
                        None => cur.push('\\'),
                    }
                }
                _ => {
                    started = true;
                    cur.push(ch);
                }
            },
        }
    }

    if mode != Mode::Normal {
        return Err("unterminated quote".to_string());
    }

    if started {
        tokens.push(cur);
    }

    Ok(tokens)
}

fn main() {
    // Read stdin; if nothing is provided, fall back to a sample.
    let mut buf = String::new();
    io::stdin().read_to_string(&mut buf).unwrap();
    let line = buf.trim_end_matches(&['\r', '\n'][..]);

    let input = if line.trim().is_empty() {
        " one  ' two  'three    four"
    } else {
        line
    };

    match tokenize(input) {
        Ok(args) => {
            println!("{} args:", args.len());
            for a in args {
                println!("<{}>", a);
            }
        }
        Err(e) => {
            eprintln!("error: {e}");
            std::process::exit(2);
        }
    }
}
