    // Since the cube is axis-aligned in *local* space, we can pick stable tangents in local space
    // for each face, then rotate them into world space with the cube rotation.
    let cube_rot = cube_xf.to_scale_rotation_translation().1;

    let n_local = hit.normal_local;
    let (u_local, v_local) = face_tangent_axes_from_normal_local(n_local);

