    let v_world = cube_rot * v_local;
    let n_world = cube_rot * n_local;

    // Build a rotation whose local axes are (X=u_world, Y=v_world, Z=n_world)
    let basis = Mat3::from_cols(u_world, v_world, n_world);
    let indicator_rot = Quat::from_mat3(&basis);

    // Face center: transform the local face-center (normal * 0.5) into world space
    let cube_to_world = cube_xf.compute_matrix();
    let face_center_world = cube_to_world.transform_point3(n_local * 0.5);

    let indicator_pos = face_center_world + n_world * 0.01;

