fn face_tangent_axes_from_normal_local(n: Vec3) -> (Vec3, Vec3) {
    // n is expected to be one of the 6 axis directions in local space.
    // We pick (u, v) so that u x v == n (right-handed), and u/v are stable per-face.
    if n.x.abs() > 0.5 {
        // ±X face
        let u = Vec3::Y;
        let v = if n.x > 0.0 { Vec3::Z } else { -Vec3::Z };
        (u, v)
    } else if n.y.abs() > 0.5 {
        // ±Y face
        let u = Vec3::Z;
        let v = if n.y > 0.0 { Vec3::X } else { -Vec3::X };
        (u, v)
    } else {
        // ±Z face
        let u = Vec3::X;
        let v = if n.z > 0.0 { Vec3::Y } else { -Vec3::Y };
        (u, v)
    }
}

fn raycast_unit_cube_obb(ray_world: Ray3d, cube_xf: GlobalTransform) -> Option<HitInfo> {
    // Transform the ray into cube-local space, intersect with local AABB [-0.5, 0.5]^3,
    // then transform hit point/normal back to world.

    let world_to_local = cube_xf.compute_matrix().inverse();

    let o_local = world_to_local.transform_point3(ray_world.origin);
    let d_local = world_to_local.transform_vector3(ray_world.direction.as_vec3());

    let (t, normal_local) = ray_aabb_unit_cube(o_local, d_local)?;

    let p_local = o_local + d_local * t;

    let local_to_world = cube_xf.compute_matrix();
    let p_world = local_to_world.transform_point3(p_local);

    let cube_rot = cube_xf.to_scale_rotation_translation().1;
    let n_world = (cube_rot * normal_local).normalize_or_zero();

    Some(HitInfo {
        point_world: p_world,
        normal_local,
        normal_world: n_world,
    })
}

fn ray_aabb_unit_cube(origin: Vec3, dir: Vec3) -> Option<(f32, Vec3)> {
    // Intersect ray with AABB min=-0.5, max=0.5.
    // Returns (t_enter, normal_at_enter) in local space.

    let min = Vec3::splat(-0.5);
    let max = Vec3::splat(0.5);

    let mut tmin = f32::NEG_INFINITY;
    let mut tmax = f32::INFINITY;

    let mut hit_axis = 0;
    let mut hit_sign = 1.0;

    for axis in 0..3 {
        let o = origin[axis];
        let d = dir[axis];
        let mn = min[axis];
        let mx = max[axis];

        if d.abs() < 1e-6 {
            if o < mn || o > mx {
                return None;
            }
            continue;
        }

        let mut t1 = (mn - o) / d;
        let mut t2 = (mx - o) / d;
        if t1 > t2 {
            std::mem::swap(&mut t1, &mut t2);
        }

        if t1 > tmin {
            tmin = t1;
            hit_axis = axis;
            // If d>0, we enter through the min plane => outward normal is -axis
            // If d<0, we enter through the max plane => outward normal is +axis
            hit_sign = if d > 0.0 { -1.0 } else { 1.0 };
        }

        tmax = tmax.min(t2);
        if tmin > tmax {
            return None;
        }
    }

    if tmax < 0.0 {
        return None;
    }

    let t = if tmin >= 0.0 { tmin } else { tmax };

    let mut n = Vec3::ZERO;
    n[hit_axis] = hit_sign;
    Some((t, n))
}
