        deserializer.deserialize_any(BVisitor)
    }
}

struct BVisitor;

#[derive(Deserialize)]
#[serde(field_identifier, rename_all = "lowercase")]
enum BField {
    Int,
    Text,
    #[serde(other)]
    Other,
}

impl<'de> Visitor<'de> for BVisitor {
    type Value = B;

    fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
        f.write_str("an integer, a string, or an object with key 'int' or 'text'")
    }

    fn visit_i64<E>(self, v: i64) -> Result<Self::Value, E> {
        Ok(B::Int(v))
    }

    fn visit_u64<E>(self, v: u64) -> Result<Self::Value, E>
    where
        E: de::Error,
    {
        Ok(B::Int(i64::try_from(v).map_err(|_| E::custom("u64 out of range for i64"))?))
    }

    fn visit_str<E>(self, v: &str) -> Result<Self::Value, E> {
        Ok(B::Text(v.to_owned()))
    }

    fn visit_string<E>(self, v: String) -> Result<Self::Value, E> {
        Ok(B::Text(v))
    }

    fn visit_map<M>(self, mut map: M) -> Result<Self::Value, M::Error>
    where
        M: MapAccess<'de>,
    {
        let mut int_val: Option<i64> = None;
        let mut text_val: Option<String> = None;

        while let Some(key) = map.next_key::<BField>()? {
            match key {
                BField::Int => {
                    if int_val.is_some() || text_val.is_some() {
                        return Err(de::Error::duplicate_field("int"));
                    }
                    int_val = Some(map.next_value()?);
                }
                BField::Text => {
                    if int_val.is_some() || text_val.is_some() {
                        return Err(de::Error::duplicate_field("text"));
                    }
                    text_val = Some(map.next_value()?);
                }
                BField::Other => {
                    let _ = map.next_value::<IgnoredAny>()?;
                }
            }
        }

        if let Some(v) = int_val {
            Ok(B::Int(v))
        } else if let Some(v) = text_val {
            Ok(B::Text(v))
        } else {
            Err(de::Error::custom("expected {int: ...} or {text: ...}"))
        }
    }
}

// ---- Custom Deserialize for A (this is where nesting happens: b = Vec<B>) ----

impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_map(AVisitor)
    }
}

struct AVisitor;

#[derive(Deserialize)]
#[serde(field_identifier, rename_all = "lowercase")]
enum AField {
    X,
    B,
    #[serde(other)]
    Other,
}

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
        f.write_str("a map with keys 'x' and 'b'")
    }

    fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut x: Option<usize> = None;
        let mut b: Option<Vec<B>> = None;

        while let Some(key) = map.next_key::<AField>()? {
            match key {
                AField::X => {
                    if x.is_some() {
                        return Err(de::Error::duplicate_field("x"));
                    }
                    x = Some(map.next_value()?);
                }
                AField::B => {
                    if b.is_some() {
                        return Err(de::Error::duplicate_field("b"));
                    }
                    // This is the nested part: since B implements Deserialize,
                    // serde can deserialize Vec<B> automatically.
                    b = Some(map.next_value()?);
                }
                AField::Other => {
                    let _ = map.next_value::<IgnoredAny>()?;
                }
            }
        }

        let x = x.ok_or_else(|| de::Error::missing_field("x"))?;
        let b = b.ok_or_else(|| de::Error::missing_field("b"))?;

        Ok(A { x, b })
    }
}

fn main() {
    // Demonstrates that keys are handled correctly (no borrowed &str key issues)
    // and that b is deserialized as Vec<B> using B's custom deserializer.
    let json = r#"
    {
      "x": 3,
      "b": [
        1,
        "hello",
        {"int": 42},
        {"text": "world"}
      ],
      "ignored": true
    }
    "#;

    let a: A = serde_json::from_str(json).unwrap();
    println!("Deserialized A: {a:#?}");

    // Show it can serialize back (Serialize is derived here).
    let out = serde_json::to_string_pretty(&a).unwrap();
    println!("\nRe-serialized JSON:\n{out}");
}
"
}
```

