    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Count whitespace chars immediately before the cursor.
        let ws_count = line[..pos]
            .chars()
            .rev()
            .take_while(|c| c.is_whitespace())
            .count();

        if ws_count > 0 {
            // Execute multiple actions for one keypress.
            // 1) Kill whitespace to the left
            // 2) Insert the typed punctuation
            Some(Cmd::Macro(vec![
                Cmd::Kill(Movement::BackwardChar(ws_count as RepeatCount)),
