}

async fn list_all_blobs(
    client: &Client,
    account: &str,
    container: &str,
    prefix: &str,
    token: &str,
) -> Result<Vec<String>> {
    let mut out = Vec::new();
    let mut marker: Option<String> = None;

    loop {
        let mut url = Url::parse(&format!(
            "https://{account}.blob.core.windows.net/{container}"
        ))
        .context("parsing container url")?;

        {
            let mut qp = url.query_pairs_mut();
            qp.append_pair("restype", "container");
            qp.append_pair("comp", "list");
            qp.append_pair("maxresults", "5000");
            if !prefix.is_empty() {
                qp.append_pair("prefix", prefix);
            }
            if let Some(m) = &marker {
                if !m.is_empty() {
                    qp.append_pair("marker", m);
                }
            }
        }

        let resp = client
            .get(url)
            .headers(azure_headers(token)?)
            .send()
            .await
            .context("listing blobs")?;

        if !resp.status().is_success() {
            let status = resp.status();
            let body = resp.text().await.unwrap_or_default();
            return Err(anyhow!("list blobs failed: {status} body={body}"));
        }

        let xml = resp.bytes().await.context("reading list blobs response")?;
        let (names, next_marker) = parse_list_blobs_response(&xml)?;
        out.extend(names);

        match next_marker {
            Some(m) if !m.is_empty() => marker = Some(m),
            _ => break,
        }
    }

    Ok(out)
}

fn parse_list_blobs_response(xml: &[u8]) -> Result<(Vec<String>, Option<String>)> {
    // Parse Azure's XML response, extracting:
    // - Blob/Name values
    // - NextMarker
    let mut reader = Reader::from_reader(xml);
    reader.config_mut().trim_text(true);

    let mut buf = Vec::new();
    let mut names = Vec::new();
    let mut next_marker: Option<String> = None;

    // Minimal state machine
    let mut in_blob = false;
    let mut capture_name = false;
    let mut capture_next_marker = false;

    loop {
        match reader.read_event_into(&mut buf) {
            Ok(Event::Start(e)) => {
                match e.name().as_ref() {
                    b"Blob" => in_blob = true,
                    b"Name" if in_blob => capture_name = true,
                    b"NextMarker" => capture_next_marker = true,
                    _ => {}
                }
            }
            Ok(Event::End(e)) => {
                match e.name().as_ref() {
                    b"Blob" => in_blob = false,
                    b"Name" => capture_name = false,
                    b"NextMarker" => capture_next_marker = false,
                    _ => {}
                }
            }
            Ok(Event::Text(t)) => {
                let text = t.unescape().context("unescaping xml text")?.to_string();
                if capture_name {
                    names.push(text);
                } else if capture_next_marker {
                    next_marker = Some(text);
                }
            }
            Ok(Event::Eof) => break,
            Err(e) => return Err(anyhow!("xml parse error: {e}")),
            _ => {}
        }
        buf.clear();
    }

    Ok((names, next_marker))
}

async fn download_blob(client: &Client, account: &str, container: &str, blob_name: &str, token: &str) -> Result<Vec<u8>> {
    let url = blob_url(account, container, blob_name)?;
    let resp = client
        .get(url)
        .headers(azure_headers(token)?)
        .send()
        .await
        .with_context(|| format!("downloading blob {blob_name}"))?;

    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        bail!("download failed for {blob_name}: {status} body={body}");
    }

    let bytes = resp
        .bytes()
        .await
        .with_context(|| format!("reading blob body {blob_name}"))?;

    Ok(bytes.to_vec())
}

fn blob_url(account: &str, container: &str, blob_name: &str) -> Result<Url> {
    // blob_name may contain '/' (virtual directories). Encode each segment.
    let encoded_path = blob_name
        .split('/')
        .map(|seg| utf8_percent_encode(seg, PATH_SEGMENT_ENCODE_SET).to_string())
        .collect::<Vec<_>>()
        .join("/");

    Url::parse(&format!(
        "https://{account}.blob.core.windows.net/{container}/{encoded_path}"
    ))
    .context("parsing blob url")
}

fn azure_headers(token: &str) -> Result<HeaderMap> {
    // With OAuth for Blob REST, include x-ms-date and x-ms-version.
    let mut headers = HeaderMap::new();

    let auth_value = HeaderValue::from_str(&format!("Bearer {token}"))
        .context("building Authorization header")?;
    headers.insert(AUTHORIZATION, auth_value);

    headers.insert(
        "x-ms-version",
        HeaderValue::from_static("2020-10-02"),
    );

    let date = fmt_http_date(SystemTime::now());
    headers.insert(
        "x-ms-date",
        HeaderValue::from_str(&date).context("building x-ms-date header")?,
    );

    Ok(headers)
}
