                eprintln!("connected to dogstatsd UDS at: {socket_path}");
                let unix_sink = BufferedUnixMetricSink::from(socket_path, sock);
                return Ok(QueuingMetricSink::from(unix_sink));
            }
            Err(e) => {
                retries += 1;
                eprintln!(
                    "dogstatsd UDS not ready (attempt {retries}/{max_retries}): {e}; retrying in {:?}",
                    retry_delay
                );
                if retries >= max_retries {
                    return Err(anyhow!(
                        "failed to connect to dogstatsd unix socket after {max_retries} attempts: {socket_path}"
                    ));
                }
                thread::sleep(retry_delay);
            }
        }
    }
