fn main() -> Result<()> {
    // Defaults chosen to match common Datadog agent UDS path on ECS/Fargate
    let socket_path = env::var("DOGSTATSD_SOCKET")
        .or_else(|_| env::var("DD_DOGSTATSD_SOCKET"))
        .unwrap_or_else(|_| "/var/run/datadog/dsd.socket".to_string());

    let prefix = env::var("METRIC_PREFIX").unwrap_or_else(|_| "rust_smoketest".to_string());

    // How long to run
    let seconds: u64 = env::var("RUN_SECONDS")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(15);

    // Target send rate (approx). Set to 0 to run as fast as possible.
    let per_second: u64 = env::var("METRICS_PER_SECOND")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(5_000);

    let max_retries: usize = env::var("CONNECT_RETRIES")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(30);

    let retry_delay_ms: u64 = env::var("CONNECT_RETRY_DELAY_MS")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(500);

    let sink = connect_uds_sink(
        &socket_path,
        max_retries,
        Duration::from_millis(retry_delay_ms),
    )?;

    let send_errors = Arc::new(AtomicU64::new(0));
    let send_ok = Arc::new(AtomicU64::new(0));

    let err_ctr = send_errors.clone();
    let client = StatsdClient::builder(prefix.as_str(), sink)
        .with_error_handler(move |e| {
            // If packets are too large (many/large tags) or the queue overflows, errors should show here.
            err_ctr.fetch_add(1, Ordering::Relaxed);
            eprintln!("[cadence error] {e:?}");
        })
        .build();

    eprintln!(
        "sending for {seconds}s to {socket_path} (prefix='{prefix}'), target rate ~{per_second}/s"
    );

    let start = Instant::now();
    let deadline = start + Duration::from_secs(seconds);

    // crude pacing
    let mut next_tick = Instant::now();
    let tick = if per_second == 0 {
        Duration::from_secs(0)
    } else {
        Duration::from_nanos(1_000_000_000u64 / per_second.max(1))
    };

    let mut i: u64 = 0;
    while Instant::now() < deadline {
        if per_second != 0 {
            let now = Instant::now();
            if now < next_tick {
                thread::sleep(next_tick - now);
            }
            next_tick += tick;
        }

        // A counter with tags similar to your example.
        // Keep tag values reasonably small; oversized packets can be dropped by the socket.
        client
            .incr_with_tags("operations.count")
            .with_tag("client_name", "smoketest")
            .with_tag("client_version", "0.1.0")
            .with_tag("network", "testnet")
            .with_tag("query", if i % 2 == 0 { "op_a" } else { "op_b" })
            .with_tag("runtime", "rust")
            .try_send()
            .with_context(|| "failed to send metric")?;

        // Also emit a gauge to make it easy to graph "last value".
        client
            .gauge_with_tags("loop.iter", i as f64)
            .with_tag("runtime", "rust")
            .try_send()
            .with_context(|| "failed to send gauge")?;

        send_ok.fetch_add(1, Ordering::Relaxed);
        i += 1;

        if i % 10_000 == 0 {
            let ok = send_ok.load(Ordering::Relaxed);
            let err = send_errors.load(Ordering::Relaxed);
            eprintln!("progress: sent_ok={ok}, send_errors={err}");
        }
    }

    // Give the queuing sink a moment to flush before process exit.
    thread::sleep(Duration::from_millis(500));

    let ok = send_ok.load(Ordering::Relaxed);
    let err = send_errors.load(Ordering::Relaxed);
    let elapsed = start.elapsed().as_secs_f64();
    eprintln!("done: sent_ok={ok}, send_errors={err}, elapsed={elapsed:.3}s");

    Ok(())
}
