  "main.rs": "use anyhow::{Context, Result};
use crossterm::terminal::{disable_raw_mode, enable_raw_mode};
use expectrl::spawn;
use nix::unistd::dup;
use std::env;
use std::fs::File;
use std::io::{Read, Write};
use std::os::unix::io::{AsRawFd, FromRawFd};
use std::thread;

/// Demonstrates a safe full-duplex PTY pattern with expectrl:
///
/// - Spawn a child in a PTY using expectrl.
/// - DUP the PTY master fd into two independent handles:
///   one dedicated reader thread (blocking read), and one writer (stdin -> PTY).
/// - No shared mutex around a single `Session`, so a blocking read never prevents writes.
///
/// Try:
///   cargo run
///   cargo run -- bash -i
///   cargo run -- python3 -q
///   cargo run -- /bin/cat
fn main() -> Result<()> {
    // Command to run inside the PTY.
    // Default: bash (interactive because it's on a PTY).
    let cmd = if env::args().len() > 1 {
        env::args().skip(1).collect::<Vec<_>>().join(" ")
    } else {
        "bash".to_string()
    };

    eprintln!("Spawning PTY child: {cmd:?}");

    // Spawn the process under a PTY.
    // We keep `session` alive for the process lifetime.
    let mut session = spawn(&cmd).with_context(|| format!("spawn({cmd:?}) failed"))?;

    // === Key idea ===
    // Don't share `Session` behind a mutex and do blocking reads while holding it.
    // Instead, duplicate the PTY master fd and create independent `File` handles.
    // A blocking read in one thread won't block a write in another.
    let master_fd = session.as_raw_fd();
    let read_fd = dup(master_fd).context("dup(read_fd) failed")?;
    let write_fd = dup(master_fd).context("dup(write_fd) failed")?;

    // SAFETY: `dup()` returns new owned fds. Converting them into `File` transfers ownership.
    let mut pty_reader = unsafe { File::from_raw_fd(read_fd) };
    let mut pty_writer = unsafe { File::from_raw_fd(write_fd) };

    // Put *our* terminal into raw mode so we forward keystrokes byte-for-byte.
    // (This is similar to what xterm.js is doing for you in a GUI.)
    enable_raw_mode().context("enable_raw_mode failed")?;
    struct RawModeGuard;
    impl Drop for RawModeGuard {
        fn drop(&mut self) {
            let _ = disable_raw_mode();
        }
    }
    let _raw_guard = RawModeGuard;

    // Thread: PTY -> stdout
    let reader_thread = thread::spawn(move || -> Result<()> {
        let mut stdout = std::io::stdout().lock();
        let mut buf = [0u8; 8192];
        loop {
            let n = pty_reader.read(&mut buf).context("PTY read failed")?;
            if n == 0 {
                break;
            }
            stdout.write_all(&buf[..n]).context("stdout write failed")?;
            stdout.flush().ok();
        }
        Ok(())
    });

    // Main thread: stdin -> PTY
    {
        let mut stdin = std::io::stdin().lock();
        let mut buf = [0u8; 4096];
        loop {
            let n = stdin.read(&mut buf).context("stdin read failed")?;
            if n == 0 {
                break;
            }
            pty_writer
                .write_all(&buf[..n])
                .context("PTY write failed")?;
            pty_writer.flush().ok();
        }
    }

    // If stdin closes, wait for the child to exit.
    // (In a GUI, you'd typically keep stdin open and drive writes from UI events.)
    let _ = session.wait();

    // Join reader thread
    match reader_thread.join() {
        Ok(res) => res?,
        Err(_) => anyhow::bail!("reader thread panicked"),
    }

    Ok(())
}
"
}

