/// Parse the ISO-like strings LanceDB shows for timestamps (no timezone, sometimes fractional).
///
/// Examples it accepts:
/// - "1970-01-01T00:00:00"
/// - "2025-08-02T17:35:41.409"
/// - (also supports RFC3339 if it ever includes a timezone, e.g. "...Z" or "+00:00")
fn parse_lancedb_datetime(s: &str) -> Result<DateTime<Utc>> {
    // If Lance ever returns a timezone, prefer RFC3339.
    if let Ok(dt) = DateTime::parse_from_rfc3339(s) {
        return Ok(dt.with_timezone(&Utc));
    }

    // Lance examples shown have no timezone offset, so parse as NaiveDateTime.
    // `%.f` handles optional fractional seconds with a leading dot.
    // Still, we try a couple formats for robustness.
    let formats = [
        "%Y-%m-%dT%H:%M:%S%.f", // with or without fractional seconds
        "%Y-%m-%dT%H:%M:%S",    // just in case
    ];

    for fmt in formats {
        if let Ok(naive) = NaiveDateTime::parse_from_str(s, fmt) {
            return Ok(DateTime::<Utc>::from_naive_utc_and_offset(naive, Utc));
        }
    }

    Err(anyhow!("Unrecognized datetime format: {s}"))
}

