  "main.rs": "use bumpalo::Bump;
use std::fmt::Debug;

// ----- Interners/state -----

#[derive(Debug)]
struct SymbolInterner {
    bump: Bump,
}

impl SymbolInterner {
    fn new() -> Self {
        Self { bump: Bump::new() }
    }

    fn intern<'e>(&'e self, s: &str) -> &'e str {
        self.bump.alloc_str(s)
    }
}

#[derive(Debug)]
struct FilenameInterner {
    bump: Bump,
}

impl FilenameInterner {
    fn new() -> Self {
        Self { bump: Bump::new() }
    }

    fn intern<'e>(&'e self, s: &str) -> &'e str {
        self.bump.alloc_str(s)
    }
}

#[derive(Debug, Clone, Copy)]
struct State<'e> {
    filename: &'e str,
    symbol_interner: &'e SymbolInterner,
}

// ----- Stream + parser output -----

#[derive(Debug)]
struct SStream<'i, 'e> {
    input: &'i str,
    pos: usize,
    state: State<'e>,
}

type ModalResult<T> = Result<T, String>;

#[derive(Debug)]
struct Cons<'e> {
    tag: &'e str,
    car: u32,
    cdr: u32,
}

#[derive(Debug)]
struct ExpectedCons {
    tag: &'static str,
    car: u32,
    cdr: u32,
}

impl<'e> PartialEq<ExpectedCons> for Cons<'e> {
    fn eq(&self, other: &ExpectedCons) -> bool {
        self.tag == other.tag && self.car == other.car && self.cdr == other.cdr
    }
}

// ----- A concrete parser function that returns a value borrowing from State<'e> -----

fn parse_cons<'i, 'e>(input: &mut SStream<'i, 'e>) -> ModalResult<Cons<'e>> {
    let s = &input.input[input.pos..];
    let s = s.trim_start();

    let mut chars = s.chars();
    if chars.next() != Some('(') {
        return Err(format!(
            "{}: expected '(' at position {}",
            input.state.filename, input.pos
        ));
    }

    // A tiny hand-rolled parser for "(NUM . NUM)"
    let after_lparen = &s[1..];
    let after_lparen = after_lparen.trim_start();

    let (car, rest) = parse_u32(after_lparen)?;
    let rest = rest.trim_start();

    let rest = rest
        .strip_prefix('.')
        .ok_or_else(|| format!("{}: expected '.'", input.state.filename))?
        .trim_start();

    let (cdr, rest) = parse_u32(rest)?;
    let rest = rest.trim_start();

    if !rest.starts_with(')') {
        return Err(format!("{}: expected ')'", input.state.filename));
    }

    // Advance position roughly (not important for this demo).
    input.pos = input.input.len() - rest[1..].len();

    let tag = input.state.symbol_interner.intern("cons");
    Ok(Cons { tag, car, cdr })
}

fn parse_u32(s: &str) -> ModalResult<(u32, &str)> {
    let mut end = 0;
    for (i, ch) in s.char_indices() {
        if ch.is_ascii_digit() {
            end = i + ch.len_utf8();
        } else {
            break;
        }
    }
    if end == 0 {
        return Err("expected integer".to_string());
    }
    let n: u32 = s[..end].parse().map_err(|e| e.to_string())?;
    Ok((n, &s[end..]))
}

// ----- The key part: use a trait with a GAT so output can depend on 'e -----

trait LocalParser<'i> {
    type Output<'e>: Debug
    where
        Self: 'e;

    fn parse<'e>(&mut self, input: &mut SStream<'i, 'e>) -> ModalResult<Self::Output<'e>>;
}

// Wrap the function parser in a concrete type.
struct ParseCons;

impl<'i> LocalParser<'i> for ParseCons {
    type Output<'e> = Cons<'e> where Self: 'e;

    fn parse<'e>(&mut self, input: &mut SStream<'i, 'e>) -> ModalResult<Self::Output<'e>> {
        parse_cons(input)
    }
}

// ----- Test helper: constructs State<'e> inside, while still supporting borrowed outputs -----

fn test_input_output<'i, ExOut, P>(input: &'i str, expected_output: &ExOut, mut parser: P)
where
    ExOut: Debug,
    P: LocalParser<'i>,
    for<'e> P::Output<'e>: PartialEq<ExOut> + Debug,
{
    // Everything that produces the 'e lifetime lives inside this function.
    let symbol_interner = SymbolInterner::new();

    let filename_interner = FilenameInterner::new();
    let filename = filename_interner.intern("<test>");

    let state = State {
        filename,
        symbol_interner: &symbol_interner,
    };

    let mut stream = SStream {
        input,
        pos: 0,
        state,
    };

    let parsed = match parser.parse(&mut stream) {
        Ok(v) => v,
        Err(e) => panic!(
            "Failed on:\n\tinput: {input:?}\n\texpected output: {expected_output:?}\n\n{e}"
        ),
    };

    assert_eq!(&parsed, expected_output);
}

fn main() {
    let expected = ExpectedCons {
        tag: "cons",
        car: 1,
        cdr: 2,
    };

    // State is created inside test_input_output, yet the parser output can borrow from it.
    test_input_output("(1 . 2)", &expected, ParseCons);

    println!("ok");
}
"
}

