  "main.rs": "use futures::task::noop_waker_ref;
use std::{
    future::Future,
    pin::Pin,
    task::{Context, Poll},
    time::Duration,
};

enum TryPollResult<T> {
    Ready(T),
    Pending,
}

/// Polls a future once using a noop waker.
///
/// This is useful when you only care whether the future is *immediately* ready.
/// If it returns `Pending`, you should later poll/await it again in a real
/// async context (e.g., a spawned Tokio task) so it gets a proper waker.
fn try_poll<F: Future>(mut fut: Pin<&mut F>) -> TryPollResult<F::Output> {
    let waker = noop_waker_ref();
    let mut cx = Context::from_waker(waker);

    match fut.as_mut().poll(&mut cx) {
        Poll::Ready(v) => TryPollResult::Ready(v),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// A non-async function (but intended to be called from async context) that:
/// - uses the value if the future is immediately ready
/// - otherwise spawns a task to await it
fn use_now_or_spawn<F>(label: &'static str, fut: F)
where
    F: Future<Output = i32> + Send + 'static,
{
    // Pin the future so we can poll it, and (if pending) move it into a task.
    let mut fut = Box::pin(fut);

    match try_poll(fut.as_mut()) {
        TryPollResult::Ready(v) => {
            println!("{label}: ready immediately -> {v}");
        }
        TryPollResult::Pending => {
            println!("{label}: not ready; spawning task to await it...");
            tokio::spawn(async move {
                let v = fut.await;
                println!("{label} (spawned): completed -> {v}");
            });
        }
    }
}

#[tokio::main]
async fn main() {
    // Immediately-ready future (no .await inside)
    use_now_or_spawn("immediate", async { 10 });

    // Not-immediately-ready future
    use_now_or_spawn("delayed", async {
        tokio::time::sleep(Duration::from_millis(200)).await;
        20
    });

    // Give spawned task time to complete.
    tokio::time::sleep(Duration::from_millis(400)).await;
}
"
}
