use std::io::{self, Write};
use std::sync::mpsc;
use std::thread;
use std::time::{Duration, Instant};

struct RawModeGuard;
impl Drop for RawModeGuard {
    fn drop(&mut self) {
        let _ = disable_raw_mode();
    }
}

fn main() -> io::Result<()> {
    // Raw mode makes key events arrive immediately (no need to press Enter).
    enable_raw_mode()?;
    let _raw_mode_guard = RawModeGuard;

    println!("Starting event loop. Press 'q' to quit.");
    println!("This version ticks every second even if you don't press keys.");
    io::stdout().flush()?;

    // Pattern: run blocking input on a separate thread and forward events via a channel.
    let (tx, rx) = mpsc::channel::<Event>();
    thread::spawn(move || {
        while let Ok(ev) = event::read() {
            if tx.send(ev).is_err() {
                break; // main thread went away
            }
        }
    });

    let tick_rate = Duration::from_secs(1);
    let mut next_tick = Instant::now() + tick_rate;

    loop {
        let now = Instant::now();
        let timeout = next_tick
            .checked_duration_since(now)
            .unwrap_or(Duration::from_secs(0));

        match rx.recv_timeout(timeout) {
            Ok(ev) => {
                println!("- Event received: {:?}", ev);
                io::stdout().flush()?;

                if let Event::Key(key) = ev {
                    if key.code == KeyCode::Char('q') {
                        println!("'q' pressed, quitting.");
                        io::stdout().flush()?;
                        break;
                    }
                }
            }
            Err(mpsc::RecvTimeoutError::Timeout) => {
                // Tick time reached
                println!("Tick!");
                io::stdout().flush()?;

                // Keep a stable tick schedule (avoid drift if we were delayed).
                let now = Instant::now();
                while next_tick <= now {
                    next_tick += tick_rate;
                }
            }
            Err(mpsc::RecvTimeoutError::Disconnected) => break,
        }
    }

    Ok(())
}
"
}
