use rustyline::validate::Validator;
use rustyline::{Context, Editor, Helper};

/// This demo shows a practical workaround for the "delete space before '.'" problem:
/// instead of trying to run multiple edit commands from a ConditionalEventHandler
/// (which rustyline can't currently do), make completion *not* insert a trailing
/// space in contexts where the user likely wants to type '.' next.
///
/// Concretely:
/// - Keyword completion inserts a trailing space: "SEL<TAB>" -> "SELECT "
/// - Table completion inserts a trailing space only after FROM/JOIN:
///     "... FROM bo<TAB>" -> "... FROM book "
/// - Table completion *does not* insert a trailing space in SELECT-list context:
///     "SELECT bo<TAB>" -> "SELECT book"   (so you can type ".title" immediately)
#[derive(Clone, Debug, Default)]
struct SqlHelper;

impl Helper for SqlHelper {}
impl Hinter for SqlHelper {
    type Hint = String;
}
impl Highlighter for SqlHelper {}
impl Validator for SqlHelper {}

impl SqlHelper {
    fn keywords() -> &'static [&'static str] {
        &[
            "SELECT", "FROM", "WHERE", "JOIN", "LEFT", "RIGHT", "INNER", "OUTER", "ON",
            "ORDER", "BY", "GROUP", "HAVING", "LIMIT", "OFFSET", "INSERT", "INTO",
            "VALUES", "UPDATE", "SET", "DELETE",
        ]
    }

    fn tables() -> &'static [&'static str] {
        &["book", "author"]
    }

    fn columns(table: &str) -> &'static [&'static str] {
        match table.to_ascii_lowercase().as_str() {
            "book" => &["year", "authorid", "title"],
            "author" => &["id", "name"],
            _ => &[],
        }
    }

    fn is_word_char(c: char) -> bool {
        c.is_ascii_alphanumeric() || c == '_'
    }

    /// Returns (start, end) byte indices for the "current word" at cursor.
    fn word_bounds(line: &str, pos: usize) -> (usize, usize) {
        let pos = pos.min(line.len());
        let mut start = pos;
        let mut end = pos;

        // Expand left over word chars
        while start > 0 {
            let prev = line[..start].chars().next_back().unwrap();
            if Self::is_word_char(prev) {
                start -= prev.len_utf8();
            } else {
                break;
            }
        }

        // Expand right over word chars (not strictly needed for TAB-at-end, but harmless)
        while end < line.len() {
            let next = line[end..].chars().next().unwrap();
            if Self::is_word_char(next) {
                end += next.len_utf8();
            } else {
                break;
            }
        }

        (start, end)
    }

    /// Tokenize input up to `upto` (byte index) into uppercase "words" (letters/digits/_).
    fn tokenize_upper(line: &str, upto: usize) -> Vec<String> {
        let upto = upto.min(line.len());
        let mut out = Vec::new();
        let mut cur = String::new();

        for ch in line[..upto].chars() {
            if Self::is_word_char(ch) {
                cur.push(ch);
            } else if !cur.is_empty() {
                out.push(cur.to_ascii_uppercase());
                cur.clear();
            }
        }
        if !cur.is_empty() {
            out.push(cur.to_ascii_uppercase());
        }
        out
    }

    /// If the cursor is after "<ident>." (optionally with a partial column), return table name.
    fn table_name_before_dot(line: &str, word_start: usize) -> Option<String> {
        // We are completing a word that might be after a '.'
        if word_start == 0 {
            return None;
        }
        let prev_ch = line[..word_start].chars().next_back()?;
        if prev_ch != '.' {
            return None;
        }

        // Find the identifier before '.'
        let mut i = word_start - 1; // points at '.' byte start
        while i > 0 {
            let prev = line[..i].chars().next_back().unwrap();
            if Self::is_word_char(prev) {
                i -= prev.len_utf8();
            } else {
                break;
            }
        }
        let table = line[i..word_start - 1].trim();
        if table.is_empty() {
            None
        } else {
            Some(table.to_string())
        }
    }

    fn has_from_join_context(tokens_before: &[String]) -> bool {
        // If the last significant keyword before the current word is FROM or JOIN,
        // we treat completion as "table name" position and append a space.
        tokens_before
            .last()
            .map(|t| t == "FROM" || t == "JOIN")
            .unwrap_or(false)
    }
}

impl Completer for SqlHelper {
    type Candidate = Pair;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        _ctx: &Context<'_>,
    ) -> Result<(usize, Vec<Pair>), ReadlineError> {
        let (word_start, word_end) = Self::word_bounds(line, pos);
        let prefix = &line[word_start..pos.min(word_end)];

        // Column completion after "table."
        if let Some(table) = Self::table_name_before_dot(line, word_start) {
