            for &col in Self::columns(&table) {
                if col.starts_with(&prefix.to_ascii_lowercase()) {
                    pairs.push(Pair {
                        display: col.to_string(),
                        replacement: col.to_string(), // no trailing space; user may type "," etc.
                    });
                }
            }
            return Ok((word_start, pairs));
        }

        let tokens_before = Self::tokenize_upper(line, word_start);
        let from_join = Self::has_from_join_context(&tokens_before);

        let mut pairs = Vec::new();
        let prefix_upper = prefix.to_ascii_uppercase();
        let prefix_lower = prefix.to_ascii_lowercase();

        // Keywords: include a trailing space in the *replacement*.
        for &kw in Self::keywords() {
            if kw.starts_with(&prefix_upper) {
                pairs.push(Pair {
                    display: kw.to_string(),
                    replacement: format!("{} ", kw),
                });
            }
        }

        // Tables: append a trailing space only in FROM/JOIN context.
        for &t in Self::tables() {
            if t.starts_with(&prefix_lower) {
                pairs.push(Pair {
                    display: t.to_string(),
                    replacement: if from_join {
                        format!("{} ", t)
                    } else {
                        t.to_string()
                    },
                });
            }
        }

        Ok((word_start, pairs))
    }
}

