use tokio::time::sleep;
use tracing::{info, Span};
use tracing_opentelemetry::OpenTelemetrySpanExt;
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt, EnvFilter};

#[derive(Clone)]
struct RequestCtx {
    /// Store the request's *root* tracing span.
    /// Any later callback (on any thread) can create children under this.
    request_span: Span,
}

/// Stage 1 callback (can be called later / on another thread).
async fn stage1(ctx: Arc<RequestCtx>) {
    // Option A (explicit parent): create the stage span as a child of the stored request span.
    let stage_span = tracing::info_span!(parent: &ctx.request_span, "stage1");

    async move {
        info!("stage1 work");
        sleep(Duration::from_millis(30)).await;
        info!("stage1 done");
    }
    // Instrument ensures this span is the *current* span even if polled on different threads.
    .instrument(stage_span)
    .await;
}

/// Stage 2 callback (can be called later / on another thread).
async fn stage2(ctx: Arc<RequestCtx>) {
    // Option B ("rehydrate" root temporarily): enter the request span *just long enough*
    // to create a child span without having to pass `parent: ...` everywhere.
    // (Don't hold the enter-guard across `.await`.)
    let stage_span = {
        let _guard = ctx.request_span.enter();
        tracing::info_span!("stage2")
    };

    async move {
        info!("stage2 work");

        // Simulate that some sub-work happens in a separate task.
        // New tasks do NOT automatically inherit the current span.
        // So, capture `Span::current()` and instrument the spawned task.
        let current = Span::current();
        let jh = tokio::spawn(
            async move {
                // This will become a child of `stage2` because we instrumented the task.
                let upstream_span = tracing::info_span!("upstream");
                async {
                    info!("calling upstream");
                    sleep(Duration::from_millis(25)).await;
                    info!("upstream done");
                }
                .instrument(upstream_span)
                .await;
            }
            .instrument(current),
        );

        jh.await.unwrap();
        info!("stage2 done");
    }
    .instrument(stage_span)
    .await;
}

async fn handle_one_request(request_id: u64) {
    // In a real proxy, you might extract an incoming OpenTelemetry context from headers.
    // Then you'd set it as the parent of the request span with:
    //     request_span.set_parent(extracted_otel_context);
    // Here we just create a fresh root span.
    let request_span = tracing::info_span!("request", request.id = request_id);

    // (Optional) demonstrate that you *can* get/store the otel context for propagation too.
    // If you had to cross a boundary where you can't carry `tracing::Span`, you could store this.
    let _otel_context = request_span.context();

    let ctx = Arc::new(RequestCtx { request_span });

    // Simulate Pingora/Tokio calling stage callbacks at arbitrary times.
    let s1 = {
        let ctx = ctx.clone();
        tokio::spawn(async move {
            sleep(Duration::from_millis(10)).await;
            stage1(ctx).await;
        })
    };

    let s2 = {
        let ctx = ctx.clone();
        tokio::spawn(async move {
            sleep(Duration::from_millis(60)).await;
            stage2(ctx).await;
        })
    };

    s1.await.unwrap();
    s2.await.unwrap();

    // When the last clone of `ctx` (and thus `request_span`) is dropped, the request span ends.
}

fn init_tracing() {
    // Export spans to stdout via OpenTelemetry.
    let exporter = opentelemetry_stdout::SpanExporter::default();
    let processor = SimpleSpanProcessor::new(exporter);

    let provider = TracerProvider::builder()
        .with_span_processor(processor)
        .with_resource(Resource::new(vec![KeyValue::new(
            "service.name",
            "pingora-like-demo",
        )]))
        .build();

    let tracer = provider.tracer("demo-tracer");
    global::set_tracer_provider(provider);

    let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);

    tracing_subscriber::registry()
        .with(
            EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| EnvFilter::new("info")),
        )
        .with(tracing_subscriber::fmt::layer())
        .with(otel_layer)
        .init();
}

#[tokio::main(flavor = "multi_thread", worker_threads = 2)]
async fn main() {
    init_tracing();

    // Run two concurrent requests to show interleaving.
    let r1 = tokio::spawn(handle_one_request(1));
    let r2 = tokio::spawn(handle_one_request(2));

    r1.await.unwrap();
    r2.await.unwrap();

    // Flush OTEL exporter.
    global::shutdown_tracer_provider();
}
