const ALLOWED_ORIGIN: &str = "https://www.example.com";

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt()
        .with_env_filter("info")
        .init();

    // Route-specific middleware: only applies to the websocket endpoint.
    let ws_routes = Router::new()
        .route("/client/{session_id}", get(client_ws_handler))
        .route_layer(from_fn(check_ws_origin));

    let app = Router::new()
        .merge(ws_routes)
        // Regular CORS for non-websocket HTTP endpoints (doesn't protect WS by itself).
        .layer(
            CorsLayer::new()
                .allow_origin(ALLOWED_ORIGIN.parse::<HeaderValue>().unwrap())
                .allow_methods([Method::GET, Method::POST])
                .allow_headers([header::CONTENT_TYPE]),
        );

    let addr: SocketAddr = "0.0.0.0:3000".parse().unwrap();
    info!(%addr, "listening");

    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
    axum::serve(listener, app).await.unwrap();
}

// Middleware that enforces Origin checks for the websocket handshake request.
async fn check_ws_origin<B>(req: Request<B>, next: Next<B>) -> Response {
    let origin = req
        .headers()
        .get(header::ORIGIN)
        .and_then(|v| v.to_str().ok());

    match origin {
        Some(o) if o == ALLOWED_ORIGIN => next.run(req).await,
        Some(o) => {
            warn!(origin = o, "rejected websocket handshake due to origin mismatch");
            StatusCode::FORBIDDEN.into_response()
        }
        None => {
            // Browsers send Origin for WebSocket handshakes.
            // If you want to allow non-browser clients, change this behavior.
            warn!("rejected websocket handshake due to missing Origin header");
            StatusCode::FORBIDDEN.into_response()
        }
    }
}

async fn client_ws_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket(session_id, socket))
}

async fn handle_socket(session_id: String, mut socket: WebSocket) {
    info!(%session_id, "websocket connected");

    while let Some(Ok(msg)) = socket.recv().await {
        match msg {
            Message::Text(text) => {
                // Simple echo
                if socket.send(Message::Text(text)).await.is_err() {
                    break;
                }
            }
            Message::Binary(bin) => {
                if socket.send(Message::Binary(bin)).await.is_err() {
                    break;
                }
            }
            Message::Close(_) => break,
            Message::Ping(p) => {
                if socket.send(Message::Pong(p)).await.is_err() {
                    break;
                }
            }
            Message::Pong(_) => {}
        }
    }

    info!(%session_id, "websocket disconnected");
}
"
}

