    pub path: String,
}

#[derive(Clone, Debug)]
pub struct Response {
    pub body: String,
}

// --------------------
// A single stored handler type
//
// Key design choice (important): the handler takes Request *by value*.
// This makes the produced future 'static, so both sync and async fns can be
// accepted ergonomically with one `add_route`.
// --------------------
type HandlerFn = dyn Fn(Request) -> BoxFuture<'static, Response> + Send + Sync + 'static;

#[derive(Clone)]
pub struct Handler(Arc<HandlerFn>);

impl Handler {
    pub fn call(&self, req: Request) -> BoxFuture<'static, Response> {
        (self.0)(req)
    }
}

// Async handler: `Fn(Request) -> impl Future<Output = Response>`
impl<F, Fut> From<F> for Handler
where
    F: Fn(Request) -> Fut + Send + Sync + 'static,
    Fut: Future<Output = Response> + Send + 'static,
{
    fn from(f: F) -> Self {
        Handler(Arc::new(move |req| Box::pin(f(req))))
    }
}

// Sync handler: `Fn(Request) -> Response`
impl<F> From<F> for Handler
where
    F: Fn(Request) -> Response + Send + Sync + 'static,
{
    fn from(f: F) -> Self {
        Handler(Arc::new(move |req| Box::pin(async move { f(req) })))
    }
}

// --------------------
// Server
// --------------------
pub struct Server {
    routes: HashMap<String, Handler>,
}

impl Server {
    pub fn new() -> Self {
        Self {
            routes: HashMap::new(),
        }
    }

    pub fn add_route<F>(&mut self, path: &str, f: F)
    where
        Handler: From<F>,
    {
        self.routes.insert(path.to_string(), Handler::from(f));
    }

    pub async fn handle(&self, path: &str) -> Response {
        let h = self.routes.get(path).expect("route not found").clone();
        let req = Request {
            path: path.to_string(),
        };
        h.call(req).await
    }
}

// --------------------
// User-side code (example)
// --------------------
fn sync_handler(req: Request) -> Response {
    Response {
        body: format!("sync handler for {}", req.path),
    }
}

async fn async_handler(req: Request) -> Response {
    Response {
        body: format!("async handler for {}", req.path),
    }
}

#[tokio::main]
async fn main() {
    let mut server = Server::new();

    // Same API call works for both sync and async handlers.
    server.add_route("/sync", sync_handler);
    server.add_route("/async", async_handler);

    let r1 = server.handle("/sync").await;
    let r2 = server.handle("/async").await;

    println!("{}", r1.body);
    println!("{}", r2.body);

    // Note:
    // If you insist on handlers of the form `fn(&Request) -> ...` (borrowing),
    // then an `async fn` can produce a future whose concrete type depends on the
    // borrow lifetime. On stable Rust today, that prevents a single blanket impl
    // from accepting both sync fns and arbitrary borrowing async fns without an
    // explicit adapter/wrapper.
}
"
}
```

