pub struct RichTextObject {
    #[serde(rename = "type")]
    pub data_type: String, // Notion uses "type": "text" (or others)
    pub text: TextObject,

    // Keep a few common Notion fields as optional
    #[serde(skip_serializing_if = "Option::is_none")]
    pub plain_text: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub href: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SelectObject {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub id: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub name: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub color: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(untagged)]
pub enum PropertyValue {
    Title { title: Vec<RichTextObject> },
    Url { url: String },
    MultiSelect { multi_select: Vec<SelectObject> },
}

// --------------- Field serializers (attribute-driven) ---------------

fn as_notion_title<S>(value: &String, serializer: S) -> Result<S::Ok, S::Error>
where
    S: Serializer,
{
    let pv = PropertyValue::Title {
        title: vec![RichTextObject {
            data_type: "text".to_string(),
            text: TextObject {
                content: value.clone(),
                link: None,
            },
            plain_text: None,
            href: None,
        }],
    };
    pv.serialize(serializer)
}

fn as_notion_url_opt<S>(value: &Option<String>, serializer: S) -> Result<S::Ok, S::Error>
where
    S: Serializer,
{
    // With `skip_serializing_if = "Option::is_none"`, None typically won't be serialized.
    // This is just a safe fallback.
    match value {
        Some(url) => PropertyValue::Url { url: url.clone() }.serialize(serializer),
        None => serializer.serialize_none(),
    }
}

fn as_notion_multiselect_opt<S>(value: &Option<Vec<Value>>, serializer: S) -> Result<S::Ok, S::Error>
where
    S: Serializer,
{
    match value {
        Some(values) => {
            let options = values
                .iter()
                .map(|v| SelectObject {
                    id: None,
                    color: None,
                    name: Some(format!("{}", v)),
                })
                .collect();

            PropertyValue::MultiSelect {
                multi_select: options,
            }
            .serialize(serializer)
        }
        None => serializer.serialize_none(),
    }
}

