// Note: Rust cannot read custom attributes like #[notion_property(...)] without a proc-macro.
// The simplest fully-self-contained approach is to use serde field attributes to drive the conversion.

#[derive(Debug, Clone, Serialize, Deserialize)]
struct MyUnit {
    // property name in Notion: "Name", property type: title
    #[serde(rename = "Name", serialize_with = "as_notion_title")]
    pub name: String,

    // property name in Notion: "Icon url", property type: url
    #[serde(
        rename = "Icon url",
        skip_serializing_if = "Option::is_none",
        serialize_with = "as_notion_url_opt"
    )]
    pub icon_url: Option<String>,

    // property name in Notion: "Roles", property type: multi_select
    #[serde(
        rename = "Roles",
        skip_serializing_if = "Option::is_none",
        serialize_with = "as_notion_multiselect_opt"
    )]
