    // 1) Serialize using the field-level serializers into the Notion JSON shape.
    let v = serde_json::to_value(unit)?;

    // 2) Convert that JSON object into the desired HashMap<String, PropertyValue>.
    //    (Each field already serialized into the correct PropertyValue JSON shape.)
    let map = serde_json::from_value::<HashMap<String, PropertyValue>>(v)?;
    Ok(map)
