macro_rules! decl_methods {
    ($(fn $name:ident(&self $(, $arg:ident : $arg_ty:ty )* ) -> $ret:ty; )* ) => {
        $(fn $name(&self $(, $arg: $arg_ty )* ) -> $ret;)*
    };
}

macro_rules! forward_to_al_rest {
    ($(fn $name:ident(&self $(, $arg:ident : $arg_ty:ty )* ) -> $ret:ty; )* ) => {
        $(
            fn $name(&self $(, $arg: $arg_ty )* ) -> $ret {
                crate::al::Rest::$name(self $(, $arg )* )
            }
        )*
    };
}

macro_rules! forward_to_rest_dispatch {
    ($(fn $name:ident(&self $(, $arg:ident : $arg_ty:ty )* ) -> $ret:ty; )* ) => {
        $(
            fn $name(&self $(, $arg: $arg_ty )* ) -> $ret {
                crate::bl::RestDispatch::$name(self $(, $arg )* )
            }
        )*
    };
}

mod al {
    use super::*;

    // Abstract trait lives here.
    pub trait Rest {
        rest_api!(decl_methods);
    }

    // Something in the abstract layer that wants a `Rest`.
    pub fn run_job(client: &impl Rest) {
        let a = client.get("/health");
        let b = client.post("/items", "{\"x\":1}");
        let c = client.delete("/items/1");
        println!("[al::run_job] get={a} post={b} delete={c}");
