        }
        fn post(&self, path: &str, body: &str) -> String {
            format!("Foo(POST {}{} body={})", self.base_url, path, body)
        }
        fn delete(&self, path: &str) -> bool {
            // Pretend Foo can delete only under /items
            path.starts_with("/items")
        }
    }

    impl al::Rest for Boo {
        fn get(&self, path: &str) -> String {
            format!("Boo(GET {} auth=Bearer..)", path)
        }
        fn post(&self, path: &str, body: &str) -> String {
            format!("Boo(POST {} token={} body={})", path, self.token, body)
        }
        fn delete(&self, _path: &str) -> bool {
