mod bl {
    use super::*;

    // Adapter trait that enum_dispatch is allowed to use (trait and enum are in same module/crate).
    // It mirrors the API of al::Rest, but we don't manually retype it; we reuse the macro.
    #[enum_dispatch]
    pub trait RestDispatch {
        rest_api!(decl_methods);
    }

