    #[enum_dispatch(RestDispatch)]
    pub enum Item {
        Foo(crate::il::Foo),
        Boo(crate::il::Boo),
    }

    // Optional but often useful: allow passing `Item` anywhere `al::Rest` is expected.
    // We forward `al::Rest` calls to the adapter trait (which then dispatches statically).
    impl crate::al::Rest for Item {
        rest_api!(forward_to_rest_dispatch);
    }

    pub fn run_with_config(use_foo: bool) {
