use std::ops::AsyncFnOnce;
use std::pin::Pin;
use tokio::sync::mpsc::UnboundedSender;

#[derive(Debug)]
pub struct Context(i32);

type BoxFuture<'a> = Pin<Box<dyn Future<Output = ()> + Send + 'a>>;

enum InnerAsyncEvent {
    DoWithContext {
        // Use FnMut so we can call it exactly once while still being object-safe.
        block: Box<dyn for<'a> FnMut(&'a mut Context) -> BoxFuture<'a> + Send>,
    },
}

pub fn with_context_async<B>(work_sender: &UnboundedSender<InnerAsyncEvent>, block: B)
where
    // Accept an async closure (AsyncFnOnce) that takes `&mut Context`.
    B: for<'a> AsyncFnOnce<(&'a mut Context,), Output = ()> + Send + 'static,
    // Crucial: require the produced future to be Send for every `'a`.
    for<'a> <B as AsyncFnOnce<(&'a mut Context,)>>::CallOnceFuture: Send + 'a,
{
    // Turn an `AsyncFnOnce` into an object-safe `FnMut` by storing it in an Option
    // and taking it on the first (and only) call.
    let mut block = Some(block);

    let _ = work_sender.send(InnerAsyncEvent::DoWithContext {
        block: Box::new(move |ctx| {
            let b = block.take().expect("block called more than once");
            Box::pin(async move {
                b(ctx).await;
            })
        }),
    });
}

#[tokio::main(flavor = "multi_thread")]
async fn main() {
    let (tx, mut rx) = tokio::sync::mpsc::unbounded_channel::<InnerAsyncEvent>();

    // Worker task that owns the context and executes events.
    let worker = tokio::spawn(async move {
        let mut ctx = Context(0);
        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { mut block } => {
                    let fut = block(&mut ctx);
                    fut.await;
                }
            }
        }
        ctx
    });

    // Send work from a different OS thread.
    let tx2 = tx.clone();
    let t = std::thread::spawn(move || {
        with_context_async(&tx2, async move |ctx: &mut Context| {
            ctx.0 += 1;
        });

        let add = 41;
        with_context_async(&tx2, async move |ctx: &mut Context| {
            ctx.0 += add;
        });
    });

    t.join().unwrap();

    // Close the channel so the worker finishes.
    drop(tx);

    let ctx = worker.await.unwrap();
    println!("final ctx = {:?}", ctx);
}
