// In a real project you could keep this in (for example) `src/python/script.py`
// and embed it with:
//     const PY_SCRIPT: &str = include_str!("python/script.py");
// (where `src/python/script.py` exists).
const PY_SCRIPT: &str = r#"""
import sys

def main():
    print("Hello from packaged Python script!")
    print("argv:", sys.argv)

if __name__ == "__main__":
    main()
""";

fn find_python() -> io::Result<String> {
    // Try common interpreter names in order.
    for candidate in ["python3", "python"].iter() {
        match Command::new(candidate)
            .arg("--version")
            .stdout(Stdio::null())
            .stderr(Stdio::null())
            .status()
        {
            Ok(status) if status.success() => return Ok((*candidate).to_string()),
            _ => continue,
        }
    }

    Err(io::Error::new(
        io::ErrorKind::NotFound,
        "Could not find a usable Python interpreter (tried: python3, python)",
    ))
}

fn write_packaged_script(dir: &TempDir) -> io::Result<PathBuf> {
    let script_path = dir.path().join("script.py");
    fs::write(&script_path, PY_SCRIPT)?;
    Ok(script_path)
}

fn main() -> ExitCode {
    let python = match find_python() {
        Ok(p) => p,
        Err(e) => {
            eprintln!("{e}");
            return ExitCode::from(127);
        }
    };

    // We write the embedded script to a temp file so we can invoke it as `python script.py`.
    let dir = match TempDir::new() {
        Ok(d) => d,
        Err(e) => {
            eprintln!("Failed to create temp dir: {e}");
            return ExitCode::from(1);
        }
    };

    let script_path = match write_packaged_script(&dir) {
        Ok(p) => p,
        Err(e) => {
            eprintln!("Failed to write packaged script: {e}");
            return ExitCode::from(1);
        }
    };

    // Pass through any CLI args after the Rust program name to the Python script.
    let args: Vec<String> = std::env::args().skip(1).collect();

    let status = match Command::new(&python)
        .arg(&script_path)
        .args(args)
        .stdin(Stdio::inherit())
        .stdout(Stdio::inherit())
        .stderr(Stdio::inherit())
        .status()
    {
        Ok(s) => s,
        Err(e) => {
            eprintln!("Failed to run {python}: {e}");
            return ExitCode::from(1);
        }
    };

    match status.code() {
        Some(code) => ExitCode::from(code as u8),
        None => ExitCode::from(1),
    }
}
