/// Builds a rotation where:
/// - local +Z points along `world_normal`
/// - local +Y / +X are aligned to the block's orientation as much as possible (no arbitrary spin)
fn rotation_flush_to_face(world_normal: Vec3, block_rotation: Quat) -> Quat {
    let n = world_normal.normalize();

    // Use the block's "up" as a reference direction, then project it onto the face plane.
    let mut ref_dir = block_rotation * Vec3::Y;
    let mut tangent = ref_dir - n * ref_dir.dot(n);

    // If the reference is nearly parallel to the normal, use a different axis.
    if tangent.length_squared() < 1e-6 {
        ref_dir = block_rotation * Vec3::X;
        tangent = ref_dir - n * ref_dir.dot(n);
    }

    let x = tangent.normalize();
    let y = n.cross(x).normalize();
    let z = n;

    // Columns are the world-space directions of the gizmo's local X, Y, Z axes.
    let m = Mat3::from_cols(x, y, z);
    Quat::from_mat3(&m)
}

fn draw_face_gizmo(mut gizmos: Gizmos, q: Query<&Transform, With<Block>>) {
    let xf = q.single();

    // Pretend this came from a raycast hit against a cube face.
    // (local +Z face)
    let local_face_normal = Vec3::Z;

    // What a physics raycast typically returns: world-space normal.
    let world_normal = (xf.rotation * local_face_normal).normalize();

    // Center of that face in world space (cube has half-extent 0.5).
    let face_center_world = xf.translation + world_normal * 0.5;

    // Compute the gizmo rotation: flush to face, but also aligned with the cube's rotation.
    let rot = rotation_flush_to_face(world_normal, xf.rotation);

    // Draw a 1x1 rect slightly above the surface to avoid z-fighting.
    gizmos.rect(
        Transform::from_translation(face_center_world + world_normal * 0.01)
            .with_rotation(rot)
            .to_isometry(),
        Vec2::splat(1.0),
        Color::WHITE,
    );

    // Optional: draw the normal.
    gizmos.arrow(
        face_center_world,
        face_center_world + world_normal * 0.4,
        Color::srgb(1.0, 0.2, 0.2),
    );
}
