use bevy::{
    app::{AppExit, ScheduleRunnerPlugin},
    asset::{Asset, AssetApp, AssetLoader, AssetPlugin, LoadContext},
    prelude::*,
    reflect::TypePath,
};
use futures_lite::io::{AsyncReadExt, AsyncSeekExt};
use std::{
    collections::HashMap,
    fs,
    io::Write,
    path::{Path, PathBuf},
    time::Duration,
};

/// An example "sub-asset" type.
///
/// We will load these from a single container file using Bevy's built-in
/// `#label` sub-asset syntax: `asset_server.load("pack.pak#hello")`.
#[derive(Asset, TypePath, Debug, Clone)]
pub struct PakText {
    pub text: String,
}

#[derive(Debug, Clone, Copy)]
struct Entry {
    offset: u64,
    len: u64,
}

/// A loader for a simple container format ("pack") that supports lazy loading by label.
///
/// Key idea:
/// - The *file path* identifies the container (e.g. `pack.pak`)
/// - The *label* identifies which entry to load (e.g. `#hello`)
/// - The loader seeks directly to that entry and reads only its bytes.
#[derive(Default)]
pub struct PakTextLoader {
    // Cache: container_path -> (entry_name -> Entry {offset,len})
    // NOTE: we avoid holding the mutex across `.await`.
    index_cache: std::sync::Mutex<HashMap<PathBuf, HashMap<String, Entry>>>,
}

#[async_trait]
impl AssetLoader for PakTextLoader {
    type Asset = PakText;
    type Settings = ();
    type Error = anyhow::Error;

    async fn load(
        &self,
        reader: &mut bevy::asset::io::Reader,
        _settings: &Self::Settings,
        load_context: &mut LoadContext<'_>,
    ) -> std::result::Result<Self::Asset, Self::Error> {
        // `pack.pak#hello` => path = "pack.pak", label = "hello"
        let asset_path = load_context.asset_path();
        let container_path = asset_path.path().to_path_buf();
        let label = asset_path
            .label()
            .ok_or_else(|| anyhow!("Missing label. Use e.g. pack.pak#hello"))?
            .to_string();

        // Fast path: if index is cached and contains this label, use it.
        if let Some(entry) = {
            let cache = self.index_cache.lock().unwrap();
            cache
                .get(&container_path)
                .and_then(|m| m.get(&label).copied())
        } {
            let bytes = read_entry_bytes(reader, entry).await?;
            let text = String::from_utf8(bytes)
                .with_context(|| format!("Entry '{label}' in {:?} is not valid UTF-8", container_path))?;
            return Ok(PakText { text });
        }

        // Slow path: build index from the container and cache it.
        // This is still "lazy" because we only read the index + the requested entry,
        // not all entries.
        let index = read_index(reader)
            .await
            .with_context(|| format!("Failed reading index from {:?}", container_path))?;

        // Cache the index.
        {
            let mut cache = self.index_cache.lock().unwrap();
            cache.insert(container_path.clone(), index);
        }

        // Now fetch the requested entry.
        let entry = {
            let cache = self.index_cache.lock().unwrap();
            cache
                .get(&container_path)
                .and_then(|m| m.get(&label).copied())
                .ok_or_else(|| {
                    anyhow!(
                        "Entry '{label}' not found in container {:?}. (Did you use the right label?)",
                        container_path
