/// Read and parse the container index.
///
/// Demo format (all little-endian):
/// - u32: entry_count
/// - repeated entry_count times:
///   - u16: name_len
///   - [u8; name_len]: UTF-8 name
///   - u64: offset (from start of file)
///   - u64: len
async fn read_index(reader: &mut bevy::asset::io::Reader) -> Result<HashMap<String, Entry>> {
    reader.seek(std::io::SeekFrom::Start(0)).await?;

    let count = read_u32_le(reader).await? as usize;
    let mut map = HashMap::with_capacity(count);

    for _ in 0..count {
        let name_len = read_u16_le(reader).await? as usize;
        let mut name_bytes = vec![0u8; name_len];
        reader.read_exact(&mut name_bytes).await?;
        let name = String::from_utf8(name_bytes).context("entry name is not valid UTF-8")?;

        let offset = read_u64_le(reader).await?;
        let len = read_u64_le(reader).await?;

        map.insert(name, Entry { offset, len });
    }

    Ok(map)
}

async fn read_entry_bytes(reader: &mut bevy::asset::io::Reader, entry: Entry) -> Result<Vec<u8>> {
    reader.seek(std::io::SeekFrom::Start(entry.offset)).await?;
    let mut buf = vec![0u8; entry.len as usize];
    reader.read_exact(&mut buf).await?;
    Ok(buf)
}

async fn read_u16_le(reader: &mut bevy::asset::io::Reader) -> Result<u16> {
    let mut b = [0u8; 2];
    reader.read_exact(&mut b).await?;
    Ok(u16::from_le_bytes(b))
}

async fn read_u32_le(reader: &mut bevy::asset::io::Reader) -> Result<u32> {
    let mut b = [0u8; 4];
    reader.read_exact(&mut b).await?;
    Ok(u32::from_le_bytes(b))
}

async fn read_u64_le(reader: &mut bevy::asset::io::Reader) -> Result<u64> {
    let mut b = [0u8; 8];
    reader.read_exact(&mut b).await?;
    Ok(u64::from_le_bytes(b))
}

