/// Create a demo pack file with a few "entries".
fn write_demo_pack(path: &Path) -> Result<()> {
    // name -> bytes
    let entries: Vec<(&str, Vec<u8>)> = vec![
        ("hello", b"Hello from inside the pack".to_vec()),
        ("lorem", b"Lorem ipsum dolor sit amet".to_vec()),
        ("unused", b"This entry is never loaded".to_vec()),
    ];

    // Compute index size.
    let count = entries.len() as u32;
    let mut index_size = 4usize; // u32 count
    for (name, _data) in &entries {
        index_size += 2; // u16 name_len
        index_size += name.as_bytes().len();
        index_size += 8; // u64 offset
        index_size += 8; // u64 len
    }

    // Assign offsets.
    let mut offset = index_size as u64;
    let mut index: Vec<(String, Entry)> = Vec::with_capacity(entries.len());
    for (name, data) in &entries {
        let len = data.len() as u64;
        index.push((name.to_string(), Entry { offset, len }));
        offset += len;
    }

    // Write file.
    let mut f = fs::File::create(path).with_context(|| format!("create {:?}", path))?;

    f.write_all(&count.to_le_bytes())?;
    for (name, entry) in &index {
        let name_bytes = name.as_bytes();
        let name_len: u16 = name_bytes
            .len()
            .try_into()
            .map_err(|_| anyhow!("entry name too long"))?;
        f.write_all(&name_len.to_le_bytes())?;
        f.write_all(name_bytes)?;
        f.write_all(&entry.offset.to_le_bytes())?;
        f.write_all(&entry.len.to_le_bytes())?;
    }

    // Data section
    for (_name, data) in &entries {
        f.write_all(data)?;
    }

    Ok(())
}
