fn spawn_signal_thread(tx: Sender<Message>) -> (thread::JoinHandle<()>, SignalsHandle) {
    let mut signals = Signals::new([SIGINT, SIGTERM]).expect("register signals");
    let handle = signals.handle();

    let join = thread::spawn(move || {
        // This loop blocks waiting for signals.
        // It terminates immediately when `handle.close()` is called from another thread.
        for sig in signals.forever() {
            let _ = tx.send(Message::Signal(sig));
            // Treat signals as shutdown in this demo.
            let _ = tx.send(Message::Quit);
        }
    });

    (join, handle)
}

fn spawn_key_thread(tx: Sender<Message>, shutdown: Receiver<()>) -> thread::JoinHandle<()> {
    thread::spawn(move || {
        crossterm::terminal::enable_raw_mode().expect("enable raw mode");

        // Use poll(timeout) so we can also react quickly to shutdown.
        // (No infinite blocking read.)
        let tick = Duration::from_millis(50);
        loop {
            if shutdown.try_recv().is_ok() {
                break;
            }

            if event::poll(tick).unwrap_or(false) {
                if let Ok(Event::Key(key)) = event::read() {
                    match key.code {
                        KeyCode::Char('q') => {
                            let _ = tx.send(Message::Quit);
                            break;
                        }
                        KeyCode::Char(c) => {
                            let _ = tx.send(Message::Key(c));
                        }
                        _ => {}
                    }
                }
            }
        }

        let _ = crossterm::terminal::disable_raw_mode();
    })
}

fn main() {
    let (tx, rx) = unbounded::<Message>();

    // One-shot shutdown broadcast:
    // - main sends one value
    // - workers periodically check it (or have their own close mechanism)
    let (shutdown_tx, shutdown_rx) = crossbeam_channel::bounded::<()>(1);

    let (sig_join, sig_handle) = spawn_signal_thread(tx.clone());
    let key_join = spawn_key_thread(tx.clone(), shutdown_rx.clone());

    eprintln!("Press 'q' to quit, or send SIGINT/SIGTERM (e.g. Ctrl-C). Type letters to see events.");

