impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// Safe, pairwise version:
    /// - no `unsafe`
    /// - updates BOTH `i` and `j` when criterion is met
    /// - only checks each pair once (j > i)
    pub fn build_lists_pairwise_serial(&mut self) {
        let n = self.elems.len();
        for b in &mut self.elems {
            b.nb.clear();
        }

        for i in 0..n {
            for j in (i + 1)..n {
                let (bi, bj) = get2_mut(&mut self.elems, i, j);
                if bi.criterion(bj) < self.cutoff {
                    bi.nb.push(j);
                    bj.nb.push(i);
                }
            }
        }
    }

    /// Parallel pairwise version using Rayon.
    ///
    /// We avoid concurrent mutable borrows of `self.elems` by:
    /// 1) reading positions immutably,
    /// 2) accumulating neighbor lists into `Vec<Mutex<Vec<usize>>>`,
    /// 3) copying the resulting lists into `self.elems[i].nb` sequentially.
    pub fn build_lists_pairwise_parallel(&mut self) {
        let n = self.elems.len();
        let cutoff = self.cutoff;

        // Immutable view for concurrent reads.
        let elems = &self.elems;

        // One neighbor list per element, protected for concurrent pushes.
        let nbs: Vec<Mutex<Vec<usize>>> = (0..n).map(|_| Mutex::new(Vec::new())).collect();

        (0..n).into_par_iter().for_each(|i| {
            for j in (i + 1)..n {
                if elems[i].criterion(&elems[j]) < cutoff {
                    nbs[i].lock().unwrap().push(j);
                    nbs[j].lock().unwrap().push(i);
                }
            }
        });

        // Write results back into the struct.
        for i in 0..n {
            let mut guard = nbs[i].lock().unwrap();
            self.elems[i].nb = std::mem::take(&mut *guard);
        }
    }

    pub fn neighbor_lists(&self) -> Vec<Vec<usize>> {
        self.elems.iter().map(|b| b.nb.clone()).collect()
    }
