    println!("\nParallel neighbor lists:");
    for (i, b) in a2.elems.iter().enumerate() {
        println!("  {i}: {:?}", b.nb);
    }

    // Basic sanity: both methods should match.
    assert_eq!(a1.neighbor_lists(), a2.neighbor_lists());
}
