fn der_encode_length(len: usize) -> Vec<u8> {
    if len < 128 {
        return vec![len as u8];
    }

    let mut tmp = Vec::new();
    let mut n = len;
    while n > 0 {
        tmp.push((n & 0xff) as u8);
        n >>= 8;
    }
    tmp.reverse();

    let mut out = Vec::with_capacity(1 + tmp.len());
    out.push(0x80 | (tmp.len() as u8));
    out.extend_from_slice(&tmp);
    out
}

fn wrap_value_as_der_sequence(value: &[u8]) -> Vec<u8> {
    let mut out = Vec::with_capacity(2 + value.len());
    out.push(0x30); // SEQUENCE
    out.extend_from_slice(&der_encode_length(value.len()));
    out.extend_from_slice(value);
    out
}

/// SCEP / old PKCS#7 encoders are sometimes observed to put SignedData into
/// ContentInfo.content as IMPLICIT [0], which means the `Any` value begins with
/// the SignedData *contents* (starting with INTEGER version), not with the
/// SignedData SEQUENCE tag.
///
/// This helper tries the normal CMS decode first, and if that fails, retries by
/// wrapping the `Any::value()` in a DER SEQUENCE header.
fn decode_signed_data_from_any(any: &Any) -> Result<SignedData> {
    let v = any.value();

    // Normal/expected case (EXPLICIT [0]): `v` starts with 0x30 (SEQUENCE)
    if let Ok(sd) = SignedData::from_der(v) {
        return Ok(sd);
    }

    // Fallback: likely IMPLICIT [0], so `v` starts with version INTEGER (0x02)
    let fixed = wrap_value_as_der_sequence(v);
    let sd = SignedData::from_der(&fixed)
        .context("failed to decode SignedData (normal decode failed; implicit-tag fallback failed too)")?;

    Ok(sd)
}

fn read_input(path: &str, base64_input: bool) -> Result<Vec<u8>> {
