    let base = haystack.as_ptr();
    let ptr = needle.as_ptr();

    // SAFETY: We rely on serde_json borrowing strings directly from the input buffer.
    // If `needle` was borrowed from `haystack`, both pointers are in the same allocation.
    let start = unsafe { ptr.offset_from(base) as usize };
