  "main.rs": "use std::env;

/// Tokenize a command line similarly to a very small subset of bash parsing:
/// - splits on runs of whitespace (space/tab/newline/etc.)
/// - single quotes preserve everything literally until the next single quote
/// - quoted and unquoted segments concatenate into the same token when adjacent
///
/// Example:
///   " one  ' two  'three    four" -> ["one", " two  three", "four"]
fn tokenize(input: &str) -> Vec<String> {
    #[derive(Clone, Copy, Debug, PartialEq, Eq)]
    enum State {
        Unquoted,
        SingleQuoted,
    }

    let mut state = State::Unquoted;
    let mut tokens: Vec<String> = Vec::new();
    let mut cur = String::new();

    for ch in input.chars() {
        match (state, ch) {
            (State::Unquoted, c) if c.is_whitespace() => {
                if !cur.is_empty() {
                    tokens.push(std::mem::take(&mut cur));
                }
            }
            (State::Unquoted, '\'') => {
                state = State::SingleQuoted;
            }
            (State::Unquoted, c) => {
                cur.push(c);
            }

            (State::SingleQuoted, '\'') => {
                state = State::Unquoted;
            }
            (State::SingleQuoted, c) => {
                cur.push(c);
            }
        }
    }

    if !cur.is_empty() {
        tokens.push(cur);
    }

    tokens
}

fn main() {
    // Pass the command string as arguments, e.g.:
    //   cargo run -- " one  ' two  'three    four"
    // If no args are given, we use the example.
    let input = if env::args().len() > 1 {
        env::args().skip(1).collect::<Vec<_>>().join(" ")
    } else {
        " one  ' two  'three    four".to_string()
    };

    let toks = tokenize(&input);

    println!("{} args:", toks.len());
    for t in toks {
        println!("<{}>", t);
    }
}
"
}
