    let a_obj: A = serde_json::from_value(root)?;

    for p in &a_obj.path_list {
        println!("{}", p.display());
    }

    Ok(())
}

fn resolve_refs_in_place(
    v: &mut Value,
    base_dir: &Path,
    cache: &mut HashMap<PathBuf, Value>,
) -> Result<(), Box<dyn Error>> {
    // If this node is exactly {"$ref": "..."}, replace it with the referenced value.
    if let Value::Object(obj) = v {
        if obj.len() == 1 {
            if let Some(Value::String(r)) = obj.get("$ref") {
                let resolved = resolve_ref(r, base_dir, cache)?;
                *v = resolved;
                // The resolved value might itself contain refs.
                return resolve_refs_in_place(v, base_dir, cache);
            }
        }
    }

    match v {
        Value::Array(arr) => {
            for item in arr {
                resolve_refs_in_place(item, base_dir, cache)?;
            }
        }
        Value::Object(map) => {
            for (_k, val) in map.iter_mut() {
                resolve_refs_in_place(val, base_dir, cache)?;
            }
