fn resolve_ref(
    r: &str,
    base_dir: &Path,
    cache: &mut HashMap<PathBuf, Value>,
) -> Result<Value, Box<dyn Error>> {
    // Support "./file.json#/json/pointer" (RFC6901 pointer after '#').
    let (path_part, pointer_part) = match r.split_once('#') {
        Some((p, frag)) => (p, Some(frag)),
        None => (r, None),
    };

    let file_path = base_dir.join(path_part);

    let doc = if let Some(v) = cache.get(&file_path) {
        v.clone()
