        let txt = fs::read_to_string(&file_path)?;
        let parsed: Value = serde_json::from_str(&txt)?;
        cache.insert(file_path.clone(), parsed.clone());
        parsed
    };

    let selected = match pointer_part {
        None | Some("") => doc,
        Some(frag) => {
            // In refs like "#/p_list", `frag` is "/p_list".
