  "main.rs": "use core::sync::atomic::{compiler_fence, AtomicUsize, Ordering};

/// Emulate `AtomicUsize::fetch_add(val, order)` using a critical section.
///
/// Key points (mirrors what you'd do on thumbv6m when you *don't* have real atomics):
/// - The critical section provides *atomicity* for the read-modify-write.
/// - The internal load/store can be `Relaxed` because mutual exclusion prevents races.
/// - If you need Acquire/Release/AcqRel/SeqCst semantics, you must add fences
///   (at least compiler fences) around the critical section.
fn fetch_add_with_cs(a: &AtomicUsize, val: usize, order: Ordering) -> usize {
    critical_section::with(|_| {
        // Acquire barrier: prevent later reads/writes from moving before we "acquired".
        // (For SeqCst we also treat entry as an acquire-like barrier.)
        match order {
            Ordering::Acquire | Ordering::AcqRel => compiler_fence(Ordering::Acquire),
            Ordering::SeqCst => compiler_fence(Ordering::SeqCst),
            Ordering::Relaxed | Ordering::Release => {}
            _ => unreachable!("unsupported ordering for this demo"),
        }

        // The actual RMW, made atomic by the critical section.
        let old = a.load(Ordering::Relaxed);
        a.store(old.wrapping_add(val), Ordering::Relaxed);

        // Release barrier: prevent earlier reads/writes from moving after we "released".
        // (For SeqCst we also treat exit as a seq-cst fence.)
        match order {
            Ordering::Release | Ordering::AcqRel => compiler_fence(Ordering::Release),
            Ordering::SeqCst => compiler_fence(Ordering::SeqCst),
            Ordering::Relaxed | Ordering::Acquire => {}
            _ => unreachable!("unsupported ordering for this demo"),
        }

        old
    })
}

fn main() {
    // In your original code you had:
    //   self.channel_index.fetch_add(1, Ordering::Relaxed)
    // If that is truly the only required semantic, then the critical-section
    // replacement can remain Relaxed (plus the critical section for atomicity).

    let counter = AtomicUsize::new(0);

    // Stress test with threads (on embedded you'd have interrupts/other core instead).
    // This demonstrates that the CS-based RMW is atomic: no lost updates.
    let threads = 8;
    let iters_per_thread = 50_000;

    let mut handles = Vec::new();
    for _ in 0..threads {
        let c_ref: &'static AtomicUsize = unsafe {
            // Leak the reference for simplicity in this demo.
            // (Not needed in real embedded code.)
            &*(&counter as *const AtomicUsize)
        };
        handles.push(std::thread::spawn(move || {
            for _ in 0..iters_per_thread {
                let _idx = fetch_add_with_cs(c_ref, 1, Ordering::Relaxed);
            }
        }));
    }

    for h in handles {
        h.join().unwrap();
    }

    let final_val = counter.load(Ordering::Relaxed);
    let expected = threads * iters_per_thread;
    println!("final counter = {final_val}, expected = {expected}");

    assert_eq!(final_val, expected);

    // Notes for your specific question:
    // - If you replaced `fetch_add(1, Relaxed)` then using Relaxed load/store inside
    //   the critical section is fine.
    // - If the original code used Acquire/Release/AcqRel/SeqCst, you must add fences
    //   around the CS to preserve ordering semantics.
}
