fn apply_edits(src: &str, mut edits: Vec<(TextRange, String)>) -> String {
    // Apply from the end to keep ranges valid.
    edits.sort_by_key(|(r, _)| std::cmp::Reverse(r.start()));

    let mut out = src.to_string();
    for (range, replacement) in edits {
        let start: usize = u32::from(range.start()) as usize;
        let end: usize = u32::from(range.end()) as usize;
        out.replace_range(start..end, &replacement);
    }
    out
}

fn build_replacement_for_use_item(src: &str, range: TextRange, leaves: &[Leaf]) -> String {
    let indent = line_indent_at(src, u32::from(range.start()) as usize);

    // Rebuild as one `use` per leaf.
    // (Semantically equivalent to a nested tree; easier than re-sugaring braces while preserving
    // every formatting edge case.)
    let mut out = String::new();
    for leaf in leaves {
        out.push_str(indent);
        out.push_str("use ");

        let path = leaf.segs.join("::");
        match leaf.kind {
            LeafKind::Glob => {
                out.push_str(&path);
                out.push_str("::*");
            }
            LeafKind::Name => {
                out.push_str(&path);
                if let Some(rename) = &leaf.rename {
                    out.push(' ');
                    out.push_str(rename);
                }
            }
        }

        out.push_str(";\n");
    }

    // Avoid adding *extra* indentation-only lines in some cases.
    // (We always end with a newline; the original file typically had one already.)
    out
