fn line_indent_at<'a>(src: &'a str, byte_offset: usize) -> &'a str {
    let line_start = src[..byte_offset].rfind('\n').map(|i| i + 1).unwrap_or(0);
    let line = &src[line_start..];
    let indent_len = line
        .char_indices()
        .take_while(|&(_, ch)| ch == ' ' || ch == '\t')
        .map(|(i, ch)| i + ch.len_utf8())
        .last()
        .unwrap_or(0);
    &src[line_start..line_start + indent_len]
}

/// Walks a `use` tree and collects leaf imports as *absolute* paths.
fn collect_leaves(tree: &ast::UseTree, prefix: &mut Vec<String>, out: &mut Vec<Leaf>) {
    let mut local_prefix = prefix.clone();

    if let Some(path) = tree.path() {
        for seg in path.segments() {
            local_prefix.push(path_segment_to_string(&seg));
        }
    }

    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            collect_leaves(&child, &mut local_prefix, out);
        }
        return;
    }

    let rename = tree.rename().map(|r| r.syntax().text().to_string());

    if tree.star_token().is_some() {
        out.push(Leaf {
            segs: local_prefix,
            rename: None,
            kind: LeafKind::Glob,
        });
    } else {
        out.push(Leaf {
            segs: local_prefix,
            rename,
            kind: LeafKind::Name,
        });
    }
}

fn path_segment_to_string(seg: &ast::PathSegment) -> String {
    if let Some(name) = seg.name_ref() {
        return name.text().to_string();
    }
    if seg.self_token().is_some() {
        return "self".to_string();
    }
    if seg.super_token().is_some() {
        return "super".to_string();
    }
    if seg.crate_token().is_some() {
        return "crate".to_string();
    }

    // Fallback: preserve original text.
    seg.syntax().text().to_string()
