    fn start_drag(&self, point_id: usize, e: MouseEvent) {
        e.prevent_default();

        let mouse = e.element_coordinates();
        let (mx, my) = (mouse.x, mouse.y);

        // Compute the offset so the point doesn't jump to the mouse position.
        let (px, py) = {
