            file: FilenameCompleter::new(),
            commands: commands.into_iter().map(|s| s.to_string()).collect(),
        }
    }
}

impl Completer for MyCompleter {
    type Candidate = Pair;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        ctx: &Context<'_>,
    ) -> rustyline::Result<(usize, Vec<Pair>)> {
        // Find the start of the "current word".
        let start = line[..pos]
            .rfind(|c: char| c.is_whitespace())
            .map(|i| i + 1)
            .unwrap_or(0);

        // Are we completing the first word (command position)?
        let is_first_word = line[..start].trim().is_empty();

        // If we're not at the command position, complete filenames.
        if !is_first_word {
            return self.file.complete(line, pos, ctx);
