type TodoList = Vec<String>;

fn load_or_default(path: &Path) -> Result<TodoList> {
    if !path.exists() {
        return Ok(Vec::new());
    }

    let data = fs::read_to_string(path)
        .with_context(|| format!("Unable to read file: {}", path.display()))?;

    let trimmed = data.trim();
    if trimmed.is_empty() {
        return Ok(Vec::new());
    }

    let list: TodoList = serde_json::from_str(trimmed)
        .with_context(|| format!("Unable to parse JSON in: {}", path.display()))?;
    Ok(list)
}

fn save(path: &Path, list: &TodoList) -> Result<()> {
    let json = serde_json::to_string_pretty(list).context("Unable to serialize JSON")?;
    fs::write(path, json).with_context(|| format!("Unable to write file: {}", path.display()))?;
    Ok(())
