            } else {
                for (i, item) in list.iter().enumerate() {
                    println!("{}. {}", i + 1, item);
                }
            }
        }
        "add" => {
            let text: String = args.collect::<Vec<_>>().join(" ");
            if text.trim().is_empty() {
                print_usage(&exe);
                anyhow::bail!("Missing todo text");
            }

            let mut list = load_or_default(&path)?;
            list.push(text);
            save(&path, &list)?;
            println!("Saved to {}", path.display());
        }
        "clear" => {
            let list: TodoList = Vec::new();
            save(&path, &list)?;
            println!("Cleared {}", path.display());
        }
        _ => {
            print_usage(&exe);
            anyhow::bail!("Unknown command: {cmd}");
