type BoolObs = LocalBoxedObservableClone<'static, bool, Infallible>;
type PairObs = LocalBoxedObservableClone<'static, (bool, bool), Infallible>;

/// RS latch built from two cross-coupled NAND gates.
///
/// Instead of wiring a re-entrant Subject->next() feedback (which can panic with
/// "RefCell already borrowed" due to synchronous propagation), we model the
/// feedback as state (previous Q/Q̅) and compute the new stable state whenever
/// S or R changes.
fn rs_latch_from_nands(s: BoolObs, r: BoolObs) -> PairObs {
    // Only react when the input pair actually changes.
    let input = s
        .combine_latest(r, |s, r| (s, r))
        .distinct()
        .box_it_clone();

    // Keep the previous stable (q, not_q) as state.
    let state = Rc::new(RefCell::new((true, true)));

    input
        .map({
            let state = state.clone();
            move |(s, r)| {
                let (mut q, mut not_q) = *state.borrow();

                // Iterate until reaching a fixed point (stable latch state).
                // (Small bound to avoid infinite loops on invalid/oscillating setups.)
                for _ in 0..16 {
                    let next_q = !(s && not_q);
                    let next_not_q = !(r && next_q);
                    if next_q == q && next_not_q == not_q {
                        break;
                    }
                    q = next_q;
                    not_q = next_not_q;
                }

                *state.borrow_mut() = (q, not_q);
                (q, not_q)
            }
        })
        .distinct()
        .box_it_clone()
}

