impl<T> Array<T> {
    pub fn from_fn(dims: Vec<usize>, mut f: impl FnMut(usize) -> T) -> Self {
        assert!(!dims.is_empty());
        let len = dims.iter().product();
        let mut store = Vec::with_capacity(len);
        for i in 0..len {
            store.push(f(i));
        }
        Self { store, dims }
    }

    pub fn dims(&self) -> &[usize] {
        &self.dims
    }

    pub fn len(&self) -> usize {
        self.store.len()
    }

    fn to_linear(&self, idx: &[usize]) -> usize {
        assert_eq!(idx.len(), self.dims.len(), "rank mismatch");
        for (i, (&x, &d)) in idx.iter().zip(self.dims.iter()).enumerate() {
            assert!(x < d, "index out of bounds at dim {i}: {x} >= {d}");
        }

        // Row-major: last dimension is contiguous.
        let mut lin = 0usize;
        let mut stride = 1usize;
        for k in (0..self.dims.len()).rev() {
            lin += idx[k] * stride;
            stride *= self.dims[k];
        }
        lin
    }

    pub fn iter(&self) -> ArrayIter<'_, T> {
        ArrayIter {
            array: self,
            lin: 0,
        }
    }

    pub fn iter_mut(&mut self) -> ArrayIterMut<'_, T> {
        // Key idea:
        // Storing `&'a mut Array<T>` directly in the iterator and then returning
        // `&'a mut T` from `next()` is rejected because indexing borrows `self`
        // for the duration of `next()` (lifetime `'1`), and the compiler cannot
        // prove the returned reference lives for `'a`.
        //
        // The standard library solves this for slice::IterMut by storing a raw
        // pointer internally and using `unsafe` to create `&'a mut T` for each
        // disjoint element.
        let len = self.store.len();
        let ptr = self.store.as_mut_ptr();
        ArrayIterMut {
            ptr,
            len,
            lin: 0,
            dims: self.dims.clone(),
            _marker: PhantomData,
        }
    }
}

impl<T> Index<&[usize]> for Array<T> {
    type Output = T;

    fn index(&self, index: &[usize]) -> &Self::Output {
        let lin = self.to_linear(index);
        &self.store[lin]
    }
}

impl<T> IndexMut<&[usize]> for Array<T> {
    fn index_mut(&mut self, index: &[usize]) -> &mut Self::Output {
        let lin = self.to_linear(index);
        &mut self.store[lin]
    }
}

fn linear_to_cartesian(mut lin: usize, dims: &[usize]) -> Vec<usize> {
    let mut idx = vec![0usize; dims.len()];
    // Inverse of row-major encoding.
    for k in (0..dims.len()).rev() {
        idx[k] = lin % dims[k];
        lin /= dims[k];
    }
    idx
}

#[derive(Debug)]
pub struct ArrayIter<'a, T> {
    array: &'a Array<T>,
    lin: usize,
}

impl<'a, T> Iterator for ArrayIter<'a, T> {
    type Item = (Vec<usize>, &'a T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.lin >= self.array.len() {
            return None;
        }
        let lin = self.lin;
        self.lin += 1;
        let idx = linear_to_cartesian(lin, self.array.dims());
        let val = &self.array.store[lin];
        Some((idx, val))
    }
}

#[derive(Debug)]
pub struct ArrayIterMut<'a, T> {
    ptr: *mut T,
    len: usize,
    lin: usize,
    dims: Vec<usize>,
    _marker: PhantomData<&'a mut T>,
}

impl<'a, T> Iterator for ArrayIterMut<'a, T> {
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.lin >= self.len {
            return None;
        }
        let lin = self.lin;
        self.lin += 1;

        let idx = linear_to_cartesian(lin, &self.dims);

        // SAFETY:
        // - `ptr` points to the Array's contiguous `Vec<T>` buffer.
        // - We yield each element exactly once (monotonic `lin`), so we never
        //   create two mutable references to the same element.
        // - The iterator was created from `&'a mut Array<T>`, so the underlying
        //   allocation stays alive for `'a` and cannot be reallocated while this
        //   iterator exists.
        let val: &'a mut T = unsafe { &mut *self.ptr.add(lin) };
        Some((idx, val))
    }
}

fn main() {
    let mut a = Array::from_fn(vec![2, 3], |i| i as i32);

    println!("dims = {:?}", a.dims());
