// A small, deterministic PRNG that is easy to implement in `const fn`.
// SplitMix64 is commonly used for seeding other generators and is fine for
// generating Zobrist keys.
const fn splitmix64_next(state: &mut u64) -> u64 {
    *state = state.wrapping_add(0x9E3779B97F4A7C15);
    let mut z = *state;
