    ///   `Fn + Sync` closures).
    /// - Offsets (strings, vectors, tables) are only meaningful within one builder, so you also
    ///   can't build parts of the *same* FlatBuffer in parallel with separate builders.
    /// - You *can* parallelize preprocessing, then do the actual FlatBuffer building on one thread.
    fn serialize_to_flatbuffer(&self) -> Vec<u8> {
        let mut builder = FlatBufferBuilder::new();

        // --- (Optional) parallel preprocessing step ---
        // Do any expensive transformations in parallel.
        let preprocessed_ignored: Vec<String> = self
            .front_matter
            .as_ref()
            .map(|fm| {
                fm.ignored_parsers
                    .par_iter()
                    .map(|s| s.trim().to_string())
                    .collect()
            })
            .unwrap_or_default();

        // --- Actual FlatBuffer building must be single-threaded ---
        let ignored_offsets: Vec<WIPOffset<&str>> = preprocessed_ignored
            .iter()
            .map(|s| builder.create_string(s))
            .collect();

        let ignored_vec = if ignored_offsets.is_empty() {
            None
        } else {
            Some(builder.create_vector(&ignored_offsets))
        };

        let content = builder.create_string(&self.content);

        let root = mdx_generated::create_mdx_parsing_result_buffer(
            &mut builder,
            &mdx_generated::MdxParsingResultBufferArgs {
                parsed_content: Some(content),
                ignored_parsers: ignored_vec,
            },
        );

        builder.finish(root, None);
        builder.finished_data().to_vec()
    }
}

fn main() {
