/// Parse LanceDB-ish ISO strings like:
/// - "1970-01-01T00:00:00"
/// - "2025-08-02T17:35:41.409"
/// - (optionally) RFC3339 like "2025-08-02T17:35:41.409Z" or with offsets
fn parse_lancedb_datetime(s: &str) -> Result<DateTime<Utc>, chrono::ParseError> {
    // Some systems emit a trailing '.' with no fractional digits.
    let s = s.trim().trim_end_matches('.');

    // If it includes a timezone (Z or +/-hh:mm), RFC3339 parsing is the most robust.
    if let Ok(dt) = DateTime::parse_from_rfc3339(s) {
        return Ok(dt.with_timezone(&Utc));
    }

    // LanceDB often returns no timezone; treat as UTC.
    // Try with optional fractional seconds, then without.
    let naive = NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S%.f")
        .or_else(|_| NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S"))?;

    Ok(Utc.from_utc_datetime(&naive))
}

/// Convert the parsed value back to a unix integer.
/// Here we return unix milliseconds to preserve fractional seconds when present.
fn date_string_to_unix_millis(s: &str) -> Result<i64, chrono::ParseError> {
    Ok(parse_lancedb_datetime(s)?.timestamp_millis())
}

