        "2025-08-10T18:31:26.628Z",
        "2025-08-10T18:31:26",
        "2025-08-10T18:31:26.",
    ];

    for s in samples {
        match parse_lancedb_datetime(s) {
            Ok(dt) => {
                let ms = dt.timestamp_millis();
                let sec = dt.timestamp();
                println!("input: {s}");
                println!("  parsed (UTC): {dt}");
                println!("  unix_seconds : {sec}");
                println!("  unix_millis  : {ms}\n");
            }
            Err(e) => {
