        pub base: String,
    }

    impl Rest for Foo {
        fn get(&self, path: &str) -> String {
            format!("Foo GET {}{}", self.base, path)
        }
        fn post(&self, path: &str, body: &str) -> String {
            format!("Foo POST {}{} body={}", self.base, path, body)
        }
        fn put(&self, path: &str, body: &str) -> String {
            format!("Foo PUT {}{} body={}", self.base, path, body)
        }
        fn delete(&self, path: &str) -> String {
            format!("Foo DELETE {}{}", self.base, path)
        }
        fn base_url(&self) -> &str {
            &self.base
        }
        fn user_agent(&self) -> &str {
            "foo-client/1.0"
        }
    }

    impl Rest for Boo {
        fn get(&self, path: &str) -> String {
            format!("Boo GET {}{}", self.base, path)
        }
        fn post(&self, path: &str, body: &str) -> String {
            format!("Boo POST {}{} body={}", self.base, path, body)
        }
        fn put(&self, path: &str, body: &str) -> String {
            format!("Boo PUT {}{} body={}", self.base, path, body)
        }
        fn delete(&self, path: &str) -> String {
            format!("Boo DELETE {}{}", self.base, path)
        }
        fn base_url(&self) -> &str {
            &self.base
        }
        fn user_agent(&self) -> &str {
            "boo-client/2.0"
        }
    }

    // This is the key idea:
    // You can keep the trait in `al` and still get static dispatch via an enum
    // WITHOUT `enum_dispatch`, by delegating the trait methods to the active variant.
    #[derive(Debug, Clone)]
    pub enum Item {
        Foo(Foo),
        Boo(Boo),
    }

    impl Rest for Item {
        delegate! {
            to match self {
                Item::Foo(x) => x,
                Item::Boo(x) => x,
            } {
                fn get(&self, path: &str) -> String;
                fn post(&self, path: &str, body: &str) -> String;
                fn put(&self, path: &str, body: &str) -> String;
                fn delete(&self, path: &str) -> String;

