use crossterm::terminal::{disable_raw_mode, enable_raw_mode};
use expectrl::spawn;
use nix::unistd::dup;
use std::fs::File;
use std::io::{self, Read, Write};
use std::os::unix::io::{AsRawFd, FromRawFd};
use std::process::Command;
use std::thread;

/// Demonstrates a safe full-duplex PTY pattern with expectrl:
/// - Spawn the child process in a PTY via expectrl.
/// - DUP the PTY master FD into two independent handles:
///     * one dedicated blocking reader thread
///     * one dedicated writer loop
/// - No mutex needed; no deadlock when the child is waiting for input.
///
/// Run: cargo run
///
/// You should get an interactive bash. Type normally.
/// Exit with: `exit` or Ctrl-D.
fn main() -> Result<()> {
    // Put *our* terminal in raw mode so we can forward keystrokes (including arrows, etc.)
    // directly into the PTY.
    enable_raw_mode().context("enable_raw_mode")?;
    let _raw_mode_guard = RawModeGuard;

    // Spawn an interactive program under a PTY.
    // Using bash as an easy demo; replace with your CLI agent.
    let mut cmd = Command::new("bash");
    cmd.arg("-i");
    cmd.env("TERM", "xterm-256color");

    // expectrl spawns with a PTY by default.
    let mut session = spawn(cmd).context("spawn bash via expectrl")?;

    // Key idea: DON'T share `Session` behind a Mutex for concurrent Read/Write.
    // Instead, duplicate the PTY master FD and do independent blocking IO.
    let master_fd = session.as_raw_fd();

    let rfd = dup(master_fd).context("dup PTY fd for reader")?;
    let wfd = dup(master_fd).context("dup PTY fd for writer")?;

    // Safety: we own rfd/wfd (dup'd); File will close them on drop.
    let mut pty_reader = unsafe { File::from_raw_fd(rfd) };
    let mut pty_writer = unsafe { File::from_raw_fd(wfd) };

    // Reader thread: PTY -> stdout
    let reader = thread::spawn(move || -> Result<()> {
        let mut out = io::stdout().lock();
        let mut buf = [0u8; 8192];
        loop {
            let n = pty_reader.read(&mut buf).context("read from PTY")?;
            if n == 0 {
                break;
            }
            out.write_all(&buf[..n]).context("write to stdout")?;
            out.flush().ok();
        }
        Ok(())
    });

    // Writer loop: stdin -> PTY
    // This can block on stdin without affecting PTY reads, and vice versa.
    let mut stdin = io::stdin().lock();
    let mut b = [0u8; 1];
    loop {
        match stdin.read(&mut b) {
            Ok(0) => break, // EOF (e.g. Ctrl-D in some contexts)
            Ok(_) => {
                // Forward raw bytes (arrow keys, ctrl sequences, etc.).
                if let Err(e) = pty_writer.write_all(&b) {
                    eprintln!("\r\n[write error: {e}]\r\n");
                    break;
                }
                let _ = pty_writer.flush();
            }
            Err(e) if e.kind() == io::ErrorKind::Interrupted => continue,
            Err(e) => {
                eprintln!("\r\n[stdin error: {e}]\r\n");
                break;
            }
        }
    }

    // Keep the session alive while reader is running.
    // (Dropping session may close the original master FD; dup'd FDs still live,
    // but the child lifecycle handling is owned by `session`.)
    drop(session);

    // Wait for reader to finish.
    if let Err(e) = reader.join() {
        eprintln!("\r\n[reader thread panicked: {:?}]\r\n", e);
    }

    Ok(())
}

struct RawModeGuard;
impl Drop for RawModeGuard {
    fn drop(&mut self) {
        let _ = disable_raw_mode();
    }
}
