  "main.rs": "use futures::task::noop_waker_ref;
use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};

enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Poll a future exactly once, synchronously.
///
/// Notes:
/// - This uses a no-op waker because we only care whether the future is *already*
///   ready right now.
/// - If it returns Pending, you should drive the future to completion elsewhere
///   (e.g. by spawning/awaiting it) using a real executor.
fn try_poll<X, F>(mut future: Pin<&mut F>) -> TryPollResult<X>
where
    F: Future<Output = X>,
{
    let waker = noop_waker_ref();
    let mut cx = Context::from_waker(waker);

    match future.as_mut().poll(&mut cx) {
        Poll::Ready(x) => TryPollResult::Ready(x),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// Non-async function that runs inside a Tokio runtime.
/// If the future is immediately ready, use it synchronously;
/// otherwise spawn a task to await it.
fn use_or_spawn<F, T>(mut fut: Pin<Box<F>>) -> Option<tokio::task::JoinHandle<T>>
where
    F: Future<Output = T> + Send + 'static,
    T: Send + 'static,
{
    match try_poll(fut.as_mut()) {
        TryPollResult::Ready(v) => {
            println!("synchronous path: future was immediately ready");
            // We can use `v` right here.
            drop(fut); // done with the future
            Some(tokio::spawn(async move { v }))
        }
        TryPollResult::Pending => {
            println!("async path: future not ready, spawning task");
            Some(tokio::spawn(async move { fut.await }))
        }
    }
}

#[tokio::main]
async fn main() {
    // Immediately-ready future
    let fut_ready = Box::pin(async { 10usize });
    let h1 = use_or_spawn(fut_ready).unwrap();
    println!("result1 = {}", h1.await.unwrap());

    // Not-immediately-ready future
    let fut_pending = Box::pin(async {
        tokio::task::yield_now().await;
        20usize
    });
    let h2 = use_or_spawn(fut_pending).unwrap();
    println!("result2 = {}", h2.await.unwrap());
}
"
