  "main.rs": "use std::{sync::Arc, time::Duration};

use opentelemetry::{global, KeyValue};
use opentelemetry_sdk::{resource::Resource, trace as sdktrace};
use tracing::{Instrument, Span};
use tracing_opentelemetry::OpenTelemetrySpanExt;
use tracing_subscriber::{fmt::format::FmtSpan, layer::SubscriberExt, util::SubscriberInitExt};

/// What you store in your request context.
///
/// Key idea:
/// - Store a `tracing::Span` handle (cloneable + Send + Sync).
/// - Keep it alive for the entire request lifetime; the span ends when the last clone drops.
/// - When callbacks happen later/on another thread, re-enter it by *instrumenting the future*.
struct RequestCtx {
    parent: Span,
    // Optional: the OTEL context corresponding to the parent span.
    // Useful when you need to interact with pure-OTEL APIs, but for async propagation
    // across awaits/threads, prefer `tracing`'s `.instrument(...)`.
    otel_cx: opentelemetry::Context,
}

fn init_tracing_and_otel() {
    // Export OTEL spans to stdout so you can see the parent/child relationships without a collector.
    let exporter = opentelemetry_stdout::SpanExporter::default();

    let provider = sdktrace::TracerProvider::builder()
        .with_simple_exporter(exporter)
        .with_resource(Resource::new(vec![KeyValue::new(
            "service.name",
            "rehydrate-demo",
        )]))
        .build();

    let tracer = provider.tracer("rehydrate-demo");
    global::set_tracer_provider(provider);

    let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);

    tracing_subscriber::registry()
        .with(tracing_subscriber::EnvFilter::new(
            std::env::var("RUST_LOG").unwrap_or_else(|_| "info".to_string()),
        ))
        .with(
            tracing_subscriber::fmt::layer()
                .with_target(false)
                .with_thread_ids(true)
                .with_span_events(FmtSpan::NEW | FmtSpan::CLOSE),
        )
        .with(otel_layer)
        .init();
}

/// Helper: run an async block as if the request parent span were the current span,
/// even if this function is called later on a different thread.
async fn in_request_parent<T>(ctx: Arc<RequestCtx>, fut: impl std::future::Future<Output = T>) -> T {
    fut.instrument(ctx.parent.clone()).await
}

async fn stage_1(ctx: Arc<RequestCtx>) {
    // Pretend Pingora/Tokio called us "out of the blue".
    in_request_parent(ctx.clone(), async move {
        // Because we're instrumented with the parent, this becomes a child span.
        let s = tracing::info_span!("stage_1");
        async move {
            tracing::info!("stage 1 doing work");
            tokio::time::sleep(Duration::from_millis(150)).await;
            tracing::info!("stage 1 done");
        }
        .instrument(s)
        .await;
    })
    .await;
}

async fn stage_2(ctx: Arc<RequestCtx>) {
    in_request_parent(ctx.clone(), async move {
        let s = tracing::info_span!("stage_2");
        async move {
            tracing::info!("stage 2 start");
            tokio::time::sleep(Duration::from_millis(50)).await;

            // Demonstrate nested work on another task/thread:
            // capture the *current* span (stage_2), and instrument the spawned task with it.
            let stage2_span = Span::current();
            let jh = tokio::spawn(
                async move {
                    let up = tracing::info_span!("upstream");
                    async move {
                        tracing::info!("calling upstream...");
                        tokio::time::sleep(Duration::from_millis(120)).await;
                        tracing::info!("upstream done");
                    }
                    .instrument(up)
                    .await;
                }
                .instrument(stage2_span),
            );

            jh.await.unwrap();
            tracing::info!("stage 2 done");
        }
        .instrument(s)
        .await;
    })
    .await;
}

#[tokio::main(flavor = "multi_thread", worker_threads = 2)]
async fn main() {
    init_tracing_and_otel();

    // Create the request parent span.
    // IMPORTANT: the parent span stays "alive" until all clones of it are dropped.
    let request_span = tracing::info_span!("request", request_id = 1);

    // Store both the tracing span handle and the corresponding OTEL context.
    // (The OTEL context is often useful at boundaries, but `.instrument(span)` is the key async tool.)
    let ctx = Arc::new(RequestCtx {
        otel_cx: request_span.context(),
        parent: request_span,
    });

    // Simulate callbacks arriving later/from anywhere.
    // These tasks are *not* spawned under the request span.
    let c1 = ctx.clone();
    let t1 = tokio::spawn(async move {
        tokio::time::sleep(Duration::from_millis(30)).await;
        stage_1(c1).await;
    });

    let c2 = ctx.clone();
    let t2 = tokio::spawn(async move {
        tokio::time::sleep(Duration::from_millis(200)).await;
        stage_2(c2).await;
    });

    // Wait for the simulated lifecycle to end.
    let _ = tokio::join!(t1, t2);

    // Drop the last ctx clone so the parent span can close.
    drop(ctx);

    // Flush OTEL stdout exporter.
    global::shutdown_tracer_provider();
}
"
}
