use bevy::asset::{io::Reader, Asset, AssetApp, AssetLoader, AssetPlugin, BoxedFuture, LoadContext};
use bevy::log::LogPlugin;
use bevy::prelude::*;
use futures_lite::io::{AsyncReadExt, AsyncSeekExt};
use std::collections::BTreeMap;
use std::fs;
use std::io::Write;
use std::path::Path;
use std::time::Duration;

/// A tiny custom asset type: a text blob stored inside a pack file.
#[derive(Asset, TypePath, Debug, Clone)]
struct PackText(pub String);

/// Loader for our custom pack file format.
///
/// IMPORTANT: this shows *lazy* loading using the `Reader` (AsyncRead + AsyncSeek):
/// we only read the pack header + directory, then seek directly to the requested entry.
///
/// Usage:
///   asset_server.load::<PackText>("demo.pak#hello")
/// where `#hello` is the entry name (label).
#[derive(Default)]
struct PackTextLoader;

impl AssetLoader for PackTextLoader {
    type Asset = PackText;
    type Settings = ();
    type Error = anyhow::Error;

    fn extensions(&self) -> &[&str] {
        &["pak"]
    }

    fn load<'a>(
        &'a self,
        reader: &'a mut dyn Reader,
        _settings: &'a Self::Settings,
        load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            let label = load_context
                .asset_path()
                .label()
                .ok_or_else(|| anyhow!("missing label. Use e.g. demo.pak#hello"))?
                .to_string();

            // Parse header (small, fixed-size)
            reader.seek(std::io::SeekFrom::Start(0)).await?;
            let mut magic = [0u8; 4];
            reader.read_exact(&mut magic).await?;
            if &magic != b"PAK0" {
                return Err(anyhow!("not a PAK0 file (bad magic)"));
            }
            let count = read_u32_le(reader).await? as usize;

            // Directory is small-ish: (name_len + name + offset + size) * count
            // We scan it but do *not* load all entries.
            let mut found: Option<(u64, u64)> = None;
            for _ in 0..count {
                let name_len = read_u16_le(reader).await? as usize;
                let mut name_bytes = vec![0u8; name_len];
                reader.read_exact(&mut name_bytes).await?;
                let name = String::from_utf8(name_bytes)
                    .context("entry name is not valid UTF-8")?;

                let offset = read_u32_le(reader).await? as u64;
                let size = read_u32_le(reader).await? as u64;

                if name == label {
                    found = Some((offset, size));
                }
            }

            let (offset, size) = found.ok_or_else(|| anyhow!("entry not found in pack: {label}"))?;

            // Lazy part: seek directly to the requested entry and read only its bytes.
            reader.seek(std::io::SeekFrom::Start(offset)).await?;
            let mut data = vec![0u8; size as usize];
            reader.read_exact(&mut data).await?;

            let text = String::from_utf8(data).context("entry data is not valid UTF-8")?;
            Ok(PackText(text))
        })
    }
}

