}

fn poll_loaded(
    handles: Res<DemoHandles>,
    asset_server: Res<AssetServer>,
    texts: Res<Assets<PackText>>,
    mut exit: EventWriter<AppExit>,
) {
    let hello_loaded = asset_server.is_loaded_with_dependencies(&handles.hello);
    let lorem_loaded = asset_server.is_loaded_with_dependencies(&handles.lorem);

    if !(hello_loaded && lorem_loaded) {
        return;
    }

    let hello = texts.get(&handles.hello).unwrap();
    let lorem = texts.get(&handles.lorem).unwrap();

    info!("Loaded demo.pak#hello = {:?}", hello.0);
    info!("Loaded demo.pak#lorem = {:?}", lorem.0);

    exit.send(AppExit::Success);
}

/// Create assets/demo.pak if it doesn't exist.
///
/// Pack format:
///   magic: "PAK0" (4 bytes)
///   count: u32
///   directory[count]:
///     name_len: u16
///     name: [u8; name_len]
///     offset: u32
///     size: u32
///   data: concatenated file bytes
fn ensure_demo_pack_exists() -> Result<()> {
    let assets_dir = Path::new("assets");
    if !assets_dir.exists() {
        fs::create_dir_all(assets_dir).context("create assets directory")?;
    }

    let pack_path = assets_dir.join("demo.pak");
    if pack_path.exists() {
        return Ok(());
    }

    // Use deterministic ordering for stable offsets.
    let mut entries: BTreeMap<String, Vec<u8>> = BTreeMap::new();
    entries.insert("hello".to_string(), b"Hello from inside the pack!".to_vec());
    entries.insert(
        "lorem".to_string(),
        b"Lorem ipsum dolor sit amet, packed and loaded lazily.".to_vec(),
    );

    // Compute directory size.
    let count = entries.len() as u32;
    let mut dir_size: usize = 0;
    for (name, _data) in entries.iter() {
        dir_size += 2; // u16 name_len
        dir_size += name.as_bytes().len();
        dir_size += 4; // u32 offset
        dir_size += 4; // u32 size
    }

    let header_size = 4 + 4; // magic + count
    let mut current_offset = (header_size + dir_size) as u32;

    // Build directory with computed offsets.
    let mut directory_bytes: Vec<u8> = Vec::with_capacity(dir_size);
    let mut data_bytes: Vec<u8> = Vec::new();

    for (name, data) in entries.iter() {
        let name_bytes = name.as_bytes();
        let name_len = u16::try_from(name_bytes.len()).context("name too long")?;

        directory_bytes.extend_from_slice(&name_len.to_le_bytes());
        directory_bytes.extend_from_slice(name_bytes);
        directory_bytes.extend_from_slice(&current_offset.to_le_bytes());
        directory_bytes.extend_from_slice(&(data.len() as u32).to_le_bytes());

        data_bytes.extend_from_slice(data);
        current_offset += data.len() as u32;
    }

    let mut file = fs::File::create(&pack_path).context("create demo.pak")?;
    file.write_all(b"PAK0").context("write magic")?;
    file.write_all(&count.to_le_bytes()).context("write count")?;
    file.write_all(&directory_bytes).context("write directory")?;
    file.write_all(&data_bytes).context("write data")?;

    Ok(())
}

async fn read_u16_le(reader: &mut dyn Reader) -> Result<u16> {
    let mut buf = [0u8; 2];
    reader.read_exact(&mut buf).await?;
    Ok(u16::from_le_bytes(buf))
}

async fn read_u32_le(reader: &mut dyn Reader) -> Result<u32> {
    let mut buf = [0u8; 4];
    reader.read_exact(&mut buf).await?;
    Ok(u32::from_le_bytes(buf))
}
