/// In rustyline, there isn't currently a built-in way to execute multiple `Cmd`s
/// from a key binding (no macro/multi-action), so deleting whitespace *and then*
/// inserting '.' in one keypress isn't straightforward.
///
/// Workaround implemented here:
/// - Add a trailing space after completion only when the context strongly
///   suggests that a space is what you want (keywords, and table names in FROM/JOIN/etc.).
/// - Do *not* add a trailing space for table names in the SELECT list context,
///   so typing `book.title` stays smooth.
struct SqlHelper {
    keywords: HashSet<&'static str>,
    tables: Vec<&'static str>,
    columns: HashMap<&'static str, Vec<&'static str>>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CompletionContext {
    AfterDot { table: &'static str },
    FromLike,     // FROM/JOIN/UPDATE/INTO
    OrderByLike,  // BY (as in ORDER BY)
    SelectLike,   // default-ish expression context
}

impl SqlHelper {
    fn new() -> Self {
        let keywords: HashSet<&'static str> = [
            "SELECT", "FROM", "WHERE", "ORDER", "BY", "GROUP", "HAVING", "LIMIT", "OFFSET",
            "INSERT", "INTO", "VALUES", "UPDATE", "SET", "DELETE", "JOIN", "LEFT", "RIGHT",
            "INNER", "OUTER", "ON", "AS",
        ]
        .into_iter()
        .collect();

