        let mut columns: HashMap<&'static str, Vec<&'static str>> = HashMap::new();
        columns.insert("book", vec!["year", "authorid", "title"]);
        columns.insert("author", vec!["id", "name"]);

        Self {
            keywords,
            tables,
            columns,
        }
    }

    fn is_ident_char(c: char) -> bool {
        c.is_ascii_alphanumeric() || c == '_'
    }

    fn find_token_start(line: &str, pos: usize) -> usize {
        // Walk left while we're in an identifier.
        // Stop at whitespace/punctuation including '.' and ','.
        let mut i = pos;
        while i > 0 {
            let prev = line[..i].chars().next_back().unwrap();
            if Self::is_ident_char(prev) {
                i -= prev.len_utf8();
            } else {
