        i
    }

    fn last_keyword_before(&self, s: &str) -> Option<String> {
        // Very small/naive SQL-ish tokenizer: collect ident-ish runs and look for keyword matches.
        let mut last: Option<String> = None;
        let mut cur = String::new();
        for ch in s.chars() {
            if Self::is_ident_char(ch) {
                cur.push(ch);
            } else {
                if !cur.is_empty() {
                    let up = cur.to_ascii_uppercase();
                    if self.keywords.contains(up.as_str()) {
                        last = Some(up);
                    }
                    cur.clear();
                }
            }
        }
        if !cur.is_empty() {
            let up = cur.to_ascii_uppercase();
            if self.keywords.contains(up.as_str()) {
                last = Some(up);
            }
        }
        last
    }

    fn detect_context(&self, line: &str, start: usize) -> CompletionContext {
        // If we're completing after "table.", offer columns for that table.
        if start > 0 {
            if let Some('.') = line[..start].chars().next_back() {
                // Find the table identifier just before the '.'
                let mut j = start - 1;
