    fn make_pairs(&self, fragment: &str, ctx: CompletionContext) -> Vec<Pair> {
        let frag_lc = fragment.to_ascii_lowercase();

        let mut out: Vec<Pair> = Vec::new();

        // Candidates depend on context.
        let mut candidates: Vec<(&str, bool /* is_keyword */)> = Vec::new();

        match ctx {
            CompletionContext::AfterDot { table } => {
                if let Some(cols) = self.columns.get(table) {
                    for &c in cols {
                        candidates.push((c, false));
                    }
                }
            }
            CompletionContext::FromLike => {
                for &t in &self.tables {
                    candidates.push((t, false));
                }
                // Also allow common keywords after FROM-like contexts.
                for &k in ["WHERE", "ORDER", "GROUP", "LIMIT", "JOIN", "ON"].iter() {
                    candidates.push((k, true));
                }
            }
            CompletionContext::OrderByLike => {
                // Unqualified columns in ORDER BY
                for cols in self.columns.values() {
                    for &c in cols {
                        candidates.push((c, false));
                    }
                }
                for &k in ["ASC", "DESC", "LIMIT"].iter() {
                    candidates.push((k, true));
                }
            }
            CompletionContext::SelectLike => {
                // Common keywords + table names in expression positions
                for &k in ["SELECT", "FROM", "WHERE", "ORDER", "BY"].iter() {
                    candidates.push((k, true));
                }
                for &t in &self.tables {
                    candidates.push((t, false));
                }
            }
        }

        for (cand, is_keyword) in candidates {
            let cand_lc = cand.to_ascii_lowercase();
            if !frag_lc.is_empty() && !cand_lc.starts_with(&frag_lc) {
                continue;
            }

            let replacement = if is_keyword {
                // Always add a space after keywords.
                format!("{} ", cand)
            } else {
                // For identifiers, only add space in contexts where it is very likely desired.
                match ctx {
                    CompletionContext::FromLike => format!("{} ", cand),
                    CompletionContext::AfterDot { .. } => format!("{} ", cand),
                    CompletionContext::OrderByLike => format!("{} ", cand),
                    CompletionContext::SelectLike => cand.to_string(),
                }
            };

            out.push(Pair {
                display: cand.to_string(),
                replacement,
            });
        }

        // De-dup by display to avoid duplicated columns from multiple tables.
        out.sort_by(|a, b| a.display.cmp(&b.display));
        out.dedup_by(|a, b| a.display == b.display);
        out
