    type Candidate = Pair;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        _ctx: &Context<'_>,
    ) -> rustyline::Result<(usize, Vec<Pair>)> {
        let start = Self::find_token_start(line, pos);
        let fragment = &line[start..pos];
        let ctx = self.detect_context(line, start);
        let pairs = self.make_pairs(fragment, ctx);
        Ok((start, pairs))
    }
