use std::{env, net::SocketAddr};
use tower_http::cors::CorsLayer;
use tracing::{info, warn};

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt()
        .with_env_filter(
            tracing_subscriber::EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| "info".into()),
        )
        .init();

    // For real deployment set this to your site, e.g. "https://www.example.com".
    // For local testing you might set: ALLOWED_WS_ORIGIN=http://localhost:5173
    let allowed_origin = env::var("ALLOWED_WS_ORIGIN").unwrap_or_else(|_| "https://www.example.com".to_string());

    // Apply origin checks only to websocket routes.
    let ws_routes = Router::new()
        .route("/client/:session_id", get(client_handler))
        .route_layer(middleware::from_fn(move |req, next| {
            let allowed_origin = allowed_origin.clone();
            ws_origin_guard(req, next, allowed_origin)
        }));

    // Normal (non-ws) routes could still use CORS (for fetch/XHR).
    let app = Router::new()
        .merge(ws_routes)
        .route("/", get(|| async { "ok" }))
        .layer(
            CorsLayer::new()
                .allow_origin("https://www.example.com".parse::<HeaderValue>().unwrap())
                .allow_methods([Method::GET, Method::POST])
                .allow_headers([header::CONTENT_TYPE]),
        );

    let addr: SocketAddr = "127.0.0.1:3000".parse().unwrap();
    info!(%addr, "listening");

    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
    axum::serve(listener, app).await.unwrap();
}

async fn ws_origin_guard(req: Request<axum::body::Body>, next: Next, allowed_origin: String) -> Response {
    if is_websocket_upgrade(&req) {
        match req.headers().get(header::ORIGIN).and_then(|v| v.to_str().ok()) {
            Some(origin) if origin == allowed_origin => {
                // ok
            }
            Some(origin) => {
                warn!(%origin, %allowed_origin, "blocked websocket due to origin mismatch");
                return (StatusCode::FORBIDDEN, "forbidden (bad origin)").into_response();
            }
            None => {
                // Browser WS requests always send Origin. Rejecting missing Origin
                // blocks non-browser clients too; adjust if you want to allow them.
                warn!(%allowed_origin, "blocked websocket due to missing Origin header");
                return (StatusCode::FORBIDDEN, "forbidden (missing origin)").into_response();
            }
        }
    }

    next.run(req).await
}

fn is_websocket_upgrade(req: &Request<axum::body::Body>) -> bool {
    let headers = req.headers();

    let upgrade_is_ws = headers
        .get(header::UPGRADE)
        .and_then(|v| v.to_str().ok())
        .is_some_and(|v| v.eq_ignore_ascii_case("websocket"));

    let connection_has_upgrade = headers
        .get(header::CONNECTION)
        .and_then(|v| v.to_str().ok())
        .is_some_and(|v| v.to_ascii_lowercase().split(',').any(|t| t.trim() == "upgrade"));

    upgrade_is_ws && connection_has_upgrade
}

async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

async fn handle_socket(mut socket: WebSocket, session_id: String) {
    info!(%session_id, "websocket connected");

    while let Some(Ok(msg)) = socket.recv().await {
        match msg {
            Message::Text(text) => {
                let reply = format!("session={}: {}", session_id, text);
                if socket.send(Message::Text(reply)).await.is_err() {
                    break;
                }
            }
            Message::Binary(bin) => {
                if socket.send(Message::Binary(bin)).await.is_err() {
                    break;
                }
            }
            Message::Close(_) => break,
            _ => {}
        }
    }

    info!(%session_id, "websocket disconnected");
}
"
}
