    // and rustyline will redraw the prompt cleanly.
    let printer = rl.create_external_printer().unwrap();

    // Thread that continuously reads child output and prints it "above" the prompt.
    let reader_handle = thread::spawn(move || {
        let reader = BufReader::new(child_stdout);
        for line in reader.lines().flatten() {
            // ExternalPrinter handles prompt refresh.
            let _ = printer.print(format!("[child] {line}"));
        }
    });

