  "main.rs": "use std::time::Duration;

tokio_stream::wrappers::BroadcastStream;
use tokio_stream::Stream;
use tokio_stream::StreamExt;

use tokio::sync::broadcast::{self, Sender};

#[derive(Debug, Clone)]
struct Event {
    n: u64,
}

#[derive(Debug)]
enum RecvError {
    Lagged,
}

pub fn events_channel() -> (EventSender, EventStreamFactory) {
    let (tx, _) = broadcast::channel(20);
    (
        EventSender { tx: tx.clone() },
        EventStreamFactory { tx },
    )
}

#[derive(Debug, Clone)]
pub struct EventSender {
    tx: Sender<Event>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        let _ = self.tx.send(event);
    }

    /// Key point: this closes the broadcast channel even if there are many Sender clones.
    /// All receivers (and BroadcastStream) will observe closure and terminate.
    pub fn shutdown(&self) {
        self.tx.close_channel();
    }

    pub fn is_shutdown(&self) -> bool {
        self.tx.is_closed()
    }
}

pub struct EventStreamFactory {
    tx: Sender<Event>,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> impl Stream<Item = Result<Event, RecvError>> + Send + 'static {
        BroadcastStream::new(self.tx.subscribe()).filter_map(|item| async move {
            match item {
                Ok(ev) => Some(Ok(ev)),
                Err(tokio_stream::wrappers::errors::BroadcastStreamRecvError::Lagged(_)) => {
                    Some(Err(RecvError::Lagged))
                }
                // Important: end the stream on shutdown.
                Err(tokio_stream::wrappers::errors::BroadcastStreamRecvError::Closed) => None,
            }
        })
    }
}

#[tokio::main]
async fn main() {
    let (sender, factory) = events_channel();

    // Simulated producer task that holds a Sender clone.
    let producer_sender = sender.clone();
    let producer = tokio::spawn(async move {
        let mut n = 0u64;
        let mut tick = tokio::time::interval(Duration::from_millis(200));

        loop {
            tokio::select! {
                _ = tick.tick() => {
                    if producer_sender.is_shutdown() {
                        break;
                    }
                    producer_sender.send(Event { n });
                    n += 1;
                }
                // Completes when ANY clone calls close_channel().
                _ = producer_sender.tx.closed() => {
                    break;
                }
            }
        }

        println!("producer: stopped");
    });

    // Simulated SSE client #1
    let mut s1 = factory.all_events();
    let client1 = tokio::spawn(async move {
        while let Some(item) = s1.next().await {
            match item {
                Ok(ev) => println!("client1 got event: {:?}", ev),
                Err(e) => println!("client1 error: {:?}", e),
            }
        }
        println!("client1: stream ended (shutdown)");
    });

    // Simulated SSE client #2
    let mut s2 = factory.all_events();
    let client2 = tokio::spawn(async move {
        while let Some(item) = s2.next().await {
            match item {
                Ok(ev) => println!("client2 got event: {:?}", ev),
                Err(e) => println!("client2 error: {:?}", e),
            }
        }
        println!("client2: stream ended (shutdown)");
    });

    // Shut down on Ctrl-C OR after a short timeout (so `cargo run` doesn't hang).
    tokio::select! {
        _ = tokio::signal::ctrl_c() => {
            println!("main: Ctrl-C received, shutting down");
        }
        _ = tokio::time::sleep(Duration::from_secs(3)) => {
            println!("main: timeout reached, shutting down");
        }
    }

    // This is the important call: it shuts down BroadcastStream even with many Sender clones.
    sender.shutdown();

    let _ = producer.await;
    let _ = client1.await;
    let _ = client2.await;

    println!("main: clean exit");
}
"
}
