fn spawn_keys_thread(
    msg_tx: channel::Sender<Message>,
    shutdown_rx: channel::Receiver<()>,
) -> thread::JoinHandle<()> {
    thread::spawn(move || {
        let tick = channel::tick(Duration::from_millis(20));
        let mut stdin = termion::async_stdin();

        loop {
            channel::select! {
                recv(shutdown_rx) -> _ => {
                    // Sender dropped => shutdown requested
                    break;
                }
                recv(tick) -> _ => {
                    // Non-blocking read: async_stdin returns immediately.
                    let mut buf = [0u8; 64];
                    match stdin.read(&mut buf) {
                        Ok(0) => {}
                        Ok(n) => {
                            for &b in &buf[..n] {
                                let c = b as char;
                                let _ = msg_tx.send(Message::Key(c));
                                if c == 'q' {
                                    let _ = msg_tx.send(Message::Quit);
                                }
                            }
                        }
                        Err(_) => {
                            // Ignore transient read errors and keep going.
                        }
                    }
                }
            }
        }
    })
}

#[cfg(unix)]
fn spawn_signals_thread(
    msg_tx: channel::Sender<Message>,
    shutdown_rx: channel::Receiver<()>,
) -> thread::JoinHandle<()> {
    use signal_hook::consts::{SIGINT, SIGTERM};
    use signal_hook::iterator::Signals;

    thread::spawn(move || {
        let mut signals = Signals::new([SIGINT, SIGTERM]).expect("register signals");
        let tick = channel::tick(Duration::from_millis(50));

        loop {
            channel::select! {
                recv(shutdown_rx) -> _ => {
                    break;
                }
                recv(tick) -> _ => {
                    // pending() is non-blocking; we poll it periodically.
                    for sig in signals.pending() {
                        let _ = msg_tx.send(Message::Signal(sig));
                        // Decide that SIGINT/SIGTERM means shutdown.
                        let _ = msg_tx.send(Message::Quit);
                    }
                }
            }
        }
    })
}

#[cfg(not(unix))]
fn spawn_signals_thread(
    _msg_tx: channel::Sender<Message>,
    shutdown_rx: channel::Receiver<()>,
) -> thread::JoinHandle<()> {
    thread::spawn(move || {
        // On non-Unix, just wait for shutdown.
        let _ = shutdown_rx.recv();
    })
}

fn main() {
    // Put terminal in raw mode so keys arrive immediately.
    let mut stdout = io::stdout().into_raw_mode().unwrap();
    writeln!(
        stdout,
        "Press keys (press 'q' to quit). Also try Ctrl-C (SIGINT) on Unix."
    )
    .ok();
    stdout.flush().ok();

    let (msg_tx, msg_rx) = channel::unbounded::<Message>();

    // Shutdown is signaled by *dropping* shutdown_tx.
    // All threads have a clone of shutdown_rx and will wake up immediately.
    let (shutdown_tx, shutdown_rx) = channel::unbounded::<()>();

    let keys_handle = spawn_keys_thread(msg_tx.clone(), shutdown_rx.clone());
    let signals_handle = spawn_signals_thread(msg_tx.clone(), shutdown_rx.clone());

    // Main event loop
    let mut quitting = false;
    while let Ok(msg) = msg_rx.recv() {
        match msg {
            Message::Key(c) => {
                writeln!(stdout, "key: {c:?}").ok();
                stdout.flush().ok();
            }
            #[cfg(unix)]
            Message::Signal(sig) => {
                writeln!(stdout, "signal: {sig}").ok();
                stdout.flush().ok();
            }
            Message::Quit => {
                writeln!(stdout, "quit requested").ok();
                stdout.flush().ok();
                quitting = true;
                break;
            }
        }
    }

    if quitting {
        // Broadcast shutdown by disconnecting the shutdown channel.
        drop(shutdown_tx);
    }

    let _ = keys_handle.join();
    let _ = signals_handle.join();

    writeln!(stdout, "clean shutdown").ok();
}
