use cms::{content_info::ContentInfo, signed_data::SignedData};
use der::{Decode, Encode, Tag};
use std::{env, fs, io::Read};

fn main() -> Result<()> {
    let args: Vec<String> = env::args().collect();

    let der_bytes = if args.len() >= 2 {
        fs::read(&args[1]).with_context(|| format!("reading {}", args[1]))?
    } else {
        let mut buf = Vec::new();
        std::io::stdin()
            .read_to_end(&mut buf)
            .context("reading DER from stdin")?;
        buf
    };

    let ci = ContentInfo::from_der(&der_bytes).context("decoding outer ContentInfo")?;
    println!("Outer contentType: {}", ci.content_type);

    let sd = decode_signed_data_from_content_info(&ci)?;
    println!("Decoded SignedData OK");
    println!("  version: {:?}", sd.version);
    println!("  digest_algorithms: {}", sd.digest_algorithms.len());
    println!("  signer_infos: {}", sd.signer_infos.0.len());

    // Certificates are optional
    if let Some(certs) = &sd.certificates {
        println!("  certificates: {}", certs.0.len());
    } else {
        println!("  certificates: <absent>");
    }

    // SCEP PKIOperation SignedData encapsulates another CMS ContentInfo as eContent.
    // In CMS, encapContentInfo.eContent is an OCTET STRING containing the DER of that inner structure.
    let econtent = sd
        .encap_content_info
        .econtent
        .as_ref()
        .map(|o| o.as_bytes());

    if let Some(octets) = econtent {
        println!("  encapContentInfo.eContent: {} bytes", octets.len());
        println!("  eContent[0..min(32)]: {}", hex::encode(&octets[..octets.len().min(32)]));

        match ContentInfo::from_der(octets) {
            Ok(inner_ci) => {
                println!("Inner (encapsulated) contentType: {}", inner_ci.content_type);
            }
            Err(e) => {
                println!("Inner (encapsulated) ContentInfo decode failed: {e:#}");
            }
        }
    } else {
        println!("  encapContentInfo.eContent: <absent>");
    }

    Ok(())
}

/// Robustly decode SignedData out of ContentInfo.
///
/// Why this exists:
/// CMS ContentInfo wraps the content in `[0] EXPLICIT`.
/// Depending on how you obtain `ci.content` (and what it contains), you may have either:
/// - the *explicit wrapper* (tag = context-specific 0), whose *value* contains the full SignedData TLV, or
/// - the SignedData SEQUENCE itself.
///
/// Using `decode_as()` can fail if you're accidentally feeding only the SEQUENCE *value* (which starts with
/// the `version INTEGER`) into a decoder that expects a full TLV.
fn decode_signed_data_from_content_info(ci: &ContentInfo) -> Result<SignedData> {
    let any = ci
        .content
        .as_ref()
        .context("ContentInfo has no content field")?;

    match any.tag() {
        // Content is already a SignedData SEQUENCE TLV.
        Tag::Sequence => {
            let tlv = any.to_der().context("re-encoding Any to DER")?;
            Ok(SignedData::from_der(&tlv).context("decoding SignedData from SEQUENCE TLV")?)
        }

        // Content is the EXPLICIT [0] wrapper; its value should contain the full SignedData TLV.
        Tag::ContextSpecific0 => {
            let inner_tlv = any.value();
            Ok(SignedData::from_der(inner_tlv)
                .context("decoding SignedData from [0] EXPLICIT wrapper value")?)
        }

        other => {
            bail!("Unexpected ContentInfo.content tag: {other:?}");
        }
    }
}
"
