type ResBody = BoxBody<Bytes, std::io::Error>;

fn boxed_empty() -> ResBody {
    Empty::new().map_err(|never| match never {}).boxed()
}

fn boxed_full_text(text: &'static str) -> ResBody {
    // Full has Error = Infallible; convert to std::io::Error (never happens).
    Full::new(Bytes::from_static(text.as_bytes()))
        .map_err(|never| match never {})
        .boxed()
}

fn simple_response(status: StatusCode, text: &'static str) -> Response<ResBody> {
    Response::builder()
        .status(status)
        .header(header::CONTENT_TYPE, "text/plain; charset=utf-8")
        .body(boxed_full_text(text))
        .unwrap()
}

fn uri_path_to_fs_path(root: &Path, uri_path: &str) -> Option<PathBuf> {
    // Very small/safe-ish mapping:
    // - strip leading '/'
    // - reject any '..' path segments
    let rel = uri_path.trim_start_matches('/');

    if rel.split('/').any(|seg| seg == "..") {
        return None;
    }

    let mut p = root.join(rel);
    if p.is_dir() {
        p.push("index.html");
    }

    Some(p)
}

async fn file_response(method: &Method, path: &Path) -> Response<ResBody> {
    let file = match tokio::fs::File::open(path).await {
        Ok(f) => f,
        Err(_) => return simple_response(StatusCode::NOT_FOUND, "Not Found\n"),
    };

    let meta = match file.metadata().await {
        Ok(m) => m,
        Err(_) => return simple_response(StatusCode::INTERNAL_SERVER_ERROR, "Metadata error\n"),
    };

    let mime = mime_guess::from_path(path).first_or_octet_stream();

    if *method == Method::HEAD {
        return Response::builder()
            .status(StatusCode::OK)
            .header(header::CONTENT_TYPE, mime.as_ref())
            .header(header::CONTENT_LENGTH, meta.len())
            .body(boxed_empty())
            .unwrap();
    }

    // Convert the file (AsyncRead) into a Stream of Bytes, then into HTTP body Frames.
    // This streams from disk to network without reading the whole file into memory.
    let stream = ReaderStream::new(file).map(|chunk_res| chunk_res.map(Frame::data));
    let body = StreamBody::new(stream).boxed();

    Response::builder()
        .status(StatusCode::OK)
        .header(header::CONTENT_TYPE, mime.as_ref())
        .header(header::CONTENT_LENGTH, meta.len())
        .body(body)
        .unwrap()
}

async fn handle(req: Request<Incoming>, root: Arc<PathBuf>) -> Result<Response<ResBody>, Infallible> {
    match *req.method() {
        Method::GET | Method::HEAD => {}
        _ => return Ok(simple_response(StatusCode::METHOD_NOT_ALLOWED, "Method Not Allowed\n")),
    }

    let Some(fs_path) = uri_path_to_fs_path(&root, req.uri().path()) else {
        return Ok(simple_response(StatusCode::BAD_REQUEST, "Bad path\n"));
    };

    Ok(file_response(req.method(), &fs_path).await)
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    let addr: SocketAddr = "127.0.0.1:3000".parse().unwrap();
    let root = Arc::new(std::env::current_dir()?);

