        let mut t1 = (mn - o) * inv_d;
        let mut t2 = (mx - o) * inv_d;

        // For the near plane: if dir>0, we hit min first (normal -axis). If dir<0, we hit max first (normal +axis).
        let axis_vec = match axis {
            0 => Vec3::X,
            1 => Vec3::Y,
            _ => Vec3::Z,
        };

        let (n_near, n_far) = if t1 <= t2 {
            (-axis_vec, axis_vec)
        } else {
            // Swap so t1 is near, t2 is far.
            std::mem::swap(&mut t1, &mut t2);
            (axis_vec, -axis_vec)
        };

        if t1 > tmin {
            tmin = t1;
            n_enter = n_near;
        }
        if t2 < tmax {
            tmax = t2;
            n_exit = n_far;
        }

        if tmin > tmax {
            return None;
        }
    }

    // If the whole box is behind the ray.
    if tmax < 0.0 {
        return None;
    }

    // If outside, use entry hit; if inside, use exit hit.
    if tmin >= 0.0 {
        Some(LocalHit {
            t: tmin,
            normal_local: n_enter,
        })
    } else {
        Some(LocalHit {
            t: tmax,
            normal_local: n_exit,
        })
    }
}
