fn visit_use_tree(tree: &ast::UseTree, prefix: &str, src: &str, edits: &mut Vec<Edit>) {
    let path = tree.path();
    let path_text = path
        .as_ref()
        .map(|p| p.syntax().text().to_string())
        .unwrap_or_default();

    // --- Special-case: hoist `devices::{...}` under `vexide::{ ... }` ---
    // Turn: `vexide::{ devices::{smart, adi} }` into `vexide::{ smart, adi }`
    if prefix == "vexide" && path_text == "devices" {
        if let Some(list) = tree.use_tree_list() {
            // Replace `devices::{ ... }` with the raw text *inside* the braces.
            // This preserves formatting/comments inside the inner list.
            if let (Some(lc), Some(rc)) = (list.l_curly_token(), list.r_curly_token()) {
