                let inner_text = slice_text_range(src, inner_range).to_string();

                edits.push(Edit {
                    range: tree.syntax().text_range(),
                    replacement: inner_text,
                });
                return; // don't recurse into children; we replaced the whole subtree
            }
        }

        // Turn: `vexide::{ devices::* }` into `vexide::{ * }`
        if tree.star_token().is_some() {
            edits.push(Edit {
                range: tree.syntax().text_range(),
                replacement: "*".to_string(),
            });
            return;
        }
    }

    // --- Path rewrites (do not require restructuring) ---
    if let Some(path) = &path {
        let old = path.syntax().text().to_string();

        let replacement = if old.starts_with("vexide::devices::") {
            // `use vexide::devices::smart::Motor;` -> `use vexide::smart::Motor;`
            Some(old.replacen("vexide::devices::", "vexide::", 1))
        } else if old == "vexide::devices" && (tree.use_tree_list().is_some() || tree.star_token().is_some()) {
            // `use vexide::devices::*;` -> `use vexide::*;`
            // `use vexide::devices::{...};` -> `use vexide::{...};`
            Some("vexide".to_string())
        } else if prefix == "vexide" && old.starts_with("devices::") {
            // `use vexide::{ devices::smart::* };` -> `use vexide::{ smart::* };`
            Some(old.replacen("devices::", "", 1))
        } else {
            None
        };

        if let Some(new_text) = replacement {
            if new_text != old {
                edits.push(Edit {
                    range: path.syntax().text_range(),
                    replacement: new_text,
                });
            }
        }
    }

    // Recurse into children.
    let next_prefix = if path_text.is_empty() {
        prefix.to_string()
    } else if prefix.is_empty() {
        path_text.clone()
    } else {
        format!("{prefix}::{path_text}")
    };

    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            visit_use_tree(&child, &next_prefix, src, edits);
        }
    }
