fn apply_edits(src: &str, edits: &mut Vec<Edit>) -> String {
    // Apply from the end of the file backwards, so earlier replacements don't shift later ranges.
    edits.sort_by_key(|e| std::cmp::Reverse(u32::from(e.range.start())));

    let mut out = src.to_string();
    let mut last_replaced_start: Option<u32> = None;

    for e in edits.iter() {
        let start_u32 = u32::from(e.range.start());
        let end_u32 = u32::from(e.range.end());

        // If this edit overlaps one we already applied (which starts later in the file), skip it.
        if let Some(prev_start) = last_replaced_start {
            if end_u32 > prev_start {
                continue;
            }
        }

        let start = start_u32 as usize;
        let end = end_u32 as usize;
        out.replace_range(start..end, &e.replacement);
        last_replaced_start = Some(start_u32);
    }

    out
}

fn slice_text_range<'a>(src: &'a str, range: TextRange) -> &'a str {
    let start = u32::from(range.start()) as usize;
    let end = u32::from(range.end()) as usize;
    &src[start..end]
}
