use rustyline::hint::Hinter;
use rustyline::history::DefaultHistory;
use rustyline::validate::Validator;
use rustyline::{Context, Editor, Helper};

use rustyline::keys::{KeyEvent, Modifiers};
use rustyline::keymap::{
    Cmd, ConditionalEventHandler, Event, EventContext, EventHandler, Movement, RepeatCount,
};

#[derive(Default)]
struct CommandHelper;

impl Helper for CommandHelper {}

impl Highlighter for CommandHelper {}
impl Validator for CommandHelper {}

impl Hinter for CommandHelper {
    type Hint = String;
}

impl Completer for CommandHelper {
    type Candidate = Pair;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        _ctx: &Context<'_>,
    ) -> rustyline::Result<(usize, Vec<Pair>)> {
        // Very small demo completer:
        // - "bo<TAB>" -> "book "
        // - "ti<TAB>" -> "title "
        // - "au<TAB>" -> "author "
        let before = &line[..pos];
        let start = before
            .rfind(|c: char| !c.is_ascii_alphanumeric() && c != '_')
            .map(|i| i + 1)
            .unwrap_or(0);
        let word = &before[start..];

        let mut out = Vec::new();
        for (trigger, replacement) in [
            ("bo", "book "),
            ("ti", "title "),
            ("au", "author "),
        ] {
            if word.starts_with(trigger) {
                out.push(Pair {
                    display: replacement.trim_end().to_string(),
                    replacement: replacement.to_string(),
                });
            }
        }

        Ok((start, out))
    }
}

struct DeleteWsBeforeCursorThenInsertPunct {
    insert: String,
}

impl DeleteWsBeforeCursorThenInsertPunct {
    fn new(insert: char) -> Self {
        Self {
            insert: insert.to_string(),
        }
    }
}

impl ConditionalEventHandler for DeleteWsBeforeCursorThenInsertPunct {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();
        let before = &line[..pos];

        let ws = before
            .chars()
            .rev()
            .take_while(|c| c.is_whitespace())
            .count();

        if ws == 0 {
            // No whitespace to clean up: fall back to the default binding
            // (i.e. normal self-insert for '.' / ',').
            return None;
        }

        let back = Movement::BackwardChar(ws as RepeatCount);

        // Rustyline's Cmd::Replace leaves the cursor at the start of the replaced region.
        // So we chain a Move(ForwardChar(1)) to land *after* the inserted punctuation.
        Some(Cmd::Macro(vec![
            Cmd::Replace(back, Some(self.insert.clone())),
            Cmd::Move(Movement::ForwardChar(1)),
        ]))
    }
}

fn bind_handler(editor: &mut Editor<CommandHelper, DefaultHistory>, key: char) {
    let event = KeyEvent::new(key, Modifiers::NONE);
    let handler = DeleteWsBeforeCursorThenInsertPunct::new(key);
    editor.bind_sequence(event, EventHandler::Conditional(Box::new(handler)));
}

fn main() -> rustyline::Result<()> {
    let mut rl = Editor::<CommandHelper, DefaultHistory>::new()?;
    rl.set_helper(Some(CommandHelper::default()));

    // Bind '.' and ',' so that if the cursor is after whitespace, the whitespace is removed
    // and the cursor ends up after the punctuation.
    bind_handler(&mut rl, '.');
    bind_handler(&mut rl, ',');

    println!("Try:  SELECT bo<TAB>.<type column>");
    println!("Type 'exit' to quit.");

    loop {
        let line = match rl.readline("zql> ") {
            Ok(l) => l,
            Err(rustyline::error::ReadlineError::Interrupted) => continue,
            Err(rustyline::error::ReadlineError::Eof) => break,
            Err(e) => return Err(e),
        };

        if line.trim().eq_ignore_ascii_case("exit") {
            break;
        }

        if !line.trim().is_empty() {
            let _ = rl.add_history_entry(line.as_str());
        }

        println!("You entered: {line}");
    }

    Ok(())
}
