{
  "Cargo.toml": "[package]
name = "rustyline_sql_completion"
version = "0.1.0"
edition = "2021"

[dependencies]
rustyline = "14"
",
  "main.rs": "use rustyline::completion::{Completer, Pair};
use rustyline::error::ReadlineError;
use rustyline::highlight::Highlighter;
use rustyline::hint::Hinter;
use rustyline::line_buffer::{Changeset, LineBuffer};
use rustyline::validate::Validator;
use rustyline::{Context, Editor, Helper};

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum Clause {
    Select,
    From,
    OrderBy,
    Other,
}

fn clause_before_cursor(s: &str) -> Clause {
    let tokens: Vec<String> = s
        .split(|c: char| c.is_whitespace() || ",().;".contains(c))
        .filter(|t| !t.is_empty())
        .map(|t| t.to_ascii_uppercase())
        .collect();

    let mut clause = Clause::Select;
    let mut i = 0;
    while i < tokens.len() {
        match tokens[i].as_str() {
            "SELECT" => clause = Clause::Select,
            "FROM" => clause = Clause::From,
            "WHERE" | "GROUP" | "HAVING" | "LIMIT" | "OFFSET" => clause = Clause::Other,
            "ORDER" => {
                if i + 1 < tokens.len() && tokens[i + 1] == "BY" {
                    clause = Clause::OrderBy;
                    i += 1; // consume BY
                } else {
                    clause = Clause::Other;
                }
            }
            _ => {}
        }
        i += 1;
    }

    clause
}

fn is_after_dot(line: &str, start: usize) -> bool {
    // look at the char immediately before the word start
    if start == 0 {
        return false;
    }
    line.as_bytes()[start - 1] == b'.'
}

fn word_start(line: &str, pos: usize) -> usize {
    let bytes = line.as_bytes();
    let mut i = pos;
    while i > 0 {
        let b = bytes[i - 1];
        if (b as char).is_ascii_alphanumeric() || b == b'_' {
            i -= 1;
        } else {
            break;
        }
    }
    i
}

struct SqlHelper {
    keywords: Vec<&'static str>,
    tables: Vec<&'static str>,
    columns: Vec<&'static str>,
}

impl SqlHelper {
    fn new() -> Self {
        Self {
            keywords: vec!["SELECT", "FROM", "ORDER", "BY", "WHERE"],
            tables: vec!["book", "author"],
            columns: vec!["year", "authorid", "title", "id", "name"],
        }
    }

    fn candidates_for(&self, clause: Clause, after_dot: bool) -> Vec<&'static str> {
        if after_dot {
            // after `table.` we only propose columns
            return self.columns.clone();
        }

        match clause {
            Clause::From => {
                // after FROM we mostly want tables
                self.tables.clone()
            }
            Clause::OrderBy => {
                // after ORDER BY we mostly want columns
                self.columns.clone()
            }
            Clause::Select => {
                // in SELECT list: could be keyword (SELECT), table (qualifier), or column
                let mut v = Vec::new();
                v.extend(self.keywords.iter().copied());
                v.extend(self.tables.iter().copied());
                v.extend(self.columns.iter().copied());
                v
            }
            Clause::Other => {
                let mut v = Vec::new();
                v.extend(self.keywords.iter().copied());
                v.extend(self.tables.iter().copied());
                v.extend(self.columns.iter().copied());
                v
            }
        }
    }

    fn should_append_space(&self, before: &str, start: usize, elected: &str) -> bool {
        let clause = clause_before_cursor(before);
        let after_dot = is_after_dot(before, start);

        if after_dot {
            return false;
        }

        let up = elected.to_ascii_uppercase();
        if self.keywords.iter().any(|k| *k == up) {
            return true;
        }

        // key idea/workaround:
        // In SELECT list we *don't* append a space after identifier completion,
        // so the user can type '.' immediately (no need for backspace).
        match clause {
            Clause::From => true,
            Clause::OrderBy => true,
            Clause::Select => false,
            Clause::Other => true,
        }
    }
}

impl Helper for SqlHelper {}
impl Hinter for SqlHelper {
    type Hint = String;
    fn hint(&self, _line: &str, _pos: usize, _ctx: &Context<'_>) -> Option<Self::Hint> {
        None
    }
}
impl Highlighter for SqlHelper {}
impl Validator for SqlHelper {}

impl Completer for SqlHelper {
    type Candidate = Pair;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        _ctx: &Context<'_>,
    ) -> Result<(usize, Vec<Pair>), ReadlineError> {
        let start = word_start(line, pos);
        let prefix = &line[start..pos];
        if prefix.is_empty() {
            return Ok((start, Vec::new()));
        }

        let before = &line[..pos];
        let clause = clause_before_cursor(before);
        let after_dot = is_after_dot(line, start);

        let prefix_up = prefix.to_ascii_uppercase();
        let mut out = Vec::new();
        for w in self.candidates_for(clause, after_dot) {
            if w.to_ascii_uppercase().starts_with(&prefix_up) {
                out.push(Pair {
                    display: w.to_string(),
                    replacement: w.to_string(),
                });
            }
        }

        Ok((start, out))
    }

    fn update(&self, line: &mut LineBuffer, start: usize, elected: &str, cl: &mut Changeset) {
        // Default update behavior is: replace current word with elected completion.
        // We override it so we can conditionally append a space.
        let end = line.pos();
        let before_str = line.as_str().to_string();
        let before_cursor = &before_str[..end];

        let mut replacement = elected.to_string();
        if self.should_append_space(before_cursor, start, elected) {
            replacement.push(' ');
        }

        line.replace(start..end, &replacement, cl);
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let helper = SqlHelper::new();

    let mut rl = Editor::new()?;
    rl.set_helper(Some(helper));

    println!(
        "Try e.g.:\n  SELECT * FROM bo<TAB>\n  SELECT bo<TAB>.title FROM book\n  SELECT * FROM book ORDER BY ti<TAB>\nCtrl-D to exit."
    );

    loop {
        match rl.readline("zql> ") {
            Ok(line) => {
                let l = line.trim();
                if l.eq_ignore_ascii_case("quit") || l.eq_ignore_ascii_case("exit") {
                    break;
                }
                rl.add_history_entry(line)?;
                println!("You entered: {l}");
            }
            Err(ReadlineError::Interrupted) => {
                // Ctrl-C
                println!("^C");
                continue;
            }
            Err(ReadlineError::Eof) => {
                // Ctrl-D
                break;
            }
            Err(e) => return Err(e.into()),
        }
    }

    Ok(())
}
